-- Poems batch 313
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('8c7d5668-f5d1-4b79-abd1-df0da9053ba2','春日獨酌十首  其六','郭祥正','宋','宋诗','song-poetry','','[]','雷聲散陽氣，晴景醉長天。',48,'全唐诗/poet.song.42000.json','["雷聲散陽氣，晴景醉長天。", "綠從何處來，染我山下泉。", "汲泉釀醇酒，舉盃復頹然。", "寄謝伯夷輩，餓名安用傳。"]'),
('ed9ec747-924a-432c-ac51-3ce9ed51cc66','春日獨酌十首  其七','郭祥正','宋','宋诗','song-poetry','','[]','春日何遲遲，萬物涵陽暉。',60,'全唐诗/poet.song.42000.json','["春日何遲遲，萬物涵陽暉。", "君看源上桃，並蔕花滿枝。", "雙雙梁間燕，營巢知所歸。", "凌霄附長松，託根亦有依。", "餘生如不飲，無以謝芳菲。"]'),
('d9a859e9-875b-44db-a854-bde13e415643','春日獨酌十首  其八','郭祥正','宋','宋诗','song-poetry','','[]','不羞雙鬢雪，折花向林間。',60,'全唐诗/poet.song.42000.json','["不羞雙鬢雪，折花向林間。", "念此光景速，未能身世閒。", "滿酌金熨斗，遙望謝公山。", "跡欲扁舟渡，心先高鳥還。", "今朝不酩酊，何以破愁顔。"]'),
('f4d323fe-a05e-4057-9c19-5f80e580c076','春日獨酌十首  其九','郭祥正','宋','宋诗','song-poetry','','[]','幾日待春光，春光易衰歇。',60,'全唐诗/poet.song.42000.json','["幾日待春光，春光易衰歇。", "流年信密移，誰能保肌髮。", "何須秉蠟炬，今夕值明月。", "但願海變酒，拍浮長出没。", "歸來歸去來，蓬山有仙闕。"]'),
('0547bfcf-8181-42c0-ad39-2353f1eb6c7d','春日獨酌十首  其一○','郭祥正','宋','宋诗','song-poetry','','[]','海棠微雨濕，枝上殘紅泣。',48,'全唐诗/poet.song.42000.json','["海棠微雨濕，枝上殘紅泣。", "山鳥啼向人，春光一何急。", "濁酒注我腸，免使新愁入。", "却欲買扁舟，漁竿荷蓑笠。"]'),
('93b0110b-7452-4c27-b329-d61fbe9b26d9','田家四時  其一','郭祥正','宋','宋诗','song-poetry','','[]','田田時雨足，鞭牛務深耕。',48,'全唐诗/poet.song.42000.json','["田田時雨足，鞭牛務深耕。", "選種隨土宜，播擲糯與秔。", "條桑去蠧枝，柔柔待春榮。", "春事不可緩，春鳥亦已鳴。"]'),
('060a848a-a8dc-4171-9511-fef12d697ae7','田家四時  其二','郭祥正','宋','宋诗','song-poetry','','[]','麻麥聞熟刈，蠶成繰莫遲。',48,'全唐诗/poet.song.42000.json','["麻麥聞熟刈，蠶成繰莫遲。", "更看田中禾，莨莠時去之。", "幸此赤日長，農事豈敢違。", "願言一歲稔，不受三冬饑。"]'),
('88335f7e-9e4f-4b6c-b3df-35750c4efd7b','田家四時  其三','郭祥正','宋','宋诗','song-poetry','','[]','開塍放餘水，經霜穀將實。',48,'全唐诗/poet.song.42000.json','["開塍放餘水，經霜穀將實。", "更黎原上疇，坎麥亦云畢。", "老叟呼兒童，敲林收橡栗。", "乃知田家勤，卒歲無閒日。"]'),
('4bb71afb-be8c-46f0-bf1f-61e1c7033bf0','田家四時  其四','郭祥正','宋','宋诗','song-poetry','','[]','田事今云休，官輸亦已足。',48,'全唐诗/poet.song.42000.json','["田事今云休，官輸亦已足。", "刈禾既盈囷，採薪又盈屋。", "牛羊各蕃衍，御冬多旨蓄。", "何以介眉壽，甕中酒新熟。"]'),
('3101342b-3e02-4b1c-934d-7203e81a75b3','朝登北山頭二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','朝登北山頭，千里入平望。',48,'全唐诗/poet.song.42000.json','["朝登北山頭，千里入平望。", "本欲寄吾懷，胡爲返惆悵。", "晴雲隨白日，西去没青嶂。", "素絲行滿頭，吾年安可壯。"]'),
('9f0f31c1-e76d-4f0e-aab3-76314857e03c','朝登北山頭二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','朝登北山頭，悠悠望江水。',48,'全唐诗/poet.song.42000.json','["朝登北山頭，悠悠望江水。", "水流無還期，人老行已矣。", "勸君把一樽，聊用置悲喜。", "生無死何有，原終乃知始。"]'),
('abaf99f2-d436-453c-a8cc-a141f2a11fea','感春二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','高枝花自舞，低枝花自笑。',48,'全唐诗/poet.song.42000.json','["高枝花自舞，低枝花自笑。", "上有濃露濯，下有清溪照。", "開落十日間，誰識春工妙。", "一杯亦頽然，獨醒時所誚。"]'),
('fc53a263-26e3-4425-9431-c9d3ebf4774b','感春二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','盎盎酒盃綠，披披花萼笑。',48,'全唐诗/poet.song.42000.json','["盎盎酒盃綠，披披花萼笑。", "雖無同心客，幸有白日照。", "趨時性已拙，悲歌聲不妙。", "素髮未能歸，猿鳥應相誚。"]'),
('d73e221e-35ed-467e-837e-a1faced95ee4','同阮時中秀才食笋二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','蒼崖長龍孫，頭角露已甚。',192,'全唐诗/poet.song.42000.json','["蒼崖長龍孫，頭角露已甚。", "呼丁恣庖割，移榻就濃蔭。", "怳疑羽林槍，羅列在紫禁。", "餘鞭横瘦蛇，密籜若紉紝。", "亭亭風勢匀，節節泉脈沁。", "藩垣謹藏護，寧使暴客闖。", "烹調衆云美，剪伐吾亦任。", "繞齒嚼冰澌，毛髮寒以澿。", "閒心本猿鳥，世詠嗟毒鴆。", "野逸誰所憐，愁思腸胃滲。", "詩才君獨勇，辨舌予久噤。", "酒行且莫辭，醉膽滄溟浸。", "况逢堯舜治，面內來左袵。", "熙熙冠蓋游，落落飽食飲。", "鸞鳳自横飛，燕雀蒙廣廕。", "徘徊食笋謠，明發扁舟賃。"]'),
('8ffffdad-c3f8-4f06-95fd-9eca95090ffb','同阮時中秀才食笋二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','予生本無羈，繆爲兹縣尹。',108,'全唐诗/poet.song.42000.json','["予生本無羈，繆爲兹縣尹。", "日長公事餘，佳客車接軫。", "入林安所食，烹庖就肥笋。", "森森蒼龍孫，頭角遭束窘。", "金刀僕爭割，紫籜手親隕。", "草火尤相宜，狼藉亦殘忍。", "聊爲一餉樂，得酒輒滿引。", "喧呼棋屢勝，慘淡詩不敏。", "予腹既便便，從君莞而哂。"]'),
('15db8501-09c6-44d3-b201-4e31b746207f','追和李太白姑熟十詠 姑熟溪','郭祥正','宋','宋诗','song-poetry','','[]','源從丹湖來，奔流朝北極。',48,'全唐诗/poet.song.42000.json','["源從丹湖來，奔流朝北極。", "雙橋跨長虹，千艘濟民食。", "日華動清曉，岸柳搖行色。", "文王未出獵，垂竿人莫識。"]'),
('02ab0e76-fca5-4279-a841-6badf060f047','追和李太白姑熟十詠 丹陽湖','郭祥正','宋','宋诗','song-poetry','','[]','湖廣際長天，永日微風止。',48,'全唐诗/poet.song.42000.json','["湖廣際長天，永日微風止。", "菱歌一舟去，雪陣羣鷗起。", "荷香迷近遠，秋色瑩表裏。", "試問賀季真，何如鏡湖水。"]'),
('128889f1-e9ea-44ea-93de-a8d3972b5cc3','追和李太白姑熟十詠 謝公宅','郭祥正','宋','宋诗','song-poetry','','[]','山腰存廢址，昔是玄暉宅。',48,'全唐诗/poet.song.42000.json','["山腰存廢址，昔是玄暉宅。", "林藏幽鳥聲，月弄野棠白。", "高賢百年盡，遺事千古積。", "此興欲誰論，摩挲問磐石。"]'),
('8bc8476f-3368-4fbe-a4ab-84e28afb2fe5','追和李太白姑熟十詠 凌敲臺','郭祥正','宋','宋诗','song-poetry','','[]','高臺築千尋，勝景供遠目。',48,'全唐诗/poet.song.42000.json','["高臺築千尋，勝景供遠目。", "雲烟護城郭，吳楚接川陸。", "不知歌舞散，雌鳳叫空竹。", "鬼火照殘碑，應有精靈讀。"]'),
('e259d546-8b0b-4352-9dbc-227b4e6b1edb','追和李太白姑熟十詠 桓公井','郭祥正','宋','宋诗','song-poetry','','[]','環營鑿九井，井深泉不竭。',48,'全唐诗/poet.song.42000.json','["環營鑿九井，井深泉不竭。", "舊甃缺瓊瑶，新苔荒歲月。", "重吟太白題，興自柏公發。", "我欲唤常娥，團圓伴澄澈。"]'),
('28fb4d9d-1026-4e61-ae93-46e55094da3e','追和李太白姑熟十詠 慈姥竹','郭祥正','宋','宋诗','song-poetry','','[]','一種碧琅玕，攢根繞蒼島。',48,'全唐诗/poet.song.42000.json','["一種碧琅玕，攢根繞蒼島。", "濃陰不透日，密幄得春早。", "笙隨緱氏仙，釣入磻溪好。", "欲識化龍蛇，唯應雪霜保。"]'),
('ae9f18c0-f7d1-433f-86c1-8e1c2015c6c0','追和李太白姑熟十詠 望夫山','郭祥正','宋','宋诗','song-poetry','','[]','登高望天涯，化石與君别。',48,'全唐诗/poet.song.42000.json','["登高望天涯，化石與君别。", "秋鬢霜露深，春衫薜蘿發。", "旅雁只空飛，悲咽長不絕。", "行客歸去來，芳心可休歇。"]'),
('0ac542f5-44da-4781-8de8-4efd1d63940f','追和李太白姑熟十詠 牛渚磯','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江瀉危磯，雷怒安可向。',48,'全唐诗/poet.song.42000.json','["長江瀉危磯，雷怒安可向。", "烟雲忽藏月，鯨鯢互噴浪。", "朱衣叱犀火，丹青豈能狀。", "引盃聊醉吟，徑卧巨鼇上。"]'),
('4afa2105-d999-4641-9aad-e485766d9f31','追和李太白姑熟十詠 靈墟山','郭祥正','宋','宋诗','song-poetry','','[]','仙人赴金闕，靈墟躡高路。',48,'全唐诗/poet.song.42000.json','["仙人赴金闕，靈墟躡高路。", "空見白雲飛，想乘黄鶴去。", "月冷步虚壇，苔深煉丹處。", "塵寰欲何爲，光陰等閒度。"]'),
('fd541a9e-df25-43e2-be91-2dd8d577df5e','追和李太白姑熟十詠 天門山','郭祥正','宋','宋诗','song-poetry','','["\u5929\u95e8\u5c71"]','巨靈擘蒼山，勢分金闕對。',48,'全唐诗/poet.song.42000.json','["巨靈擘蒼山，勢分金闕對。", "月引曉嵐交，江翻寒影碎。", "雙鳬落人間，千帆出天外。", "我欲往高吟，凌虛踏烟靄。"]'),
('6dc9506c-32d9-40eb-99d8-9d1f6aebe078','追和李白秋浦歌十七首  其一','郭祥正','宋','宋诗','song-poetry','','[]','碧水碧如淀，染成秋浦愁。',60,'全唐诗/poet.song.42000.json','["碧水碧如淀，染成秋浦愁。", "長橋通驛道，危堞起朱樓。", "蕩槳誰家女，菱歌自風流。", "江心雪浪湧，知解渡江不。", "却羡雲中雁，低飛過北州。"]'),
('15b91b6a-c18c-48d7-9e95-6f6d3cecd159','追和李白秋浦歌十七首  其二','郭祥正','宋','宋诗','song-poetry','','[]','此夕宿秋浦，蕭蕭古岸頭。',48,'全唐诗/poet.song.42000.json','["此夕宿秋浦，蕭蕭古岸頭。", "白雲和月散，江水晴空流。", "不及水中鳥，隨波上下游。", "客情須自遣，知命適虚舟。"]'),
('b38d2700-39dc-4f38-b786-1e6c2b1575d0','追和李白秋浦歌十七首  其三','郭祥正','宋','宋诗','song-poetry','','[]','水晚舟檝止，山寒猿狖稀。',24,'全唐诗/poet.song.42000.json','["水晚舟檝止，山寒猿狖稀。", "雖憐秋浦好，未敢濯征衣。"]'),
('96186f4c-5a61-4060-9d99-0db95ef5438f','追和李白秋浦歌十七首  其四','郭祥正','宋','宋诗','song-poetry','','[]','霜落荻洲晚，水殘魚市衰。',24,'全唐诗/poet.song.42000.json','["霜落荻洲晚，水殘魚市衰。", "唯逢採荷女，素手理輕絲。"]'),
('a3a0a3b2-1968-4e48-b936-e4160af80cf8','追和李白秋浦歌十七首  其五','郭祥正','宋','宋诗','song-poetry','','[]','莫聽猿夜啼，莫看蘆花雪。',24,'全唐诗/poet.song.42000.json','["莫聽猿夜啼，莫看蘆花雪。", "倦客多少愁，離家八九月。"]'),
('b85ed4f6-4206-4233-9ecf-7e1a5f7887db','追和李白秋浦歌十七首  其六','郭祥正','宋','宋诗','song-poetry','','[]','水有錦駝鳥，山多杜宇花。',24,'全唐诗/poet.song.42000.json','["水有錦駝鳥，山多杜宇花。", "扁舟投夜泊，来自長風沙。"]'),
('ece38bf6-641f-4de7-b0ce-13e6e7968909','追和李白秋浦歌十七首  其七','郭祥正','宋','宋诗','song-poetry','','[]','秋水適瀰漫，寧分馬與牛。',24,'全唐诗/poet.song.42000.json','["秋水適瀰漫，寧分馬與牛。", "酒樓翻擅價，不當白狐裘。"]'),
('f47d6eb5-554c-4ebb-a809-2c094aa1ba5a','追和李白秋浦歌十七首  其八','郭祥正','宋','宋诗','song-poetry','','[]','秋浦試北望，參天九峰奇。',24,'全唐诗/poet.song.42000.json','["秋浦試北望，參天九峰奇。", "緣何謫仙客，名作碧蓮枝。"]'),
('edd23581-ed34-44c3-b450-93ac224461dc','追和李白秋浦歌十七首  其九','郭祥正','宋','宋诗','song-poetry','','[]','萬丈水車嶺，還如九疊屏。',24,'全唐诗/poet.song.42000.json','["萬丈水車嶺，還如九疊屏。", "北風来不斷，六月亦冰生。"]'),
('9ac7631b-d3b7-4ac3-9810-d43c7767fc3d','追和李白秋浦歌十七首  其一○','郭祥正','宋','宋诗','song-poetry','','[]','捨檝乘藍輿，十里穿松林。',36,'全唐诗/poet.song.42000.json','["捨檝乘藍輿，十里穿松林。", "悲風西北至，千千龍鳳吟。", "史君如杜牡，方有愛山心。"]'),
('c1d2180a-2bc8-4c47-aeac-4a45ecaecf40','追和李白秋浦歌十七首  其一一','郭祥正','宋','宋诗','song-poetry','','[]','齊山一百洞，咫尺接危梁。',24,'全唐诗/poet.song.42000.json','["齊山一百洞，咫尺接危梁。", "雨過頻登望，逼人松檜香。"]'),
('1d25c144-5b48-4035-a67d-2d0da9664041','追和李白秋浦歌十七首  其一二','郭祥正','宋','宋诗','song-poetry','','[]','清溪十里岸，蘆花八月天。',24,'全唐诗/poet.song.42000.json','["清溪十里岸，蘆花八月天。", "不惜錦袍濕，應須櫂釣船。"]'),
('cda7e70f-4868-49ab-a8d2-49efea4b7f27','追和李白秋浦歌十七首  其一三','郭祥正','宋','宋诗','song-poetry','','[]','秋浦勝姑熟，白鷴無數飛。',24,'全唐诗/poet.song.42000.json','["秋浦勝姑熟，白鷴無數飛。", "謫仙如得句，須换一雙歸。"]'),
('4ccfe0cd-d794-4c3e-814d-0dca45b52120','追和李白秋浦歌十七首  其一四','郭祥正','宋','宋诗','song-poetry','','[]','老謝奪秋景，横卷披雲烟。',24,'全唐诗/poet.song.42000.json','["老謝奪秋景，横卷披雲烟。", "寓目不知遠，何須家輞川。"]'),
('9bd11e24-76ba-486e-aaad-49e29559eb9b','追和李白秋浦歌十七首  其一五','郭祥正','宋','宋诗','song-poetry','','[]','鏡潭弄秋月，始知秋興長。',24,'全唐诗/poet.song.42000.json','["鏡潭弄秋月，始知秋興長。", "金龜能换酒，客鬢不嫌霜。"]'),
('8eac87de-5e7d-48df-b256-4438b9ab4dbc','追和李白秋浦歌十七首  其一六','郭祥正','宋','宋诗','song-poetry','','[]','半空紫微亭，翫月動經宿。',24,'全唐诗/poet.song.42000.json','["半空紫微亭，翫月動經宿。", "更待雨中來，林林看銀竹。"]'),
('fe52e216-f23e-4700-a4f4-621dfba20101','追和李白秋浦歌十七首  其一七','郭祥正','宋','宋诗','song-poetry','','[]','秋浦一何好，名因太白聞。',24,'全唐诗/poet.song.42000.json','["秋浦一何好，名因太白聞。", "溪山圍市井，鼓角下烟雲。"]'),
('14f1ac8f-1d57-4f34-a4ff-bc40cae12d36','追和李白登金陵鳳凰臺二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','采鳳何年此地遊，高臺千古自風流。',64,'全唐诗/poet.song.42000.json','["采鳳何年此地遊，高臺千古自風流。", "寒烟淡淡籠城郭，寶器時時出冢丘。", "舴艋競歸芳草渡，鷺鷥羣舞碧蘆洲。", "重華不返簫韶斷，落日秦淮添客愁。"]'),
('ba583327-a2c9-47f5-9524-2668e91f7ccb','追和李白登金陵鳳凰臺二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','高臺不見鳳凰遊，望望青天入海流。',64,'全唐诗/poet.song.42000.json','["高臺不見鳳凰遊，望望青天入海流。", "舞罷翠娥同去國，戰殘白骨尚盈丘。", "風搖落日催行櫂，潮卷新沙換故洲。", "結綺臨春無覓處，年年芳草向人愁。"]'),
('ab345002-5b73-4978-bf70-6f64f558bff3','舟次新林先寄府尹安中尚書用李白寄楊江寧韻二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','金陵龍虎國，况與王謝期。',108,'全唐诗/poet.song.42000.json','["金陵龍虎國，况與王謝期。", "掛帆須一往，願借天風吹。", "昔解徐孺榻，别来勞夢思。", "鐘峰當北戶，浮玉出東池。", "柳青白下門，鷺棲瓊樹枝。", "但對樽中物，何嗟鏡裏絲。", "如聞紫泥詔，起公翊明時。", "霈爲天下霖，一洗旱暵悲。", "請歌甘棠歌，翻作新林詩。"]'),
('16f6f640-d00c-40e0-a573-3a7a3be3febd','舟次新林先寄府尹安中尚書用李白寄楊江寧韻二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','休居尚蒙祿，願赴興龍期。',108,'全唐诗/poet.song.42000.json','["休居尚蒙祿，願赴興龍期。", "况此孱病姿，感公久嘘吹。", "相望止百里，株坐徒傾思。", "呼僮刷鶴羽，駕言别清池。", "往將投新林，新林有高枝。", "仰聽鸞鳳音，軋軋如抽絲。", "窮陰欲雪天，燕雀無聲時。", "接物伸妙理，運心廣真悲。", "如何持一盃，要我百篇詩。"]'),
('11148ba3-70ae-45bd-82a6-5547427fd3e8','舟次白鷺洲再寄安中尚書用李白寄楊江寧韻  其一','郭祥正','宋','宋诗','song-poetry','','[]','白鷺飛還集，新沙没故洲。',72,'全唐诗/poet.song.42000.json','["白鷺飛還集，新沙没故洲。", "山形龍晦角，江氣蜃爲樓。", "欲問前朝事，空懷去國憂。", "鐘聲萬家曉，霜葉半城秋。", "化值唐虞盛，人逢王謝流。", "徐生思解榻，兵醞可銷愁。"]'),
('f7eb07dd-1003-4ed6-9dcd-a83ca1784615','舟次白鷺洲再寄安中尚書用李白寄楊江寧韻  其二','郭祥正','宋','宋诗','song-poetry','','[]','終朝蕩雙槳，夜泊碧蘆洲。',72,'全唐诗/poet.song.42000.json','["終朝蕩雙槳，夜泊碧蘆洲。", "重城已在望，聞公晏層樓。", "華燈燦繁星，浩歌正忘憂。", "賓朋集珠履，佳節臨千秋。", "願言刷微羽，一飲清冷流。", "舉目送高鳳，簫韶洗民愁。"]'),
('50f72baa-1f68-445f-856f-8e26cf1d0d62','奉同安中尚書用李白留别王嵩韻送毛王仲大夫移浙漕','郭祥正','宋','宋诗','song-poetry','','["\u592a\u6e56"]','春岸草回綠，春江日浮金。',108,'全唐诗/poet.song.42000.json','["春岸草回綠，春江日浮金。", "蘭舟忽言發，芥蔕悲我心。", "藹藹松柏友，雍雍鸞鳳吟。", "願同三歲遙，毋使離别侵。", "奈何千丈材，亭亭不依林。", "眷爲九重知，移節宣德音。", "遂令帝王澤，深于太湖深。", "豈同失羣鶴，飲啄憐空岑。", "誰將勞勞歌，一瀉無瑶琴。"]'),
('5e484229-a6de-42ae-9482-ff59c1524064','將遊宣城先寄賈太守侍御用李白寄崔侍御韻','郭祥正','宋','宋诗','song-poetry','','[]','峨峨敬亭山，玄暉有佳作。',120,'全唐诗/poet.song.42000.json','["峨峨敬亭山，玄暉有佳作。", "賈公乃後身，風流今與昨。", "豸冠觸姦邪，分符宛陵郭。", "江湖暫徘徊，烟霄必騰躍。", "予方臥閒雲，時或乘皓鶴。", "水縮龍蜃歸，霜清天宇廓。", "安能坐隴畝，凄凄眷藜霍。", "陳蕃有虛榻，黄埃侵斷索。", "能如汲黯直，定許季生諾。", "往哉不可失，行聞還鳳閣。"]'),
('a5e65506-5641-483a-96c4-b07f52afe5c9','追和李白宣州清溪','郭祥正','宋','宋诗','song-poetry','','[]','清溪安在哉，欲弄清溪水。',48,'全唐诗/poet.song.42000.json','["清溪安在哉，欲弄清溪水。", "更邀琴高生，攜竿會於此。", "日落翠屏間，鷄鳴桃花裏。", "不見避秦人，誰嗟遠遊子。"]'),
('29e9f20a-e187-48e8-bb64-a823bc767d22','留别陳元輿待制用李白贈友人韻','郭祥正','宋','宋诗','song-poetry','','[]','沈吟澗底松，不及堯階草。',60,'全唐诗/poet.song.42000.json','["沈吟澗底松，不及堯階草。", "不經君王顧，枉被風霜老。", "弱羽戀一枝，敢思浴天池。", "聞君有餘力，何惜一噓吹。", "青雲與黄壌，迴首隔追隨。"]'),
('497ceb0f-cbdc-4d80-a1d6-ba31fd5504a2','留别宣守賈侍御用李白贈趙悅韻','郭祥正','宋','宋诗','song-poetry','','[]','賈誼幾世孫，閑邪誠所存。',288,'全唐诗/poet.song.42000.json','["賈誼幾世孫，閑邪誠所存。", "一登御史府，直氣壮中原。", "五載三去國，出論皆騰喧。", "浩養固無害，宣城况名藩。", "下車究積弊，摘節仍除根。", "乃遷孔子學，方庭樹蘭蓀。", "講解得董生，思單先生恩。", "軒軒慕高第，各各不窺園。", "修橋濟行邁，掩骼招旅魂。", "蕭蕭囹圄空，清風時掃門。", "尋山出近郭，玉船紅浪翻。", "誰爲坐上客，能酬謝公言。", "自愧翅翎短，謬參鴻與鵷。", "不有瓦礫賤，那知圭璧尊。", "矧曰半面雅，歲久情愈敦。", "三章寵新作，詞源何駿奔。", "幾欲效長吉，微吟謝高軒。", "霜威信凛冽，即之自溫溫。", "又如太古鏡，磨開蒼蘚昏。", "肝膽悉照徹，魑魅安敢論。", "行聞紫泥詔，沙路馳歸轅。", "豈容隱巖子，留連愛石盆。", "看君楊天翼，北溟終化鵾。", "而我隨白鳥，丹湖往孤鶱。"]'),
('fd393154-7f39-40f6-9f17-f39fd587ee28','追和李白郎官湖寄漢陽太守劉宜父','郭祥正','宋','宋诗','song-poetry','','[]','遷客昔登覽，愁烟頹四隅。',60,'全唐诗/poet.song.42000.json','["遷客昔登覽，愁烟頹四隅。", "身趨夜郎道，戀咸陽陽都。", "此景古來好，此人今則無。", "空餘秋夜月，素影湛平湖。", "便欲凌風去，酣歌與君俱。"]'),
('cca12836-c3e5-4d03-8d1d-33e6d8851b91','題化城寺新公清風亭用李白元韻','郭祥正','宋','宋诗','song-poetry','','[]','唐時升老亭，剪棘今重開。',156,'全唐诗/poet.song.42000.json','["唐時升老亭，剪棘今重開。", "南瞻峨嵋闕，北峙凌敲臺。", "新公將家子，爲僧亦多才。", "譬彼獨鶴唳，安用羣雞猜。", "或彈玉軫琴，傾耳濯纖埃。", "清風不知處，冷冽時時來。", "吹雲雲窈窕，吹月月徘徊。", "幽人許共賞，渴心咀珍梅。", "了然得真味，塵魔屢崩摧。", "令妷人豪傑，書名駭奔雷。", "禪談屢終夕，茗酌無餘盃。", "還歌太白篇，事往良可哀。", "古今儻同轍，浩氣不寒灰。"]'),
('e5948c2c-b39e-4713-b417-74d9ec7240f6','太守陳侯見要登黄山送馬東玉遂用李白登黄山送族弟濟赴華陰韻呈陳侯并送東玉','郭祥正','宋','宋诗','song-poetry','','[]','潁川賢大夫，虛懷藴虹霓。',192,'全唐诗/poet.song.42000.json','["潁川賢大夫，虛懷藴虹霓。", "雖分銅虎符，合在帝苑棲。", "邀我登黄山，攀雲絕長梯。", "霜林正搖落，寒鳥鳴慘悽。", "金牛飲空渚，天鏡開峨嵋。", "塵埋宋武妓，蘚剥開元碑。", "謫仙送客處，魂斷白日低。", "松梢想獨鶴，軒昂避羣雞。", "還思北溟釣，赤脚蹋鯤鯢。", "時窮壯士恥，思遠騷人悲。", "且舉一盃酒，肯分雲與泥。", "坐有北歸客，張帆震雷鼙。", "往獻白玉璞，不憐紅粉啼。", "薦章已交達，高名動朝閨。", "君相必見收，烟霄速横飛。", "盃停可以起，看君開羽儀。"]'),
('151360ce-b9fb-4487-9bac-aeee95689a06','盛仲舉秀才歸自九華極談勝賞亟取李白九華聯句原韻作二首誌之  其一','郭祥正','宋','宋诗','song-poetry','','[]','客從青陽歸，爲我談九華。',48,'全唐诗/poet.song.42000.json','["客從青陽歸，爲我談九華。", "雪潭昨夜宿，衣上有殘霞。", "鳴溜隔深木，白鷴栖翠崖。", "南遊豈是遠，乘興必攜家。"]'),
('1a03b6ad-128c-4a9c-92cc-296773dca7a5','盛仲舉秀才歸自九華極談勝賞亟取李白九華聯句原韻作二首誌之  其二','郭祥正','宋','宋诗','song-poetry','','[]','昔號九仙子，今名九蓮華。',48,'全唐诗/poet.song.42000.json','["昔號九仙子，今名九蓮華。", "差差浮碧海，葉葉散晴霞。", "積靄迷金寺，飛流濺雪崖。", "開簾陪岸幘，須覓夏侯家。"]'),
('7a9bb9ed-d48d-41b6-b631-6600bcb4dccb','望九華山寄夏公酉','郭祥正','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','扁舟泝南江，羣山漸秀發。',156,'全唐诗/poet.song.42000.json','["扁舟泝南江，羣山漸秀發。", "遙瞻九華峰，點點出天末。", "迤邐見雄奇，平地犀尖拔。", "夕陽凝紫煙，仙簪聚鴉髪。", "又疑碧蓮花，倒插黄金闕。", "想像終未工，靈襟謾超越。", "矧彼山中人，了與塵事絕。", "採秀既忘年，道授飛仙說。", "世間名任高，物外緣皆滅。", "百憂眷薄祿，我輩志已屑。", "趨榮羞捷途，就卑老剛節。", "雅知名山樂，勇往胡未決。", "此興待君論，青衫可偕裂。"]'),
('58d716fa-550a-43ef-9cdf-69a8a7ce5aef','感懷贈鄂守李公擇','郭祥正','宋','宋诗','song-poetry','','[]','君顔削寒冰，君心抱堅玉。',288,'全唐诗/poet.song.42000.json','["君顔削寒冰，君心抱堅玉。", "自甘正諫黜，不受公議辱。", "請言會面初，遭艱守窮屋。", "屋臨修水陽，蓬門入深竹。", "伯季止三人，羣書聚頭讀。", "野夫學孟郊，苦吟中夜哭。", "公達學伊尹，經濟飽胸腹。", "君乃學揚雄，草玄明倚伏。", "遂兼孔氏易，極變悟神速。", "亭亭出林材，濯春千丈綠。", "我願從之遊，旦暮同飲餗。", "忠規日有益，文彩觀郁郁。", "不肖俄遭讒，逃形入空谷。", "諸君釋服起，爲貧苟微祿。", "君來宣城幕，衆謂得杜牧。", "我適游昭亭，林中騎白鹿。", "時趨資深堂，遇君亦休沐。", "飲酣河漢低，談高鬼神肅。", "出處二三年，於焉失羈束。", "一別幾何時，離羣念幽獨。", "野夫今郎官，佐郡馳朱轂。", "公達遽不幸，高名收鬼錄。", "君昔居諫省，上方容啟沃。", "忽分江夏符，善教蘇弊俗。"]'),
('7731cbe4-c27a-4134-8d72-894c058c3f60','采石峨嵋亭登覽贈翰林張唐公','郭祥正','宋','宋诗','song-poetry','','[]','巨舟發長溪，簫鼓奏雲漢。',288,'全唐诗/poet.song.42000.json','["巨舟發長溪，簫鼓奏雲漢。", "史君領賓從，險絕窮壯觀。", "逶迤轉滄洲，稍泊大江岸。", "前登千丈峰，萬里瞰瀰漫。", "峨嵋聳雙碧，斬斬天塹斷。", "誰驅六龍轡，事逐孤煙散。", "如聞限南北，謬彼曹公嘆。", "寧知真人興，遐徼服輝煥。", "僭王苟餘息，窘束若鼠竄。", "虹蜺渡戈甲，雷雨洗屯難。", "石根有遺迹，俯首想神算。", "承平逾百年，鍼砭決癰𤴯。", "幸茲國老賢，州事無留斷。", "披榛構危亭，突兀出天半。", "樂成須吾曹，嘯詠爭璀璨。", "天空纖靄沒，川動日華亂。", "羣鷗或飛舞，縞練遺片段。", "歸艎鯨鬣擺，漁火星點燦。", "靈犀安用燬，神理幽可贊。", "翻思袁謝輩，道貴一以貫。", "遇古名空傳，逢今歲非晏。", "我公神采瑩，皎皎白玉瓘。", "言詞珠內擲，肝腎錦繡爛。", "平生存至誠，許與比象彖。"]'),
('4cb17b35-44a3-4c39-937e-76a1f5747699','贈泗守宋子堅','郭祥正','宋','宋诗','song-poetry','','[]','憶昔始相遇，諫院吳侯家。',240,'全唐诗/poet.song.42000.json','["憶昔始相遇，諫院吳侯家。", "君顔清且少，皓雪敷瓊花。", "把酒聽高談，正氣橫鏌鋣。", "倏別二十載，各在天一涯。", "君去登朝閨，我方浮海槎。", "進退自殊轍，音塵空雁駕。", "朅來淮上守，政聲被幽遐。", "填德在風俗，餘春散禾麻。", "斤斤梁棟材，葱蒼蟄龍蛇。", "匠石未迴首，電雹無傾斜。", "而我造賓榻，逢鬢吹塵沙。", "歡言問往事，念此歲月賒。", "開館使休息，投文誤矜誇。", "伯樂雖一顧，慚非真渥漥。", "功名業已晚，世路今仍差。", "獨既醒不容，混迹良可嗟。", "清江秀山水，白酒浮月華。", "深犁熟粳稻，淺釣多魚蝦。", "長爲避俗翁，不落猛虎牙。", "願言雖未諧，行矣君及瓜。"]'),
('ec2f072b-9dae-4ba0-b113-2832f21762a5','贈元龍圖子發','郭祥正','宋','宋诗','song-poetry','','[]','明公有盛名，十年懷慕向。',240,'全唐诗/poet.song.42000.json','["明公有盛名，十年懷慕向。", "昨聞守桂林，清風掃蠻瘴。", "否來偶遷謫，暫泊宛溪上。", "斯事公議存，君命詎惆悵。", "坐扃顧申卯，自忘曾帥將。", "徯餘領兒孫，時時入重嶂。", "遇勝寄幽懷，覽古興絕唱。", "況逢謫御史，文章號宗匠。", "賡酬戛金玉，側耳聽響亮。", "神交付逍遙，外物隨得喪。", "漢庭憂乏才，賈誼豈終放。", "未即登金鑒，行須復牙帳。", "矧公飽經術，義足明霸王。", "推忠結聖主，大業繼賢相。", "霈成三日霖，一慰天下望。", "微生實幸會，漫刺詣高閌。", "塵埃蒙弊裘，何以異罔象。", "屏詘誠所宜，獎與若爲當。", "逢知信有時，報德亦非妄。", "且陪昭亭遊，昭亭春盎盎。"]'),
('e6fa56d3-8e27-4258-9aba-d586dbc3ede9','贈夏公酉寺丞','郭祥正','宋','宋诗','song-poetry','','["\u8861\u5c71"]','秋浦明似鏡，九華碧參天。',288,'全唐诗/poet.song.42000.json','["秋浦明似鏡，九華碧參天。", "秀色動南斗，乃生名世賢。", "卓越夏夫子，其才文武全。", "一覽無復遺，萬卷能口傳。", "奏書黄金闕，坐可安二邊。", "功名初自許，世路多迴邅。", "亭亭出林幹，暴爲狂風纏。", "乘槎往滄海，怒濤觀大川。", "還聞上南嶽，闊步從飛仙。", "解衣祝融峰，濯足天池淵。", "下視白日沒，九州渺蒼煙。", "傾罍弔屈賈，汝道吾未然。", "胡爲奪浩氣，慘淡趨重泉。", "冥心想太古，妙理追淳源。", "白雲起歸興，卻泛千丈船。", "少泊姑溪頭，春林聽杜鵑。", "謝李迹已往，高風在遺編。", "浮魂試一招，相望誰後先。", "伊余亦何人，謬拍洪崖肩。", "放身逍遙鄉，致主知何緣。", "斯時方泰熙，薰風播朱弦。", "奇才森大庭，拔茅茹相連。", "豈聞卞氏璧，指以微瑕捐。", "願取魋倉徒，投北首可懸。"]'),
('5379e213-2463-415e-9553-5d65a12583cc','贈二李居士','郭祥正','宋','宋诗','song-poetry','','[]','二子跨黄犢，尋春造龍眠。',288,'全唐诗/poet.song.42000.json','["二子跨黄犢，尋春造龍眠。", "身披五雲裝，翠發散垂肩。", "羣兒漫相逐，不識南昌仙。", "我往一長揖，問我聊停鞭。", "深林藉草坐，對酌臨潺湲。", "瑯瑯聽險語，了了出愛纏。", "月殿折芳桂，高名金榜懸。", "掉頭不回顧，息迹棦淳源。", "窮幽採紫芝，長嘯呼青猿。", "使我慕高節，神魄方森然。", "言歸恨不早，白雪羞盈顛。", "於時業無補，碌碌隨冗員。", "交趾近反逆，蟻聚浮戰船。", "邕廉皆失守，聖主憂南邊。", "上將命逵卨，睿算天所傳。", "虎羆十萬衆，干戈與雲連。", "傾海洗梟巢，拓境除狼煙。", "悵懷炎瘴地，何日聞凱旋。", "北虜恃驕黠，分疆亦逾年。", "廟謨非不深，遣使皆俊賢。", "此事竟未果，艱虞甚防川。", "安得傅介子，萬里威名宣。", "不然隨隱淪，漁釣求深淵。", "出處兩齬齟，悲歌寫哀弦。"]'),
('e9c6654d-e286-4888-9be6-dd0b6a25bd6d','贈樂嶽山人','郭祥正','宋','宋诗','song-poetry','','[]','樂老出三峽，騎驢訪名山。',96,'全唐诗/poet.song.42000.json','["樂老出三峽，騎驢訪名山。", "一見五老峰，笑傲遂忘還。", "蕭蕭太古松，徙倚青崖間。", "泉石託生計，雲霞會追攀。", "我寧求世人，世人非我閑。", "鍊氣得真惠，神針起疵癏。", "何時駕皓鶴，定應出塵寰。", "王母如問僕，爲謝今鈍頑。"]'),
('6435bc2d-e174-4981-a26d-b23fe59ec348','贈辨才宗衍大師','郭祥正','宋','宋诗','song-poetry','','[]','開帆出長淮，泊舟近禪剎。',144,'全唐诗/poet.song.42000.json','["開帆出長淮，泊舟近禪剎。", "仰瞻窣雲塔，俯壓神物穴。", "衍語如懸河，事從古先說。", "欣聞佛力聖，降魔未嘗殺。", "爾來居幾年，戒履皎霜雪。", "領徒三百人，晝飯天廚說。", "重重殿閣陰，清爽無六月。", "固知出世緣，了與俗士別。", "此生猶孤蓬，驚風畏飄瞥。", "長林宿鳥盡，而我歸路絕。", "出處既不同，凈社無由結。", "三嘆復何言，疏鍾雲外滅。"]'),
('fa8ef061-7661-461c-ab18-119b69f2a2ca','贈圓通訥禪師','郭祥正','宋','宋诗','song-poetry','','[]','禪師古豪英，識之恨已晚。',180,'全唐诗/poet.song.42000.json','["禪師古豪英，識之恨已晚。", "浩氣雖自充，靈標固天產。", "瓊枝玉府秀，春波鏡湖滿。", "妙趣玄中玄，高談簡復簡。", "痊予萬古病，金刀刮昏眼。", "朗如秋月明，不害浮雲生。", "始知金仙教，六幽同一情。", "一情亦何有，紛紛逐妍醜。", "遂令世上人，浮沉嗟白首。", "我願卿相知，薦師爲國師。", "一言了萬化，堯舜誠無爲。", "逢時揚至道，曠劫開羣迷。", "儒佛實皆聖，胡爲相是非。", "本亡末愈弱，行僞言空持。", "嗚呼可奈何，師也予同歸。"]'),
('8c79d40a-3576-4c0f-92d2-0e9e37ebe597','贈端禪師','郭祥正','宋','宋诗','song-poetry','','[]','十年不變舊，交深情愈淡。',48,'全唐诗/poet.song.42000.json','["十年不變舊，交深情愈淡。", "世樂貽真羞，去若出穽陷。", "故林泉石新，悠然在虛鑑。", "寂寂夜香沉，無心答鍾梵。"]'),
('15abb285-0b9f-4b4d-98c9-3984cb6e2ca1','贈隱靜禪師','郭祥正','宋','宋诗','song-poetry','','[]','平生厭羈束，樂爲名山遊。',156,'全唐诗/poet.song.42000.json','["平生厭羈束，樂爲名山遊。", "五峰數千仞，拔地凌斗牛。", "山光落澗影，倒掛天河流。", "靈草霧露香，老木陰翳稠。", "鳥鳴春盎盎，虎嘯風飀飀。", "耳目兩以醒，虛襟清氣浮。", "況有希世交，居焉治林丘。", "玄談傾醍醐，蕩滌方寸愁。", "出沒死生際，日用誠吾由。", "應嗟世俗士，俯首窺王侯。", "百年聊汩汩，外物終何求。", "我將脫冠带，筑室東巖陬。", "長年丐香飯，師也能容不。"]'),
('f7049dbb-2a45-4121-a9b2-efd5933cf424','贈利安禪伯','郭祥正','宋','宋诗','song-poetry','','[]','名山多隱者，五峰遇僧安。',72,'全唐诗/poet.song.42000.json','["名山多隱者，五峰遇僧安。", "屹然高世姿，眉目冰雪寒。", "極談了無迹，卷舌回驚湍。", "令我愧道心，齷齪滯小官。", "不能與斯人，物外振羽翰。", "惜爲山下別，落月在林端。"]'),
('2b681eb9-aab1-40b9-bf2a-770bcb9109b6','贈陳醫','郭祥正','宋','宋诗','song-poetry','','[]','吾嘗奇華佗，腸胃真割剖。',168,'全唐诗/poet.song.42000.json','["吾嘗奇華佗，腸胃真割剖。", "神膏既傅之，頃刻活殘朽。", "昔聞今則信，絕技世嘗有。", "堂堂潁川客，察脈極淵藪。", "攣足四五年，下針使之走。", "珍丸起病瘠，蟲鱠隨泄嘔。", "一言儻不合，萬金莫可誘。", "又復能賦詩，往往吐瓊玖。", "卷紙誇速成，語怪若神授。", "名聲動京洛，混迹逐良莠。", "相逢但長嘯，遇飲輒掩口。", "獨醒竟何如，無乃寡俗偶。", "顧非避世翁，疑是壁中叟。", "安得斯人術，付之經國手。"]'),
('3e417c85-10be-4104-8b1a-f01f8dcdb060','寄常執中長官棄官歸霅上','郭祥正','宋','宋诗','song-poetry','','[]','高飛不上雲，不如棲白蘋。',84,'全唐诗/poet.song.42000.json','["高飛不上雲，不如棲白蘋。", "屈身五斗粟，何似種松筠。", "聞君將掛冠，筑室苕溪濱。", "況有朱少翁，達論可相親。", "欹枕待落月，尋花送餘春。", "市喧不入耳，休羨桃源人。", "我亦促歸計，行當趨後塵。"]'),
('b0007d9f-2c3d-4366-96c6-b0fc166c33fb','寄清流許令','郭祥正','宋','宋诗','song-poetry','','[]','霅溪皎寒玉，霅山臥蒼龍。',96,'全唐诗/poet.song.42000.json','["霅溪皎寒玉，霅山臥蒼龍。", "我方窮眺覽，忽與旌陽逢。", "教告非俗語，泠泠啟昏蒙。", "我舊騎蹇驢，君去跨冥鴻。", "一別十五載，曠懷渴清風。", "今聞佩縣印，高鳳潛衰蓬。", "誰信五彩爛，卑棲能自容。", "終當振羽翮，萬里滄溟東。"]'),
('c390f885-2f90-4445-afc4-8e54a6d205d5','寄虔州慈雲惠禪師','郭祥正','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','惟昔廬山舊，舜師稱老禪。',144,'全唐诗/poet.song.42000.json','["惟昔廬山舊，舜師稱老禪。", "惠也乃上足，解空無比肩。", "我嘗叩其說，活活如湧泉。", "況復能吟哦，俯視唐皎然。", "一別二十載，相望修途邅。", "音信誰謂隔，月華長自圓。", "嗟予困俗累，久負香火緣。", "適爲幕府客，遠泛瀟湘船。", "還過廬山下，廬山安足憐。", "既無故人語，頑碧徒參天。", "多謝子規鳥，數聲空谷傳。", "準擬趁汝飛，飛落贛水邊。"]'),
('d47f5cdb-4c26-40f1-8be6-c33b4c3fb9cd','蔣穎叔要予同賦平雲閣','郭祥正','宋','宋诗','song-poetry','','[]','宣城多名山，詩人舊經歷。',264,'全唐诗/poet.song.42000.json','["宣城多名山，詩人舊經歷。", "獨無平雲篇，煞怯作者敵。", "不然靈祇護，晦此神女色。", "留與無心人，開軒初占得。", "羣奔萬馬放，片墮孤鷹擊。", "縷縷蠶繭抽，樅樅羽林直。", "怳隨片月散，又逐嵐光滴。", "縞带裁未成，蛟綃瑩無隔。", "蒼龍奮修鱗，皓鶴舒春翼。", "天墀聳羣玉，胡陣望鳴鏑。", "尤憐欲雪時，鐵甲萬里黑。", "變化固無窮，想象豈盡識。", "賢哉謫御史，注目倚寒壁。", "吟非宋玉賦，心在漢皇席。", "愁來把樽酒，薄詠繼朝夕。", "迷魂招屈賈，大句壓甫白。", "初屯念經綸，作解須霹靂。", "終朝去爲霖，未信長抱石。", "卷舒能及時，慰此長太息。", "詩言我枯疏，返類羣兒劇。", "君探驪頷珠，不憚海神惜。", "更當俟來唱，研盡廷珪墨。"]'),
('a8ea9276-3481-4860-9857-d2a5eb5cc5a7','寄題陳生九華閣','郭祥正','宋','宋诗','song-poetry','','[]','潁川有佳士，放懷慕清閑。',144,'全唐诗/poet.song.42000.json','["潁川有佳士，放懷慕清閑。", "或遊公侯門，得詩乃言還。", "瀟灑青松姿，俗駕何由攀。", "買田數百畝，家住濡須灣。", "匣有雷張琴，旋撥春醅綠。", "客來留一醉，聽我彈數曲。", "收身趣已遠，愛山心未足。", "千金建危閣，遙望九華峰。", "紫光射晚日，點點金芙蓉。", "南風吹秀色，半落樽罍中。", "酒味愈冷冽，琴聲又玲瓏。", "飄然紫霄想，何日跨冥鴻。"]'),
('0be1bff7-dce2-40a9-86c8-e3c65db87901','寄題東城耿天騭歸潔堂','郭祥正','宋','宋诗','song-poetry','','[]','東城耿天騭，讀書五千卷。',240,'全唐诗/poet.song.42000.json','["東城耿天騭，讀書五千卷。", "有義或未通，至忘寢與膳。", "潛心唯丘軻，弟子並時彥。", "晚從進士起，青衫落銓選。", "捕賊偶詿誤，差池困州縣。", "寧知賈馬才，不上明光殿。", "功名既無成，祿廩豈足戀。", "歸來潔其身，舊學進吾善。", "構堂剪深竹，江山使對面。", "秀色覽天鏡，毛髪瑩可見。", "閑情寄浮雲，零落兩三片。", "頹然墮支體，隱几自峨弁。", "有時明月來，朋簪合清醼。", "狂爲梁甫吟，璀錯珠玉串。", "夫人無妬忌，羣妾美目眴。", "大兒富文學，又隨太守薦。", "百口不憂貧，九品不爲賤。", "內足外亦足，此樂信無倦。", "軒冕達士寄，形色聖人踐。", "他時采高名，猶冠儒林傳。"]'),
('4c2f282e-1758-4f03-b046-a8b6387c9bfd','寄題吳子山孤雲亭','郭祥正','宋','宋诗','song-poetry','','[]','重華不可見，曾參久爲塵。',120,'全唐诗/poet.song.42000.json','["重華不可見，曾參久爲塵。", "孝道遂零落，爲子吟孤雲。", "孤雲泊南山，山下藏二親。", "孤雲自朝夕，墳草幾冬春。", "悠悠我之思，孤雲浩無垠。", "注視詎能攬，傾耳那得聞。", "音容勞夢想，涕淚濡衣巾。", "作亭墳之隅，奚止簠簋陳。", "揚名與行道，勉勉期終身。", "采彼孤雲篇，爲子書諸紳。"]'),
('56e3220d-0b9d-404b-91ab-b0e7c7bd0aac','題冶父山實際禪院','郭祥正','宋','宋诗','song-poetry','','[]','虎兮弗食子，誰謂虎性惡。',48,'全唐诗/poet.song.42000.json','["虎兮弗食子，誰謂虎性惡。", "一見慈孝人，帖身不敢縛。", "舊廬當絕巓，今寺據幽壑。", "人虎皆已非，斷碑蒼蘚剝。"]'),
('ca30af71-4176-4e08-9bd6-ca076f344a20','題宣州天慶觀秋水閣','郭祥正','宋','宋诗','song-poetry','','[]','偶登秋水閣，靜吟秋水篇。',120,'全唐诗/poet.song.42000.json','["偶登秋水閣，靜吟秋水篇。", "初不辨牛馬，河泊方欣然。", "及見北海若，始驚大小懸。", "大小不相借，致令夔愛蚿。", "學者儻悟此，心忘真乃全。", "白雲散林表，蒼山落簷前。", "中有醉道士，兀兀知何年。", "寒風灑面醒，暖日曝背眠。", "彈琴不終曲，撫掌望青天。", "誰來達渠意，勿作虛名傳。"]'),
('2a94e587-5b20-4ca1-8b09-07390b77da54','題旌德虞令觀妙菴','郭祥正','宋','宋诗','song-poetry','','[]','深溪徹寒鑑，蒼山開翠屏。',120,'全唐诗/poet.song.42000.json','["深溪徹寒鑑，蒼山開翠屏。", "結菴當此間，觀妙題其扃。", "借問觀何妙，伊人養性靈。", "豈爲娛耳目，是將達神明。", "滯有乃爲病，趨無亦何營。", "外感適變化，中虛藏窅冥。", "夜深片月散，林鳥三四聲。", "寥寥太古風，吹我襟嘗惺。", "逍遙形骸外，浩蕩天地情。", "未能同子樂，聊用歌強名。"]'),
('29208570-6eb8-4109-a2b1-5cdd4968a2bd','題泗州龜山寺','郭祥正','宋','宋诗','song-poetry','','[]','蒼山如巨龜，長淮就吞吐。',240,'全唐诗/poet.song.42000.json','["蒼山如巨龜，長淮就吞吐。", "石林含霜明，爻卦儼可數。", "相傳有神物，在昔遭聖禹。", "縶鐵送潭中，作鎮亘萬古。", "乾坤未云息，魑魅那得侮。", "至今崖下潭，不敢設網罟。", "邇來建佛廟，金碧爛庭戶。", "長廊肖深洞，夜香鬰濃霧。", "一讀碑上文，颯爾精神聚。", "憫旱截臂翁，開山即初祖。", "借僧百萬人，下壇三尺雨。", "至尊親賜詩，高名動寰宇。", "樓閣疑化成，何年運斤斧。", "洄流漲平沙，舟楫永無阻。", "尤憐瞻仰地，曾是欹傾所。", "王者唯好仁，佛力豈無補。", "我來解征鞍，赫日正卓午。", "涼風如冰霜，灑我襟上土。", "仰慚雲衲禪，未嘗倦行旅。", "還思治水功，冥寞今何許。"]'),
('ec1e7060-817a-42ec-8e5c-44833b7dde7e','題抱黄洞景德觀','郭祥正','宋','宋诗','song-poetry','','[]','晉道昔紛亂，志士多學仙。',180,'全唐诗/poet.song.42000.json','["晉道昔紛亂，志士多學仙。", "乃願脫塵網，畢身飛絳煙。", "卓彼抱黄子，遺迹茲山巓。", "地靈無惡木，杉松碧參天。", "四時不變春，脩脩女蘿鮮。", "下有白鹿臥，上有青猿懸。", "微風五音奏，不假朱絲弦。", "來者迭宏構，深門秘真筵。", "餘芳考金刻，眇末期羌肩。", "回念時運泰，巖谷無逃賢。", "寓遊足以樂，攜壺謾思玄。", "黄冠四五輩，達者余所憐。", "未嘗詣州府，白髪猶侵顛。", "而況塵中人，欲以永歲年。", "聊書一日事，繼之逍遙篇。"]'),
('52f1689d-298a-4cbe-800e-77093ec0a10b','題雨華臺','郭祥正','宋','宋诗','song-poetry','','[]','雲公說法時，諸天雨名花。',288,'全唐诗/poet.song.42000.json','["雲公說法時，諸天雨名花。", "此事古老傳，豈爲虛語誇。", "至今數畝地，長松肖龍蛇。", "下不生蔓草，上不存棲鴉。", "夜或散瑞光，爛若赤城霞。", "沿崖僅可到，狹徑寧容車。", "嚴嚴渤海公，好古心無涯。", "攜筇徐步至，極眺頻吁嗟。", "不唯古佛迹，絕景來幽遐。", "城郭如鉤環，井廬雜禾麻。", "青山斷綠野，白水連平沙。", "翔帆出天鏡，疊鼓傳摻撾。", "又復聽歸櫓，大澤鳴雁駕。", "雲煙失浦溆，霜雪摧蒹葭。", "顧瞻指掌間，千里無毫差。", "中天二龍飛，此邦恃犬牙。", "納士業已緩，何殊井中蛙。", "神兵半夜集，城裂如剖瓜。", "唯仁乃無敵，四海同一家。", "我公乘閑來，式宴賓亦嘉。", "作亭當舊址，海月浮窗紗。", "舉杯莫辭酒，越女彈琵琶。", "爲我謝雲公，亦有三春葩。", "真法忌揀擇，豈校靜與嘩。"]'),
('1cf87c8c-2eda-4218-ae85-5d253b472928','太平觀','郭祥正','宋','宋诗','song-poetry','','[]','下馬攜瘦筇，凌晨極幽賞。',143,'全唐诗/poet.song.42000.json','["下馬攜瘦筇，凌晨極幽賞。", "騰身孤峰半，縱目浮雲上。", "嚴嚴洞天路，靄靄靈氣王。", "古木藏春容，飛流落天幌。", "斷崖傾鬰蘿，深宮秘真像。", "壇心綵虹貫，幡腳仙飇颺。", "老鶴時一鳴，衆鳥不敢傍。", "人寰杳何處，仕路險已忘。", "高歌樂逍遙，撫掌遺得喪。", "長生豈無術，靜理聊自放。", "獨醒世不容，苟合情輒枉。", "咄嗟胡乎，茲焉卜長往。"]'),
('9623655f-e534-4438-95ea-975e9693174b','尋真觀','郭祥正','宋','宋诗','song-poetry','','[]','蒼崖猶積雪，凍林春未歸。',120,'全唐诗/poet.song.42000.json','["蒼崖猶積雪，凍林春未歸。", "石徑稍可通，決決泉聲遲。", "薄遊欲何適，攜筇負陽暉。", "覽勝輒長嘯，世事吾何羈。", "忽到仙人家，樓殿勢欲飛。", "皓鶴向人舞，青猿攀樹啼。", "屏風疊蒼玉，深潭瑩瑠璃。", "誰云蟄龍臥，朗詠前人詩。", "颼飀太古風，會生松桂枝。", "回首歸興遙，日暮青雲低。"]'),
('873a75ed-d9b9-483c-9bd2-0e6353510467','水磨','郭祥正','宋','宋诗','song-poetry','','[]','盤石琢深齒，貫輪激清陂。',120,'全唐诗/poet.song.42000.json','["盤石琢深齒，貫輪激清陂。", "運動無晝夜，柄任誰與持。", "霹靂駕飛雪，盛夏移冬威。", "功成給衆食，勢轉隨圓機。", "翻思兵家言，千仞俯可窺。", "又想對明月，大壑投珠璣。", "睥睨巧匠手，不使差毫釐。", "牛驢免穿領，僮僕逃胼胝。", "利用固已博，沉吟豈虛辭。", "願將水磨篇，薦之調鼎司。"]'),
('22a505fa-ecef-482b-9594-fabb702122fa','同蔡持正長官觀齊景蒨虞部家藏遠祖成公監修國史誥','郭祥正','宋','宋诗','song-poetry','','[]','稟稟齊成業，得之權公碑。',288,'全唐诗/poet.song.42000.json','["稟稟齊成業，得之權公碑。", "逢時初多難，退密安庭闈。", "深懷經綸策，起佐虎羆師。", "省郎拜侍御，出賑關中饑。", "俄登諫諍列，忤旨領一麾。", "徐遷河南府，法令嚴張施。", "宿奸即誅殄，和氣回霜威。", "德宗治勤勞，器公達精微。", "付之元化柄，庶績幾純熙。", "兼職在國史，直筆信不疑。", "皇皇君臣際，忠孝世所推。", "宜其源流長，千載尚弗遺。", "於今見遠孫，大雅敦形儀。", "銀章佩縣印，白玉涵山輝。", "丈人與先翁，登科實同時。", "相逢進餘烈，語訖及祖基。", "家傳唐相誥，綈襲常親攜。", "焚香俾一讀，令我增嘆嘻。", "璽文儼如新，是亦權公詞。", "顧鄭崔許輩，其名各親題。", "邈然想高風，拂拂雲霧披。", "芬芳一何遠，陰德未少隳。", "幾經兵火餘，定有神物持。", "不落他人家，後嗣賢可知。"]'),
('ba8582da-1615-4bbc-8f48-643ecadd835c','觀柳殿丞家藏竹柏圖','郭祥正','宋','宋诗','song-poetry','','[]','君實名卿孫，妙畫篋所聚。',120,'全唐诗/poet.song.42000.json','["君實名卿孫，妙畫篋所聚。", "壁間四幅畫，收盡蒼洲趣。", "瘦柏盤大石，雪霜迥不懼。", "舉斧揮棟材，未辨在縑素。", "離披老竹梢，直裂見枯處。", "鳳凰欲來巢，俯視猶屢顧。", "壯觀殊未已，白日去還暮。", "愁懷起窗壁，注目亂煙霧。", "煩君燈燭張，免我顔色沮。", "乃知頃刻意，直有千載寓。"]'),
('64277978-9d05-4c6b-b8d7-42cd8d76bf87','李公擇學士出示胡九齡歸牧圖','郭祥正','宋','宋诗','song-poetry','','[]','橫披五尺素，中有萬疊山。',132,'全唐诗/poet.song.42000.json','["橫披五尺素，中有萬疊山。", "山卜千丈溪，怳疑瀉潺潺。", "西風偃古木，慘淡秋色頑。", "蓼紅菱荇碧，缺岸如破環。", "小舟半閣沙，茅屋深無關。", "三牛行嚙草，一犢隨母還。", "牧兒掣牛鼻，望家喜生顔。", "欲知田家樂，此趣何由攀。", "而況畫手妙，意思能餘閑。", "遠出物象外，不在粉墨間。", "臨之發孤興，飄忽辭塵寰。"]'),
('819cc4cd-f18c-4b5e-8648-b577e6f39a82','謝許棲默道士手寫黄庭經見寄','郭祥正','宋','宋诗','song-poetry','','[]','與君有前期，共爲名山樂。',168,'全唐诗/poet.song.42000.json','["與君有前期，共爲名山樂。", "十宿太上家，百骸失塵縛。", "夜半瞻星辰，離離半空閣。", "香氳結蓋網，華燈煥朱琧。", "金鐘擊清霜，遠響答玄壑。", "太霞無別境，洞章自酬酢。", "君雖潛賤貧，志意在寥廓。", "暫爲處羣雞，曾是橫空鶴。", "一別幾何時，又見圓蟾落。", "長鬚俄及門，金石重然諾。", "手寫黄庭經，寄我辟邪惡。", "我方閉空屋，隱几效南郭。", "爲君興一讀，玉液瀉河洛。", "何當結長遊，相伴趨恬寞。"]'),
('bf71599a-04d4-4005-89ec-674c60e16224','蔣穎叔招遊瑯琊以馬病不赴','郭祥正','宋','宋诗','song-poetry','','[]','一別隔千里，夢寐期追尋。',96,'全唐诗/poet.song.42000.json','["一別隔千里，夢寐期追尋。", "聞君宿瑯琊，浩氣酬雲林。", "雪霽望明月，山光如縷金。", "天高歸鳥盡，海凍諸峰沉。", "騎鯨人已去，玉溜揚清音。", "君當繼絕唱，老鳳霜梧吟。", "釋彼猿鶴怨，解此塵坌襟。", "駑馬鞭不行，空負希驥心。"]'),
('bbac611a-2f83-44eb-8450-e6dff5b6cdbd','與柳丞夜話廬山','郭祥正','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','君家廬山下，我昔廬山遊。',216,'全唐诗/poet.song.42000.json','["君家廬山下，我昔廬山遊。", "蕪陰偶會合，共憶林泉幽。", "山腳仙佛居，寶閣連瓊樓。", "客子多所至，未足勤吾求。", "最愛山北岡，鳥道通巖陬。", "其初惠遠輩，遺芳至今留。", "嵬峨定心石，欲脫如簪抽。", "下視千仞溪，半空五雲浮。", "石門扼危磴，天瀑垂還收。", "微風仙籟奏，靈草香氣柔。", "龍吟萬壑響，桂子落三秋。", "安棲雖未能，歷覽稍已周。", "一別幾三年，萬事何悠悠。", "日月隨轉目，霜雪易滿頭。", "饑將無稻糧，寒亦乏衣裘。", "雖非聖賢恥，自起妻兒羞。", "慨欲攜鋤犁，爲君耕舊丘。", "經年飽蔬粟，吾道從休休。"]'),
('8070060f-ae5a-4c85-80f9-1b8421c5ee3e','蔣穎叔席上','郭祥正','宋','宋诗','song-poetry','','[]','春風歸未歸，白日一何速。',120,'全唐诗/poet.song.42000.json','["春風歸未歸，白日一何速。", "偶陪御史驄，逶迤傍林麓。", "名花結深洞，繁枝綴寒玉。", "疏青愛老柏，壯節詠孤竹。", "諸君皆俊賢，笑傲失羈束。", "何生家最窮，昨日旋糴粟。", "尚能邀我飲，盤饌逮張燭。", "今夕寧須辭，酩酊固所欲。", "醉則騎馬歸，官長定不辱。", "酒行姑徐之，聊用講心曲。"]'),
('2ea15488-3c45-48d1-ac76-b490b378efdf','自適','郭祥正','宋','宋诗','song-poetry','','[]','積憂避紛謗，杜門甘賤貧。',72,'全唐诗/poet.song.42000.json','["積憂避紛謗，杜門甘賤貧。", "破屋敗風雨，荒蹊絕車輪。", "幸無塵坌集，靜與鳬雁鄰。", "吾年半已過，空花眷餘春。", "往來猶康莊，安用煩距訢。", "念此良自適，浩歌洗憂屯。"]'),
('e953996a-76e0-46cb-bb31-ad19e74a84ff','溪上閑居  其一','郭祥正','宋','宋诗','song-poetry','','[]','溪頭守窮屋，白晝常靜臥。',48,'全唐诗/poet.song.42000.json','["溪頭守窮屋，白晝常靜臥。", "唯聞鳥雀喧，豈有車馬過。", "苔沿土階綠，風尖紙窗破。", "遺編對古人，千載默相和。"]'),
('0a62b791-081f-4074-b747-98c518decca2','溪上閑居  其二','郭祥正','宋','宋诗','song-poetry','','[]','愛此城南靜，窮年守茅舍。',48,'全唐诗/poet.song.42000.json','["愛此城南靜，窮年守茅舍。", "無能聊自安，有智必趨詐。", "紅蕖笑池面，白鷺時時下。", "呼兒補疏籬，選吉得天赦。"]'),
('415b270d-9363-45b5-8759-08425fb85ae4','溪上閑居  其三','郭祥正','宋','宋诗','song-poetry','','[]','衡茅頗幽獨，物景資所好。',48,'全唐诗/poet.song.42000.json','["衡茅頗幽獨，物景資所好。", "脩篁清風來，遠渚曉煙冒。", "才短難趨時，囊空不憂盜。", "靜幾無纖塵，焚香讀真誥。"]'),
('e416b862-393e-4c6d-9203-117464561fed','倚樓','郭祥正','宋','宋诗','song-poetry','','[]','官閑何所之，倚樓縱遠目。',216,'全唐诗/poet.song.42000.json','["官閑何所之，倚樓縱遠目。", "田疇耒耜出，高下春雨足。", "人家有生意，慰我苦幽獨。", "憶昨水沴餘，海氣蕩坤軸。", "蛟龍坼川原，舟楫造溪谷。", "禾麻安更論，未能保骨肉。", "有子殺爲食，何以厚風俗。", "上賴天子聖，詔書勤撫育。", "雖使發倉廩，飽歲實無畜。", "郡縣徒倉黄，論丁具糟粥。", "所救無幾何，往往委溝瀆。", "今茲氣候正，逋民稍來復。", "楚風重祠廟，纔歸競巫祝。", "此物豈有靈，焉能助豐熟。", "渺思濟時策，慎擇良宰牧。", "金繒斥誅求，教化行比屋。", "祖宗德澤深，萬歲長沐浴。", "題詩起高興，飄然跨鴻鵠。"]'),
('f5403a96-02d8-440e-a335-124d5101281d','與內飲有贈','郭祥正','宋','宋诗','song-poetry','','[]','甕中有濁酒，畦中多美蔬。',84,'全唐诗/poet.song.42000.json','["甕中有濁酒，畦中多美蔬。", "呼童取大網，更向溪中漁。", "鱍鱍得鮮鱗，斫膾選肥鱸。", "君生不能織，我生不能鋤。", "兒孫無白丁，生理已有餘。", "陶然共一醉，隙間馳白駒。", "倏忽各已死，體化委蟲蛆。"]'),
('37fa64d1-74e5-4b1a-8ef7-fc6d1b3223c0','送湖南運判蔡如晦赴闕','郭祥正','宋','宋诗','song-poetry','','[]','鶚飛不在泥，決有青雲趣。',288,'全唐诗/poet.song.42000.json','["鶚飛不在泥，決有青雲趣。", "鳳凰不妄出，恐爲時所誤。", "桓桓南都賢，幸遭明主顧。", "垂紳正手板，磊落奏治具。", "源流出無窮，胸膽豁以露。", "帝曰卿良哉，予僚汝之父。", "果見麒麟兒，騰驤蹈前步。", "擢爲東宮允，往漕八州賦。", "予將觀汝能，慎勿憚細故。", "朅來重湖南，君恩密宣布。", "拔才惟俊明，逐吏皆狡蠹。", "朝廷方更化，免役出金助。", "深沉詳施爲，委曲善告諭。", "有司絕誅求，比屋樂農務。", "貧富一以均，歌頌喧道路。", "七月新書成，入奏馳駿馭。", "君來萬家春，君去秋色暮。", "清湘似君心，偏使醜影懼。", "何時到金闕，顯用期必遇。", "成法無瑕玼，後效有程度。", "皇皇太上聖，赫赫師尹輔。", "大業日愈新，虛懷未嘗飫。", "諫垣將峻陟，使節豈還付。", "卻憶仁祖朝，天下復庠序。"]'),
('8bc70a1b-81e4-45e1-854a-9515be69736f','湘西四絕堂再送蔡如晦  其一','郭祥正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','長城截湘江，盤盤據天險。',288,'全唐诗/poet.song.42000.json','["長城截湘江，盤盤據天險。", "承平逾百年，民富德澤漸。", "層居出雲漢，門戶當翠琰。", "尤愛湘西山，佛寺金碧儼。", "引泉甃深池，因崖起危廣。", "長松爭嵯峨，衆木就退斂。", "遠思秦漢間，疑此藏玉檢。", "盤石可徑臥，苔髪滑勝簟。", "方塘纔俯窺，引手取蓮芡。", "四絕校重輕，歐沈信已忝。", "卓然韓杜詩，光焰不可掩。", "大羹味全醇，美玉滅瑕點。", "悄若蓬萊峰，夜浪豈憂颭。", "又如上帝籙，默誦破羣魘。", "惟驚落俗口，一讀一遭貶。", "知音希世逢，誰謂此言諂。", "窮奇須竟歡，憂來熱吾臉。", "不得陪俊遊，自知冗官玷。", "論情既霄壤，咫尺隔秦陝。", "不爲謝安侈，應慕楊綰儉。", "賡酬繼前唱，巖壁俟鐫剡。", "去爲經世霖，慰此楚封歉。", "離盃空酣酣，離恨猶冉冉。", "雁鳴洞庭闊，霜雪鬢毛染。"]'),
('577e2909-3a86-4c23-b70e-0f3f358c0698','湘西四絕堂再送蔡如晦  其二','郭祥正','宋','宋诗','song-poetry','','[]','嘗讀大易辭，可止戒遇險。',288,'全唐诗/poet.song.42000.json','["嘗讀大易辭，可止戒遇險。", "麓山俯城郭，盤盤進以漸。", "重崗如連環，斗起若圭琰。", "佛宮敞金碧，儒舍陋茅廣。", "修篁萬兵肅，老柏壯士儼。", "獨鶴時一鳴，衆鳥歸翼斂。", "蘭風新麝裂，芰雨真珠颭。", "虛堂羣動寂，冠纓墮枕簟。", "頹然委支體，清夢竟無魘。", "引阬酌醇醑，激齒碎圓芡。", "載歌少陵篇，一重復一掩。", "桃源歸路隔，回首驚俗檢。", "不唯縱逍遙，且喜遠邪諂。", "清湘稚子浴，其樂吾與點。", "況聞長老言，了悟生理忝。", "心如碧蓮花，忍使紅塵梁。", "又愛御史碑，白玉不可玷。", "能忘遷謫憂，直筆正褒貶。", "清曠終何爲，名迹漫鐫剡。", "吾君方更化，凡百務節儉。", "楚封勞賢侯，重地比二陝。", "施爲若霖雨，一飽蒼生歉。", "新法持以歸，戀山休荏苒。", "想當奏御時，和氣動舜臉。"]'),
('1be54f96-cf6f-4f62-8fdf-a9f3671df9dd','高鴻送唐彥範司勳移蘇守','郭祥正','宋','宋诗','song-poetry','','["\u897f\u6e56"]','高鴻方冥飛，萬里不回首。',289,'全唐诗/poet.song.42000.json','["高鴻方冥飛，萬里不回首。", "況當移杪時，霜露濕星斗。", "鼓翼無何鄉，永避網羅咎。", "君子重出處，此義安可負。", "嶷嶷潭府公，清譽比瓊玖。", "節制臨八州，時命非不偶。", "胡爲請分務，念念在林藪。", "切嘗聽公言，三朝祿食久。", "四十有五年，數爲漕與守。", "慎事無纖瑕，收身養吾壽。", "兒孫皆賞延，君恩誠已厚。", "朝廷新法度，利害喧衆口。", "紛馳使者車，必行無可否。", "嗟予力已疲，何以爲父母。", "不待老有請，連章至八九。", "君相惜其才，符竹今仍剖。", "蘇臺古名邦，震澤當運氣牖。", "拜恩臣豈邀，客賀但揮手。", "便道將徑歸，辭疾上印綬。", "家園瞰西湖，雲月是鄰友。", "翛然一榻外，長物復何有。", "隱几悟僧禪，頹形若陵阜。", "不學陶朱公，反爲利端誘。", "不學陶淵明，區區愛琴酒。"]'),
('7c15c8b2-1628-4458-be16-e7b74f207837','送宋景瞻秘校赴選','郭祥正','宋','宋诗','song-poetry','','[]','我欲渡湖湘，君乃赴京闕。',120,'全唐诗/poet.song.42000.json','["我欲渡湖湘，君乃赴京闕。", "官期安可常，念此千里別。", "人生幾何時，倏忽變華髪。", "難成唯功名，易往嗟日月。", "在貴勿外矜，抱窮豈中熱。", "顧彼四老人，未嘗事干謁。", "一朝扶太子，千載名不滅。", "安之命與時，爲君頗詳說。", "西風吹月華，冷靜若冰雪。", "何處望鄉關，鄉關此時節。"]'),
('00d71026-b748-4d77-8b9a-a243f517b1c9','送鄭說道太博監內法酒庫','郭祥正','宋','宋诗','song-poetry','','[]','故人京洛來，共話十年別。',120,'全唐诗/poet.song.42000.json','["故人京洛來，共話十年別。", "朱顔雖未彫，頗有鬢間雪。", "夫君起文學，今乃官麴糵。", "雖云屈雄才，猶喜待金闕。", "朝政今更新，百執勇施設。", "願言慎所職，法釀務精潔。", "上方祭祀餘，一飲茲以悅。", "雲霄即橫飛，勉勉著勳烈。", "行將鴛鷺羣，何暇笑跛鼈。", "跛鼈亦自知，中心冷如鐵。"]'),
('a2b84102-4cfb-4a67-9453-983a1aa22335','寄別朱復之郎中','郭祥正','宋','宋诗','song-poetry','','[]','我昔發溪口，君來具華筵。',180,'全唐诗/poet.song.42000.json','["我昔發溪口，君來具華筵。", "燭光射酒色，四座凝春煙。", "飲闌贈嘉唱，響韻勝彈弦。", "聞君今解印，念我簿書攣。", "不及姑溪流，會隨千丈船。", "君才世無雙，君名天下傳。", "五十試一州，治術如潁川。", "上方爭政務，下詔稽漢宣。", "誰能薦此人，惟賢乃知賢。", "聃聃范文正，道德諸公先。", "辟君登幕府，師友金石堅。", "大匠忽云逝，美璞疇敢鐫。", "古來出林秀，多爲風雨纏。", "明主往自結，獻書玉墀前。", "功名期待達，況當未衰年。"]'),
('a6cd2876-a6c3-480a-af24-58f949fb1be5','留別受禪師','郭祥正','宋','宋诗','song-poetry','','[]','長沙多禪翁，受也予所慕。',240,'全唐诗/poet.song.42000.json','["長沙多禪翁，受也予所慕。", "清猶玉潭冰，不著纖垢汙。", "堅如歲寒柏，不入螻蟻蠹。", "一聽玄談玄，銀潢自天注。", "源流何其長，湧絕曹溪路。", "請陳會面初，赤白照窻戶。", "短鞭驅瘦馬，一蹶復一步。", "北趨林下門，解榻欣我遇。", "圓瓜剖青瑤，激齒寒漿聚。", "搘筇拈古語，法樂過韶濩。", "廓然外生死，頭角白牛露。", "師云三百年，儒者莫爾悟。", "自茲往遊數，道合忘細故。", "倏忽捧邊徼，狡穴首招諭。", "微功有司奏，一命金闕赴。", "扁舟泊沙尾，行色業已具。", "惆悵難再留，何以慰心素。", "日月若馳駃，報體孰堅固。", "願期圓照中，生生迭相度。", "回首欲無言，月上瀟湘渡。"]'),
('2a50db16-ffa4-4224-9ad3-9e3b3cd75be0','送寶覺大師懷義還湖南','郭祥正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雲收嶽麓靜，月渡湘水明。',108,'全唐诗/poet.song.42000.json','["雲收嶽麓靜，月渡湘水明。", "獨鶴唳空谷，哀笳奏重城。", "巾屨塵坌遠，懷抱冰霜清。", "云何別彼土，忽作中州行。", "中州七八載，浪得丹青名。", "歸心故歲發，白鬢新年生。", "客帆欣所託，何時經洞庭。", "逸筆寫秋色，煙嵐吹素屏。", "殷勤遠相寄，萬里鴻冥冥。"]'),
('032f0baf-2a04-46bf-ad88-5803a8851da4','送僧白','郭祥正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我有高世想，喜逢高世人。',96,'全唐诗/poet.song.42000.json','["我有高世想，喜逢高世人。", "談詩何所極，元化浩無垠。", "物象不得晦，丹青亦通神。", "逃名出京洛，寓迹遺埃塵。", "錫飛天柱月，杯泛洞庭春。", "問我別來久，請吟佳句新。", "便欲結幽社，靜棲還本真。", "陶潛須一醉，寧起遠公嗔。"]'),
('670ebf44-9b0c-4247-8bd3-019fd98daeee','送僧璉','郭祥正','宋','宋诗','song-poetry','','[]','釋從白雲來，衣上白雲濕。',48,'全唐诗/poet.song.42000.json','["釋從白雲來，衣上白雲濕。", "借問來何勤，道師碑未立。", "文言予豈能，孝節爾誰及。", "卻返舊山中，猿啼暮風急。"]'),
('449ed383-a346-485a-b6fc-220da5d00ac2','送吳景山宮教供職','郭祥正','宋','宋诗','song-poetry','','[]','先生辭太學，得邑治陽羨。',204,'全唐诗/poet.song.42000.json','["先生辭太學，得邑治陽羨。", "仁義稍施設，澆浮遂丕變。", "訟庭寂無事，案几閑筆硯。", "青山落樽酒，白鳥聚畦甸。", "長橋跨空碧，溪光拖晴練。", "追隨斬蛟處，想象昔人見。", "高吟壯魂魄，老句掣驚電。", "休焉聊自放，性理還吾善。", "忽聞新天子，下詔羅俊彥。", "教由宗族先，六經咨講辨。", "先生應詔起，肝膽露萬卷。", "制度惟日新，漸磨豈聞倦。", "長苗忌速揠，良金務多鍊。", "杳杳青雲衢，闊步從茲踐。", "朝登諸王府，暮侍金鑾殿。", "勿興山水思，固有夔卨願。", "寄聲陽羨人，棠陰有餘戀。"]'),
('b9700c90-3e51-4f8f-aab8-d7e7170557c2','送周泳主簿','郭祥正','宋','宋诗','song-poetry','','[]','東風不肯住，發盡梅花白。',96,'全唐诗/poet.song.42000.json','["東風不肯住，發盡梅花白。", "又着柳梢黄，搖搖向行客。", "客行無時休，何以銷客憂。", "今古一樽酒，酩酊江上樓。", "黄鵠飛青雲，誤隨秋雁羣。", "網羅千萬里，涇渭欲誰分。", "詩思陽春發，平湖望明月。", "若遇北歸人，芳音無我絕。"]'),
('21453ec7-79a6-4094-885c-585a9ce8ec27','送錢公瑾長官','郭祥正','宋','宋诗','song-poetry','','[]','羣山凌皓雪，修途無點塵。',144,'全唐诗/poet.song.42000.json','["羣山凌皓雪，修途無點塵。", "寒梅數枝發，持送北歸人。", "人歸向瑤闕，頭角屈以伸。", "十年困塵滓，一旦乘風雲。", "大用多晚年，請看釣渭濱。", "又如四公子，長揖取名勳。", "其餘瑣細輩，爲君何足陳。", "我忝交君印，俯顔愧斯民。", "疲駑追逸驥，澆漓雜醲醇。", "物理有屯泰，賢愚固難倫。", "感君重然諾，西郊待歸輪。", "非君肯卑屈，誰復許相親。"]'),
('bb7fa553-8255-458a-8cea-40a708718b35','送陶秀才二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','我愛陶淵明，隱不羣異學。',84,'全唐诗/poet.song.42000.json','["我愛陶淵明，隱不羣異學。", "今朝識其孫，璨璨真玉璞。", "森然家風在，辯說傾電雹。", "江頭偶逢我，笑我何齪齪。", "恨不從君去，高飛同飲啄。", "顧此翅翎短，豈能超五嶽。", "我止愁復愁，君行樂其樂。"]'),
('c6fe659b-dd12-4430-bf9b-23962c3909d6','送陶秀才二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','江天九旬雨，江路三尺泥。',48,'全唐诗/poet.song.42000.json','["江天九旬雨，江路三尺泥。", "扶家遂遠適，羸馬正難騎。", "傳舍野煙中，子規連夜啼。", "鄉園歸得到，應已血沾衣。"]'),
('e5d114e4-cfaa-478c-83f9-20630a2246c2','送朱伯原祕校','郭祥正','宋','宋诗','song-poetry','','["\u592a\u6e56"]','泠泠皖溪水，悠悠天柱雲。',144,'全唐诗/poet.song.42000.json','["泠泠皖溪水，悠悠天柱雲。", "雲行水光動，水洗雲影分。", "幽人坐臥吟，孤絕迥出羣。", "資彼雲水秀，釋此塵垢紛。", "胡爲倏言別，扁舟連夜發。", "往登姑蘇臺，而望太湖月。", "卻尋史遷迹，但見蒼煙滅。", "覽古竟論今，治具校工拙。", "有才不得施，著書貽後世。", "何必腰黄金，自享千載貴。", "鱸魚秋正熟，雲泉味尤美。", "若逢吳市門，更訪長生理。"]'),
('bfbbe95a-4b26-4788-9972-9dcffb80fe0b','同蔣穎叔遊丁山彰教寺','郭祥正','宋','宋诗','song-poetry','','[]','北風方苦寒，冰霜晝未消。',180,'全唐诗/poet.song.42000.json','["北風方苦寒，冰霜晝未消。", "偶傾御史蓋，同上丁山椒。", "空崖白雲宿，拱木獼猴跳。", "碑皴龜腹裂，泉活龍尾搖。", "枯松起幽籟，中天奏雲韶。", "苔深鴉髪翠，石立壯土翹。", "荒墳瘞參軍，沉魄誰與招。", "卻讀樂安詞，慘淡窺泬寥。", "矧復見猶子，危言動清朝。", "甘心脫豸冠，竄迹投冗寮。", "公議在後世，美才無吝驕。", "六經收滿腹，辨析皆有條。", "登山聽君語，淙淙碎瓊瑤。", "但驚白日落，歸馭不可邀。", "明發余亦往，安得同漁樵。"]'),
('3e394a3e-79dd-433d-b46a-f176e6b312fd','招蔣穎叔遊丁山彰教寺','郭祥正','宋','宋诗','song-poetry','','[]','閒心樂名山，景象恣吟剽。',288,'全唐诗/poet.song.42000.json','["閒心樂名山，景象恣吟剽。", "昭亭西南隅，亂峰最青峭。", "盤盤得修逕，豁豁漸明眺。", "一讀道旁碑，古興恣雅要。", "知有金仙家，即往不俟召。", "平田轉回塘，飛瓦接危嶠。", "東邊卧石虎，徐王舊墳兆。", "但驚深蘚晦，不見金碧耀。", "圖形半殘缺，冷榻孤燈照。", "深篁歸鳥没，空巖雪風叫。", "勅書刊翠琰，靈跡獲獵燒。", "寒潭多蟄鱗，佛子忌漁釣。", "動活各遂性，蕃衍理可校。", "餘暉初月散，幽籟發玄竅。", "中有無心人，禪禪自相紹。", "問年踰耳順，膚色尚如少。", "翻令念達人，鴻蒙首頻掉。", "時平冠珮繁，往往屬不肖。", "豈如棄以歸，林泉自投跳。", "卓彼蔣夫子，詩辭極精妙。", "能來同我遊，險絕共長嘯。", "終當爲君誦，古律變新調。", "更評江南事，僣跡又足悼。", "不能降真人，卒用焚祖廟。"]'),
('a0b4f625-a5c4-46a4-86f1-a6de49ea54da','同蔣穎叔殿院遊昭亭山廣教寺','郭祥正','宋','宋诗','song-poetry','','[]','晴光散餘翳，佳辰值清和。',240,'全唐诗/poet.song.42000.json','["晴光散餘翳，佳辰值清和。", "聯車不辭遠，共登昭亭阿。", "步夷愜蒼石，緣險捫修蘿。", "迥出白雲上，俯瞰飛鳥過。", "凌霄插危觀，裂地注明河。", "微風解蘭芷，廣陂浴鳬鵝。", "潭潭紫華君，左右森矛戈。", "雷電在呼吸，玉帛薦牲犧。", "廟食溢千載，祐民理無訛。", "崔碑夢恊吉，謝守詩載歌。", "却憩林下寺，裴顔跡尤多。", "丹青業已晦，長髯但皤皤。", "筆畫肖家法，燕尾無偏頗。", "覽古發遐想，緣情還獨哦。", "逢時不榮達，憔悴同苫蓑。", "嗒焉姑自喪，安之如命何。", "彼美蔣御史，道術追雄軻。", "眄予委泥涸，有意傾餘波。", "薦士古來重，披劍今則那。", "書爲昭亭篇，昭亭崕可磨。"]'),
('9cadad36-ad73-4f38-a398-a9a44de92993','同許棲默遊華陽洞','郭祥正','宋','宋诗','song-poetry','','[]','春歸白晝永，庭虚民事退。',168,'全唐诗/poet.song.42000.json','["春歸白晝永，庭虚民事退。", "尋幽何所之，佳賓幸同載。", "出門十餘里，仙者餘跡在。", "非實固難評，洞壑茅可愛。", "綠蘿垂長簾，秘景得藏晦。", "造深揭葦火，陟險汗漸背。", "中寛稍可休，仰視覆圓蓋。", "石乳忘歲年，物象千萬態。", "龍泓紺澄碧，溢溜漸飛灑。", "陰森毛骨寒，志往力殊怠。", "磨崕記名姓，斯遊定難再。", "人生足離合，世役異屯泰。", "清風起林杪，蕭瑟動天籟。", "歸歟亦何求，盈筐採蘭艾。"]'),
('e24f75e8-d55c-43b8-be47-916ac2d91c16','同劉繼鄴秀才遊嶽麓登法華臺呈如水長老','郭祥正','宋','宋诗','song-poetry','','[]','南出長沙城，西渡瀟湘水。',288,'全唐诗/poet.song.42000.json','["南出長沙城，西渡瀟湘水。", "誰鋪碧鮫綃，迥透黄金底。", "中分橘直洲，隱若鼇背起。", "府邑古稱雄，地勢信少比。", "苟非仁義圖，疇將甲兵洗。", "晚色烟霧開，人家明鏡裏。", "斯須捨舟楫，縱步踏蘭芷。", "遥遥望松門，物象愈奇偉。", "枝葉既不繁，霜雪詎能毁。", "傳云陶將軍，屯營手植此。", "至今凌雲氣，猶如大君子。", "纔過清風峽，路轉不容跬。", "塵寰自此隔，佛界朗瞻跂。", "層梯上重門，繪塑光煒煒。", "皓鶴去無蹤，寒泉但清泚。", "遂登法華臺，平目瞰千里。", "返驚人世卑，塹壁徒爲耳。", "連甍十萬戶，羅列在案几。", "想當韓杜時，荆棘晦遺址。", "不見湘西篇，惟誇道林美。", "幸同劉子來，縱視眼不眯。", "作詩君勿謙，前輩尚可擬。", "揮筆方爭豪，求心翻自鄙。", "請看梁上題，半是泉中鬼。"]'),
('b2c8513a-a530-41b0-86b1-19943e17df92','遊雲蓋寺','郭祥正','宋','宋诗','song-poetry','','[]','名山寺多占，此寺山尤名。',144,'全唐诗/poet.song.42000.json','["名山寺多占，此寺山尤名。", "妙雲鎮彌覆，層層結縵纓。", "日光晝微開，燦射黄金城。", "木老枝葉簡，水長音韻清。", "五峰如紺蓮，中有樓殿横。", "是必龍華宫，禪禪悟無生。", "一燈破羣暗，衆燈迭相明。", "紛空素葩墜，悲晚孤猿驚。", "予方困邅途，寓宿骨已輕。", "願言永棲此，讀盡寶藏經。", "顧盼適所適，了絕物外營。", "馬秣僕亦飯，奈何催北征。"]'),
('af25845f-1a00-4969-8828-050da1832c0c','遊鹿苑寺','郭祥正','宋','宋诗','song-poetry','','[]','遊遍湘西山，晚至鹿苑寺。',192,'全唐诗/poet.song.42000.json','["遊遍湘西山，晚至鹿苑寺。", "平岡列城郭，長松肖兵衞。", "入門尤清涼，讀碑辨往事。", "乃知阿育王，曾此藏舍利。", "浮屠當殿陰，令人竦瞻視。", "寶網敷金雲，倏忽變蒼翠。", "僧云秋杪時，月靜甘露墜。", "大覺去無蹤，山祗自靈異。", "白鹿不我逢，殘花在巖際。", "居者多壽老，安禪信無累。", "笻衲爲生涯，心不墜情僞。", "源源聽法語，陶陶襲和氣。", "簪紳胡爲乎，頂踵縛憂愧。", "願從彼上人，預聞第一義。", "煩心沃醍醐，頓悟超十地。", "聊爲鹿苑吟，清夢不成寐。"]'),
('b99bae48-6fb1-48a6-9ac3-4927fbbbc14e','遊華陽洞阻雨','郭祥正','宋','宋诗','song-poetry','','[]','此洞昔無聞，人跡固稀到。',288,'全唐诗/poet.song.42000.json','["此洞昔無聞，人跡固稀到。", "一昨紫微遊，刻石記所好。", "遂令天下知，遊者爭欲造。", "我方珮縣印，事閒慕高蹈。", "聯鑣二三子，並堅松柏操。", "樽罍薄攜持，丁壯却前導。", "行行逼崕巔，紫翠射襟帽。", "方疑攀鬰蘿，又若堆海潦。", "石門未及窺，忽值山雨暴。", "風雲暗衢路，雷電拆巖嶠。", "蒼黄僕夫語，踴躍猿猱叫。", "黄泥濡衣裳，安得白日照。", "初遊成歡愉，中險觸憤懊。", "佛舍距幾何，望望目睛眊。", "擊鐙促疲馬，十步九欹倒。", "登堂亟就榻，釋子數相勞。", "尋幽尚齟齬，處世信難料。", "暫眠稍蘇息，起坐復悲嘯。", "寧非山鬼護，不使俗客眺。", "桓桓翠琰文，愈讀愈精妙。", "名由今日新，跡入萬古耀。", "騏驥步莫追，駑駘志彌劭。", "猶期六月來，散髪避炎燎。", "一雨路阻絕，何以爲壯少。"]'),
('be1128eb-fce5-4beb-aa8f-6520a682882b','夏日遊環碧亭','郭祥正','宋','宋诗','song-poetry','','[]','登山得斯亭，佳賓幸過從。',120,'全唐诗/poet.song.42000.json','["登山得斯亭，佳賓幸過從。", "取筍蒼玉林，置酒黄金鍾。", "願言壽而康，泰運寧易逢。", "孔孟陟三事，堯舜乘六龍。", "民財皆辨析，田壤仍登豐。", "關關禽聲和，剪剪木影濃。", "濯足就綠水，披衣攬清風。", "微吟百憂散，達道千古同。", "諸君况才豪，如羆復如熊。", "莫辭爛醉歸，皓月還生東。"]'),
('1a5ab549-df91-466f-bfd0-7879a759d036','和穎叔丁山黯字','郭祥正','宋','宋诗','song-poetry','','[]','寒日少晶光，山色亦慘慘。',216,'全唐诗/poet.song.42000.json','["寒日少晶光，山色亦慘慘。", "瀑泉凍不飛，啼鳥聲頓減。", "傳呼繡衣來，僧鼓擊坎坎。", "石坐無氈裀，團團織蒲菼。", "比爲泉石游，固已慕清淡。", "愛君神采瑩，皎若白玉鑑。", "一登林際亭，毫髪無遺瞰。", "勇起發孤唱，四坐噤莫闞。", "君辭如太羮，我語效鹽鹹。", "卷旗促降敵，賢將釋不斬。", "雖生已包羞，鉛刀竟誰鏨。", "却讀道旁碑，往事增新感。", "功名能幾何，回首歲時暫。", "胡爲奪浩氣，百憂煎一膽。", "趨時既迍邅，獨往固勇敢。", "白雲無人爭，皓月從我攬。", "開樽直一醉，莫驚别袖摻。", "明發何所思，龍斷坐汲黯。"]'),
('94bfd72f-a44b-4321-b310-6a8114847162','和梅謙叔丁山吃字','郭祥正','宋','宋诗','song-poetry','','[]','臘月衣未綿，兩股凍成疾。',180,'全唐诗/poet.song.42000.json','["臘月衣未綿，兩股凍成疾。", "誰復爲我扶，平步時時蹶。", "文章那更論，精魄恐墜失。", "緣何御史君，相招傍寒日。", "迤邐造林泉，塵坌爲披拂。", "霓幡雲外垂，石虎草間出。", "深門窺泬漻，拱木遞蕭瑟。", "丹青與老碑，遺事知彷彿。", "僣跡已榛蕪，新遊論膠漆。", "主人才何如，驥足千里逸。", "梅君南昌後，襟韻猶凄溧。", "劉子亦可奇，彖象久精詰。", "顧予最空疏，百辨今已吃。", "謗言來戈矛，自量幾不密。", "終甘首陽餓，豈效操瓢乞。"]'),
('669d8488-e565-46b5-94a7-c6f5f3066f6b','酬穎叔見寄','郭祥正','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','鏗鏗南華經，語意妙復妙。',192,'全唐诗/poet.song.42000.json','["鏗鏗南華經，語意妙復妙。", "高能出蒼旻，卑不厭藜藋。", "陰靜偶暫處，影跡兩莫弔。", "息踵真人徒，息喉愚者紹。", "方同造物言，萬變領樞要。", "既能無怛化，勿鑿混沌竅。", "百家拾其餘，所得及遺溺。", "至音聽以氣，世或昧此調。", "不見杏壇講，猶爲漁父誚。", "君看泰山頂，半夜日先照。", "惟逢蔣穎叔，沉默造玄窔。", "落筆逾萬言，嚴密若誥詔。", "嗟予久聾瘖，此道雅未剽。", "一昨聞君談，神悟百骸療。", "人忘道術遊，魚忘江海跳。", "昭亭果見期，爲子發長嘯。"]'),
('97ce0213-60fd-44c2-8d6e-5c5da54489b1','秋水閣席上呈穎叔原道','郭祥正','宋','宋诗','song-poetry','','[]','吾愛秋水閣，水影照采椽。',180,'全唐诗/poet.song.42000.json','["吾愛秋水閣，水影照采椽。", "瑩碧不知極，定與銀漢連。", "荷花十丈開，白藕想如船。", "雙鶴時一鳴，寒霄下迴旋。", "况復對羽客，豈異蓬萊仙。", "便當沽玉液，猛飲明月前。", "人生不嗜此，何物能逃年。", "請君傾醉耳，松風奏薰弦。", "身世能兩忘，安用養浩然。", "夢覺事已殊，此道誰能全。", "馳驅冠劍徒，百歲猶倒懸。", "深深下於地，冥冥高出天。", "君語達已達，君歌玄復玄。", "大笑問劉子，細窮秋水源。", "秋水源可到，更寄琳瑯篇。"]'),
('d5ea609e-5626-45e7-9873-efe035a2b09b','酬耿天隲見寄','郭祥正','宋','宋诗','song-poetry','','[]','追維平昔遊，十幾喪六七。',180,'全唐诗/poet.song.42000.json','["追維平昔遊，十幾喪六七。", "與君雖尚在，踸踔各衰疾。", "功名無幾何，歲月忽已失。", "伻來辱新詩，欲和久閣筆。", "文章老愈精，光彩爛星日。", "市門果神仙，參軍真俊逸。", "又如闚沙漠，鐵騎萬餘匹。", "一戰孰與當，百勝得深術。", "有過懼不聞，愚惡志所嫉。", "言歸潔其身，天命能自詰。", "知音我愈寡，深谷詎敢出。", "相望止一江，高議容接膝。", "請觀商山皓，寧終守蓬蓽。", "衆人拉其華，君子俟其實。", "定當卜鄰去，攜手藏於密。"]'),
('5535c3ef-742e-4682-a819-eaf4d3a72be9','酬李公擇謝予贈范李猿獐','郭祥正','宋','宋诗','song-poetry','','[]','黄獐雄領雌，青猿母抱子。',120,'全唐诗/poet.song.42000.json','["黄獐雄領雌，青猿母抱子。", "一落罝網中，城市就生死。", "不如圖畫上，山深石泉美。", "永無罝網憂，精神自全耳。", "愛之寫横軸，容易披案几。", "動靜適自感，物我忘表裏。", "猶疑跳躑去，毫端詎能止。", "易生名獨擅，斯人嗟往矣。", "後來稱李范，贈君君勿鄙。", "縱令筆未妙，猶勝負塗豕。"]'),
('d2a2e3d3-24b6-4fdb-b8fb-1a68230f5527','同陳公彦推官登峨嵋亭','郭祥正','宋','宋诗','song-poetry','','[]','新亭彼誰搆，名因翰林揭。',144,'全唐诗/poet.song.42000.json','["新亭彼誰搆，名因翰林揭。", "惟南極空曠，朗詠佳興發。", "傾蓋忘形骸，輒莫歎華髪。", "歸帆天外低，渡鳥雲端没。", "中原崢嶸際，天塹限楚越。", "寧知承平來，但見山花歇。", "君相方聖賢，胡爲念京闕。", "但窮林泉樂，躡屐上崷崪。", "酒量孰先降，樽罍未云竭。", "欲尋太白墳，草間迷斷碣。", "神交無古今，清風來飄忽。", "征轡還催人，東峰掛寒月。"]'),
('697d5d56-5b3e-424d-9d22-a7030915ddc6','穎叔見招赴何秀才家飲','郭祥正','宋','宋诗','song-poetry','','[]','鞭驢赴君招，十步九蹶促。',204,'全唐诗/poet.song.42000.json','["鞭驢赴君招，十步九蹶促。", "相逢即忘勞，深圍坐重褥。", "怳疑出塵寰，氣象豁雙目。", "名花散天香，仙露浥柔玉。", "寄樂方寸間，豈必待華屋。", "脱屣遠市朝，散髪免羈束。", "更聞誦新作，字字芝蘭馥。", "堆盤櫻實紅，滿斝醱醅淥。", "幽歡未言歸，酒令不須督。", "平時常卷舌，動靜畏險俗。", "玄談今盡傾，我難愜君欲。", "朝聞夕可死，悟矣無遲速。", "感君傾醍醐，灑我久饑腹。", "又如旱田禾，沛然甘雨沃。", "主人意殷懃，呼兒具燈燭。", "誰家有斯客，貰衣心亦足。", "明朝得長篇，調險不可續。"]'),
('0f8aa6a5-3b57-461c-b427-ddb397783185','和公擇觀李煜書法喜禪師碑','郭祥正','宋','宋诗','song-poetry','','[]','五代迭凋喪，江南最偷安。',144,'全唐诗/poet.song.42000.json','["五代迭凋喪，江南最偷安。", "三世弄翰墨，煜札尤可觀。", "禪林榜法喜，妙勢如飛鸞。", "塵埃一藏晦，皴斮脱羽翰。", "適逢集仙守，好古將模刊。", "振襟自披拂，塗飾粉與丹。", "呼僧辨遺像，彷彿存纖紈。", "作書究本末，風雨生毫端。", "精神還故物，霹靂驚蟄蟠。", "幽光亦煥發，令我復長歎。", "念彼士君子，窮年抱饑寒。", "不及稽古踪，冺默知遇難。"]'),
('2cea4a22-30ba-43db-8260-6294a764ce29','和樊希韓解元','郭祥正','宋','宋诗','song-poetry','','[]','君馬一足病，瑣瑣阻行邁。',168,'全唐诗/poet.song.42000.json','["君馬一足病，瑣瑣阻行邁。", "况復梅雨天，坐卧不能快。", "空山無大臠，何以具君嘬。", "墻根採肥杞，湖漘買鮮鱠。", "開樽薦濁酒，高論幸忘憊。", "寸心拔茅塞，兩耳抉雙聵。", "文醇潛大和，詩險露幽怪。", "聯吟極物象，君勝我屢敗。", "東野久龍鍾，多慚退之拜。", "奇才必自重，雖黜愈勿懈。", "卞璧未遇時，在璞豈能壞。", "鑒賞一日逢，青紫信如芥。", "君行且遲留，馬病願未差。", "貰衣亦何辭，庶用接嘉話。"]'),
('22ef21ed-d517-4712-926e-0d5968fbc495','和公擇遊壽聖院啜茶題名','郭祥正','宋','宋诗','song-poetry','','[]','史君尚清淨，攜客無杯肴。',60,'全唐诗/poet.song.42000.json','["史君尚清淨，攜客無杯肴。", "茗酌誦佛經，塵緣頓沉抛。", "疏雲墮簷際，微風汎林梢。", "吾心已皎皎，我學豈譊譊。", "濡毫題名姓，識此逍遥交。"]'),
('d5f42255-9869-46e3-a7af-8452095b8a17','和法宗上人月下懷故人','郭祥正','宋','宋诗','song-poetry','','[]','山沉江海闊，月行天中央。',48,'全唐诗/poet.song.42000.json','["山沉江海闊，月行天中央。", "遊子宿何許，只應歸夢長。", "浮雲且莫生，星河助餘光。", "徘徊問孤影，惆悵安可忘。"]'),
('7ba80b28-bf1a-489f-8a11-9f5807fb8425','酬耿天隲見寄','郭祥正','宋','宋诗','song-poetry','','[]','我思昔人言，處世猶大夢。',168,'全唐诗/poet.song.42000.json','["我思昔人言，處世猶大夢。", "塵編堆牀頭，撫事聊一誦。", "興衰繫時運，賈誼爾何慟。", "又思東方朔，爲鼠知不用。", "誰憐胯下兒，能領百萬衆。", "勢去競詆排，功成乃歌頌。", "人情豈相遠，此理古今共。", "桓桓耿夫子，策射金榜中。", "老彼澗底松，未作明堂棟。", "暫來令句曲，尋仙造深洞。", "摩挲瑶琪花，借問誰所種。", "開落既忘年，一奏熏風弄。", "詩言此歸隱，不戀五斗俸。", "何時定掛冠，我願爲僕從。"]'),
('b0e650e2-231a-4c92-b905-83147d769670','和韓求仁推官','郭祥正','宋','宋诗','song-poetry','','[]','終日汩城市，閒心眷犁鋤。',48,'全唐诗/poet.song.42000.json','["終日汩城市，閒心眷犁鋤。", "故登原上亭，解此塵中裾。", "芬香採薇蕨，馴狎憐麋狙。", "却願物理變，四角生我車。"]'),
('60c14a0f-bd6f-4f94-b32d-a781ace6a409','樊山','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','漢室火符熄，羣雄起縱横。',192,'全唐诗/poet.song.42000.json','["漢室火符熄，羣雄起縱横。", "兩京蕩爲墟，萬里無農耕。", "曹操劫神器，欲竊禪讓名。", "吳蜀恥北面，鼎峙方戰爭。", "殺人如鱠魚，天地厭血腥。", "至今武昌邑，尚傳吳主城。", "長江吞八極，圓壇窺杳冥。", "想當禋郊時，志勇掃攙搶。", "燔柴封玉牒，冠弁羅公卿。", "登山錫宴喜，日光爛旗旌。", "寧知後嗣弱，壯業竟無成。", "空餘舊基址，千載未欹傾。", "常時屢掩卷，每讀涕泗盈。", "而况泊舟檝，披榛自徑行。", "霸圖何所見，芳草與雲平。", "晚浪淙石脚，猶疑兵甲聲。"]'),
('b71b7583-0217-4b25-b05a-a881ead3a22c','觀怡亭序銘','郭祥正','宋','宋诗','song-poetry','','[]','有唐三百年，絕出陽冰篆。',192,'全唐诗/poet.song.42000.json','["有唐三百年，絕出陽冰篆。", "最憐怡亭序，筆畫兼衆善。", "磨崕深雲間，人跡到應鮮。", "亦如大君子，隱晦久而顯。", "裂素印麝煤，字字未訛舛。", "冰凍垂瓦石，犀尖利刀剸。", "連環不可解，虬尾勇自卷。", "誰云模以刻，曾是玉工碾。", "銘辭志尤宏，雲翼待風展。", "琳琅諧八音，雅重參二典。", "英豪逢一時，江山供廣宴。", "遺蹤逐飛鳥，舊址没榛蘚。", "良朋信稀遇，古興浩難遣。", "吾宋垂百年，教化固非淺。", "人人擅文翰，比唐殊媚軟。", "作詩聊自驚，中道尚可勉。"]'),
('89ce8e49-19da-4c80-bdc6-02e6badc14f0','殊亭','郭祥正','宋','宋诗','song-poetry','','[]','昔人才行殊，亭名至今在。',108,'全唐诗/poet.song.42000.json','["昔人才行殊，亭名至今在。", "何年復基構，勢壓鯨鼇背。", "中間鄙俗令，元碑遭睚眦。", "豺狼爾何營，龜螭手親碎。", "甚哉憎疾心，曾不校異代。", "我將掇其餘，補刻尚可再。", "仰瞻天宇寛，俯視江流大。", "危危一葉舟，故欲萬里邁。", "差池想遺風，雲山有殊態。"]'),
('4bb60155-bdbf-4365-b2f1-3f633dd0b7f1','怡亭','郭祥正','宋','宋诗','song-poetry','','[]','英才欣會遇，曠懷各無瑕。',72,'全唐诗/poet.song.42000.json','["英才欣會遇，曠懷各無瑕。", "二李妙分篆，裴銘語尤嘉。", "盤盤虬奮鱗，灼灼月吐華。", "天影望不盡，雁行飛屢斜。", "晴雲依晚岫，芳草接平沙。", "東溟與西塞，吾寧辨渚涯。"]'),
('8014645d-6b17-4981-8431-228cbf51e944','石門','郭祥正','宋','宋诗','song-poetry','','[]','雙崕屹然起，剔蘚認題識。',48,'全唐诗/poet.song.42000.json','["雙崕屹然起，剔蘚認題識。", "乃知賢令尹，曾同漫叟醉。", "落景正西盡，長川自東逝。", "唯此兩石門，不開亦不閉。"]'),
('379bc854-1870-4b09-a10a-0475a3032a38','郎官湖','郭祥正','宋','宋诗','song-poetry','','[]','張公昔愛湖，湖名自公始。',96,'全唐诗/poet.song.42000.json','["張公昔愛湖，湖名自公始。", "寥寥三百年，逢秋愈清泚。", "移船菱荇香，游魚數頳尾。", "回望武昌郭，樓臺碧天裏。", "石照瀉靈光，湖波皓如洗。", "此景絕世無，愛之心不已。", "緬懷昔賢期，林表清風起。", "終當歸結網，來此養衰鄙。"]'),
('6c82c5f0-a1f0-44a7-b65d-b7689942de74','峰頂','郭祥正','宋','宋诗','song-poetry','','[]','登山不辭險，探景須窮幽。',48,'全唐诗/poet.song.42000.json','["登山不辭險，探景須窮幽。", "行徹五千仞，回首視九州。", "人寰莽何處，大野蒼煙浮。", "更酌天池泉，古意空悠悠。"]'),
('1cdf49d8-f31d-4e79-8356-6701bdebc367','醉石','郭祥正','宋','宋诗','song-poetry','','[]','裂嶂飛寒澗，絕壁散明珠。',120,'全唐诗/poet.song.42000.json','["裂嶂飛寒澗，絕壁散明珠。", "盤石偃中塢，修林陰翳敷。", "世道紛莫救，逸人此提壺。", "一酌寄乾坤，回首忘車書。", "山花謾相笑，山鳥徒相呼。", "更逢山月來，夜響真笙竽。", "粹靈淘耳目，幽獨寧賢愚。", "留蹤千載間，遊子空踟蹰。", "清風起木末，餘涼生坐隅。", "浩歌歌去來，逸韻凌遥虚。"]'),
('6792d7f9-c579-4493-be9b-9d39756d328d','洞庭阻風','郭祥正','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','南風吹炎蒸，歲望固已休。',120,'全唐诗/poet.song.42000.json','["南風吹炎蒸，歲望固已休。", "怒濤掀洞庭，信宿留歸舟。", "沙場萬馬放，大壑羣龍投。", "陰靈孰爾職，曾無與天謀。", "崩山作深潭，深潭變高丘。", "上天有號令，豈汝可自由。", "朝蠅徒咂咂，暮蚊况啾啾。", "歸興邈以阻，觸緒增新愁。", "安得跨白鹿，山行肆悠悠。", "誰能守荒浦，泛險終何求。"]'),
('6b24e697-205b-456d-8baf-e5c61313c844','濡須山頭亭子','郭祥正','宋','宋诗','song-poetry','','[]','孤亭壓危峰，絕景入平眺。',180,'全唐诗/poet.song.42000.json','["孤亭壓危峰，絕景入平眺。", "雙崕控巢水，禹力萬古耀。", "林傾乾象闢，濤淙地軸掉。", "茅茨數椽屋，噫哉魏武廟。", "心殊岐山伯，跡異甘棠召。", "荒戍傳遺靈，血食豈亡誚。", "吞吳勢雖壯，晉起國旋剽。", "樓船戰士去，滄浪盡魚釣。", "平時欲何爲，覽古謾長嘯。", "愁烟起孤壑，白鳥聚殘照。", "誰令五月來，不見萬山燒。", "又復想大雪，下上玉巖嶠。", "重遊莫能期，將歸且停趬。", "詩辭捜亦苦，物狀竟難肖。", "終篇寫亭壁，翻慚畫師妙。"]'),
('ba92a2f4-2e77-489c-bece-c9cdbcd4c9b2','謁桐鄉張府君廟','郭祥正','宋','宋诗','song-poetry','','[]','桐鄉富山水，此地最深秀。',180,'全唐诗/poet.song.42000.json','["桐鄉富山水，此地最深秀。", "諸峰合屏圍，二岡屹龍鬭。", "谷暖禽語滑，岸束溪聲逗。", "老木如巨賢，森衞備前後。", "神功金刻存，廟古何年構。", "衣冠近唐人，名字嗟莫究。", "憫旱鞭怒蛟，深潭此身仆。", "明誠動蒼天，雷雨洗白晝。", "至今福斯民，血食固宜厚。", "予生本屯賤，竊位憂致寇。", "約身既多缺，何以撫耆舊。", "况瞻賢達跡，彼美松柏茂。", "芳醪薦樽爵，馨蔬實籩豆。", "悠悠神之思，餘光破昏愗。", "歸歟歌蕪辭，聊用答靈祐。"]'),
('3332f958-fbf6-4adc-928c-9a30c96a77a4','大風','郭祥正','宋','宋诗','song-poetry','','[]','一鳥忽驚鳴，衆鳥高下噪。',120,'全唐诗/poet.song.42000.json','["一鳥忽驚鳴，衆鳥高下噪。", "飄風自南至，汹汹結陰瀑。", "須臾江濤翻，石裂巨木倒。", "禾麻安愗論，畦隴漭若掃。", "蒼天本好仁，孰使風伯虣。", "有叟重咨嗟，吾年行已耄。", "此風未嘗見，神理所誡告。", "我因諭彼儂，天地廣覆燾。", "噫氣亦偶然，何必泥應報。", "掉頭不吾顧，植杖復悲悼。"]'),
('f9e4559d-8703-4498-9321-bab4da0e73e8','蘭陵請雨','郭祥正','宋','宋诗','song-poetry','','[]','夜半何所適，請雨之名山。',108,'全唐诗/poet.song.42000.json','["夜半何所適，請雨之名山。", "蘭陵古仙府，妙跡殊可攀。", "秘文呼蟄龍，舒雁薦層壇。", "屏氣注誠想，百靈啟玄關。", "綠章封事奏，金闕承恩還。", "林風生泠泠，澗溜添潺潺。", "遥峰靄冥霧，倏歘迷區寰。", "殷雷無猛威，激雨增微瀾。", "寧獨濡枯焦，永願清塵煩。"]'),
('9bae7417-c902-4df8-8a20-2a9d397d576f','觀雨','郭祥正','宋','宋诗','song-poetry','','[]','不雨九十日，火氣流郊郛。',216,'全唐诗/poet.song.42000.json','["不雨九十日，火氣流郊郛。", "空山渴虎兕，涸泥困龍魚。", "農事固騷屑，令人但長吁。", "渺思真宰意，反復竟何如。", "去歲百川溢，園田變江湖。", "南民遂乏食，十九棄路衢。", "那聞今秋旱，性命當無餘。", "祀龍稽往法，撃鼓煩羣巫。", "殷殷百里雷，奮自東南隅。", "陰雲隨電合，密雨應時須。", "馳驅蒼黄際，慘淡氣色蘇。", "登樓注遠目，百憂聊滌除。", "銀浪徹平地，玉繩迷太虚。", "日月洗塵坌，山川改焦枯。", "法宫朝大舜，冠珮皆鴻儒。", "况當禮樂新，百靈共持扶。", "和氣自兹肇，風雨安敢逾。", "欲傳千歲音，詠言愧蘼蕪。"]'),
('2ad2b9c5-d285-4617-85ce-2ddad5261498','春日懷桐鄉舊游','郭祥正','宋','宋诗','song-poetry','','[]','二年桐鄉邑，乘春覽榮芳。',216,'全唐诗/poet.song.42000.json','["二年桐鄉邑，乘春覽榮芳。", "日日遶花樹，與客傾壺觴。", "况有青澗泉，潺潺穿北墻。", "容爲方廣池，白虹卧危梁。", "誰磨青銅鏡，朗照紅粉妝。", "唯恐浮雲來，遮我逍遥場。", "舞娥回皓雪，笛叟鳴鳳凰。", "醉則卧花下，所惜徂春陽。", "作詩數十篇，素壁揮琳瑯。", "詔書徙幕府，籠鳥無高翔。", "却治歷川獄，幽憂坐空堂。", "有女殺其母，逆氣凌穹蒼。", "郡縣失實辭，吏侮爭持贓。", "辟刑固無赦，何以來嘉祥。", "高垣密閽禁，但覺白日長。", "茫然思舊遊，今成參與商。", "世網未能脱，樂事安可常。", "咄嗟勿重陳，昏昏燈燭光。"]'),
('b1b4ae68-4974-4688-a24f-f57101f0b0a7','東望','郭祥正','宋','宋诗','song-poetry','','["\u5929\u95e8\u5c71"]','歷陽望姑熟，撫掌衣带隔。',180,'全唐诗/poet.song.42000.json','["歷陽望姑熟，撫掌衣带隔。", "却瞻天門山，落日一雙碧。", "不如雲中鳥，自在鼓兩翼。", "冠裳漫羈紲，髪綠今已白。", "功名隨浮烟，所得乃祿食。", "天兵下安南，獠穴須滅跡。", "騰山吼豺虎，跨海轟霹靂。", "殺氣暗南溟，萬古一洗滌。", "借令伏波在，縮手定歎息。", "男兒逢此時，弗往荷矛戟。", "胡爲守文法，銖銖較朝夕。", "終當解官去，大艦掛長蓆。", "乘風捲雲濤，載月奏玉笛。", "不作凌烟人，猶爲釣鼇客。", "誰能對鄉關，跬步歸未得。"]'),
('152ad45b-bf78-470b-9644-6c8fea7cff31','把鏡','郭祥正','宋','宋诗','song-poetry','','[]','念念遞遷謝，新新來未停。',120,'全唐诗/poet.song.42000.json','["念念遞遷謝，新新來未停。", "把鏡覽素髪，不覺今年生。", "生世能幾何，焰長燭愈短。", "勸吾杯中物，到手莫辭滿。", "陽春纔爛漫，花片已飛舞。", "紛如晴後雪，半作燕巢土。", "堯舜竟何在，楚漢空戰爭。", "勝負一日事，寂寥千載名。", "隱几聊自悲，悲竟復長嘯。", "真體元空無，誰與我同調。"]'),
('4f1c9792-95bb-4b2f-8b3f-d0a0782bd654','望白紵山','郭祥正','宋','宋诗','song-poetry','','[]','隔江望白紵，葱蒼壓牛渚。',180,'全唐诗/poet.song.42000.json','["隔江望白紵，葱蒼壓牛渚。", "却憶跨黄犢，渡橋溪東去。", "悠悠登此山，直待圓蟾午。", "汗漫丹湖水，萬頃浸天宇。", "北斗酌不乾，光烱反吞吐。", "諸峰若案几，白雲俯可取。", "覽景壯我懷，長謡念前古。", "傳聞桓將軍，致酒領歌舞。", "雄風回秋霜，英聲散鼉鼓。", "寧知千載後，荒榛老狐鼠。", "男兒及時樂，一餉亦足許。", "前年翰林公，絕頂構堂廡。", "我方客沅湘，盛事未能睹。", "及今佐肥幕，治獄歷陽府。", "注目聊獨吟，何時達庭戶。"]'),
('aaae81da-d64e-418b-96c8-c08b8906030b','合肥何公檜部使者楊公潛古命予賦之','郭祥正','宋','宋诗','song-poetry','','[]','合肥有老檜，得名自何公。',168,'全唐诗/poet.song.42000.json','["合肥有老檜，得名自何公。", "何公何代人，名跡了莫窮。", "高枝偃羽蓋，低枝卧蒼龍。", "盤根徹厚地，疏影落寒空。", "荏苒九天碧，仍爲烟霧濛。", "相傳魏武帝，解甲休鐵驄。", "嘗坐此檜下，吞吳未成功。", "至今晦暝夕，往往揚英風。", "我公心好古，清標聳千峰。", "鑒賞揮巨筆，丹青孰爲工。", "璨璨發明玉，琤琤叩絲桐。", "談笑走兵役，垣墻密泥封。", "拂拭枯折幹，一助春風融。", "願回拔山力，移植明光宫。"]'),
('d9e43b47-da4c-4dfc-85cb-abb04239c620','懷平雲閣兼簡明惠大師仙公','郭祥正','宋','宋诗','song-poetry','','[]','跨空起高閣，北望敬亭山。',168,'全唐诗/poet.song.42000.json','["跨空起高閣，北望敬亭山。", "白雲無根蔕，舒卷隨風還。", "或墮溪水上，却縈松石間。", "就之既明滅，了然不可攀。", "謝公賽雨詩，千秋瀉潺潺。", "李白弄月處，寒光湛清灣。", "神交自冥合，彷彿眉睫間。", "使我戀此境，每來終日閒。", "如何一揮手，失勢落塵寰。", "功業復未就，但驚鬚鬢斑。", "滄浪不可濯，執熱長汗顔。", "緬懷大道師，焚香坐玄關。", "悲心度羣苦，振錫鳴金鐶。", "行當稟慈誨，惠照開昏頑。"]'),
('22b0dbb3-d20f-4caa-8dd3-d7536eaaf01b','和耿天隲見寄二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','熠熠陽氣動，春事不可禦。',108,'全唐诗/poet.song.42000.json','["熠熠陽氣動，春事不可禦。", "君家富林園，宴豆樂賓主。", "况當解官歸，精魄還六腑。", "或乘青板船，縱纜東溪滸。", "溪光如碧玉，皓月無人取。", "信哉浴乎沂，點也丘所與。", "又聞全於天，卓越莊周語。", "我方治幽獄，歸期日日數。", "讀君新詩章，對面若吳楚。"]'),
('984fbf9b-252e-4b80-9a62-308f32dffb49','和耿天隲見寄二首  其二','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','猛風卷長江，驚湍勢莫禦。',108,'全唐诗/poet.song.42000.json','["猛風卷長江，驚湍勢莫禦。", "虬龍元噴薄，陰怪豈無主。", "扁舟未能往，何以慰心腑。", "想君東城居，林花爛溪滸。", "濁醪初醱醅，豚鱭又新取。", "論詩予素降，泛愛君獨與。", "一聞韶濩奏，卷舌欲無語。", "却瞻項籍祠，繪畫安足數。", "悵然歌虞兮，炎漢已得楚。"]'),
('93a61c3c-640d-4b5d-acb8-96240cba99e3','對酒愛月示客','郭祥正','宋','宋诗','song-poetry','','[]','誰云月無私，那知月有情。',48,'全唐诗/poet.song.42000.json','["誰云月無私，那知月有情。", "我住月亦住，君行月亦行。", "致此一壺酒，都忘千歲名。", "胸中各有月，莫遣暗雲生。"]'),
('8ad69fe9-9295-4a17-808f-a813bafe6c11','望牛渚有感三首  其一','郭祥正','宋','宋诗','song-poetry','','[]','身滯歷陽浦，心傾牛渚雲。',48,'全唐诗/poet.song.42000.json','["身滯歷陽浦，心傾牛渚雲。", "聖人開六合，於此渡三軍。", "霸氣掃無跡，神功千載聞。", "明朝有歸興，石上洗塵紛。"]'),
('e42fd93f-47fb-4058-8af7-c02d49ed903d','望牛渚有感三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','遥憐牛渚磯，柳带拖春綠。',48,'全唐诗/poet.song.42000.json','["遥憐牛渚磯，柳带拖春綠。", "歸思無時闌，斷弦聲自續。", "更聽漁父吟，悠揚寫心曲。", "何日效斯人，烟波洗雙足。"]'),
('8cf2b590-e546-4b18-a968-49181576b326','望牛渚有感三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','江迥偏留月，山空不住雲。',48,'全唐诗/poet.song.42000.json','["江迥偏留月，山空不住雲。", "遥憐李太白，曾憶謝將軍。", "帆影隨潮上，樵聲隔岸聞。", "柳花迷客眼，三月雪紛紛。"]'),
('bb3087c1-3c34-4c26-b03e-0347a39b4511','轂轂','郭祥正','宋','宋诗','song-poetry','','[]','轂轂復轂轂，怪禽安用啼。',168,'全唐诗/poet.song.42000.json','["轂轂復轂轂，怪禽安用啼。", "杏花已爛漫，月色正相宜。", "提壺取新酒，酌我金屈巵。", "行恐風雨來，亂紅辭舊枝。", "尚恨碧城鏁，阻邀白雪姬。", "耳邊無清歌，素飲方自怡。", "爾何騁鳴聲，彈射不肯飛。", "初亦厭爾聒，既久不復疑。", "但能怖愚俗，又足驚童兒。", "天翁造爾軀，無乃私自欺。", "爪吻異鵰鶚，安能司禍機。", "又不似羣烏，凶報吉亦隨。", "白日竄深棘，夜鳴殊不棲。", "勸爾勿轂轂，鳳凰倏來儀。"]'),
('82aa8f03-4dc8-4603-a03f-84523737f518','登歷陽城望凌歊臺','郭祥正','宋','宋诗','song-poetry','','[]','平昔登凌歊，西望歷陽岸。',168,'全唐诗/poet.song.42000.json','["平昔登凌歊，西望歷陽岸。", "江空蘆葦闊，日落烟霧散。", "倏然别鄉國，三載客淮甸。", "賞心無復有，離渚但紛亂。", "邇來治冤獄，文字堆几案。", "置之步城堞，山川却對面。", "崔嵬浮圖出，巨筆插天半。", "秀色凌丹青，長毫蘸河漢。", "翻思宋武帝，此地嘗壯觀。", "美人厭煩暑，揮衣待霜霰。", "流芳千歲間，陵谷未云變。", "碑陰杜牧題，缺玉稍可辨。", "歸魂招不得，舊土常情戀。", "時作梁甫吟，清風忽吹斷。"]'),
('c9722ccd-4593-47c4-a1de-83d857266d1f','懷當塗石城寺','郭祥正','宋','宋诗','song-poetry','','[]','城東二十里，寺有古石城。',192,'全唐诗/poet.song.42000.json','["城東二十里，寺有古石城。", "過盡綠桑野，還依流水行。", "水窮山亦合，老木一區平。", "蘚留虎豹跡，巖多猿狖鳴。", "樓殿横澗陰，像塑鉛黄剥。", "庭中有高花，碧葉抱丹渥。", "不知何歲年，舂容鎮柔濯。", "山僧亦龐眉，發語頗真樸。", "却讀羅泰碑，始知征戰場。", "赤谷納箭血，夜鬼嗥冷創。", "雲霧第黯黲，英雄今則亡。", "誰建大法宇，救援弘津梁。", "每來即忘還，覽古恣吟眺。", "沿崕采菖蒲，興發輒長嘯。", "偶隨辟書起，末路遂難料。", "十年未能歸，應爲山僧誚。"]'),
('3e35f344-993d-4741-b724-2531775928e4','昨遊寄徐子美學正','郭祥正','宋','宋诗','song-poetry','','[]','念昔未弱冠，與君昆弟遊。',288,'全唐诗/poet.song.42000.json','["念昔未弱冠，與君昆弟遊。", "各懷經綸業，壯氣凌陽秋。", "知音得袁宰，鑒賞稱琳璆。", "君家天地崩，泣血城南陬。", "釋服就鄉舉，名姓必見收。", "數爲禮部黜，考命寧怨尤。", "子山僅五十，感疾遽不瘳。", "子美如孤鴻，哀鳴大江頭。", "其聲最酸楚，聞者皆涕流。", "有才多困蒙，此理不可求。", "我初佐星子，老守如素仇。", "避之拂衣去，寓跡昭亭幽。", "篇章自此富，寫詠窮歡憂。", "慈母待祿養，復尉湓浦州。", "隨辟宰環峰，碌碌三載周。", "纔歸遭酷罰，五體戕戈矛。", "旦夕期殞滅，餘生安敢偷。", "粗能襄事畢，寒餓妻兒羞。", "復入湖外幕，萬里浮扁舟。", "幾葬江魚腹，迍邅百端愁。", "到官未三月，開疆預參謀。", "招降五萬戶，給田使鋤耰。", "論功輒第一，謗語達冕旒。", "得邑敢自訴，斷木當沉溝。"]'),
('dd60f6b5-268b-4589-963b-38b8a7c6b487','送宋前之赴調','郭祥正','宋','宋诗','song-poetry','','[]','東岡送終畢，北堂待榮養。',120,'全唐诗/poet.song.42000.json','["東岡送終畢，北堂待榮養。", "短箠跨羸驢，西風吹祖帳。", "玉盤堆鱠縷，金船倒新釀。", "勸君當勇去，回首勿悽愴。", "胸中五千卷，立事須少壯。", "揚名永不滅，孝節乃可尚。", "長安集紛華，出處慎所向。", "肯爲聲色惑，一婢百金償。", "不知粉黛蠧，血氣迷凋喪。", "胡爲發斯言，期予以相將。"]'),
('1e4265f1-7823-42b9-a7be-51807fa9aa6f','浪士歌','郭祥正','宋','宋诗','song-poetry','','[]','江上浪如屋，海中浪如山。',48,'全唐诗/poet.song.42000.json','["江上浪如屋，海中浪如山。", "浪士乘浪舟，兀兀在浪間。", "浪頭幾時息，士心殊自閒。", "死生生死爾，浪歌聊破顔。"]'),
('5ab61b43-c7b6-45b0-b4ac-727dd5ff529f','戴氏鹿峰亭二首呈同游  其一','郭祥正','宋','宋诗','song-poetry','','[]','開亭面鹿峰，白鹿每經過。',120,'全唐诗/poet.song.42000.json','["開亭面鹿峰，白鹿每經過。", "忽啣落花去，還來卧青莎。", "仙者不可見，孤峰但嵯峨。", "疏篁映秀木，好鳥鳴相和。", "飛泉灑天窗，六月凉氣多。", "賓朋四五輩，飲酒朱顔酡。", "璆琳粲明質，芝术芬長哦。", "皆爲廊廟器，偶會林泉阿。", "磻溪與桐廬，回旋竟如何。", "却笑晉右軍，弄筆憐白鵝。"]'),
('fd88b821-030b-44a3-a1cb-3b85b38f0000','戴氏鹿峰亭二首呈同游  其二','郭祥正','宋','宋诗','song-poetry','','[]','未能騎黄鶴，高飛出塵寰。',120,'全唐诗/poet.song.42000.json','["未能騎黄鶴，高飛出塵寰。", "且來跨白鹿，隱見蒼崕間。", "誰爲鹿峰亭，名聞戴氏園。", "仙者去已遠，捲簾對青山。", "秀木染深塢，鳴泉掛危欄。", "春風吹綠鬢，皓月頽朱顔。", "賓朋合簪履，昆季芬芝蘭。", "黄鶴安足騎，白鹿不須跨。", "但願有濁酒，長嘯此峰下。", "醉醒醒復醉，黄金任高價。"]'),
('4e8eb3e6-bf76-417e-9867-b94f2f1ebfdb','陳安止遷居三首  其一','郭祥正','宋','宋诗','song-poetry','','[]','陳子勇於退，退無十椽屋。',144,'全唐诗/poet.song.42000.json','["陳子勇於退，退無十椽屋。", "鄰家頗好事，借宅並山隩。", "堂廡稍寛靜，垣墻亦新築。", "春渠漲朝雨，涓涓潄寒玉。", "呼童種瓜果，教僕洗松竹。", "身雖在城郭，志實寓磎谷。", "誦持方廣經，一餐止蔬粟。", "所喜遠羶腥，佛事要清肅。", "弗學陶長官，持盃媚秋菊。", "弗學屈大夫，含悲葬魚腹。", "唯慕金粟老，不二常具足。", "若許浪士遊，時時跨黄犢。"]'),
('e85a2677-7d5b-4160-9c8a-371cf41b7971','陳安止遷居三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','陳子貧無居，東家借茅屋。',144,'全唐诗/poet.song.42000.json','["陳子貧無居，東家借茅屋。", "達士寧羞貧，四方所居隩。", "平臺荔陰下，天匠資爾築。", "青分一畦蘭，綠種萬竿玉。", "幸遭文明運，志豈效孤竹。", "又非遠人音，欲以逃空谷。", "翛然置藤榻，示疾肖金粟。", "呪飯施諸鬼，夜半風肅肅。", "嗟予在羅網，未暇親杞菊。", "憂愁無端來，刀劍攪胸腹。", "渺思泛滄浪，期君濯雙足。", "時或臨大野，泥耕看健犢。"]'),
('fd798980-87b0-43ad-8fbd-3f96b25cf840','陳安止遷居三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','彼美隱官隱，蒼林映深屋。',144,'全唐诗/poet.song.42000.json','["彼美隱官隱，蒼林映深屋。", "俗駕遠庭除，佛像鎮堂隩。", "蘭芷稍扶疏，荆榛已鋤築。", "沉思第一義，修持若礱玉。", "覺城開迷雲，魔軍當破竹。", "接人有餘地，拔我出坑谷。", "齋羞復招要，甘香蒸黍粟。", "永與羶葷辭，既飽精神肅。", "石坐襯枯蒲，茶甌泛新菊。", "醍醐灌諸頂，饑火滅空腹。", "昔聞居士飯，一鉢萬人足。", "君若乘三車，願爲車下犢。"]'),
('552c7726-67f4-4cb8-960d-b3f8b2da36b8','喜雨','郭祥正','宋','宋诗','song-poetry','','[]','陰雲海上來，飄風亦隨至。',120,'全唐诗/poet.song.42000.json','["陰雲海上來，飄風亦隨至。", "填空翻猛雨，溢溜迸平地。", "豈惟滋稼穡，高視掃瘴癘。", "羣山各藏晦，萬壑恣吞噬。", "蚊蠅暫驅除，草木起憔悴。", "榕枝碧如染，荔子紅欲墜。", "呼兒索杯盤，四體襲涼氣。", "豐年固有兆，此雨信嘉瑞。", "一人堯舜聖，三公夔卨備。", "陰陽兹調和，樂飲真吾事。"]'),
('91f227ef-f050-485f-8d57-4a6d7abc63df','月下懷留二君儀','郭祥正','宋','宋诗','song-poetry','','[]','默坐兩股痹，幽行整頭簪。',48,'全唐诗/poet.song.42000.json','["默坐兩股痹，幽行整頭簪。", "無家不成寐，有酒何處斟。", "山色九秋靜，月華中夜深。", "遙想端居人，焚香哦妙音。"]'),
('cceeeb91-8ee3-4991-a75d-fe674b811c6c','寄題留二君儀田園基石亭二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','磐石發天巧，新亭君所營。',120,'全唐诗/poet.song.42000.json','["磐石發天巧，新亭君所營。", "席展瑶琪滑，坐久寒陰生。", "遠瀑曳修幔，他山列蒼屏。", "水田白鷺下，霜樹青猿鳴。", "回首同安縣，殘陽樓觀横。", "不逢車馬來，時愛牛羊經。", "童僕種刈畢，父老樽罍傾。", "昇平信難遇，歡笑聊舒情。", "况攻李杜吟，字字無淫聲。", "春來成幾章，想有基石銘。"]'),
('4c0dea43-2d28-470b-9496-fcc3331ed449','寄題留二君儀田園基石亭二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','人世無百歲，塵勞枉營營。',96,'全唐诗/poet.song.42000.json','["人世無百歲，塵勞枉營營。", "豈如田園樂，歌嘯送餘生。", "况同盤石上，開亭石爲屏。", "卷簾春雨足，洗耳松風鳴。", "孤鳥望中没，淡烟山際横。", "時復命兒息，講道或傳經。", "經罷哦五言，珠璣滄海傾。", "嗟我無羽翼，往適幽憂情。"]'),
('3a70ba31-da7d-448e-849d-6847dda2b6a9','同蕭英伯登陳安止嘯堂','郭祥正','宋','宋诗','song-poetry','','[]','食訖雨初霽，相將陟高臺。',180,'全唐诗/poet.song.42000.json','["食訖雨初霽，相將陟高臺。", "縹緲臨諸峰，幔卷濃雲開。", "秀特不可掩，擎天碧崔嵬。", "漳流欲赴海，澎湃西南來。", "陰陰荔子木，合抱何年栽。", "幽鳥轉枝語，清風與春回。", "佛宫四面出，紺碧疑蓬萊。", "寓隱得斯地，足以攄君懷。", "方庭有蘭芷，近郭無虎豺。", "萬事不掛慮，長年效僧齋。", "一爲孫登嘯，而與數子諧。", "顧我病且老，况復時運乖。", "兒歸半道死，旅棺未葬埋。", "破甑已棄物，乃非君子儕。", "從遊得無玷，泯默甘擯排。"]'),
('a9a686f2-003b-4e45-b8c4-f5fb6c107e9e','送廣東漕孫知損失官歸汶上','郭祥正','宋','宋诗','song-poetry','','[]','平生愛東州，土厚人不罄。',132,'全唐诗/poet.song.42000.json','["平生愛東州，土厚人不罄。", "見公惜已晚，達論聳予聽。", "五馳使者車，中道罹陷阱。", "開懷無怨尤，得失兩以正。", "歸程萬餘里，翛然一烟艇。", "鄉關今非遥，踴躍理三逕。", "進則仗忠義，退則樂温凊。", "高卧固無必，求才堯舜聖。", "亭亭南澗松，愈老節愈勁。", "柔柔水中蒲，涵春自嚴靜。", "百年未闔棺，安之吾有命。"]'),
('e5691391-313b-4609-855c-21ce599b33dc','讀陶淵明傳二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','我愛陶淵明，超然遺世想。',96,'全唐诗/poet.song.42000.json','["我愛陶淵明，超然遺世想。", "一奏無弦琴，妙曲寄玄響。", "翛然聽以氣，萬籟應諸掌。", "舟車就所便，丘壑信孤往。", "泉涓木欣欣，酌酒助俯仰。", "酣醉頽雲烟，舒嘯逸羅網。", "斯人孰可見，夢寐期彿彷。", "兀如南山松，亭亭植千丈。"]'),
('71001289-0058-482b-99cd-1f3e0ba2fd0c','讀陶淵明傳二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','陶潛真達道，何以避俗翁。',96,'全唐诗/poet.song.42000.json','["陶潛真達道，何以避俗翁。", "蕭然守環堵，褐穿瓢屢空。", "粱肉不妄受，菊杞欣所從。", "一琴既無弦，妙音默相通。", "造飲醉則返，賦詩樂何窮。", "密網懸衆鳥，孤雲送冥鴻。", "寂寥千載事，撫卷思冲融。", "使遇宣尼聖，故應顔子同。"]'),
('dfb73e9e-8a60-4fde-9e4c-cf5f21f548de','普利寺自周上人高明軒','郭祥正','宋','宋诗','song-poetry','','[]','世人孰無累，貴彼方外人。',120,'全唐诗/poet.song.42000.json','["世人孰無累，貴彼方外人。", "超然雲霞趣，迥脱生死輪。", "周也漳南釋，開軒瞰漳濱。", "山光并水影，二物長清新。", "尤愛明月夕，蒼林變金銀。", "焚香坐軒上，時或要靜賓。", "幸無歌吟喧，得與麋鹿馴。", "嘗茶煮山藥，長養菩提因。", "豈慕富且貴，寧憂賤與貧。", "我來勿厭數，從爾陶天真。"]'),
('1b4580c6-a4c8-4f72-96f0-2972d1667dc0','同留二君儀登高明軒','郭祥正','宋','宋诗','song-poetry','','[]','羈客厭卑濕，登軒喜高明。',96,'全唐诗/poet.song.42000.json','["羈客厭卑濕，登軒喜高明。", "紅日簷下度，白雲窗半生。", "并吞山川秀，映带樓殿平。", "舟航濟吳楚，笑語落蓬瀛。", "春風時一來，百鳥相和鳴。", "隔墻酒可沽，千金爲君傾。", "既絕世上趣，雅遂林中情。", "勿云暮靄合，更望孤蟾升。"]'),
('dde30bfc-5a25-4c34-af5f-e3108b7a9f9a','同陳安止登高明軒','郭祥正','宋','宋诗','song-poetry','','[]','有客學清淨，喜爲林下遊。',96,'全唐诗/poet.song.42000.json','["有客學清淨，喜爲林下遊。", "兹軒高且明，駐策同其休。", "目界既朗徹，心官欣自由。", "棄祿慕居士，讀經親比丘。", "雲樹樵聲遠，石層春水流。", "鳥羽瑩可數，花光暖爭浮。", "已知隔人寰，日落山更幽。", "適此悟無生，餘事安足求。"]'),
('e52decb9-c16c-4ede-a774-e1daf901059c','題淨惠院','郭祥正','宋','宋诗','song-poetry','','[]','方塘水未漲，荷芰新展綠。',120,'全唐诗/poet.song.42000.json','["方塘水未漲，荷芰新展綠。", "遊子愜輕衣，步與孤雲逐。", "初臨寺外橋，已聽鐘聲肅。", "徐登山後亭，葱蒼翳松竹。", "諸峰却羅列，龍蛇互奔觸。", "紅綃卷晴霞，白雲落孤鶩。", "了然身世忘，豈念冠带束。", "平時謬持節，善地甘厚祿。", "更窮泉石樂，曾未伸啟沃。", "何以報君恩，堯天漫凝目。"]'),
('88b75819-eccb-402c-b01e-ee94ce792c02','題淨衆院贈蒙禪伯','郭祥正','宋','宋诗','song-poetry','','[]','南州三百寺，此寺最輝煥。',120,'全唐诗/poet.song.42000.json','["南州三百寺，此寺最輝煥。", "石開千丈渠，泉飛日華亂。", "供僧無定員，連牀接雲漢。", "經營始十載，物物悉已換。", "上人固多才，不獨悟禪觀。", "其師老黄蘖，簡肅衆所憚。", "承音既親切，妙頂醍醐灌。", "登門已清凉，定步濟彼岸。", "融融接軟語，羣疑自消泮。", "每遊即忘還，微風灑塵汗。"]'),
('9e0dd34c-5206-48e2-a9b8-267d63d8cb29','題月淵亭','郭祥正','宋','宋诗','song-poetry','','[]','仰攀明月輪，俯瞰滄海淵。',120,'全唐诗/poet.song.42000.json','["仰攀明月輪，俯瞰滄海淵。", "乾坤惜形勝，此池何其偏。", "靈溪九龍躍，仙山一峰圓。", "微紅散晴綺，遠碧襯瑶烟。", "幽香發野秀，接語皆老禪。", "緣何近城郭，了無人世諠。", "邂逅攝邦守，所樂多林泉。", "唯憂代者至，不得經殘年。", "老矣寧復來，吟哦强留連。", "他時考陳跡，不滅斯亭篇。"]'),
('42071e66-5acb-4841-ba7f-d33ed597dac1','送范端仲推官','郭祥正','宋','宋诗','song-poetry','','[]','范君建陽客，讀書過萬卷。',144,'全唐诗/poet.song.42000.json','["范君建陽客，讀書過萬卷。", "下筆又神速，數預賢能薦。", "省闥復擅場，聲名動海縣。", "一投紅蓮幕，阻上金鑾殿。", "志氣老不衰，苦柏冒霜霰。", "當塗少知已，薄祿勢所戀。", "君子困下僚，佞士即華選。", "顧我駑散才，攝守頗優便。", "公庭可羅雀，雲山復對面。", "坐卧臨清風，吟哦揮羽扇。", "相逢始相樂，瞥去若驚電。", "君行我幽獨，送君聊自喭。"]'),
('4b91e2bc-5b79-4537-8f91-d228adb02d49','池上晚景分得上字','郭祥正','宋','宋诗','song-poetry','','[]','秋風何處來，蕭然洗炎瘴。',96,'全唐诗/poet.song.42000.json','["秋風何處來，蕭然洗炎瘴。", "時要二三子，臨池倒嘉釀。", "逢辰既昇平，覽景又清曠。", "寂無人世喧，頗覺神魄王。", "雪鷺集滄洲，金烏没青嶂。", "悠悠漁笛還，漫漫潮痕漲。", "黄蜂立蓮葉，赬鯉吹萍浪。", "始信莊生言，觀魚樂濠上。"]'),
('285348d7-f4cc-42db-89d2-5871827679df','漳南書事','郭祥正','宋','宋诗','song-poetry','','[]','元豐五年秋，七月十九日。',240,'全唐诗/poet.song.42000.json','["元豐五年秋，七月十九日。", "猛風終夜發，拔木壞廬室。", "須臾海濤翻，倒注九溪溢。", "湍流崩重城，萬戶競倉卒。", "萬牛豈復辨，涯渚怳已失。", "嬰老相攜扶，迴首但悽慄。", "憂心漫如焚，救疹竟無術。", "憶昨攝印初，歲望頗云吉。", "田疇時雨足，秔糯各秀實。", "胡爲兆陰怪，平地遭潏汨。", "尤嗟梁棟材，中道摧折畢。", "日月有常度，金行正蕭瑟。", "疇咨風雨師，殘害皆天物。", "天心本好仁，忍視久不恤。", "况今大上聖，治具嚴且密。", "騎馬藏民間，教兵授神筆。", "四夷還舊疆，百辟奉新律。", "固宜集和氣，祥瑞爲時出。", "緣何漳南民，憔悴抱愁疾。", "終當呼長鯨，一吸見蓬蓽。"]'),
('2e0944f0-fb5d-43fa-a28f-a48576111a95','臨漳亭觀水分得大字','郭祥正','宋','宋诗','song-poetry','','[]','憂民登危亭，注視萬里外。',120,'全唐诗/poet.song.42000.json','["憂民登危亭，注視萬里外。", "溟濛雲氣浮，勢與江海匯。", "蒼山恐低沉，况復問畎澮。", "禾麻安更論，老稚念顛狽。", "蛟鼉自出没，牛馬失向背。", "雨師恣侵凌，人理亦可罪。", "殷殷非雷聲，遠近屋廬壞。", "君臣正逢時，上下宜交泰。", "驅雲清白日，朗徹照幽怪。", "一雨即瀰漫，孰謂乾坤大。"]'),
('76b7855b-80d7-4551-84f0-6c33f8fb0e22','送孫公素朝奉還臺','郭祥正','宋','宋诗','song-poetry','','[]','暑雨正鬰陶，流汗坐深甑。',120,'全唐诗/poet.song.42000.json','["暑雨正鬰陶，流汗坐深甑。", "忽聞公素來，清風先滿徑。", "高談别後事，琳瑯發吾聽。", "聽之復何如，五月冰雪瑩。", "况逢至治朝，日月開二聖。", "大臣用老成，羣辟要方正。", "如公亦幾人，尚未擢諫諍。", "浮舟每經年，山川寓幽興。", "皇皇歲華晚，曳屣漫吟咏。", "行矣勿徘徊，金門待新命。"]'),
('eaf71f79-532c-4ef9-aaf8-0ce9fd509f8d','題妙勝院西軒并贈權師','郭祥正','宋','宋诗','song-poetry','','[]','老木不知年，蒼藤已垂地。',120,'全唐诗/poet.song.42000.json','["老木不知年，蒼藤已垂地。", "高枝生晚陰，低枝散凉氣。", "好鳥時復來，鳴聲似弦吹。", "道人開小軒，幽庭增廣庇。", "庬眉霜雪頂，休焉釋塵累。", "餘功又及物，丹砂和靈劑。", "一粒愈沉疴，求者四方至。", "應接運真悲，平等均我施。", "相逢惜已晚，殘光念如寄。", "何當擇深山，同師樂禪味。"]'),
('76a09e62-7f40-4934-9496-d4d8f3c8d5a1','清江臺致酒贈范希遠龍圖','郭祥正','宋','宋诗','song-poetry','','[]','行手出烟霧，致酒清江臺。',144,'全唐诗/poet.song.42000.json','["行手出烟霧，致酒清江臺。", "水淺横沙露，林疏遠山來。", "白鳥一雙落，青猿三叫哀。", "誰展摩詰圖，而把淵明杯。", "妙娥始七歲，彈箏殷晴雷。", "或如鸞鳳吟，唤得陽春回。", "主人亞父孫，卓犖王佐才。", "高談使我聽，明珠欲傾懷。", "爽魄超太虚，月窟無飛埃。", "一飲不知醉，浩歌忘草萊。", "遲明繫雙櫂，回首安在哉。", "尺水公自養，以待天門開。"]'),
('d1d1461b-4d2d-4e84-bd70-53758b476421','贈陳師道判官','郭祥正','宋','宋诗','song-poetry','','[]','自從梅老死，詩言失平淡。',180,'全唐诗/poet.song.42000.json','["自從梅老死，詩言失平淡。", "我欲回衆航，力弱不可纜。", "栖遲二十年，時時漫孤噉。", "忽逢陳夫子，兩目海水湛。", "爲我聊一吟，粹芳超俗艷。", "又如趙氏璧，毫髪絕瑕玷。", "愈多愈精好，璀璀摘驪頷。", "借令李杜在，决敵未應敢。", "低頭亟趨降，吞聲就誅貶。", "招來君尚謙，且曰吾與點。", "窮朝把樽酒，金斝紅浪颭。", "胡爲眷幕府，半百尚壈坎。", "幽蘭没蕭艾，明珠混野芡。", "何當叩相閣，斯人願收斂。", "置之翰林中，萬丈看光焰。"]'),
('5ac6da85-b2c1-44ba-95e1-49ad9681ca06','鳳凰驛','郭祥正','宋','宋诗','song-poetry','','[]','晚泊鳳凰驛，得名知謂何。',120,'全唐诗/poet.song.42000.json','["晚泊鳳凰驛，得名知謂何。", "鳳凰不可見，篁竹空婆娑。", "四傍俱石崖，一逕縈雲蘿。", "慘慘陰欲雨，淙淙澗跳波。", "驛吏指英州，兩舍皆平坡。", "久寒無瘴癘，虚市饒雞鵝。", "我行既已遠，樂少憂常多。", "過江紅葉舞，度嶺黄鸝歌。", "時序逼衰老，羽翰驚網羅。", "一夕得佳處，休焉聊獨哦。"]'),
('fdff7a55-8ed9-48c9-9df7-a6643d055335','輪石','郭祥正','宋','宋诗','song-poetry','','[]','輪石如車輪，削立萬丈壁。',120,'全唐诗/poet.song.42000.json','["輪石如車輪，削立萬丈壁。", "湍流走其根，倒影翠霧滴。", "天公不推去，此意人莫識。", "雖無載輓功，免有圓轉跡。", "隔江欲登臨，賃舟終不得。", "既乏官長威，人事輕遠客。", "胡爲秀絕姿，往往在幽僻。", "童僕驚日晚，策馬苦相逼。", "哀哉攜妻子，未暇往棲息。", "沉吟復回首，舍旃欲何適。"]'),
('fb6a53a7-f878-41aa-8ab6-09b21c1b0c4e','題清遠峽廣慶寺壁','郭祥正','宋','宋诗','song-poetry','','[]','平明下碧落，晚投清遠峽。',144,'全唐诗/poet.song.42000.json','["平明下碧落，晚投清遠峽。", "銀潢注地來，翠壁連天插。", "中含五峰秀，寺載三車法。", "龍歸石有痕，犀躍無遺柙。", "直釣誰得魚，危磯待鷗狎。", "長廊覽前題，習之最爲甲。", "物理求其全，用材無乃狹。", "渾詩亦可取，小雨纔一霎。", "未能臻甫白，源長流不乏。", "持盃聊酌茗，清風爲停箑。", "超然望日下，嵐翠忽頽壓。", "忍涕上孤舟，低頭隨雁鴨。"]'),
('0898a692-ccee-4b1c-b83e-0098b310deb7','次韻穎叔修撰游朱明及字','郭祥正','宋','宋诗','song-poetry','','[]','朱明洞天門，元戎要客入。',96,'全唐诗/poet.song.42000.json','["朱明洞天門，元戎要客入。", "誰云蓬萊遠，浮丘果相挹。", "如超頓地禪，曾不假梯級。", "綠篁隔葱蒨，沆瀣朗呼吸。", "玉山有嘉禾，鳳凰乃來集。", "桃李爾何知，濯濯紅露泣。", "應嗟塵世人，窗間白駒急。", "行樂如之何，不樂嗟何及。"]'),
('0746adb5-5049-4b37-a4d2-f3e3408348e8','五仙謡','郭祥正','宋','宋诗','song-poetry','','[]','番禺五仙人，騎羊各一色。',103,'全唐诗/poet.song.42000.json','["番禺五仙人，騎羊各一色。", "手持六秬穗，翺翺遶城壁。", "翩然去乘雲，諸羊化爲石。", "至今留空祠，異像猶可識。", "曾聞經猛火，毫髪無痕跡。", "五仙寧復來，三說頗難測。", "只憂風雨至，半夜隨霹靂。", "君不見羌廬劉越之洞天，萬象森羅無一尺。"]'),
('8ad92a4a-0aa2-4be7-818c-b68fef349e4d','誌游呈蔣帥穎叔','郭祥正','宋','宋诗','song-poetry','','[]','焚香瞻五仙，登樓瞰滄海。',132,'全唐诗/poet.song.42000.json','["焚香瞻五仙，登樓瞰滄海。", "題軒名雙林，却酒飯蔬菜。", "還趨法性寺，爛漫發幽晦。", "房公潤經處，蘭茝遺芳在。", "老木已千年，成林播佳話。", "危壇半頽缺，曾傳祖師戒。", "達多與藥止，古像各瀟灑。", "歸時已殘陽，心淵生沆瀣。", "蘭亭世俗飲，尚足傳異代。", "佛境清淨緣，浩劫永不壞。", "聊誌一日遊，結交向方外。"]'),
('58f19fc2-4f91-474b-8221-819efcede7a1','再和穎叔誌遊','郭祥正','宋','宋诗','song-poetry','','[]','君爲五羊仙，我效退之拜。',204,'全唐诗/poet.song.42000.json','["君爲五羊仙，我效退之拜。", "默契如來禪，安用傳畫繪。", "滄海雖云闊，萬里有限際。", "請從造物論，一瞬即破碎。", "靈龜胡爲乎，鑽灼爛腹背。", "生能發幽冤，神理助奇怪。", "晚投古寺食，葷味不如菜。", "摩挲庭下碑，百歲蒼蘚晦。", "忽逢潤經處，房公儼如在。", "度人要成林，今已播禪話。", "忽爲殺盜淫，佛勅所告戒。", "種子積無明，應須法雨灑。", "幸陪蓮社緣，彼此吸清瀣。", "噫嗟縶軒冕，憔悴塵垢態。", "一朝趨地獄，苦惱孰肯代。", "瑩如摩尼珠，誰使濁水壞。", "與公誌斯遊，浩蕩形骸外。"]'),
('83f051bb-6406-4adc-a2bf-e7ecedd77b1e','獨遊藥洲懷穎叔修撰','郭祥正','宋','宋诗','song-poetry','','[]','驅車何所適，獨往觀藥洲。',168,'全唐诗/poet.song.42000.json','["驅車何所適，獨往觀藥洲。", "荒蘆喧鳥雀，怪石森龍虬。", "大亭插層城，玉虹跨深溝。", "雙門控西渚，九星聚中流。", "其名何壯哉，像貎儼可求。", "鋹王卷國去，故物惟此留。", "滄溟霸氣滅，落日孤烟浮。", "空畦已無藥，草蔓春柔柔。", "常年一百五，載酒傾城遊。", "炎炎二聖作，德澤覃海陬。", "大帥用文儒，靜鎮十五州。", "諸公握鴻筆，剗蘚揮戈矛。", "仍要水宫月，一笑挹浮丘。", "蓬萊自兹往，稳踏金鼇頭。"]'),
('37175499-e1b3-40f4-b081-4befa2e7b9a7','九曜石奉呈同遊蔣帥穎叔吳漕翼道','郭祥正','宋','宋诗','song-poetry','','["\u592a\u6e56"]','番禺西城偏，九石名九曜。',144,'全唐诗/poet.song.42000.json','["番禺西城偏，九石名九曜。", "危根插滄浪，古魄鎮臨眺。", "何人試巧手，鑿此混沌竅。", "森森毛髪散，偉偉儀形肖。", "葱蒼翠霧濕，玲瓏秋月照。", "痕添海潮上，聲酸朔風叫。", "龍歸憂利劍，鼇泣怖長釣。", "曾非借霹靂，安得離巖嶠。", "菱溪與太湖，所得信未妙。", "誰將置濠隍，我願植廊廟。", "堅貞以類舉，邪僻令遁趒。", "濡毫勒陰崕，卑語君莫誚。"]'),
('8746a422-99c9-4cd8-92dc-c30d7130edc2','和穎叔遊浮丘觀','郭祥正','宋','宋诗','song-poetry','','[]','潭潭洞天門，孰出朱明右。',192,'全唐诗/poet.song.42000.json','["潭潭洞天門，孰出朱明右。", "突疑雲翼張，竦見冰骨痩。", "飛仙時往來，别有通海竇。", "此事僅傳聞，世人豈能覯。", "欹簷榛棘合，壞壁青紅舊。", "汲泉煉丹處，頽廢無完甃。", "不逢博物人，妙跡誰復究。", "黄冠禀使者，乘時力營構。", "飛閣凌滄波，誅林逐羣狖。", "松蘿翠欲滴，蘭茝芬可嗅。", "秋蟾助餘魄，蓬島分小岫。", "披披宿靄散，泠泠諸籟奏。", "超然俗慮息，揮手出宇宙。", "况逢老集仙，氣奪天下秀。", "落筆誠千言，霹靂震白晝。", "于兹惜分攜，作惡須摻袖。"]'),
('9b939c6c-566c-42cd-ac59-0bd5ec51fdae','穎叔招飲吳圃','郭祥正','宋','宋诗','song-poetry','','[]','五鼓開畫戟，平明出重闉。',216,'全唐诗/poet.song.42000.json','["五鼓開畫戟，平明出重闉。", "小橋分野徑，吳圃會衆賓。", "番禺二月尾，落花已無春。", "唯有薔薇水，衣襟四時薰。", "短垣乃浮丘，樓觀何斬新。", "我公發幽晦，輸金走車輪。", "蓬萊飛一島，雲外拖晴紳。", "此景在眉睫，圖繪未必勻。", "從來不彈弋，傍砌鳥雀馴。", "寄語北海若，停風護松筠。", "負才詩傲敵，縱酒吞湖漘。", "酩酊安足辭，不飲終成塵。", "逍遥一日事，浮脆百年身。", "何須跨黄鶴，追彼瑶池人。", "但當聽公歌，賣交斥張陳。", "達道齊生死，筆端真有神。", "揮灑十八韻，一一無價珍。", "老彼杜工部，玄哉揚子雲。"]'),
('0e3cccda-c2bf-4bd5-97db-84caaf59e871','鵠奔亭呈帥漕二公','郭祥正','宋','宋诗','song-poetry','','[]','新江自南來，西與端江匯。',216,'全唐诗/poet.song.42000.json','["新江自南來，西與端江匯。", "寒光入靈羊，一碧浸羅带。", "屹然鵠奔亭，遺音溢千載。", "羽儀莫可見，窈窕想姝態。", "遭戕瘞同坎，襦布久不壞。", "訴冤如生平，隱顯一何怪。", "讐人闔戶戮，化質摶風快。", "且將憂患辭，浩蕩烟霄外。", "舄飛并劍躍，類與神靈會。", "物變固難窮，撫事增感慨。", "周侯昔行部，美績此尤最。", "江生引爲言，建平平捐罪。", "宋興跨唐虞，乾坤正交泰。", "皇華命俊哲，枉横無纖芥。", "琳瑯斯亭篇，證古欲陳戒。", "殺人貴滅口，覆族竟自敗。", "姦諛誅既死，潛德發幽晦。", "堅珉可磨鐫，榮光庶長在。"]'),
('a52c3ea0-ce53-4f3e-a4f2-e44d7e1fca87','端州逢故人劉暐光道致酒鵠奔亭作','郭祥正','宋','宋诗','song-poetry','','[]','貴池昔分袂，端江復傾蓋。',144,'全唐诗/poet.song.42000.json','["貴池昔分袂，端江復傾蓋。", "屈指十六秋，華髪驚老大。", "雲霄邈功名，荆榛森患害。", "衆人皆欲戮，出門即有礙。", "咄哉不復道，致酒强高會。", "蒼梧帝魂寂，鵠化遺亭在。", "翠葆攖玉簪，金鱗躍羅带。", "風澄嵐靄散，櫂擊天影碎。", "往古悉已空，來今竟何待。", "勞形百年間，投足萬里內。", "秋水正瀰漫，醉膽逐澎湃。", "一絲攜六鼇，猛擲滄溟外。"]'),
('9491d641-30a3-40cf-9466-6bdb64c09bb2','將歸三首  其一','郭祥正','宋','宋诗','song-poetry','','[]','春田豈不美，春園亦可佳。',120,'全唐诗/poet.song.42000.json','["春田豈不美，春園亦可佳。", "田水流决决，園禽語喈喈。", "荷笠復攜鋤，動作頗自諧。", "鄰叟三五輩，擊壤歡無涯。", "祿仕四十年，志運良已乖。", "許國既無補，陷穽幾沈埋。", "皇恩湛昭洗，印綬蒙優差。", "內循齒髪衰，愧彼英俊偕。", "休焉保其終，飛章乞殘骸。", "將歸樂復樂，清風掃孤懷。"]'),
('4e3cc01c-1cb9-41bb-9031-d2dfa734ef98','將歸三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','結廬謝山下，門荒蘿逕深。',60,'全唐诗/poet.song.42000.json','["結廬謝山下，門荒蘿逕深。", "寂無車馬跡，而有猿鳥音。", "高峰落日盡，遠壑歸雲沉。", "死生一吾趣，長嘯亡頭簪。", "勇往復此樂，俛仰安可任。"]'),
('a1efc051-1d3e-4d54-b2cb-910d060c75aa','將歸三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','垂老度庾嶺，西江守端州。',84,'全唐诗/poet.song.42000.json','["垂老度庾嶺，西江守端州。", "逾年忝祿食，歸思忽驚秋。", "結廬丹湖邊，種朮果屢收。", "掛冠已不早，玄花隨兩眸。", "休休保殘齡，擊壤歌皇猷。", "有兒集吏選，餘事復何求。", "回首天地恩，瞑目終難酬。"]'),
('3fbcc100-2d5b-4a4a-9b0c-c8a441d67b1b','贈上藍晉禪師','郭祥正','宋','宋诗','song-poetry','','[]','泐潭月公晦，其禪妙諸方。',180,'全唐诗/poet.song.42000.json','["泐潭月公晦，其禪妙諸方。", "傳之晉伯明，獨步入豫章。", "一登上藍座，日月迥輝光。", "問法瞻丈室，方廣不可量。", "人人得甘露，灌頂心清凉。", "又通世俗書，落筆皆文章。", "衆鳥難悉名，卓然唯鳳凰。", "羽儀下雲霄，五色在山岡。", "先帝昔臨御，京城開寶坊。", "明詔求法才，衆老爭低昂。", "惟師不妄念，安之如太行。", "乃知北遠師，駕幸不下牀。", "所傳信匪訛，千載兩相望。", "篁竹架清風，喬松裛寒霜。", "回心剃鬚髪，永願陪翺翔。"]'),
('511abf18-931a-412a-9fab-4910b0593101','望廬山懷陶淵明','郭祥正','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','羌廬初在望，復憶柴桑翁。',72,'全唐诗/poet.song.42000.json','["羌廬初在望，復憶柴桑翁。", "醉來卧磐石，悶默天地通。", "不入惠遠社，自彈無弦桐。", "悠悠出谷雲，漠漠栖林風。", "傍巖片月白，落磴寒泉洪。", "此意非眺聽，遥知與君同。"]'),
('4310ff78-a8dc-4c56-b8c4-8628c2b11823','追和韋應物廬山西澗瀑布下作','郭祥正','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','徘徊西澗下，聽泉濯煩襟。',72,'全唐诗/poet.song.42000.json','["徘徊西澗下，聽泉濯煩襟。", "煩襟遂蕭爽，妙音非世音。", "不知岐路絕，貪玩烟蘿深。", "斧斤未嘗入，高材自成林。", "鶴鳴豈有怨，雲去本無心。", "寥寥陵澗寂，古意難追尋。"]'),
('8b3400e7-e7db-4bce-9fb1-3807d373d4cb','宿栖賢寺','郭祥正','宋','宋诗','song-poetry','','[]','遥憐李太白，吟望瀑布水。',144,'全唐诗/poet.song.42000.json','["遥憐李太白，吟望瀑布水。", "不知三峽流，翠灑虚烟裏。", "雄聲雷雨驟，遠響松風靡。", "誰留千丈虹，長在雲根倚。", "遂令車馬來，朗瞻樓殿啟。", "明明銀色界，浩浩蟾波洗。", "居中梵天衆，聞思悟玄理。", "長老乃摩詰，取供在彈指。", "普薰毛孔香，真寶超凡鄙。", "病夫寄一榻，清泠濯心耳。", "飄然睡鄉去，策杖中夜起。", "不能跨鯨魚，揮筆信非美。"]'),
('3d1affe0-55e2-45bf-8791-a3e7205c4bf7','宿歸宗寺','郭祥正','宋','宋诗','song-poetry','','[]','曠懷王逸少，宅地如翔鸞。',120,'全唐诗/poet.song.42000.json','["曠懷王逸少，宅地如翔鸞。", "池水至今黑，云是墨未乾。", "施作金仙宫，樓殿排羽翰。", "銀榜留飛烏，玉蜃吐驚湍。", "耶舍寶塔近，筆插青雲端。", "貝葉五千書，兩藏龍鱗蟠。", "鐘磬遞虚籟，松杉扶歲寒。", "護持不變滅，鑪烟晝漫漫。", "暫遊寄僧榻，翛然心界寛。", "愧無驚絕草，付與蒼崖刊。"]'),
('4d451ace-447b-409d-aa63-f52ea7f6302e','新昌吟寄穎叔待制','郭祥正','宋','宋诗','song-poetry','','[]','元祐丙寅冬，新昌有狂寇。',288,'全唐诗/poet.song.42000.json','["元祐丙寅冬，新昌有狂寇。", "名探其姓岑，厥初善巫咒。", "南民欣尚鬼，來者爭輻輳。", "經年惑羣衆，詭術遂潛構。", "摧城止三闞，作蜂唯撒豆。", "竹竿變鎗旗，鋭兵莫吾鬭。", "此事古未聞，造意無乃陋。", "蚩蚩彼何知，丁壯擁前後。", "長驅向城郭，塵土翳白晝。", "刺史亟閉戶，神理默垂祐。", "城頭無百兵，坐待五羊救。", "賊中衆所見，戢戢羅甲胄。", "須臾薄寒陰，凍立多僵仆。", "平明若鳥散，賊本未遑究。", "權帥計倉卒，遣將速誅蹂。", "貪功恣殺戮，原野民血溜。", "嬰兒與婦女，屠割僅遺脰。", "傳報及南昌，新帥若烟走。", "入境亟止殺，渠惡用機購。", "逾旬果獲探，腰斬餘悉宥。", "朝廷方好仁，帥畧寔能副。", "臺章請褒賞，詔語優以懋。", "撫綏聊借才，侍從爾來復。", "身居江湖上，名近日月右。"]'),
('b96ad07e-08ae-400b-bbc7-45391ff47228','送許栖墨道士','郭祥正','宋','宋诗','song-poetry','','[]','結廬守親冢，淡食畢喪制。',168,'全唐诗/poet.song.42000.json','["結廬守親冢，淡食畢喪制。", "焚香誦寶經，傾悲拔冥滯。", "神明扶孝思，肌髪保陽氣。", "支離僅不死，鄰里爲歔欷。", "倏然叩予門，殷勤謝銘誌。", "袖攜一幅圖，離坎備形勢。", "明堂正丘穴，松檟列新翠。", "身雖離冢旁，披圖即流涕。", "拏舟遽言别，諱曰仲春至。", "酌水採嘉蔬，藉草具嚴祭。", "又言廣栽植，薄取歲時利。", "事死如事生，終焉達斯志。", "儒者似君稀，况復褐冠類。", "誰爲孝子傳，吾詩信無僞。"]'),
('d1740728-1938-4cb6-abca-db7de29adc47','送胡推官赴無錫丞','郭祥正','宋','宋诗','song-poetry','','[]','愛山不離山，君來訪山間。',120,'全唐诗/poet.song.42000.json','["愛山不離山，君來訪山間。", "山間只欠水，聽君語潺潺。", "滋我山色秀，洗我塵心煩。", "如何遽言别，鸞驂欲翩翻。", "試才得佳邑，割雞鳴刀鐶。", "雙親尚未老，伯氏趨朝班。", "藍田玉一雙，浮出濡須灣。", "天作王者瑞，寧獨名鄉關。", "自憐困已甚，風流邈難攀。", "新詩倘可寄，秋雁無空還。"]'),
('96b20d19-afc5-410b-b0e7-ab26f7bdd193','送胡與幾被召赴闕','郭祥正','宋','宋诗','song-poetry','','[]','嗟我老已疲，掛冠歸舊廬。',240,'全唐诗/poet.song.43000.json','["嗟我老已疲，掛冠歸舊廬。", "素乏二頃田，無可把犁鋤。", "窮年小山下，獨伴千卷書。", "作止隨古人，襟懷稍欣如。", "又無樽中酒，能延故人車。", "感君數相過，氣豁眉宇疏。", "天馬出月窟，回薄萬里餘。", "其才無不宜，祿仕猶拘拘。", "忽聞明廷詔，一節馳輕輿。", "往必陟臺省，公言壯皇圖。", "潛心救世弊，肯意爲身謨。", "法密吏愈偷，食衆財益虚。", "末大本漸弱，豈在專防胡。", "指瑕一二人，此事尤可吁。", "細碎何足論，綱舉網不踰。", "譬彼脉已病，其身尚膏腴。", "要當速內究，珍丸應時須。", "良醫望數公，潤澤回焦枯。", "願如范文正，挺持真丈夫。", "老死見太平，委棄甘路衢。"]'),
('3c1e3be4-ff87-4559-9fd1-955912c2d40b','送馬東玉朝散還朝','郭祥正','宋','宋诗','song-poetry','','[]','秋空若明鏡，雲物瑩可數。',216,'全唐诗/poet.song.43000.json','["秋空若明鏡，雲物瑩可數。", "臨高送遠發，况復瞰牛渚。", "崔嵬水帝宫，半出燃犀浦。", "橋基插波瀾，王氣逐龍虎。", "歸艎豈能留，兩漿幾欲舞。", "重光瞻舜日，羣材入天罟。", "聃聃馬東玉，松柏耐寒暑。", "五載佐吾邦，大匠善規矩。", "仁民而愛物，巨細各有補。", "宴閒集賓朋，風流照樽俎。", "能詩又敏速，往往造險語。", "交章久薦達，名聲動寰宇。", "胸中蟠虹蜺，行矣須一吐。", "伊予百無堪，投老尚好古。", "垂竿魚未食，茹蘗口忘苦。", "唯君最相知，稱謂等鮑庾。", "君歸我何適，形影守溪滸。", "時寄一行書，焦枯望霖雨。"]'),
('43c5e372-01d4-45ec-bec6-2e08f1179085','謝涇川宋宰惠近詩','郭祥正','宋','宋诗','song-poetry','','[]','不到涇上邑，倏忽二十載。',204,'全唐诗/poet.song.43000.json','["不到涇上邑，倏忽二十載。", "環山敞樓閣，金碧想未改。", "長溪拖翠玉，洗月發光彩。", "秋聲咽松杉，夜氣馥蘭茝。", "白鳥自成羣，黄猿行作隊。", "仙人控鯉去，巖下遺跡在。", "猶疑深雲中，彈琴尚相待。", "唐儒工翰墨，石壁露璀璨。", "意有神明憐，塵蘚不得浼。", "地勝來俊哲，宋子今出宰。", "公餘綴吟筆，爛漫排珠琲。", "又如崆峒兵，百萬森甲鎧。", "寄我數十篇，翛然起沉痗。", "胸中强搜抉，舊學久荒餒。", "欲追天馬蹤，蹇蹶竟難逮。", "撫卷懷昔遊，魂魄飛𩅝靉。", "何當裂雲牋，看君吐江海。"]'),
('36175346-625f-473a-9485-93b2ac12ccfa','寄杭州天竺辨才大師','郭祥正','宋','宋诗','song-poetry','','[]','我聞辨才師，解空稱第一。',120,'全唐诗/poet.song.43000.json','["我聞辨才師，解空稱第一。", "病子得摩頂，其疾頓若失。", "救物運真悲，了心非幻術。", "聲名動寰宇，退身性愈密。", "峨峨龍井峰，篁竹不透日。", "終朝無來賓，笻枝自横膝。", "此道何寥寥，差肩佛摩詰。", "無生無不生，一以貫禪律。", "安得兩羽翰，歸飛參丈室。", "稽首慕高風，天地相終畢。"]'),
('7634ad42-c5ee-430e-8f2a-a8521e8da6b6','送外甥法真一師','郭祥正','宋','宋诗','song-poetry','','[]','仕祿不及養，勇往學金仙。',168,'全唐诗/poet.song.43000.json','["仕祿不及養，勇往學金仙。", "棄家如脱屣，壞衣披稻田。", "見汝若見母，令我涕泗漣。", "我方齓齠時，巨獄遭摧顛。", "汝母挈我往，西江赴臨川。", "愛育比其兒，衣食無頗偏。", "追隨二三載，思親我言還。", "是時汝未産，顧今三十年。", "汝壯我已老，死者歸重泉。", "悠悠記昨夢，幻妄真可憐。", "汝能逃世累，趣尚固已賢。", "京華勿久棲，還當擇深淵。", "返窮生死本，勿爲言句纒。", "拭我衣上淚，贈汝金石篇。"]'),
('5628b6ab-1317-4710-820b-18b44ebf2691','送甥沈濟秀才下第南歸','郭祥正','宋','宋诗','song-poetry','','[]','炎風吹黄塵，去興不可止。',36,'全唐诗/poet.song.43000.json','["炎風吹黄塵，去興不可止。", "丈夫固有命，得失致悲喜。", "何當永相將，錫山酌泉水。"]'),
('5e14a9e7-b65b-4532-b1c7-1a8e62c9dba0','送胡子企大夫還臺','郭祥正','宋','宋诗','song-poetry','','[]','聯鑣出梅山，倐然二十載。',120,'全唐诗/poet.song.43000.json','["聯鑣出梅山，倐然二十載。", "君嘗佐天府，我遂泛雲海。", "音書魚雁絕，夢寐想風采。", "營車忽來過，笑語珠璀璀。", "故交悉相忘，而君獨不改。", "天王堯舜資，化柄付良宰。", "網羅收鴻鵠，臺閣茂蘭茝。", "君歸必殊顯，發策救民痗。", "形容入凌烟，丹青永無浼。", "使我觀太平，白首甘凍餒。"]'),
('2e57db20-0fb2-4dff-a3ae-10e83a383029','投宿繁昌徐氏水閣','郭祥正','宋','宋诗','song-poetry','','[]','東池種蓮子，西池養肥魚。',144,'全唐诗/poet.song.43000.json','["東池種蓮子，西池養肥魚。", "盈缸釀美酒，滿盤具新蔬。", "客來徑一醉，疑是桃源圖。", "此事未足議，弟兄皆業儒。", "大弟已登科，高名動鄉閭。", "季弟復連薦，豹變應時須。", "長兄恬自養，雲卧隨卷舒。", "物至我則應，隱德良有餘。", "客有醉吟叟，六月騎蹇驢。", "避暑尋名山，遂登君子居。", "飲弄池上月，一宿能清虚。", "相看不相厭，欲去且踟蹰。"]'),
('76ca7965-b78c-41aa-86a4-71f8b4e70aa4','和姜伯輝見贈醉吟畫詩','郭祥正','宋','宋诗','song-poetry','','[]','蒼崖一萬丈，中寫白玉泉。',144,'全唐诗/poet.song.43000.json','["蒼崖一萬丈，中寫白玉泉。", "飛鳥度不得，而我長攀緣。", "洗盡心地垢，吟成元化篇。", "更復有何物，一樽當我前。", "忽逢姜伯輝，爽量涵水淵。", "開談了無跡，所得全於天。", "便欲脱青衫，泛我江東船。", "結交要終始，相忘復頽然。", "徑呼妙手畫，秋江霜景全。", "冰輪正卓午，照影無頗偏。", "誰能騎蹇驢，世路空流連。", "咄哉可以往，揮手從飛仙。"]'),
('032b4e1e-86e3-430d-8031-d816d675765b','觀唐植夫所藏古墨','郭祥正','宋','宋诗','song-poetry','','[]','黑龍蟠黑雲，久蟄黄金闕。',180,'全唐诗/poet.song.43000.json','["黑龍蟠黑雲，久蟄黄金闕。", "緣何落人間，數餅若古月。", "蝦蟆不敢蝕，利刀豈能截。", "温潤比方玉，芬香麝臍裂。", "乃知廷珪名，桓桓久不滅。", "植夫名世俊，所蓄號奇絕。", "護以紫錦囊，篋之復扃鐍。", "渺思五季亂，江南頗偷逸。", "三主皆能書，撥鐙聳痩骨。", "一朝歸大明，流散餘故物。", "金華座右銘，清凉自題佛。", "二寶藏予家，時時一披拂。", "及觀植夫墨，清風愈飄忽。", "異國想塵勞，精靈豈沉没。", "聊爲識古篇，分手各蕭瑟。"]'),
('0262e242-4ed0-4405-b8d8-6ed4d08c4038','酬富仲容朝散見贈因以送之','郭祥正','宋','宋诗','song-poetry','','[]','牧之吟齊天，太白詠秋浦。',192,'全唐诗/poet.song.43000.json','["牧之吟齊天，太白詠秋浦。", "至今三百年，光焰不埋土。", "我朝文愈盛，往往出前古。", "仲容生相門，璨然鳳凰羽。", "作鎮薄書閒，盈編金玉吐。", "牧之何足論，白也真爾汝。", "一朝解符歸，暫泊采江滸。", "肩輿過蓬蓽，高談辰及午。", "洗我塵坌聽，不覺歡欲舞。", "又如熟黄粱，連餐釋饑苦。", "昔聞鄭國公，片言戢狂虜。", "廟食配神宗，昭昭仲山甫。", "今逢族弟賢，家法中規矩。", "郎省寧淹回，往自結明主。", "不惟唐蕭家，繼踵登相府。", "請驅千里雲，時作三日雨。"]'),
('4a6a8854-d5e2-485b-a92a-edcd924b4e37','宿鍾山贈泉禪師','郭祥正','宋','宋诗','song-poetry','','[]','夜半松柏響，繞巖鸞鳳音。',120,'全唐诗/poet.song.43000.json','["夜半松柏響，繞巖鸞鳳音。", "披衣送遐盼，明月方庭深。", "樓殿遍瑶層，寶塔樓中岑。", "定分付赤刀，世故仍癡淫。", "六朝遺破塚，四聖崇幽林。", "香廚飯玉粒，千歲聞于今。", "况逢大道師，妙傳諸佛心。", "其徒五百人，坐忘靜沈沈。", "寶光泳琉璃，永無塵垢侵。", "何以明歸仰，頓首興微吟。"]'),
('d98b7054-dbc2-4b4d-8fb1-89f07062c7cc','送倪敦復往池州决獄','郭祥正','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','忽領外臺檄，離家不辭艱。',72,'全唐诗/poet.song.43000.json','["忽領外臺檄，離家不辭艱。", "破雪陟遠道，侵星出重關。", "提刀聊四顧，决獄談笑間。", "旦經五峰寺，遂發九華山。", "朗飲雲泉秀，妙依松石閑。", "琳瑯如得句，先寄南風還。"]'),
('c063453d-ad35-4595-94a2-9fc6c58bbf74','送敦復至觀音寺再用前韻祝别','郭祥正','宋','宋诗','song-poetry','','[]','太道既如砥，安輿寧險艱。',72,'全唐诗/poet.song.43000.json','["太道既如砥，安輿寧險艱。", "通溝水決決，出林鳥關關。", "紫詔下天外，黄氣生眉間。", "歸當趨玉陛，豈容眷名山。", "接物齊彼分，存誠肅吾閑。", "我心如路草，願君與春還。"]'),
('b67b9365-6c93-4423-99fe-9db821d3cd88','陶然軒呈孔掾','郭祥正','宋','宋诗','song-poetry','','[]','我醉不在酒，心常醉於天。',120,'全唐诗/poet.song.43000.json','["我醉不在酒，心常醉於天。", "出處無固必，四時任陶然。", "世網誰拘拘，冥鴻自翩翩。", "隱凡樂吾樂，陶然名此軒。", "採掇富菊杞，芬香籍蘭荃。", "啼鳥助春喜，相呼語涓涓。", "好風集清微，時寫朱絲弦。", "秋月瑩池上，臘雪堆簷前。", "客来亦把酒，客去醉還眠。", "爲君發短調，意將千載傳。"]'),
('297416e4-49f8-47c4-bd7e-5fd988af55c4','安中尚書見招同諸公登雨華臺','郭祥正','宋','宋诗','song-poetry','','[]','城南五里近，驅車稍停休。',288,'全唐诗/poet.song.43000.json','["城南五里近，驅車稍停休。", "層臺臨古刹，欣陪清淨遊。", "憑高送遠目，考古思名流。", "更讀琳瑯篇，叙事何其周。", "尸黎與法雲，接跡居巖幽。", "趣將金仙諧，行匪邪徑由。", "至今手植松，千丈騰龍虬。", "悟發特異衆，妙齡已依劉。", "天華無根蒂，應講來飛浮。", "帝釋昔舉手，此理誰可侔。", "邇來表前蹤，新亭壓鼇頭。", "空渚栖古月，大江浴清秋。", "曠懷出十地，壯氣横九州。", "三山連天門，水府卧金牛。", "故國羅綺滅，深宫榛莽留。", "興亡千歲間，愁緒如繰抽。", "惟餘北嶺雲，無心自悠悠。", "高鴻正飛冥，網羅安得收。", "公等真丈夫，問學皆淵丘。", "不應持使旄，歸合登瀛洲。", "桓桓鼎鼐司，落落金馬儔。", "君臣若堯舜，明良互賡酬。", "胡爲慕瞿聃，玄微解而優。", "願舒三日霖，慰此旱歲求。"]'),
('fabdc654-d2c2-4352-8643-bc7535eb4003','送李嘉甫朝散還臺','郭祥正','宋','宋诗','song-poetry','','[]','春風連作惡，吹雪深尺五。',168,'全唐诗/poet.song.43000.json','["春風連作惡，吹雪深尺五。", "元宵無燈火，閉關與誰語。", "忽聞營從過，傾蓋挹眉宇。", "相親如故人，坐久加循撫。", "蓬茅只數間，餘無一丘土。", "半俸足以飽，未嘗詣州府。", "白雲寓遠目，清溪照靈腑。", "趨閒已忘憂，浩歌唯汲古。", "明公志方壯，富貴何可取。", "高才孰能當，如羆亦如虎。", "致君爲唐虞，澤民作霖雨。", "功名垂乾坤，兒孫列簪組。", "於予一何遼，而能强相與。", "聊書送行章，欲以明出處。"]'),
('0bd1875f-cfc9-40d9-bbcf-a0d264dd763e','前春雪','郭祥正','宋','宋诗','song-poetry','','[]','玄冥奪春令，連旬雪塞屋。',180,'全唐诗/poet.song.43000.json','["玄冥奪春令，連旬雪塞屋。", "嗷嗷何物聲，云是饑民哭。", "來請義倉米，奈何久空腹。", "寒威如戈矛，命盡須臾速。", "憶昨去年水，雲濤卷平陸。", "高村既無麥，低田又無穀。", "民間已乏食，租稅仍未足。", "縣令欲逃責，催科峻鞭朴。", "嗟哉吾邦民，何以保骨肉。", "昂頭訴蒼蒼，和氣待春育。", "春工本好生，此雪無乃酷。", "誰家敞園館，草樹變瓊玉。", "美人學回風，歡笑列燈燭。", "不如萬戶寒，唯憂五更促。", "世無採詩官，悲歌寄鴻鵠。"]'),
('ea8ed35c-04cf-4b45-88df-ee9d0c35998d','後春雪','郭祥正','宋','宋诗','song-poetry','','[]','前雪深尺五，後雪深五尺。',168,'全唐诗/poet.song.43000.json','["前雪深尺五，後雪深五尺。", "動地北風惡，連天凍雲塞。", "通逵絕行人，萬物同一色。", "燭龍爪生冰，陽烏觜插翼。", "牛羊何足論，虎豹餓無食。", "此雪昔未有，父老均歎息。", "况當長養時，玄冥翻怒赫。", "我欲請雷車，夜半轟霹靂。", "斗杓斡春陽，和氣隨甲拆。", "溶爲大田水，青發龍頭麥。", "南民少蘇醒，白骨免堆積。", "朝廷方體仁，乾坤應合德。", "有酒不敢飲，獨樂神所責。", "悲歌閉空屋，寫慰同心客。"]'),
('a03a1333-c577-4b64-82b1-939d18cfb2e3','送黄吉老察院','郭祥正','宋','宋诗','song-poetry','','[]','積學久未遇，忠言今可施。',240,'全唐诗/poet.song.43000.json','["積學久未遇，忠言今可施。", "請君略細故，吐出胸中奇。", "悉救當世弊，自結明主知。", "不唯振憲綱，進當司鼎彛。", "用廣財已乏，官冗人愈卑。", "政寛法不舉，將偄邊無威。", "家家侈聲樂，淳源變澆漓。", "土木絢金碧，佛仙競新祠。", "此乃腹心疾，豈止爲瘡痍。", "言者曾未及，雖言多恚私。", "苟非大奸邪，惡足求瑕玼。", "舉朝無完人，何以禆明時。", "嘗讀喜似篇，左右皆宜之。", "乃知荆山璧，天地終不道。", "去堊無變容，誠明達神祗。", "我方卧巖谷，所友鹿與麋。", "感君營從過，枯木春風吹。", "又如得黄粱，慰我久苦饑。", "承詔不敢留，歡言遽暌違。", "殷勤何以報，報君以蕪辭。"]'),
('0b9a8562-5a96-4e00-973d-189c64f0903f','和敦復留題池州弄水序','郭祥正','宋','宋诗','song-poetry','','[]','我寄江南隱，數爲弄水遊。',168,'全唐诗/poet.song.43000.json','["我寄江南隱，數爲弄水遊。", "讀君弄水篇，感慨攀巢由。", "赤脚踏雲雨，投竿翫汀洲。", "鷗鳥不見猜，飛舞相應酬。", "誰傾百斛珠，跳躑無復收。", "一發海客秘，爛副貧家求。", "李杜縮光焰，王謝慚風流。", "開卷起予興，飄欲乘桴浮。", "如觀秋浦圖，晚景入兩眸。", "愛之不能捨，饑魚適吞鈎。", "嘗置几案間，出没窺巖幽。", "一别幾何時，歲月已十周。", "跡滯若匣劍，繡澀不可抽。", "何當隨君車，吟哦與君侔。"]'),
('8c700899-6112-4f0e-9061-1258eb78b056','謝胡丞寄錫泉十瓶','郭祥正','宋','宋诗','song-poetry','','[]','怜我酷嗜茗，遠分名山泉。',120,'全唐诗/poet.song.43000.json','["怜我酷嗜茗，遠分名山泉。", "兹山固多錫，泉味甘尤偏。", "幸遇佳客便，十缸附輕船。", "開缸潄清泠，不待同茗煎。", "想君民事休，時時造泉邊。", "入碾龍鳳碎，浮甌乳花圓。", "一啜未能止，七盃誇玉川。", "兩腋生清風，飛逐蓬莱仙。", "江心與谷簾，較之孰爲妍。", "欲報吾子惠，仍思陸生賢。"]'),
('512e6365-8c44-4a33-93dc-5c161a1800af','謝魏戶曹惠酒','郭祥正','宋','宋诗','song-poetry','','[]','官醪不許買，兵醖未嘗得。',96,'全唐诗/poet.song.43000.json','["官醪不許買，兵醖未嘗得。", "愁殺避俗翁，甘爲獨醒客。", "緣何魏夫子，心仁生憫惻。", "雙壺輒分送，涸鱗被甘澤。", "鐺杓再施設，併欲醉君德。", "百川供長虹，叱吒天地窄。", "儘從秋水來，大笑問河伯。", "胡爲辨牛馬，灔灔浮月魄。"]'),
('3857da70-311b-45f1-bc91-8f85dbf82b9f','川漲','郭祥正','宋','宋诗','song-poetry','','[]','朱夏久不雨，川源條然漲。',144,'全唐诗/poet.song.43000.json','["朱夏久不雨，川源條然漲。", "三潮渺相連，狂風蹴高浪。", "蛟龍遞出没，魚鼈隨浩蕩。", "羣山悄低徊，阡陌失背向。", "嗟嗟圩中田，一埂安可障。", "去年已大潦，十戶九凋喪。", "幸頼官廩實，囂囂命所仰。", "官廩今已空，農事未敢望。", "理水竟無術，祈禱俟靈貺。", "退寸復進尺，潮勢頗難量。", "彼蒼罪斯民，殺戮不以杖。", "令人思禹功，巍巍百王上。"]'),
('da9b9eb6-378f-45d5-9b37-acdaab282e3c','答魏掾招飲','郭祥正','宋','宋诗','song-poetry','','[]','我欲招魏子，小山嘗白醪。',108,'全唐诗/poet.song.43000.json','["我欲招魏子，小山嘗白醪。", "月華雖未滿，已覺秋風高。", "何物佑樽酌，肥鱸併蟹螯。", "一飲洗百憂，軒冕稍可逃。", "此語未及發，辱君先見要。", "乃知志趣同，盍簪皆俊僚。", "亦應唤舞娥，紅雲欲飛飄。", "不然避謗傷，談話傾漁樵。", "期歸一酩酊，世事如芭蕉。"]'),
('46bd285e-8046-4cfc-a426-0403d613fc1e','酬彭法曹留題小山用次來韵','郭祥正','宋','宋诗','song-poetry','','[]','讀君小山詩，語勢欲飛舞。',72,'全唐诗/poet.song.43000.json','["讀君小山詩，語勢欲飛舞。", "乃知甘與賈，年少心則古。", "又如東方生，用之必爲虎。", "予方坐空谷，屏息避煩暑。", "開緘揖清風，不覺生毛羽。", "攜之出人間，瑶池贈王母。"]'),
('f17b7210-13c0-4a1c-874d-325bc9cd94f3','送黄彦發還臺','郭祥正','宋','宋诗','song-poetry','','[]','予方寓小山，感君忽相過。',96,'全唐诗/poet.song.43000.json','["予方寓小山，感君忽相過。", "風標奪瑩玉，氣語排懸河。", "君初佩金印，治蠻真有科。", "彼侮我即斬，威行濟之和。", "使知朝廷尊，帖帖無愆訛。", "聖主方求才，四海張網羅。", "麒麟并鳳凰，所獲寧爲多。", "如君必見取，爲君吟菁莪。"]'),
('5ccbf114-3bf5-4d65-a1af-b0a8e75121e5','酬陳掾留題小山二首用次來韵  其一','郭祥正','宋','宋诗','song-poetry','','[]','我愛小山石，翩翩鸞鳳姿。',72,'全唐诗/poet.song.43000.json','["我愛小山石，翩翩鸞鳳姿。", "胡爲不飛去，似與幽人期。", "志澤未及物，收身聊自嬉。", "不教三徑荒，寧歌吾意詞。", "舊交安在哉，歲晏逢子知。", "殷勤結惠好，琅玕分一枝。"]'),
('4906ef8c-8741-4a0e-a602-758f77662c0a','酬陳掾留題小山二首用次來韵  其二','郭祥正','宋','宋诗','song-poetry','','[]','兹山何亭亭，鬰有高人姿。',72,'全唐诗/poet.song.43000.json','["兹山何亭亭，鬰有高人姿。", "朝容白雲過，夜與明月期。", "幽蘭翠碧秀，好鳥鳴聲嬉。", "更逢佳客來，惠好留美詞。", "遂令一丘樂，能垂千載知。", "殷勤謝陳子，蒹葭倚瓊枝。"]'),
('1dc239b5-edc0-4457-a120-f8edbc8e5449','和陳掾效陶齋','郭祥正','宋','宋诗','song-poetry','','[]','君欲效陶潛，超然異今趣。',84,'全唐诗/poet.song.43000.json','["君欲效陶潛，超然異今趣。", "開齋即吾廬，欣欣同所慕。", "潛魚不羣游，栖鳥不返顧。", "無意亦無我，何思復何慮。", "遂趨羲皇上，日息自休裕。", "百年能幾何，不知歲云暮。", "終當隨白雲，悠悠此山去。"]'),
('89919895-abbe-4862-916c-d65e8413da26','喜鍾山泉禪師見過','郭祥正','宋','宋诗','song-poetry','','[]','聞師飛錫来，七日遠葷飲。',48,'全唐诗/poet.song.43000.json','["聞師飛錫来，七日遠葷飲。", "欣諧清淨談，中夜未能寢。", "師提寶公刀，爲我裁古錦。", "言歸不須忙，溪上冰雪凛。"]'),
('8ab0083f-04b7-4ef3-9f2a-005174dcb1ac','送魏掾赴調','郭祥正','宋','宋诗','song-poetry','','[]','齠齓已承祿，資賦况超邁。',96,'全唐诗/poet.song.43000.json','["齠齓已承祿，資賦况超邁。", "三年瑩無玼，一日忻有代。", "芳洲清風微，夕浦寒烟䨴。", "翩翩莫能留，逡巡遠山外。", "浮生離合際，志士懷耿介。", "渺思歲月往，俯視天壤隘。", "人驚甘羅少，帝憶賈生對。", "竟言若爲期，充實光輝大。"]'),
('21bd98ec-5287-4271-b7cc-9e44564fd07e','送喻明仲朝請還臺','郭祥正','宋','宋诗','song-poetry','','[]','出馳使者星，歲月一何久。',96,'全唐诗/poet.song.43000.json','["出馳使者星，歲月一何久。", "巨航始北歸，華髪已盈首。", "讀書過五車，滿腹藏瓊玖。", "行行赴金闕，朝帝見太母。", "乾坤運元氣，斟酌須北斗。", "願如范文正，上疏發纊黈。", "明明納忠諫，聖作古無有。", "道行且寄書，慰我窮老叟。"]'),
('6945802d-8d34-4448-9b84-68e569d4e714','送倪敦復朝奉還臺','郭祥正','宋','宋诗','song-poetry','','[]','有力乃致遠，中道力不任。',144,'全唐诗/poet.song.43000.json','["有力乃致遠，中道力不任。", "言歸閉空屋，敢復求知音。", "君來監郡務，猥巷一見臨。", "稱褒借陽春，片礫成寸金。", "觴酌每追隨，嘯詠舒悰襟。", "不覺三歲過，啟櫂離江南。", "君懷有玉寶，未嘗獻于今。", "于今不往獻，千歲惜湮沈。", "流景良可悲，鬚雪來侵侵。", "前途漸就窄，後會安可尋。", "屋梁見落月，殷憂存我心。", "猶期澤萬物，霈然作商霖。"]'),
('19302300-25e4-4a96-a7d7-a79f7c15fa4d','邀敦復小酌爲别','郭祥正','宋','宋诗','song-poetry','','[]','三年同賞梅，梅花爛晴雪。',72,'全唐诗/poet.song.43000.json','["三年同賞梅，梅花爛晴雪。", "一日言北歸，梅黄雨初歇。", "誰將金彈丸，綴在綠枝上。", "結實勝開花，邀君更同賞。", "食梅齒牙軟，銜盃奈離憂。", "過江桃李熟，回首憶梅不。"]'),
('22dcca31-e225-4f89-b87d-feaa91473087','送楊縝供備還京','郭祥正','宋','宋诗','song-poetry','','[]','伯玉弘農後，軒軒真丈夫。',156,'全唐诗/poet.song.43000.json','["伯玉弘農後，軒軒真丈夫。", "首雖峨武弁，滿腹藏詩書。", "三年監郡兵，一日云解符。", "考之閭井言，公廉卒如初。", "未嘗害一物，縱捨乃有餘。", "我方卧空屋，袒跣與世疏。", "感君數相過，晨坐定及晡。", "新詩并美酒，問遺無時無。", "老境重可惜，遠别復何如。", "羨君五福全，客官奚拘拘。", "子孫俱祿仕，京城富園閭。", "精神趁强健，優游早懸車。", "祝君可以歸，爲君吟歸歟。"]'),
('d2309bb3-fe8f-41d1-8484-e688f23341c9','聽惠守錢承議談羅浮山因以贈之','郭祥正','宋','宋诗','song-poetry','','[]','久憶觀滄海，喜君語羅浮。',192,'全唐诗/poet.song.43000.json','["久憶觀滄海，喜君語羅浮。", "浮從會稽來，與羅相獻酬。", "誰欲通兩山，鐵橋跨山頭。", "笙簫響瑶臺，佛仙棲石樓。", "靈光燭商舶，七星被林幽。", "飛泉難悉名，異草香氣柔。", "危峰聚白鹿，深塢眠青牛。", "葛洪安期生，遺蹤尚綢繆。", "攀巔瞰海水，湛碧纔一甌。", "不見波濤翻，颶風駕龍虬。", "又云朱明天，飄然落遐陬。", "方廣吞五嶽，盤紆臨十洲。", "不得預封禪，自起烟雲羞。", "此理固莫測，勝境輸君遊。", "君語洗我耳，我詩瑩君眸。", "羅浮杳何許，爲我商聲謳。"]'),
('7408ac4f-706d-42b1-8798-ae1d3ad0ba9f','送錢節七承議還臺','郭祥正','宋','宋诗','song-poetry','','[]','平昔未識面，已景才業殊。',120,'全唐诗/poet.song.43000.json','["平昔未識面，已景才業殊。", "及來公詡家，把酒情忻如。", "分攜八换歲，益聞峻名譽。", "我方姑熟隱，君解惠國符。", "鷁舟始云泊，駕言過茅廬。", "傾談洗塵聽，積憂令我舒。", "鳳窼無凡毛，龍窟多美珠。", "朝家正清明，往矣涉亨衢。", "澤民冀姚宋，致主優唐虞。", "史筆採循吏，非君復誰書。"]'),
('ef18e05e-9cbd-4a39-a441-00c86c291091','自釋二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','去日不可追，来日已無多。',84,'全唐诗/poet.song.43000.json','["去日不可追，来日已無多。", "衰頽復自念，遷謝當奈何。", "賢達并賤愚，百歲同消磨。", "不如泳觴酌，徘徊眄庭柯。", "流翠自成幄，好風時經過。", "憎愛理兼忘，虛淡神所和。", "運盡即隨盡，葬骨南山陂。"]'),
('5fcd41e9-78c6-48ca-aed6-13be821f1de7','自釋二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','遭時如堯舜，擊壤歡且歌。',60,'全唐诗/poet.song.43000.json','["遭時如堯舜，擊壤歡且歌。", "歸田尚叨祿，天寵固已多。", "敢復邀長年，寓景隨流波。", "有酒即觴酌，風日眷清和。", "俯悲秦晉士，含饑避干戈。"]'),
('1d9d312f-0c34-4893-8c32-00f32c2f2d74','懷友二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','夕陽在窻戶，凉氣何處來。',60,'全唐诗/poet.song.43000.json','["夕陽在窻戶，凉氣何處來。", "微風泛庭柯，蕭蕭歷空階。", "抱琴一寫之，冰霜濺孤懷。", "但惜對樽酌，而無良友偕。", "聊將幽獨思，滔滔寄長淮。"]'),
('a247673a-4795-4741-b56c-177d7e9e5727','懷友二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','晚坐庭樹下，凉颸經我懷。',60,'全唐诗/poet.song.43000.json','["晚坐庭樹下，凉颸經我懷。", "亦有樽中物，佳人殊未來。", "佳人隔重城，誰復爲之儕。", "瞻雲雲行天，步月月滿階。", "想聞誦聲作，崩騰瀉江淮。"]'),
('7877ccc8-5828-4358-bfc6-e494decaf5b3','七月八日要閻公達承議晚酌二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','河橋散靈鵲，曜景逾佳期。',60,'全唐诗/poet.song.43000.json','["河橋散靈鵲，曜景逾佳期。", "池華延舒月，尚可傾一巵。", "欲以要良賓，秋事言凄其。", "歲往豈再得，綠髮含霜滋。", "寓意不在飲，營駕君莫辭。"]'),
('049552dd-ecbb-4f2f-abc2-ac4d3ddf2cc8','七月八日要閻公達承議晚酌二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','營駕君莫辭，寓飲不在酒。',72,'全唐诗/poet.song.43000.json','["營駕君莫辭，寓飲不在酒。", "得酒亦可喜，話情庶延久。", "鷺白不翳塵，山光含美璞。", "霞綺映池葩，條蟬嘶露渥。", "時平無横愁，身退兹餘裕。", "彈琴來薫風，高軒良可佇。"]'),
('02d76f78-2a91-45cb-abf2-22d0174359d5','嚴氏西齋','郭祥正','宋','宋诗','song-poetry','','[]','立屋聚羣經，執經授諸兒。',108,'全唐诗/poet.song.43000.json','["立屋聚羣經，執經授諸兒。", "趨善務深畜，言行蹈前規。", "譬欲種嘉禾，春膏力鋤犁。", "一朝秀而實，刈熟當如坻。", "遂爲道德飽，用濟斯民饑。", "庭木豈不美，凉陰奉遨嬉。", "池水豈不深，濯熱臨清漪。", "作止既可樂，左右皆宜之。", "瑶琴誰爲彈，倚聲奏吾詩。"]'),
('0655c842-7f2b-4252-9da1-4f401922aa45','志士吟二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','羣材欣向榮，志士寂無託。',60,'全唐诗/poet.song.43000.json','["羣材欣向榮，志士寂無託。", "獨鳥千里飛，天末孤雲泊。", "越女殊西子，秦聲異别鶴。", "守貞不辭貧，怡怡內常樂。", "高歌戛金玉，其聲震寥廓。"]'),
('ab670683-e952-46d1-921b-c98f64dc310d','志士吟二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','歲華忽已晚，志士將奈何。',60,'全唐诗/poet.song.43000.json','["歲華忽已晚，志士將奈何。", "摧車眷前修，停澤無餘波。", "知命守窮賤，脱屣南山阿。", "出從麋鹿遊，坐與猿鳥歌。", "采菊復采薇，聊以養天和。"]'),
('8df03e65-c467-402e-a266-c6f08ef848ec','聞砧','郭祥正','宋','宋诗','song-poetry','','[]','天潢轉斜白，庭菊汎團露。',72,'全唐诗/poet.song.43000.json','["天潢轉斜白，庭菊汎團露。", "紈扇辭玉纖，雲幄含幽素。", "濕螢遞疏牖，寒螿鳴外戶。", "南鄰發砧響，凉夕敢虚度。", "不作舞衣裳，爲君理繒絮。", "邊磧多苦寒，先秋寄征戍。"]'),
('40998390-0dce-44ff-8f74-f9521f7eb771','秋扇','郭祥正','宋','宋诗','song-poetry','','[]','輕素裁團扇，投君掌握中。',72,'全唐诗/poet.song.43000.json','["輕素裁團扇，投君掌握中。", "爲君却煩暑，動搖挹凉風。", "一朝霜飈至，羅幃衾被重。", "辭君且屏跡，棄置隨斷蓬。", "物理古如此，用捨安可窮。", "願君千萬壽，執熱還相逢。"]'),
('b306f6f9-4ce3-40b1-b101-4b746238a35d','庭竹','郭祥正','宋','宋诗','song-poetry','','[]','眷此庭中竹，羅生橫十尋。',72,'全唐诗/poet.song.43000.json','["眷此庭中竹，羅生橫十尋。", "疏疏挺高節，密密敷清陰。", "好風每相過，流塵詎能侵。", "其下無蔓草，其傍遠脩林。", "結根自得所，非高亦非深。", "誰復採笙簫，玉宇思和音。"]'),
('d108e971-621e-4014-875b-17f8a1898e76','賞蓮','郭祥正','宋','宋诗','song-poetry','','[]','濯濯水中華，香艷勝蘋藻。',120,'全唐诗/poet.song.43000.json','["濯濯水中華，香艷勝蘋藻。", "英英泥中根，絜素常自保。", "房實又堪食，無一不爲好。", "乃知金仙經，譬喻肆論討。", "游宴集賓僚，賞詠固宜早。", "一朝霜飈至，莖葉變枯槁。", "抑亦如佳人，妍媚忽衰老。", "顧眄豈復憐，棄置不足道。", "幽懷向君開，芳樽爲傾倒。", "木末誰能搴，愁烟起孤島。"]'),
('960a486e-44c9-42d2-af64-297e7393f1d6','將至金陵謁曾子開侍郎','郭祥正','宋','宋诗','song-poetry','','[]','秋空久不雨，漠漠風卷沙。',144,'全唐诗/poet.song.43000.json','["秋空久不雨，漠漠風卷沙。", "胡爲起高興，昨夜辭山家。", "明投金陵郭，府觀凌紫霞。", "公解豫章榻，我停銀漢槎。", "一傾别後言，電雹鳴交加。", "借公口中春，發我枝上花。", "又如出地雷，空山走龍蛇。", "公能結明主，我亦思無邪。", "但驚歧路别，進退各有涯。", "浮生能幾時，鬢髮忽已華。", "會合豈易得，兵厨酒仍佳。", "慎勿學謝安，捫涕空慼嗟。"]'),
('3c9d2e52-7b5c-4324-9dc3-a3cac1a553e7','雙泉軒贈太平守梁正叔','郭祥正','宋','宋诗','song-poetry','','[]','開池得雙泉，因泉構華屋。',120,'全唐诗/poet.song.43000.json','["開池得雙泉，因泉構華屋。", "池中種菱荇，池上列花竹。", "與春蘸新紅，遇風搖淨綠。", "輕鷗自飛舞，纖鱗隨出縮。", "操舟往江海，端憂龍蜃觸。", "卷衣入山林，而防虎狼欲。", "豈如一憑欄，俯仰快心目。", "朝吟吟有餘，暮醉醉不足。", "雙泉長涓涓，比公享天祿。", "公歸民懷公，聽我雙泉曲。"]'),
('449e7f86-2be3-4dab-9fd8-62f8bda7f922','徐子美楊君倚李元翰小酌言舊','郭祥正','宋','宋诗','song-poetry','','[]','南方多苦熱，北地尤苦寒。',180,'全唐诗/poet.song.43000.json','["南方多苦熱，北地尤苦寒。", "徐子掾招宜，七載濱夷蠻。", "楊李仕并代，毳裘霜雪殘。", "一朝相續歸，相看涕汍瀾。", "捫涕喚家僮，草草羅杯盤。", "念昔共庠序，垂髫競癡頑。", "及今過六十，各各嗟衰顔。", "光陰信如馳，生死無百年。", "妻兒半凋喪，少喜多憂患。", "吾方慕陶潛，行歌眷南山。", "山氣日夕佳，吾廬未嘗關。", "猿鳥相與居，絲桐時一彈。", "三子方急祿，遑遑未能閒。", "努力佐州縣，須防官長難。", "暫當陪我醉，餘事不足言。"]'),
('8c22a36c-2669-4dbf-8ec5-c3ac7dacfaee','寄題九江陶子駿佚老堂','郭祥正','宋','宋诗','song-poetry','','[]','未老已先佚，構堂名佚老。',96,'全唐诗/poet.song.43000.json','["未老已先佚，構堂名佚老。", "與其寵辱驚，何似歸未早。", "淵明乃吾祖，此道能自保。", "歸來無一事，時時爲酒惱。", "紙帳春氣融，不寐聽春鳥。", "關關枝上語，報我竹間曉。", "我醉未能起，爾音一何好。", "却笑世間人，忘憂種萱草。"]'),
('37f17a5f-932f-44c9-af0f-8ad5f1f6dc95','復雪','郭祥正','宋','宋诗','song-poetry','','[]','連朝雪復雪，吾獨擁紅爐。',96,'全唐诗/poet.song.43000.json','["連朝雪復雪，吾獨擁紅爐。", "樽中亦有酒，不爲饑寒驅。", "目前奚所憂，所憂在村墟。", "去年旱兼水，二稅多逃逋。", "十家九乏食，往往死路衢。", "空山嗥虎豹，深淵卧龍魚。", "飛鳥各斂翼，康莊斷行車。", "倚門獨悲歌，陽氣何時舒。"]'),
('f74aaad5-5af2-480d-8d17-e9461e773dd8','將至壽陽謁朱行中龍圖作','郭祥正','宋','宋诗','song-poetry','','[]','魏臺公送我，春風花落盡。',72,'全唐诗/poet.song.43000.json','["魏臺公送我，春風花落盡。", "壽陽我訪公，蕭蕭朔風緊。", "且復念殘年，鬢髮安得鬒。", "高才久外補，惠愛益不泯。", "聊歌古柏行，歌罷仰天哂。", "長淮白魚肥，冰壺酒堪引。"]'),
('ed8628cb-ee43-4d8f-87ba-1b51c6c23a55','暮春之月謁廬守陳元輿待制作','郭祥正','宋','宋诗','song-poetry','','[]','百年憫秋霜，念念流運歇。',120,'全唐诗/poet.song.43000.json','["百年憫秋霜，念念流運歇。", "一昨辭周行，于今鬢垂雪。", "幽獨誰爲扶，寸心徒自折。", "翻然駕柴車，賓閎重款謁。", "與公論襟期，及此陽春月。", "英英欄中花，滋露正妍發。", "濁濁瓮中醪，浮醅想芬冽。", "朝廷用直道，郡邑罕所闕。", "嬿婉我之友，皎若環與玦。", "良辰不同樂，衰暮空惜别。"]'),
('029c5b28-e9aa-4777-bd41-15e92a7310eb','廬陵樂府十首  其一','郭祥正','宋','宋诗','song-poetry','','[]','妾擡纖纖手，一拂白玉琴。',72,'全唐诗/poet.song.43000.json','["妾擡纖纖手，一拂白玉琴。", "琴聲寫三疊，寄妾萬里心。", "朱弦斷可續，妾心常不足。", "纔驚楓葉丹，又見楊枝綠。", "望君君未到，妾貌寧長好。", "雲鬢懶重梳，從敎似秋草。"]'),
('1a54c588-03d5-4c57-9bca-e464da7f626e','廬陵樂府十首  其二','郭祥正','宋','宋诗','song-poetry','','[]','鴻雁殊未來，思君一彈琴。',72,'全唐诗/poet.song.43000.json','["鴻雁殊未來，思君一彈琴。", "泠泠别鶴語，折盡幽蘭心。", "蛛絲漫相續，難繫驊騮足。", "白日無時停，雲鬢寧長綠。", "年華要不老，不若丹青好。", "對之雖無言，猶勝種萱草。"]'),
('3f85cbb5-f7c3-4af0-b808-2344e86d9b9f','廬陵樂府十首  其三','郭祥正','宋','宋诗','song-poetry','','[]','與子初執手，效彼瑟與琴。',72,'全唐诗/poet.song.43000.json','["與子初執手，效彼瑟與琴。", "子去既不返，誰復知我心。", "寶刀能切玉，願斷金烏足。", "留住枝上春，花紅葉長綠。", "懊惱復懊惱，憔悴變妍好。", "不見庭中蘭，埋没隨百草。"]'),
('dcd928de-8aff-4c1e-a73f-af88e0b1fe5a','廬陵樂府十首  其四','郭祥正','宋','宋诗','song-poetry','','[]','妾身厭塵埃，專心託君子。',72,'全唐诗/poet.song.43000.json','["妾身厭塵埃，專心託君子。", "感君一面眄，涸轍逢秋水。", "雍容未經年，結誓同生死。", "胡爲忽言别，短書無一紙。", "愁思魂夢飛，鵲語不成喜。", "歲晚君不來，紅妝爲君洗。"]'),
('216dd8d4-c12b-4fd0-bd4e-4fe33dacf398','廬陵樂府十首  其五','郭祥正','宋','宋诗','song-poetry','','[]','嵯峨姑射山，綽約飛行子。',72,'全唐诗/poet.song.43000.json','["嵯峨姑射山，綽約飛行子。", "絳唇啟皓玉，明眸漾寒水。", "方平與麻姑，相期永不死。", "手披黄庭經，金字寫青紙。", "胡爲謫人間，離合溢悲喜。", "妖桃凝露珠，東風任吹洗。"]'),
('da8a2198-165e-4e3f-8c05-b4a358ca3f6c','廬陵樂府十首  其六','郭祥正','宋','宋诗','song-poetry','','[]','庭下幽花羃寒霧，金鴨冷烟無一縷。',64,'全唐诗/poet.song.43000.json','["庭下幽花羃寒霧，金鴨冷烟無一縷。", "從君别妾駕紅鸞，望斷三山無覓處。", "平時曲調休重舉，長袖空垂不成舞。", "醒眼牽愁送春去，獨立殘陽與誰語。"]'),
('5c536743-9eee-420e-a6a7-f7c88bb75816','廬陵樂府十首  其七','郭祥正','宋','宋诗','song-poetry','','[]','英英玉山禾，乃是鳳凰食。',48,'全唐诗/poet.song.43000.json','["英英玉山禾，乃是鳳凰食。", "鳳凰殊未來，禾生亦何益。", "幽香眷春盡，孤根含露寂。", "委棄同蒿萊，咄嗟人莫識。"]'),
('6dba2228-cdd2-4afb-b379-6d60e6da2a54','廬陵樂府十首  其八','郭祥正','宋','宋诗','song-poetry','','[]','自君之往矣，幽房守歲華。',48,'全唐诗/poet.song.43000.json','["自君之往矣，幽房守歲華。", "眉頭勻翠淡，裙带縷金斜。", "魂魄空成夢，音書不到家。", "憑誰度庾嶺，和淚寄梅花。"]'),
('917daf0e-3c40-4f1a-adee-8bae2578a52f','廬陵樂府十首  其九','郭祥正','宋','宋诗','song-poetry','','[]','粉黛元知假，丹青豈是真。',48,'全唐诗/poet.song.43000.json','["粉黛元知假，丹青豈是真。", "桃花初過雨，溪水暗流春。", "眼眼隨雲斷，書書託雁頻。", "漁郎自迷路，狂殺武陵人。"]'),
('d81c76f9-2795-40fd-9711-8b2bf6be3960','廬陵樂府十首  其一○','郭祥正','宋','宋诗','song-poetry','','[]','不作巫山雨，螺川久住家。',48,'全唐诗/poet.song.43000.json','["不作巫山雨，螺川久住家。", "欲知冰未釋，須信玉無瑕。", "對局拈棋子，開窻摘杏花。", "誰能諳此意，紅日又西斜。"]'),
('6fcc5a1e-e8f1-400b-853a-fb09b1b79f88','妾薄命','郭祥正','宋','宋诗','song-poetry','','[]','雌鳳始營巢，妖桃半敷萼。',72,'全唐诗/poet.song.43000.json','["雌鳳始營巢，妖桃半敷萼。", "憶昔嫁君時，相逢一何樂。", "朱顔妾未變，白眼君先惡。", "君恩不下濟，妾意正難託。", "空牀春寂寥，孤燈夜蕭索。", "哀弦時一彈，彈終淚還落。"]'),
('bbf25620-d2b2-4562-bb84-ac43ed658692','怨别二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','渡江君别妾，恨不如桃葉。',72,'全唐诗/poet.song.43000.json','["渡江君别妾，恨不如桃葉。", "桃葉解隨君，渡江不用楫。", "妾既不得隨，渡江楫如飛。", "自憐妾命薄，江頭還獨歸。", "一步一回首，碧雲凝落暉。", "空將盈掬淚，和粉灑羅衣。"]'),
('03895142-45b8-46f6-b77e-b25acdeb5382','怨别二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','團扇不遮面，欲君永相見。',72,'全唐诗/poet.song.43000.json','["團扇不遮面，欲君永相見。", "胡爲忽别妾，船逐南風便。", "君行妾獨處，妾復誰爲主。", "正似晚春花，零落隨風雨。", "有情頻寄書，莫令書更疏。", "却羡路傍草，到處逢君車。"]'),
('ff7bc717-cd87-4a7f-a7f2-0af28a08f145','代古相思','郭祥正','宋','宋诗','song-poetry','','[]','妾面如花開，妾心似蘭死。',96,'全唐诗/poet.song.43000.json','["妾面如花開，妾心似蘭死。", "花開色易衰，蘭死香不已。", "願持枯蘭心，終焉託君子。", "君行胡不歸，兩見秋風起。", "鴻雁只空來，音書無一紙。", "夜夜夢見君，朝朝懶梳洗。", "不憶霜月前，絲桐爲君理。", "千古萬古悲，悠揚逐流水。"]'),
('9b9a44b0-7132-4698-994e-a45bd542a175','擬桃花歌','郭祥正','宋','宋诗','song-poetry','','[]','酣酣桃始花，灼灼粉面笑。',144,'全唐诗/poet.song.43000.json','["酣酣桃始花，灼灼粉面笑。", "粉色射花光，奪盡丹青妙。", "藍衫馬上郎，風流亦年少。", "語言雖未通，精誠默相照。", "斂容緩步復掩門，只見桃花不見人。", "輕紅淺白正含露，欲落半開將送春。", "凝心駐馬日漸晚，隱忍時時下前坂。", "回頭又不見桃花，唯有青山遮醉眼。", "揚鞭擊鐙歌團扇，相見不如不相見。", "逢人寄語問桃花，春殘吹洗落誰家。"]'),
('c00eaf4e-d3f8-46ba-a26f-823e3d741227','怡軒吟贈番陽張孝子','郭祥正','宋','宋诗','song-poetry','','[]','古云蜀道難，蜀道之難難於上青天。',296,'全唐诗/poet.song.43000.json','["古云蜀道難，蜀道之難難於上青天。", "孝子尋親不辭遠，草蹻負米離番川。", "西從荆州望夔國，捫蘿躡石穿林巔。", "峽山愈深人跡絕，但聞悲風泠澗聲潺湲。", "汲溪鑽火行復餐，夜宿茅屋衣裳單。", "迴看江南路九千，一見歸客吞悲酸。", "寄聲吾母形骸安，慎勿爲語皮皴乾。", "涪州城西遇征蠻，城門防盜白晝關。", "撫膺仰天涕汍瀾，見親之難難於蜀道難。", "成都漸近心稍寛，踴躍可得瞻耆顔。", "父昔離家子方孕，子得見父今壯年。", "胡弗歸兮死敢請，慰我慈母心懸懸。", "三往三返又十載，孝子執轡方言還。", "番人聞歸競嗟喜，夫婦白首重團圓。", "誅茅立屋奉甘旨，陳侯篆榜名怡軒。", "春禽提壺助春飲，綵衣自舞春風前。", "腰金饌玉非我欲，但願眉壽雙松堅。", "朝熙熙，暮熙熙，誰將朱絲繩，奏我怡軒詩。"]'),
('6ac5d71f-6c4e-4a32-9002-f6cd4c0f9e78','憶敬亭山作','郭祥正','宋','宋诗','song-poetry','','[]','忽憶敬亭山，翠碧千萬尋。',188,'全唐诗/poet.song.43000.json','["忽憶敬亭山，翠碧千萬尋。", "白雲拂地弄晴影，黄猿嘯晚清人心。", "桃花流水三月深，柳絮披烟辭故林。", "重樓複殿据山脚，像塑制度祠非淫。", "晉時謝守曾賽雨，至今石上鐫遺吟。", "五言雅重參二典，琅琅一誦鏗璆琳。", "綠潭無底白玉沈，千載何人知此音。", "李白騎鯨出滄海，回鞭曾宿岧嶤岑。", "却泛虚舟弄溪月，紫霞之杯傾不歇。", "醉來更約崔宗之，秋水玄談清興發。", "數公逸駕何當還，悵望英風不可攀。", "信道相看兩不厭，古來只有敬亭山。"]'),
('5cdfc61c-9b57-4c40-8fcc-ab668b0861cc','神宗皇帝挽詞二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','物物皆成化，熙熙十九春。',48,'全唐诗/poet.song.43000.json','["物物皆成化，熙熙十九春。", "壽觴方奏樂，法座忽流塵。", "遺治前無古，稱宗孰有神。", "烟霄歧路别，百辟共沾巾。"]'),
('37866bb5-bd67-46ec-8526-e5b9e054e96c','神宗皇帝挽詞二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','原廟工初畢，神遊竟不還。',48,'全唐诗/poet.song.43000.json','["原廟工初畢，神遊竟不還。", "鼎湖龍馭遠，湘岸竹枝斑。", "謚號尊逾聖，陵基别有山。", "九重春忽暝，四海慘愁顔。"]'),
('0a7a937b-211f-4140-8292-ef1ce6167334','王丞相荆公挽詞二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','間世君臣會，中天日月圓。',48,'全唐诗/poet.song.43000.json','["間世君臣會，中天日月圓。", "裕陵龍始蟄，鍾阜鶴隨仙。", "畜德何人紹，成書闔國傳。", "回頭盡陳跡，麟石臥孤烟。"]'),
('c8c992f7-3fac-43b0-ad38-c22e1567fdcd','王丞相荆公挽詞二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','公在神明聚，公亡泰華傾。',48,'全唐诗/poet.song.43000.json','["公在神明聚，公亡泰華傾。", "文章千古重，富貴一毫輕。", "若聖丘非敢，猶龍耳强名。", "悲風白門路，啼血送銘旌。"]'),
('f86bf10b-5d29-4032-b104-061af98ab08a','哭梅直講聖俞','郭祥正','宋','宋诗','song-poetry','','[]','生事念死隔，歘如過鳥飛。',288,'全唐诗/poet.song.43000.json','["生事念死隔，歘如過鳥飛。", "長空不留跡，清叫竟何之。", "死者固已矣，生者謾相思。", "昭亭雪塞山，相遇忘寒饑。", "解劍貰濁酒，果餚躬自攜。", "掃除長少分，曠蕩文章期。", "贈蒙以大白，自謂無復疑。", "及將起草茅，謹札還先馳。", "邀我采石渡，爛醉霜蟹肥。", "沉吟望夫曲，朗誦天門詩。", "險絕必使和，凡魚豈龍追。", "篇篇被許可，當友不當師。", "凌晨掛高帆，公行我言歸。", "一别三四秋，音問山中稀。", "去年集選曹，僮瘦馬力羸。", "訪公國東門，問我來何時。", "青芻與白飯，諸子爭賫持。", "論新復談故，謂我今逾奇。", "南還得長篇，萬里銜光輝。", "此德未云報，訃音裂肝脾。", "桓桓萬人英，不遇終愁羈。", "一官止太學，薄命吁可悲。", "所嗟吾道喪，斯文竟何爲。", "譬彼卞子玉，棄置汙濁泥。"]'),
('3b71b40d-60e7-4f79-9699-6588edb0f180','哭夏寺丞公酉','郭祥正','宋','宋诗','song-poetry','','[]','齊山鬰愁烟，鏡潭墜孤月。',60,'全唐诗/poet.song.43000.json','["齊山鬰愁烟，鏡潭墜孤月。", "佳人去不還，生别成死别。", "有才曾未施，負冤終莫雪。", "世情多反覆，美玉不如鐵。", "無路攀魂車，隔江寄清血。"]'),
('d62705ae-27ff-4156-8c67-90ad98977054','哭子點','郭祥正','宋','宋诗','song-poetry','','[]','五歲養育恩，一朝隨埃塵。',144,'全唐诗/poet.song.43000.json','["五歲養育恩，一朝隨埃塵。", "琅琅讀書聲，在耳猶如新。", "哽哽臨絕言，喚爺眉屢顰。", "永痛卑栖邑，醫脈非良真。", "微疾遽夭殤，吾家失麒麟。", "嗥天天莫知，拊地地不聞。", "淚迸睛欲枯，腸斷鼻愈辛。", "汝臥長夜臺，我孤大夢身。", "後嗣復誰望，有車已摧輪。", "佳雛墮危巢，異芳零短春。", "黄泉無白日，青冢多愁雲。", "哀弦寫悲歌，弔汝冥漠魂。"]'),
('e34738b8-f4bf-4600-9042-c6bce408320c','哭宗叔致政大將軍','郭祥正','宋','宋诗','song-poetry','','[]','文鋒困挫離場屋，武略縱横勤冕旒。',64,'全唐诗/poet.song.43000.json','["文鋒困挫離場屋，武略縱横勤冕旒。", "國士傳家雖有子，將軍終老不封侯。", "抱冰末路垂三紀，埋玉空山第一秋。", "餘派江東藉雲蔭，載瞻遺像涕交流。"]'),
('e858f002-e9ce-4ca5-a5aa-818458851f1d','故臨川太守石公挽詞二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','憶昔江頭别，悲歡失後期。',48,'全唐诗/poet.song.43000.json','["憶昔江頭别，悲歡失後期。", "姦言誣直節，枉獄累明時。", "白玉原無玷，青天孰可欺。", "有兒能雪恥，泉壤釋餘悲。"]'),
('c0b3973c-bd8d-4fbb-b142-e2d6c860f951','故臨川太守石公挽詞二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','半道逢豺虎，吞聲力已窮。',48,'全唐诗/poet.song.43000.json','["半道逢豺虎，吞聲力已窮。", "命從冤獄喪，言有諫臣公。", "玉樹埋長夜，金魚委斷蓬。", "旅魂雖獲雪，千載起悲風。"]'),
('b3df100d-24ad-489e-8fff-72e56ada68fb','陳伯育承事挽詞二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','海鶴冰爲骨，霜潭月作心。',48,'全唐诗/poet.song.43000.json','["海鶴冰爲骨，霜潭月作心。", "要賓唯飲酒，焚券不論金。", "相望縈離恨，何嗟得訃音。", "春回墳草綠，誰伴夜臺吟。"]'),
('21b61694-0ee8-46b9-a51f-a36140902927','陳伯育承事挽詞二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','二子皆攀桂，一生唯好吟。',48,'全唐诗/poet.song.43000.json','["二子皆攀桂，一生唯好吟。", "夜臺如得句，泉路孰知音。", "飲態思頽玉，交情失斷金。", "奠芻何以報，折盡老夫心。"]'),
('d92b0eae-75b5-4b33-b7b1-66ea347795f1','鄒宣德挽詞二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','憶昔姑溪上，分攜歲月賒。',48,'全唐诗/poet.song.43000.json','["憶昔姑溪上，分攜歲月賒。", "清標冰有骨，靜德玉無瑕。", "不殺居爲戒，傳經大厥家。", "西山問仙籍，公合在烟霞。"]'),
('0881421d-f019-44ab-a851-67b0731c09e9','鄒宣德挽詞二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','靜樂疇能匹，翛然几杖間。',48,'全唐诗/poet.song.43000.json','["靜樂疇能匹，翛然几杖間。", "有兒專使節，無念落塵寰。", "流水歸何處，孤雲去不還。", "成仙應蜕骨，誰謂掩泉關。"]'),
('6d773934-f018-4f81-83fc-1042d3a3f578','哭漳州蔡温老秀才','郭祥正','宋','宋诗','song-poetry','','[]','交游氣概如君少，患難扶持及我多。',64,'全唐诗/poet.song.43000.json','["交游氣概如君少，患難扶持及我多。", "萬里相思魂往返，一書報死淚滂沲。", "文場決策終難必，旅館捐軀可奈何。", "猶得有兒傳素業，幾時歸葬舊山坡。"]'),
('d77079a7-ac18-4aa2-8c48-a3b64d222e79','楊次公侍講挽詞二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','力學窺前古，扶經翊太平。',48,'全唐诗/poet.song.43000.json','["力學窺前古，扶經翊太平。", "樂成天地格，祧正祖宗明。", "知命窮猶達，趨玄死亦生。", "世無班馬筆，誰爲勒幽銘。"]'),
('543da2ba-9181-46e8-9b2e-1293f2236f91','楊次公侍講挽詞二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','孤進終難達，文章誤此生。',48,'全唐诗/poet.song.43000.json','["孤進終難達，文章誤此生。", "纔趨王府講，已夢玉樓成。", "遺篋書千卷，招魂酒一觥。", "空餘淮上月，不到夜臺明。"]'),
('2064ff17-9b27-48b3-a230-ad8d5e049299','楊次思博士挽詞','郭祥正','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','有志吞戎虜，成書達帝庭。',48,'全唐诗/poet.song.43000.json','["有志吞戎虜，成書達帝庭。", "長江傾學術，短炬速年齡。", "玉樹埋蒿壤，泉臺掩夜扃。", "功勳何可問，不得上丹青。"]'),
('b933acc5-c093-4e20-b79f-3bab2c94f23c','亡友留君儀挽詞二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','信報君儀訃，將如吾道何。',48,'全唐诗/poet.song.43000.json','["信報君儀訃，將如吾道何。", "交游亡玉樹，涕淚瀉金波。", "三子先凋冺，一身纒病痾。", "人生誰不死，遺恨獨君多。"]'),
('cfffbee4-a044-4898-8e69-6de80f3d42c2','亡友留君儀挽詞二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','壯子皆先隕，親喪未啟欑。',48,'全唐诗/poet.song.43000.json','["壯子皆先隕，親喪未啟欑。", "病成終不愈，魂散若爲安。", "結義從今冺，遺編忍復看。", "亭開基石處，雲水想漫漫。"]'),
('8ee5fd24-01e7-4b42-844d-47911681bc54','弔故友吳延之屯田','郭祥正','宋','宋诗','song-poetry','','[]','吳老歸泉後，人間未有君。',48,'全唐诗/poet.song.43000.json','["吳老歸泉後，人間未有君。", "春深來陽草，月亂采江雲。", "孤嘯猿求侶，哀鳴雁失羣。", "姑溪一樽酒，遙酹五峰墳。"]'),
('abe09d05-6014-45c4-b0c2-adc3aefb2b16','哭亡友李公達','郭祥正','宋','宋诗','song-poetry','','[]','忽得凶音淚不收，可憐英氣隕荒幽。',64,'全唐诗/poet.song.43000.json','["忽得凶音淚不收，可憐英氣隕荒幽。", "天垂北斗夜臺靜，虎嘯西風墳樹愁。", "學道未行嘗自信，高名雖在復何求。", "謾攜一榼招魂酒，獨對修江想獻酬。"]'),
('c52c4759-e346-451a-a0ec-5a4ae8c10f1b','弔黄塘寺知白上人','郭祥正','宋','宋诗','song-poetry','','[]','今日黄塘寺，昔年知白師。',48,'全唐诗/poet.song.43000.json','["今日黄塘寺，昔年知白師。", "悟禪兼悟律，能畫亦能詩。", "舊卷春涵瞑，新墳月掩悲。", "餘生我何有，騎馬送衰遲。"]'),
('451fd57a-66e7-4441-b0a7-8ca2758df674','弔亡友袁世弼太博','郭祥正','宋','宋诗','song-poetry','','[]','自掩斯人骨，西山秀色低。',48,'全唐诗/poet.song.43000.json','["自掩斯人骨，西山秀色低。", "文章驚早悟，壽夭理難齊。", "絕壑沉寒玉，空江没斷霓。", "兒孫今賣宅，感舊只酸嘶。"]'),
('fe6caa58-10a3-41f7-b8bb-02e803d3fd6a','三亡詩','郭祥正','宋','宋诗','song-poetry','','[]','榮翁苦于學，腹實五車書。',276,'全唐诗/poet.song.43000.json','["榮翁苦于學，腹實五車書。", "尤明禮樂事，畫就百幅圖。", "獻之神宗朝，不報還舊廬。", "白頭著青衫，老憤猶欲舒。", "佐邑曾未赴，瞑目忽已殂。", "何子稍家富，恬不爲利拘。", "執筆工詞章，科第學有餘。", "終遭有司黜，才命誠難俱。", "今聞亦長往，令我勤悲吁。", "二家各有子，素業傳門閭。", "登科既同籍，奔喪又同途。", "李君出世胄，軒軒珮瓊琚。", "計偕冠多士，場屋喧名譽。", "晚乃樂高隱，賣藥荒村墟。", "愈貧愈自信，純潔不可汙。", "天胡奪其齡，否極泰則無。", "斯人皆舊游，想望空踟蹰。", "顧我雖未死，目眊霜盈鬚。", "近酒已先惡，趨時跡尤疏。", "飛章乞殘骸，輕舟下重湖。", "將投永安泊，訪舊相歡娛。", "那知死生隔，三秀同時枯。", "欲爲招魂篇，悲風涕沾濡。"]'),
('a0e8712e-8223-447c-9a3d-c9dd19fbd9e6','擬挽歌五首  其一','郭祥正','宋','宋诗','song-poetry','','[]','百年苦役役，一死已休休。',60,'全唐诗/poet.song.43000.json','["百年苦役役，一死已休休。", "惟我方自適，妻子空悲愁。", "滿樽奠美酒，滿盤薦珍羞。", "我終不可起，汝情謾悠悠。", "送我入蒿里，寂寞無春秋。"]'),
('358db47a-e5b2-41c5-be4b-684102e60b40','擬挽歌五首  其二','郭祥正','宋','宋诗','song-poetry','','[]','形壞影亦滅，有神竟何依。',60,'全唐诗/poet.song.43000.json','["形壞影亦滅，有神竟何依。", "漠漠空木中，豈知經四時。", "以此爲長年，誰人不同歸。", "兒孫汝勿泣，朋舊汝勿悲。", "歲月易經過，冥默終相期。"]'),
('aa8782d9-4f3d-49d3-9021-b680f1967a4c','擬挽歌五首  其三','郭祥正','宋','宋诗','song-poetry','','[]','生前勢有殊，死去分始齊。',48,'全唐诗/poet.song.43000.json','["生前勢有殊，死去分始齊。", "且將耳目靜，安用親舊啼。", "鴻雁任南北，日月隨東西。", "陵谷亦已變，道化復何爲。"]'),
('a8cc342d-f0c7-47b9-8a1f-6bc4c655d06a','擬挽歌五首  其四','郭祥正','宋','宋诗','song-poetry','','[]','于生動以擾，既死靜且潛。',48,'全唐诗/poet.song.43000.json','["于生動以擾，既死靜且潛。", "黄土假面目，青草爲鬚髯。", "榮華春風吹，憔悴秋霜霑。", "迴嗟在世人，不識此理兼。"]'),
('47689e9d-b07a-4bb7-ae3c-42351bab1a60','擬挽歌五首  其五','郭祥正','宋','宋诗','song-poetry','','[]','枯骨螻蟻餘，空棺蔓草纒。',36,'全唐诗/poet.song.43000.json','["枯骨螻蟻餘，空棺蔓草纒。", "欲訴既無路，欲窺不見天。", "休休可奈何，達道乃自然。"]'),
('b91ed907-559c-4ad8-bc95-f036ab70528e','四皓','郭祥正','宋','宋诗','song-poetry','','[]','彼美四賢老，高風萬古寒。',48,'全唐诗/poet.song.43000.json','["彼美四賢老，高風萬古寒。", "去逃秦鼎鑊，歸識漢衣冠。", "翼翼羽翰就，堂堂宗社安。", "商山弊廬在，還入白雲端。"]'),
('ee362045-fbd9-4f21-828d-27cfcc63ba9d','晚望','郭祥正','宋','宋诗','song-poetry','','[]','久客心嘗折，登樓望轉迷。',48,'全唐诗/poet.song.43000.json','["久客心嘗折，登樓望轉迷。", "風傾蘋葉亂，雨重柳條低。", "未得趨金馬，何當似木雞。", "細尋鄉國路，愁聽暝鴉啼。"]'),
('436d5d2e-359d-40a3-93ab-5ede0a00bd14','即事','郭祥正','宋','宋诗','song-poetry','','[]','北戶風欺幌，南橋水拍城。',48,'全唐诗/poet.song.43000.json','["北戶風欺幌，南橋水拍城。", "柳長無嫩色，鶯老有新聲。", "書帙看慵卷，茶甌不厭擎。", "故園何日返，此地獨含情。"]'),
('8dc90f34-6a7f-4dc3-9cc3-212e8f81c75d','幽居','郭祥正','宋','宋诗','song-poetry','','[]','春晚堪行樂，幽居獨閉門。',48,'全唐诗/poet.song.43000.json','["春晚堪行樂，幽居獨閉門。", "忘形付詩酒，吾道委乾坤。", "壞壁蝸涎亂，殘經鼠跡翻。", "交游今已絕，孤坐欲何言。"]'),
('b07193cf-ab90-4ab2-952a-d7347d205989','江亭','郭祥正','宋','宋诗','song-poetry','','[]','江亭孤坐久，野望眼偏明。',48,'全唐诗/poet.song.43000.json','["江亭孤坐久，野望眼偏明。", "映日浮雲簿，搖風細柳輕。", "出牆新笋熟，拍岸晚潮生。", "遣僕沽春酒，幽歡取次成。"]'),
('4c9a1b32-22ed-443c-bcda-fdb2e6c44909','遣意','郭祥正','宋','宋诗','song-poetry','','[]','髮爲烟嵐秃，愁因患難添。',48,'全唐诗/poet.song.43000.json','["髮爲烟嵐秃，愁因患難添。", "徑荒無過客，筍迸任穿簷。", "啅雀誰能遣，驚烏不用占。", "有巾堪漉酒，聊欲效陶潛。"]'),
('52e27cc0-20b2-456b-82a8-cf6126b6ef11','春水','郭祥正','宋','宋诗','song-poetry','','[]','春水碧泱泱，平堤映綠楊。',48,'全唐诗/poet.song.43000.json','["春水碧泱泱，平堤映綠楊。", "田疇資灌溉，鷗鳥共徜徉。", "放餌愁空掣，浮杯興最長。", "晚風吹細浪，仍送落英香。"]'),
('fe929cb5-dbb5-4733-8909-0b04f89cc2e5','早起','郭祥正','宋','宋诗','song-poetry','','[]','客愁偏早起，衰病愜晴明。',48,'全唐诗/poet.song.43000.json','["客愁偏早起，衰病愜晴明。", "索酒防春瘴，披衣聽鳥聲。", "舊書慵檢閲，新客懶逢迎。", "何日籠樊啟，再歸溪上耕。"]'),
('7523e5b8-baee-4097-b27e-7217bc8967ab','初夜','郭祥正','宋','宋诗','song-poetry','','[]','初月未成魄，瘴天雲霧低。',48,'全唐诗/poet.song.43000.json','["初月未成魄，瘴天雲霧低。", "浦昏船競入，林密鳥爭栖。", "褊性憐幽獨，香醪自挈攜。", "布衾今夜冷，猶得避兒啼。"]'),
('b27bd6e5-0793-46d6-bfb0-1e22ccf26c48','可惜','郭祥正','宋','宋诗','song-poetry','','[]','可惜花飛盡，春歸客未歸。',48,'全唐诗/poet.song.43000.json','["可惜花飛盡，春歸客未歸。", "艱難行路險，老大賞心稀。", "翰墨誰曾問，漁樵與願違。", "江干空駐目，藜杖得相依。"]'),
('03a29fac-bce4-43f8-83ca-7ab77e8c4234','客禁','郭祥正','宋','宋诗','song-poetry','','[]','客禁何時釋，驚魂夢裏歸。',48,'全唐诗/poet.song.43000.json','["客禁何時釋，驚魂夢裏歸。", "深憂鄰虎穴，那得並魚磯。", "草色欣欣茂，螢光箇箇微。", "殘生苦多難，搔首掩荆扉。"]'),
('e899e5e0-72c3-47a0-817b-0708ec3525ed','卧柳','郭祥正','宋','宋诗','song-poetry','','[]','冉冉碧濠邊，三株細柳眠。',48,'全唐诗/poet.song.43000.json','["冉冉碧濠邊，三株細柳眠。", "根欹元著水，葉大鎮藏烟。", "不作棟梁用，豈憂斤斧先。", "春風任飄泊，客意亦留連。"]'),
('b5a22a2f-59c4-43d2-b4f6-34a33855a034','水漲','郭祥正','宋','宋诗','song-poetry','','[]','山雨連朝注，溪流没草亭。',48,'全唐诗/poet.song.43000.json','["山雨連朝注，溪流没草亭。", "蛟鼉方汹汹，鴻雁自冥冥。", "只恐翻河漢，終當見日星。", "波瀾平地作，嗟歎未曾經。"]'),
('be5db61a-5004-4927-97ae-e69896ed44cd','水花','郭祥正','宋','宋诗','song-poetry','','[]','水畔花饒笑，欹枝映小亭。',48,'全唐诗/poet.song.43000.json','["水畔花饒笑，欹枝映小亭。", "日光烘欲醉，江色冷還醒。", "淺白渾迷鷺，殘紅尚襯萍。", "幽人頗蕭索，此地要頻經。"]'),
('68fc02ce-22d9-4c53-8cbd-0ad108e10716','西齋二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','西齋吾所構，簷角頗依林。',48,'全唐诗/poet.song.43000.json','["西齋吾所構，簷角頗依林。", "瀟灑松篁影，暄和燕雀音。", "青春那肯住，白髮任相侵。", "稍悟淵明樂，時時撫素琴。"]'),
('ee887899-459f-4b68-a93f-7cabb077128b','西齋二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','西齋吾所愛，一徑綠蘿深。',48,'全唐诗/poet.song.43000.json','["西齋吾所愛，一徑綠蘿深。", "終日聽新鳥，令人忘故林。", "地偏無客到，山潤有苔侵。", "禍患須安命，優游不廢吟。"]'),
('79681665-aac1-460d-a0c9-448205e4064b','南樓','郭祥正','宋','宋诗','song-poetry','','[]','兀坐南樓夜，欄干俯列星。',48,'全唐诗/poet.song.43000.json','["兀坐南樓夜，欄干俯列星。", "村遙喧瓦鼓，塔近震金鈴。", "濕草埋昏瘴，飛蟲接小螢。", "物生皆有理，吾亦委頽齡。"]'),
('709cf0cd-4878-4034-b123-b6eba77e06b5','自貽','郭祥正','宋','宋诗','song-poetry','','[]','自恨心肝拙，題詩愈不工。',48,'全唐诗/poet.song.43000.json','["自恨心肝拙，題詩愈不工。", "癡迷循磨蟻，辛苦打窻蟲。", "妙道知何補，多言自取窮。", "不如長寂默，塊爾白頭翁。"]'),
('ae4adf3e-6835-4091-85e8-3d5b0b84933e','溪岸','郭祥正','宋','宋诗','song-poetry','','[]','溪岸逢春暮，柔條儘意攀。',48,'全唐诗/poet.song.43000.json','["溪岸逢春暮，柔條儘意攀。", "輕鷗翔近渚，好鳥響空山。", "小艇長欹側，孤雲自往還。", "遠遊成底事，白首憶鄉關。"]'),
('e4153fba-0df0-4a77-80e0-bc97b2c175cf','要客','郭祥正','宋','宋诗','song-poetry','','[]','要客來何晚，重乾漉酒巾。',48,'全唐诗/poet.song.43000.json','["要客來何晚，重乾漉酒巾。", "玉琴虚别操，藤榻恐流塵。", "山暗蕭蕭雨，花辭短短春。", "杖藜慵緩步，愁殺獨遊人。"]'),
('5d3f999b-32be-479a-9941-0a90feac7f07','城南','郭祥正','宋','宋诗','song-poetry','','[]','淡沲城南路，參差柳絆烟。',48,'全唐诗/poet.song.43000.json','["淡沲城南路，參差柳絆烟。", "稻秧纔一寸，蠶子始三眠。", "曲折藏花地，暄和載酒天。", "清江深有興，只欲解歸船。"]'),
('d79823b4-2150-4f84-9261-bc96a299ec6b','夜興','郭祥正','宋','宋诗','song-poetry','','[]','日没草堂陰，收書復掛琴。',48,'全唐诗/poet.song.43000.json','["日没草堂陰，收書復掛琴。", "閉門人跡絕，危坐客愁深。", "星漢光鋩動，湖山氣象沈。", "嫦娥如借月，蚊蚋莫相侵。"]'),
('cb1c50e5-4828-45af-868a-6028ac69fe55','夕陽','郭祥正','宋','宋诗','song-poetry','','[]','夕陽沈谷口，海水接天南。',48,'全唐诗/poet.song.43000.json','["夕陽沈谷口，海水接天南。", "歸鳥自成陣，暝山如半酣。", "看雲貪仰面，移杖忽遺簪。", "幽獨誰相過，人情老始諳。"]'),
('497d41b6-938c-4ac6-b326-e671d11a048e','遷居','郭祥正','宋','宋诗','song-poetry','','[]','殊方留滯客，遷館避諠譁。',48,'全唐诗/poet.song.43000.json','["殊方留滯客，遷館避諠譁。", "破榻依寒竹，疏窻對晚花。", "燕歸疑識面，鳥噪默懷家。", "囊橐無書卷，新愁有五車。"]'),
('9171c9ea-15e2-4667-bd49-80741ab58a1f','交游','郭祥正','宋','宋诗','song-poetry','','[]','一作閩南客，幽憂忽過春。',48,'全唐诗/poet.song.43000.json','["一作閩南客，幽憂忽過春。", "交游半卿相，蹤跡自埃塵。", "未附垂天翼，空成涸轍鱗。", "吾廬松菊在，悵望熟溪濱。"]'),
('4423acb3-c565-4b5b-b3f2-9bbc1acd6642','微寒','郭祥正','宋','宋诗','song-poetry','','[]','廣潦生寒夜，幽人獨倚樓。',48,'全唐诗/poet.song.43000.json','["廣潦生寒夜，幽人獨倚樓。", "渚涯迷海若，燈火想漁舟。", "雷鼓蛙爭響，雲天月暗流。", "未應時序變，初夏反如秋。"]'),
('0e3c8e3b-ef08-4509-a87f-1f5306d7e846','旅食','郭祥正','宋','宋诗','song-poetry','','[]','旋煮青芹滑，新炊白稻香。',48,'全唐诗/poet.song.43000.json','["旋煮青芹滑，新炊白稻香。", "僧居同淡泊，旅食幸康强。", "未擬沉湘水，深防死耒陽。", "上書終自達，聖世本虞唐。"]'),
('228e1773-4301-412b-aa93-9022220527a9','客問','郭祥正','宋','宋诗','song-poetry','','[]','來時麥未吐，今見秀盈畦。',48,'全唐诗/poet.song.43000.json','["來時麥未吐，今見秀盈畦。", "投穽還遭石，登雲孰有梯。", "爾讒徒似錦，吾醉只如泥。", "行止無勞問，空山杜宇啼。"]'),
('1727355f-789a-4402-a8d3-22d4b0fd2b0e','廢閣','郭祥正','宋','宋诗','song-poetry','','[]','疊甓基猶在，排空閣已摧。',48,'全唐诗/poet.song.43000.json','["疊甓基猶在，排空閣已摧。", "燕愁尋舊棟，蟻蠧傍新苔。", "月色閒圓缺，風聲自去來。", "廢興何可問，劫火亦成灰。"]'),
('2f7c41bf-85cd-4916-8941-bc263270989f','松風','郭祥正','宋','宋诗','song-poetry','','[]','夜寂松風度，魂清客枕寒。',48,'全唐诗/poet.song.43000.json','["夜寂松風度，魂清客枕寒。", "琴聲傳不盡，詩句寫應難。", "驟雨傾瑤砌，真珠落玉盤。", "隱居如可訪，吾欲跨翔鸞。"]'),
('20a16479-a025-402d-af6a-07a8b8b175db','揮扇','郭祥正','宋','宋诗','song-poetry','','[]','四月長汀郭，晴多暑氣濃。',48,'全唐诗/poet.song.43000.json','["四月長汀郭，晴多暑氣濃。", "欲眠難藉草，選蔭必依松。", "綠水遙思濯，青雲底處逢。", "西巖殘照盡，揮扇待疏鐘。"]'),
('58a696e5-d5a6-4347-85a8-14f51e8968a5','寓館','郭祥正','宋','宋诗','song-poetry','','[]','一徑松陰合，重門院落深。',48,'全唐诗/poet.song.43000.json','["一徑松陰合，重門院落深。", "客來聽鵲喜，春過惜鶯吟。", "風月時經檻，塵埃不到襟。", "黄庭看在手，白雪任盈簪。"]'),
('15a230ca-87cb-40c7-bd2c-ca212fdd3938','松櫪','郭祥正','宋','宋诗','song-poetry','','[]','婆娑松與櫪，夾徑碧濛濛。',48,'全唐诗/poet.song.43000.json','["婆娑松與櫪，夾徑碧濛濛。", "未辨雪霜操，同霑雨露功。", "低枝翻翠蓋，垂葉密樊籠。", "他日爲梁柱，掄材合至公。"]'),
('7a0fc558-a900-4056-bc85-ce69bae43542','立夏','郭祥正','宋','宋诗','song-poetry','','[]','歲旦辭江國，炎天客瘴鄉。',48,'全唐诗/poet.song.43000.json','["歲旦辭江國，炎天客瘴鄉。", "浴陂羣鳥白，含霧野梅黄。", "恨别山隨眼，消愁酒滿觴。", "殘魂終易斷，回首只茫茫。"]'),
('3871848e-4f7f-40a8-b57b-e8c1f85eae12','深夜','郭祥正','宋','宋诗','song-poetry','','[]','四天垂翠碧，一水湛星辰。',48,'全唐诗/poet.song.43000.json','["四天垂翠碧，一水湛星辰。", "寂寞殊方夜，漂流片葉深。", "帝鄉勞夢想，客路只風塵。", "鐘鼓還催曉，深慚釣渭濱。"]'),
('2a101517-4452-4ecc-8ce0-5810636d2faa','競渡','郭祥正','宋','宋诗','song-poetry','','[]','競渡傳風俗，旁觀亦壯哉。',48,'全唐诗/poet.song.43000.json','["競渡傳風俗，旁觀亦壯哉。", "棹爭飛鳥疾，標奪彩龍回。", "江影渾翻錦，歌聲遠震雷。", "輕生一餉樂，時序密相催。"]'),
('fa9b68d6-55d1-46f1-a760-007fa3c9f496','傷春二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','臘月花開盡，中春不見花。',48,'全唐诗/poet.song.43000.json','["臘月花開盡，中春不見花。", "柳陰空拂地，草色漫平沙。", "客路心常折，僧窻鬢自華。", "故鄉何處是，瘴海暗天涯。"]'),
('09f7dcf5-d65c-47ca-8640-96ced45e18be','傷春二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','春雨時時暗，春花眼未經。',48,'全唐诗/poet.song.43000.json','["春雨時時暗，春花眼未經。", "生涯隨過鳥，世態委浮萍。", "瘴霧何由避，蠻歌不忍聽。", "誰家有醇酎，吾欲醉兼醒。"]'),
('ef53fe0f-7330-4368-a3f5-87a3a531b585','西池','郭祥正','宋','宋诗','song-poetry','','[]','雨漲西池水，微瀾拍畫橋。',48,'全唐诗/poet.song.43000.json','["雨漲西池水，微瀾拍畫橋。", "不愁蓮芡没，唯恐棟梁漂。", "扶杖防危步，移牀避晚潮。", "何當風日爽，一舞看纖腰。"]'),
('17a0ae17-cb25-4562-9f96-40e30c10a362','積潦','郭祥正','宋','宋诗','song-poetry','','[]','積潦連江海，舂撞說劍鋒。',48,'全唐诗/poet.song.43000.json','["積潦連江海，舂撞說劍鋒。", "郡城千丈拆，民食五年凶。", "雨脚懸麻直，雲頭潑墨濃。", "忘機唯白鳥，不解避蛟龍。"]'),
('15aff599-2d39-4290-83fc-a4869b4ebca0','自笑','郭祥正','宋','宋诗','song-poetry','','[]','自笑姑溪客，還投瘴海邊。',48,'全唐诗/poet.song.43000.json','["自笑姑溪客，還投瘴海邊。", "不才無進路，多病復殘年。", "欲種千竿竹，將求二頃田。", "人生底事足，且愛酒涓涓。"]'),
('489642b6-0d60-42e8-ae1a-efdfbc35ce3a','喜晴','郭祥正','宋','宋诗','song-poetry','','[]','瘴鄉仍久雨，生事念樵漁。',48,'全唐诗/poet.song.43000.json','["瘴鄉仍久雨，生事念樵漁。", "江海雲歸盡，乾坤日上初。", "短垣張澣服，幽圃理殘蔬。", "佐國知無術，聊欣病體舒。"]'),
('77f950c7-e6fd-41ed-80e9-44c71ca75cc9','城上','郭祥正','宋','宋诗','song-poetry','','[]','危步欲何適，城頭獨杖藜。',48,'全唐诗/poet.song.43000.json','["危步欲何適，城頭獨杖藜。", "水歸滄海後，雲散暮天時。", "秋色長空淡，笳聲迥野悲。", "泥沙埋熟稻，一穗亦無遺。"]'),
('4d2a2e99-a607-43e8-b8ef-eceacdd11ca9','獨醒','郭祥正','宋','宋诗','song-poetry','','[]','野性惟憐酒，無聊遂獨醒。',48,'全唐诗/poet.song.43000.json','["野性惟憐酒，無聊遂獨醒。", "風塵雙白鬢，天地一青萍。", "鵩鳥寧須賦，離騷未是經。", "回頭付陳跡，終欲醉冥冥。"]'),
('19f36bc7-823a-4765-9d2f-ffd9b62395cd','邸報','郭祥正','宋','宋诗','song-poetry','','[]','立法新三省，論材只數公。',48,'全唐诗/poet.song.43000.json','["立法新三省，論材只數公。", "簿書期會正，風俗見聞同。", "邊塞瘡痍後，朝廷氣概中。", "不才思獻賦，天路恐難通。"]'),
('afc8039a-a76d-4782-aa00-cbaad414fcc1','宦情','郭祥正','宋','宋诗','song-poetry','','[]','宦情聊落甚，况在九溪邊。',48,'全唐诗/poet.song.43000.json','["宦情聊落甚，况在九溪邊。", "瘴霧易成雨，颶風偏覆船。", "水殘餘盜賊，村迥少人烟。", "欲達中州信，迢迢路六千。"]'),
('51fe502e-6a03-4bb3-a0df-823c51f9d0f7','自遣','郭祥正','宋','宋诗','song-poetry','','[]','骨相殊屯賤，無官只有階。',48,'全唐诗/poet.song.43000.json','["骨相殊屯賤，無官只有階。", "半生萍梗過，兩鬢雪霜排。", "去國腸空斷，求田心未諧。", "新交莫相笑，中立一枝柴。"]'),
('e4160c6f-b51c-4ba8-920c-39076960e2dd','西庵','郭祥正','宋','宋诗','song-poetry','','[]','一庵丹荔下，更與畫橋鄰。',48,'全唐诗/poet.song.43000.json','["一庵丹荔下，更與畫橋鄰。", "不許塵埃到，每期風月親。", "好音聞度鳥，斜影辨疏筠。", "拂拭白藤榻，欹眠穩病身。"]'),
('d2c00cc0-31bf-40c0-a149-d16f8b1f1b0c','雨過','郭祥正','宋','宋诗','song-poetry','','[]','雨過添幽事，褰裳步暖沙。',48,'全唐诗/poet.song.43000.json','["雨過添幽事，褰裳步暖沙。", "竹梢含凈霧，藤刺罥輕槎。", "鸂鶒雙隨浪，蜻蜓對覓花。", "老夫詩思愜，頗覺日沉車。"]'),
('5e12f5df-7646-4fdc-8c55-96b9062f815a','野寺','郭祥正','宋','宋诗','song-poetry','','[]','野寺盤山腹，高秋雨霽天。',48,'全唐诗/poet.song.43000.json','["野寺盤山腹，高秋雨霽天。", "拂簷雲漫漫，穿竹水涓涓。", "接食憐馴鳥，搘笻慕老禪。", "經年無客到，門巷疊青錢。"]'),
('39af6da4-10d7-4a44-a619-0c98c4f6ad8e','晚晴','郭祥正','宋','宋诗','song-poetry','','[]','川漲那堪雨，今朝喜晚晴。',48,'全唐诗/poet.song.43000.json','["川漲那堪雨，今朝喜晚晴。", "幽花縈露重，濁水止蛙鳴。", "圩稻應全刈，村醪可强傾。", "吾雖無一畝，亦足慰餘生。"]'),
('85645ad1-4563-498f-a34e-691539c3bda9','屏跡','郭祥正','宋','宋诗','song-poetry','','[]','屏跡已恨晚，疲軀今自由。',48,'全唐诗/poet.song.43000.json','["屏跡已恨晚，疲軀今自由。", "百年無七十，一日有千憂。", "覓酒開青眼，憑詩遣白頭。", "莫言賓客少，池上兩三鷗。"]'),
('5dbf2af0-3bf0-419a-bb46-5fa54da5fc84','却卧','郭祥正','宋','宋诗','song-poetry','','[]','曉起梳頭畢，開窻却卧時。',48,'全唐诗/poet.song.43000.json','["曉起梳頭畢，開窻却卧時。", "素烟收枕席，紅日上藩籬。", "仰面看書卷，移牀近酒池。", "紛紛萬方事，安用老夫知。"]'),
('fa8663e9-2147-4020-9d45-c05884078e9a','無客','郭祥正','宋','宋诗','song-poetry','','[]','病久人情厭，經旬客不來。',48,'全唐诗/poet.song.43000.json','["病久人情厭，經旬客不來。", "簾因風力卷，門待月華開。", "柳上新蟬咽，城頭暮角哀。", "勞生隨物化，孰免葬蒿萊。"]'),
('230e9035-e8f7-4569-a3c6-812d179deebd','門巷','郭祥正','宋','宋诗','song-poetry','','[]','肅肅秋容凈，蕭蕭門巷深。',48,'全唐诗/poet.song.43000.json','["肅肅秋容凈，蕭蕭門巷深。", "荆榛元自合，車馬少過尋。", "問婢催蔬熟，呼兒取酒斟。", "藤牀未成寐，野鳥噪歸林。"]'),
('f7b906b6-7165-43d8-be96-59bc57a70f0c','賦分','郭祥正','宋','宋诗','song-poetry','','[]','賦分從來薄，明時敢妄干。',48,'全唐诗/poet.song.43000.json','["賦分從來薄，明時敢妄干。", "六年悲對獄，五十速休官。", "水送雲天凈，山開洞壑寒。", "一枝能息影，何暇北溟寛。"]'),
('c660ea33-66bf-4b46-bc5d-c9f2d3a2f513','農事','郭祥正','宋','宋诗','song-poetry','','[]','三歲悲農事，官倉亦已貧。',48,'全唐诗/poet.song.43000.json','["三歲悲農事，官倉亦已貧。", "勅書雖赦獄，恩澤未蘇民。", "南國供輸大，中宵涕泗頻。", "一心隨草木，無復念沉淪。"]'),
('d487eeea-1dbc-4810-816c-e5df7d727e8a','野望','郭祥正','宋','宋诗','song-poetry','','[]','暑雨收殘候，秋雲結薄陰。',48,'全唐诗/poet.song.43000.json','["暑雨收殘候，秋雲結薄陰。", "山光翠兼紫，水影凈還深。", "竹密羣鴉入，天空一雁沈。", "興來搔白首，衰颯愧儒林。"]'),
('c450cdb2-5c43-4851-9d09-f7d86a2b999d','日暮','郭祥正','宋','宋诗','song-poetry','','[]','倚杖孤亭久，無心辨俗訛。',48,'全唐诗/poet.song.43000.json','["倚杖孤亭久，無心辨俗訛。", "暮山青掃淀，秋漢白浮波。", "岸震歸船鼓，村喧刈稻歌。", "未收西望眼，問罪有干戈。"]'),
('89676d8d-440e-4fa2-a868-e3fe06fe2c02','歸燕','郭祥正','宋','宋诗','song-poetry','','[]','天外秋風勁，梁間燕羽稀。',48,'全唐诗/poet.song.43000.json','["天外秋風勁，梁間燕羽稀。", "營巢雛未老，何地汝成歸。", "蜃澤多樓閣，茅堂無穽機。", "故園春色動，還趁社前飛。"]'),
('01d1e9a4-e699-4ffe-adf5-bee13264c428','遣懷','郭祥正','宋','宋诗','song-poetry','','[]','節物驚心事，摶金菊放花。',48,'全唐诗/poet.song.43000.json','["節物驚心事，摶金菊放花。", "潛魚防餌釣，高雁避城笳。", "南浦秋風冷，西江夕照斜。", "異鄉消息斷，林外更聞鴉。"]'),
('b376c27c-c6e0-4005-84e5-e697cdda0106','搗衣','郭祥正','宋','宋诗','song-poetry','','[]','清秋送殘暑，隔屋忽聞砧。',48,'全唐诗/poet.song.43000.json','["清秋送殘暑，隔屋忽聞砧。", "遠震星河夜，遙興關塞心。", "欲知針縷密，即是淚痕深。", "他日功成後，逢人寄好音。"]'),
('eeba3f8e-a4a0-46b6-af28-9bfdac8447b2','植杖','郭祥正','宋','宋诗','song-poetry','','[]','獨往憐漁艇，羣飛愛暮鷗。',48,'全唐诗/poet.song.43000.json','["獨往憐漁艇，羣飛愛暮鷗。", "誰云天地窄，自伴水雲游。", "荇葉青爭老，蓼花紅半收。", "江頭人事絕，植杖我何憂。"]'),
('67dba53f-5869-4a28-8447-621ad5eccbaf','空囊','郭祥正','宋','宋诗','song-poetry','','[]','牀有牛衣卧，厨供石髓餐。',48,'全唐诗/poet.song.43000.json','["牀有牛衣卧，厨供石髓餐。", "此身知是幻，卒歲不爲難。", "冰合潛蛟冷，雲深病鶴寒。", "青錢無得選，空掛一囊看。"]'),
('f98a8a01-c5f9-4424-bb12-fdfd7b4e2eef','秋笛','郭祥正','宋','宋诗','song-poetry','','[]','清秋聞笛弄，獨立露霑衣。',48,'全唐诗/poet.song.43000.json','["清秋聞笛弄，獨立露霑衣。", "天外雲留住，水中龍未歸。", "悠揚聲益苦，感激思何微。", "不似前春聽，梅花片片飛。"]'),
('734f3b3f-a5a0-4af6-a8ff-b670994895fd','黄山二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','秋物已瀟灑，臨高念歲窮。',48,'全唐诗/poet.song.43000.json','["秋物已瀟灑，臨高念歲窮。", "陣收羣雁没，峰斷片雲空。", "月色山川內，笛聲關塞中。", "西人未柔服，長策在諸公。"]'),
('2450e38f-4735-4dc0-8195-a849c669ba9f','黄山二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','秋晚陟浮丘，西臨古渡頭。',48,'全唐诗/poet.song.43000.json','["秋晚陟浮丘，西臨古渡頭。", "鐘聲沉斷岸，橋影散中流。", "雪讓蘆花密，雲排稻穗稠。", "乾坤均帝力，草木豈能酬。"]'),
('5e583b68-973b-48c5-b0c7-972d1f1f0ac2','柴門','郭祥正','宋','宋诗','song-poetry','','[]','水落烟村迥，柴門四五家。',48,'全唐诗/poet.song.43000.json','["水落烟村迥，柴門四五家。", "晚風回斷雁，寒雨側幽花。", "世事紛無已，人生自有涯。", "鯨鼇真可釣，吾興欲乘槎。"]'),
('07248d54-aa6a-49ac-8da9-707e6abe8bbd','復寒','郭祥正','宋','宋诗','song-poetry','','[]','三月閩南國，陰寒變慘淒。',48,'全唐诗/poet.song.43000.json','["三月閩南國，陰寒變慘淒。", "市樓添酒價，山雨勒鶯啼。", "田父憂春種，商人怯路泥。", "何當好風日，稚子浴清溪。"]'),
('cbdfdb12-3793-479b-bef7-05e09c5cc54c','元輿攜酒見過三首  其一','郭祥正','宋','宋诗','song-poetry','','[]','永日門常掩，欣聞五馬過。',48,'全唐诗/poet.song.43000.json','["永日門常掩，欣聞五馬過。", "社餘巢燕入，花散蜜蜂多。", "望斷千山綠，愁來兩鬢皤。", "肝腸思一濯，須藉酒爲河。"]'),
('5fd5b0d7-de5d-48e4-8af6-9f34ffb141f8','元輿攜酒見過三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','酒味年來美，攜觴約屢過。',48,'全唐诗/poet.song.43000.json','["酒味年來美，攜觴約屢過。", "交情貧始見，詩思老仍多。", "許國心常赤，思家髮任皤。", "誦君新得句，秀色攬山河。"]'),
('51ec0e3c-5bcb-4b44-aa78-fd46dc6039cb','元輿攜酒見過三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','沉毅陳夫子，談兵孰與過。',48,'全唐诗/poet.song.43000.json','["沉毅陳夫子，談兵孰與過。", "運籌知必勝，善將不論多。", "漢陣千重黑，胡沙萬里皤。", "如聞洗戈甲，誰爲挽天河。"]'),
('e625e72c-fcd6-43fa-aa6b-636f4a7912fd','雨中喜君儀要溫老希聖同見過二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','蕭蕭山寺雨，漠漠暮雲寒。',48,'全唐诗/poet.song.43000.json','["蕭蕭山寺雨，漠漠暮雲寒。", "不恨麻衣薄，深愁酒盞乾。", "離披花刺眼，容易雪衝冠。", "要客能相遇，寧辭濕錦鞍。"]'),
('99fccb0c-0523-46d8-a379-6d5d1ad4a597','雨中喜君儀要溫老希聖同見過二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','萬里鄉園别，一春風雨多。',48,'全唐诗/poet.song.43000.json','["萬里鄉園别，一春風雨多。", "亂蛙聲鬭急，歸燕舞緣何。", "石榻昏苔蘚，柴門暗薜蘿。", "橛株方自笑，忽枉故人過。"]'),
('b870df53-4e79-4bec-aa48-cc52fa642d79','謝君儀攜酒要客慰唁愁寂二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','佳客過窮巷，良朋復可要。',48,'全唐诗/poet.song.43000.json','["佳客過窮巷，良朋復可要。", "靜緣棋局亂，愁逐酒杯銷。", "花底鶯聲度，林間雨點飄。", "晚春頻一醉，何必擬松喬。"]'),
('97e3d9b7-b502-4f8b-b72d-43707944154a','謝君儀攜酒要客慰唁愁寂二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','讒人未投北，君子獨相親。',48,'全唐诗/poet.song.43000.json','["讒人未投北，君子獨相親。", "歲月驚春晚，壺觴慰我貧。", "松聲風外急，山色雨中新。", "一醉無歸夢，寧論寂寞濱。"]'),
('14a05dcd-7593-4d01-861a-81e3aa191a07','白蓮啟日上人退避長老之命以四韻高之','郭祥正','宋','宋诗','song-poetry','','[]','結宇古城邊，能詩復悟禪。',48,'全唐诗/poet.song.43000.json','["結宇古城邊，能詩復悟禪。", "鉢分摩詰飯，池種遠公蓮。", "竹颭春烟靜，禽歌夜月圓。", "潔身吾有趣，回首謝塵緣。"]'),
('05554880-cdaf-4564-9a0c-b62cde2fdd4d','送李絳伯華戶曹','郭祥正','宋','宋诗','song-poetry','','[]','國士苟微祿，攜家千里行。',48,'全唐诗/poet.song.43000.json','["國士苟微祿，攜家千里行。", "鄉關寒食節，郵舍冷猿聲。", "落日和雲盡，離觴與淚傾。", "銜冤仍送别，何以慰浮生。"]'),
('5fe3f007-d0c9-47e3-ab33-1e72d2adb82f','和石聲叔留題君儀基石亭二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','高才攄遠趣，鑿石架危亭。',48,'全唐诗/poet.song.43000.json','["高才攄遠趣，鑿石架危亭。", "宿鳥依林白，春苗接海青。", "雲光隨箒亂，泉響置琴聽。", "况得少陵句，宜鐫座右屏。"]'),
('a83d23d1-6c81-4aab-85f0-1664570b025a','和石聲叔留題君儀基石亭二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','因山基大石，華榜揭高亭。',48,'全唐诗/poet.song.43000.json','["因山基大石，華榜揭高亭。", "畦稻翻新綠，山嵐浮遠青。", "鳥行雲際度，松籟雨餘聽。", "安得吳生畫，爲予傳小屏。"]'),
('9977eda3-df59-4807-a3c1-80b76db2d445','謝君儀寄新茶二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','建溪春物早，正月有新茶。',48,'全唐诗/poet.song.43000.json','["建溪春物早，正月有新茶。", "得自參軍掾，分來居士家。", "輾開黳玉餅，湯濺白雲花。", "一啜清魂魄，醇醪豈足誇。"]'),
('46f5a55e-c54b-4996-9b4d-d1a2632fbd08','謝君儀寄新茶二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','北苑藏和氣，生成絕品茶。',48,'全唐诗/poet.song.43000.json','["北苑藏和氣，生成絕品茶。", "豈宜分旅館，只合在仙家。", "點處成雲蕊，看時變雪花。", "琳琅得新句，又勝玉川誇。"]'),
('42029b77-9c27-4633-983b-b1128d008427','曉起聞禽寄元輿','郭祥正','宋','宋诗','song-poetry','','[]','幽鳥語清晨，窻間宅禁人。',48,'全唐诗/poet.song.43000.json','["幽鳥語清晨，窻間宅禁人。", "只知添白髮，不覺度青春。", "救過須三省，觀空止一塵。", "賢交如未棄，時送濁醪醇。"]'),
('fa189a3b-d3f3-4a92-94da-6436d30593b0','寒食感懷示子燾二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','柳暗青春暮，鶯啼靜院陰。',48,'全唐诗/poet.song.43000.json','["柳暗青春暮，鶯啼靜院陰。", "鄉關隔寒食，父子共沾襟。", "未舉鵬天翼，聊爲鵩舍吟。", "驚魂招不得，時節感人深。"]'),
('14c39aa7-c6fb-406b-a2db-cce302b3ef91','寒食感懷示子燾二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','寒食金波淚，他鄉此日心。',48,'全唐诗/poet.song.43000.json','["寒食金波淚，他鄉此日心。", "草連天際色，泉斷隴頭音。", "先冢三年别，飛埃萬里侵。", "只憑欹枕夢，時到謝山陰。"]'),
('9551d8f7-9e5c-4f5d-b5a2-54db9716276c','寒食元輿見要南樓把酒','郭祥正','宋','宋诗','song-poetry','','[]','五馬登城堞，平分載酒船。',48,'全唐诗/poet.song.43000.json','["五馬登城堞，平分載酒船。", "無家寒食客，小雨惜花天。", "循撫恩何厚，飄零命最邅。", "閒愁不用遣，一醉暫成仙。"]'),
('1c01116e-9b1e-47b9-b823-96da2d6d812f','夜雨感懷二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','夜雨霪難霽，溝塍復亂蛙。',48,'全唐诗/poet.song.43000.json','["夜雨霪難霽，溝塍復亂蛙。", "輕寒侵病骨，餘響答空階。", "杜子嗟沾濕，莊生失渚涯。", "通宵不成寐，歸思瀉長淮。"]'),
('d7657ea3-05dc-47cc-88b4-0d40f7003d71','夜雨感懷二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','羽毛零落易摧傷，父子同幽瘴癘鄉。',32,'全唐诗/poet.song.43000.json','["羽毛零落易摧傷，父子同幽瘴癘鄉。", "歸夢不成殘夜雨，空階滴滴到愁腸。"]'),
('d33334ea-e276-4779-8465-066172cf7026','憶小子鼎','郭祥正','宋','宋诗','song-poetry','','[]','元朝别家去，音信隔三春。',48,'全唐诗/poet.song.43000.json','["元朝别家去，音信隔三春。", "讀易應終卷，端居莫患貧。", "定交疏燕雀，養節慕松筠。", "冤獄何時辨，思兒淚滿巾。"]'),
('36059e60-4d2b-4344-abdd-7169f1800dc4','排悶呈元輿','郭祥正','宋','宋诗','song-poetry','','[]','交態非今薄，人情自古難。',48,'全唐诗/poet.song.43000.json','["交態非今薄，人情自古難。", "敝裘甘我老，雄劍請君彈。", "魂逐雲峰斷，心依酒海寛。", "百年能幾許，日月似跳丸。"]'),
('70712320-ec34-4762-a897-d0a2901a0346','懷天隲','郭祥正','宋','宋诗','song-poetry','','[]','築室君先隱，窮途我正難。',48,'全唐诗/poet.song.43000.json','["築室君先隱，窮途我正難。", "流鶯春谷暖，别鶴玉琴寒。", "泉響經時聽，雲光抵暮看。", "異方空淚眼，何日共幽歡。"]'),
('2d27e9aa-5ce1-4150-b613-6aef12a7e020','元輿三月三十日致酒','郭祥正','宋','宋诗','song-poetry','','[]','衰病仍爲客，相依過一春。',48,'全唐诗/poet.song.43000.json','["衰病仍爲客，相依過一春。", "和篇驚韻險，把酒沃愁頻。", "紫燕巢方穩，黄鸝語尚新。", "何時公赴召，終欲託車輪。"]'),
('ad546e66-4ad8-4fba-b88d-0e4c9579fbe2','元輿試北苑新茗','郭祥正','宋','宋诗','song-poetry','','[]','建溪雖接壤，春末始嘗茶。',48,'全唐诗/poet.song.43000.json','["建溪雖接壤，春末始嘗茶。", "旋汲鄰僧水，同烹北苑芽。", "月圓龍隱鬣，雲散乳成花。", "貢入明光殿，分來王謝家。"]'),
('4250f2ae-e1b0-4229-af28-3a29501a2afa','别南樓','郭祥正','宋','宋诗','song-poetry','','[]','寄榻六十日，朝朝上碧城。',48,'全唐诗/poet.song.43000.json','["寄榻六十日，朝朝上碧城。", "雲光隨近遠，山色變陰晴。", "濠靜魚頻躍，樓空燕不驚。", "他時那復到，欲去重含情。"]'),
('10e773ea-9ee1-4e36-a839-5e41684b7c77','四月一日','郭祥正','宋','宋诗','song-poetry','','[]','有瘴從今始，斯須雨復晴。',48,'全唐诗/poet.song.43000.json','["有瘴從今始，斯須雨復晴。", "草蒸蛇肆毒，榛密鵩嘗鳴。", "晚食宜防飽，村醪可强傾。", "何時擊歸鐙，高視歎浮生。"]'),
('26e5e4ae-bc57-496d-b23b-fb54066db0f0','别濠上','郭祥正','宋','宋诗','song-poetry','','[]','自得莊生樂，觀魚近碧濠。',48,'全唐诗/poet.song.43000.json','["自得莊生樂，觀魚近碧濠。", "觸萍時鼓鬣，防餌不投刀。", "柳挹春風靜，鷗眠夜月高。", "捨旃吾有適，滄海釣鯨鼇。"]'),
('465bd1b1-ff95-4554-b2a7-aeec8991ddfa','聞舊居敎樂','郭祥正','宋','宋诗','song-poetry','','[]','昔作幽人宅，今爲舞女場。',48,'全唐诗/poet.song.43000.json','["昔作幽人宅，今爲舞女場。", "燕驚弦管雜，草避綺羅香。", "諠靜雖殊致，興衰自有常。", "遙憐巖桂下，誰拂讀書牀。"]'),
('ed3f0650-0ee9-461a-9385-d3cce8231df8','登清音亭二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','已别城樓景，還登樹杪亭。',48,'全唐诗/poet.song.43000.json','["已别城樓景，還登樹杪亭。", "地高鄰北斗，山遠接南溟。", "蟾影依雲斷，樵歌隔浦聽。", "客愁安用遣，此處可忘形。"]'),
('4f08fd57-717d-4326-a4eb-926bbc0f0fe8','登清音亭二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','薄暮杳何適，高高登古亭。',48,'全唐诗/poet.song.43000.json','["薄暮杳何適，高高登古亭。", "地無南國瘴，簾卷半空星。", "石痩長人立，潭春皓雪停。", "短才吟不就，終欲付丹青。"]'),
('b8526f13-4879-4fad-bc47-fbe641b7b03f','雨中懷元輿','郭祥正','宋','宋诗','song-poetry','','[]','暫阻龍山雨，還思鳳閣人。',48,'全唐诗/poet.song.43000.json','["暫阻龍山雨，還思鳳閣人。", "凌雲曾獻賦，薄霧豈藏身。", "酒釀公田秫，羮調紫豉蓴。", "稍晴應見過，酬唱莫辭頻。"]'),
('ceb5ae53-3302-40fb-92c7-93b1f9ccab92','雨晴都按口號呈元輿','郭祥正','宋','宋诗','song-poetry','','[]','雨爲華筵止，晴牽飲興長。',48,'全唐诗/poet.song.43000.json','["雨爲華筵止，晴牽飲興長。", "管弦隨晝永，羅綺散風香。", "衛仗留春碧，宫衣想赭黄。", "明年今日事，歸捧祝堯觴。"]'),
('8e93aa8f-8bec-48c4-b3d6-45fdbce64021','元輿憐我復有漳南之行以麴局不可出遂置一樽託公域弟酌發眷眷之情於此可見矣以四韻謝元輿并呈公域弟','郭祥正','宋','宋诗','song-poetry','','[]','憐我萬里别，南荒多瘴埃。',48,'全唐诗/poet.song.43000.json','["憐我萬里别，南荒多瘴埃。", "身爲官事隔，酒託故人開。", "飲德知難報，論歡默可猜。", "宗家有毛女，冰潔勝寒梅。"]'),
('f06f973f-81de-47f6-ae48-162fe2577924','與元輿論詩而風雨驟至','郭祥正','宋','宋诗','song-poetry','','[]','一作城頭飲，重論别後詩。',48,'全唐诗/poet.song.43000.json','["一作城頭飲，重論别後詩。", "倐然雲雨至，應有鬼神悲。", "敘事公偏富，求聲我最知。", "賡酬三百首，餘韻付咸池。"]'),
('a83d2032-4d35-43b9-9c3c-9e442039767e','元輿近詩加妙用寄四韻','郭祥正','宋','宋诗','song-poetry','','[]','誰識子昂孫，新詩靄暮雲。',48,'全唐诗/poet.song.43000.json','["誰識子昂孫，新詩靄暮雲。", "體兼諸謝備，名與少陵分。", "今去知無敵，從來自出羣。", "南山能射虎，只許李將軍。"]'),
('3ad11af4-86d7-4cc8-89b5-5af0c4d3f434','謝元輿送鮮鯉煮酒','郭祥正','宋','宋诗','song-poetry','','[]','鮮鯉江湖味，香醪日月春。',48,'全唐诗/poet.song.43000.json','["鮮鯉江湖味，香醪日月春。", "撫循時有贈，飽暖遂忘貧。", "玉縷空投筯，金波漫入脣。", "交情今乃見，晚節共松筠。"]'),
('712d0ac6-14da-49b2-a097-a2e6eff24cb4','招孜祐二長老嘗茶二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','無物滋禪味，來烹北苑茶。',48,'全唐诗/poet.song.43000.json','["無物滋禪味，來烹北苑茶。", "碾成雲母粉，香濺碧松花。", "消渴梅何俗，安神术謾誇。", "清談嘗數椀，莫笑老盧家。"]'),
('3c93a2df-58ba-4115-ba16-0285ddaa06a8','招孜祐二長老嘗茶二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','昔人多嗜酒，今我酷憐茶。',48,'全唐诗/poet.song.43000.json','["昔人多嗜酒，今我酷憐茶。", "軟玉裁成餅，輕雲散作花。", "石泉助甘滑，腸胃滌煩邪。", "却怪少陵客，曾無新句誇。"]'),
('b0308210-8844-40a1-95ec-6617b686e54a','追和故友袁世弼酬孜老四韻','郭祥正','宋','宋诗','song-poetry','','[]','坐諷湯休句，閩南朱夏時。',48,'全唐诗/poet.song.43000.json','["坐諷湯休句，閩南朱夏時。", "碧雲生海嶠，清吹散松枝。", "救物寧論報，安禪不履危。", "江東飽芹蕨，肯赴野人期。"]'),
('baed3688-13e3-4045-9f58-9e8839f554c1','寄題建陽王祖聖朝奉南澗樓','郭祥正','宋','宋诗','song-poetry','','[]','郎省辭榮早，樓居鶴髮翁。',48,'全唐诗/poet.song.43000.json','["郎省辭榮早，樓居鶴髮翁。", "響分南澗水，清占北窻風。", "紫府雲常近，黄塵路不通。", "何當陪杖屨，有意學冥鴻。"]'),
('834e9802-3e7f-477b-a11d-e502cc7c5a95','壺公山方卿墓亭','郭祥正','宋','宋诗','song-poetry','','[]','鄞國棠陰在，壺山墓草黄。',48,'全唐诗/poet.song.43000.json','["鄞國棠陰在，壺山墓草黄。", "慶源長不竭，善訓永無忘。", "燕雀春風裏，烟雲碧瓦傍。", "命書何日下，潛德發幽光。"]'),
('b842dfec-776f-4ffc-a0fe-c77aeac42468','至節日君儀見過誦思猿佳作','郭祥正','宋','宋诗','song-poetry','','[]','不赴郡樓宴，能過野寺門。',48,'全唐诗/poet.song.43000.json','["不赴郡樓宴，能過野寺門。", "撫循悲節物，飄泊任乾坤。", "瘴霧經霜盡，溪潮向晚渾。", "思猿有佳作，敢爲倒清樽。"]'),
('2a0035ee-0790-4e02-9bd5-2ebd6b497bdc','雨懷安止三首  其一','郭祥正','宋','宋诗','song-poetry','','[]','春雨霪難霽，春山阻俊游。',48,'全唐诗/poet.song.43000.json','["春雨霪難霽，春山阻俊游。", "綠迷芳草恨，紅濕落花愁。", "古劍空彈鋏，疏簾懶上鈎。", "何當生羽翼，一日似三秋。"]'),
('0e8b976b-d371-4a65-8900-0149e3b827e2','雨懷安止三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','身隔空山雨，心同物外游。',48,'全唐诗/poet.song.43000.json','["身隔空山雨，心同物外游。", "成篇超俗格，開卷釋新愁。", "鸞鳳翔青瑣，蛟鼉掛玉鈎。", "重吟垂翼句，春氣返如秋。"]'),
('27d5d94c-4b5e-43f1-bd80-8a6c980581f6','雨懷安止三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','雨隔陳夫子，僧坊懶獨游。',48,'全唐诗/poet.song.43000.json','["雨隔陳夫子，僧坊懶獨游。", "閉門誰復過，欲語已含愁。", "病翼深防彈，驚鱗遠避鈎。", "交情君勿替，松柏挺霜秋。"]'),
('98036399-0d4d-4b17-b418-a677911870af','聞惠休師將浮海如吳省寶覺禪師','郭祥正','宋','宋诗','song-poetry','','[]','去興已翩翩，輕包赴海船。',48,'全唐诗/poet.song.43000.json','["去興已翩翩，輕包赴海船。", "霧收山翠濕，月出浪華鮮。", "鼓動看風力，浮沈信佛緣。", "何時達鍾阜，重省寶公禪。"]'),
('01353e8f-5065-4afa-b3fd-b70397a1ded5','雨霽懷進醇老','郭祥正','宋','宋诗','song-poetry','','[]','宿雨洗林扃，開窻曉色清。',48,'全唐诗/poet.song.43000.json','["宿雨洗林扃，開窻曉色清。", "池深魚競躍，花落鳥頻驚。", "結友論三益，營居共一城。", "風騷真有意，世事久無情。"]'),
('5fd79679-88d7-4567-9f3b-d75d1a6fea3c','覽進醇老詩卷','郭祥正','宋','宋诗','song-poetry','','[]','羈栖海上州，歲晚得師游。',48,'全唐诗/poet.song.43000.json','["羈栖海上州，歲晚得師游。", "句瀉碧潭月，篇成清夜秋。", "雲根龍洞鏁，花氣蜜房收。", "此理何人達，營營枉白頭。"]'),
('90369a1a-9bd3-4eee-987d-21e205df7e57','同蕭英伯登凈惠寺山亭二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','策杖輕衣愜，凭欄遠目明。',48,'全唐诗/poet.song.43000.json','["策杖輕衣愜，凭欄遠目明。", "清江排暮釣，綠野碎春耕。", "嗜酒今非勇，題詩尚有情。", "薄游攀俊德，唐相舊家聲。"]'),
('44349343-1a8c-4b06-ac27-12565adc7284','同蕭英伯登凈惠寺山亭二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','一徑穿林麓，幽人借杖扶。',48,'全唐诗/poet.song.43000.json','["一徑穿林麓，幽人借杖扶。", "西山螺頂秀，南塔筆鋒孤。", "好鳥當花語，輕烟襯草鋪。", "登臨情未足，暝色欲吞吳。"]'),
('daf16c34-b159-46e4-85d0-9aa5e6fe3d29','又和英伯四首  其一','郭祥正','宋','宋诗','song-poetry','','[]','亭出林巒表，春歸氣象明。',48,'全唐诗/poet.song.43000.json','["亭出林巒表，春歸氣象明。", "江晴稚子浴，田暖老夫耕。", "弱柳禁風力，游絲奈客情。", "欲歸歸未得，愁聽杜鵑聲。"]'),
('01ef9f7e-6961-4be1-8657-11e3b45ea37e','又和英伯四首  其二','郭祥正','宋','宋诗','song-poetry','','[]','野興憐詩逸，春酲要酒扶。',48,'全唐诗/poet.song.43000.json','["野興憐詩逸，春酲要酒扶。", "登臨同俊哲，笑傲不羈孤。", "日落金霞卷，江翻雪浪鋪。", "閩山又寒食，何日到東吳。"]'),
('eb3c25f5-f621-4c70-a41d-a4257e1993c8','又和英伯四首  其三','郭祥正','宋','宋诗','song-poetry','','[]','亭臨天外構，春物望中明。',48,'全唐诗/poet.song.43000.json','["亭臨天外構，春物望中明。", "客興託詩酒，野心憐釣耕。", "露花如有恨，風柳自含情。", "何事子規鳥，故爲腸斷聲。"]'),
('f7fcf0ae-d696-444b-bf20-a3df4269618a','又和英伯四首  其四','郭祥正','宋','宋诗','song-poetry','','[]','開亭當險絕，疑有百神扶。',48,'全唐诗/poet.song.43000.json','["開亭當險絕，疑有百神扶。", "江靜羣鷗集，天空一鶚孤。", "落英紅錦碎，狂絮白氈鋪。", "試問江南信，歸帆至自吳。"]'),
('9a19bed8-ade3-4bc5-b5b7-7c3c0665ceae','送惠休師浮海如吳','郭祥正','宋','宋诗','song-poetry','','[]','游吳興不淺，真欲跨冥鴻。',48,'全唐诗/poet.song.43000.json','["游吳興不淺，真欲跨冥鴻。", "豈畏海波險，自明禪性空。", "柁樓瞻北斗，帆索張東風。", "我欲江南去，音書却易通。"]'),
('ff17df97-be5f-44d2-92b1-310f50d48f65','雨中酌君儀所送酒有懷','郭祥正','宋','宋诗','song-poetry','','[]','冬雷知不密，地震復如何。',48,'全唐诗/poet.song.43000.json','["冬雷知不密，地震復如何。", "海角晴明少，客心憂慮多。", "白鷗欺浪舞，黄鳥挾春歌。", "幸有故人酒，門深掩薜蘿。"]'),
('c8d36fd1-fce3-4f49-9765-03179eadc834','午日送酒與元輿','郭祥正','宋','宋诗','song-poetry','','[]','前歲菖蒲酒，臨汀共一樽。',48,'全唐诗/poet.song.43000.json','["前歲菖蒲酒，臨汀共一樽。", "迴思當觸網，猶有未招魂。", "抱義君偏厚，餘生我尚存。", "都城酬此酌，佳節可重論。"]'),
('992c20ec-b784-4245-b27c-5be30ac79c14','樂游軒呈運使陳大夫','郭祥正','宋','宋诗','song-poetry','','[]','狹徑通蕭寺，牆開薜荔陰。',48,'全唐诗/poet.song.43000.json','["狹徑通蕭寺，牆開薜荔陰。", "坐聞松籟奏，歸待月華沈。", "雅有賢人樂，清無俗坌侵。", "一軒寧久駐，四海望爲霖。"]'),
('93ed4d88-7d2b-4eaf-97ea-e7c73194504d','西池水漫蓮葉資深勸予理之','郭祥正','宋','宋诗','song-poetry','','[]','短短芰荷葉，深深野水漫。',48,'全唐诗/poet.song.43000.json','["短短芰荷葉，深深野水漫。", "何神能止雨，無術理驚湍。", "久客懷三徑，包羞拘一官。", "賞心那復數，歲望骨毛寒。"]'),
('8650f44e-f046-4c8a-abc5-2cc320baf6b2','稍霽二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','稍止今朝雨，猶埋瘴嶺雲。',48,'全唐诗/poet.song.43000.json','["稍止今朝雨，猶埋瘴嶺雲。", "亂流安可塞，故老未嘗聞。", "陰怪羣難數，陽光晚漸分。", "僅能存井邑，不復念耡耘。"]'),
('39150828-a7f8-47ac-86ee-44d60ac37e3d','稍霽二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','霪霖霾晝夜，積潦接郊郛。',48,'全唐诗/poet.song.43000.json','["霪霖霾晝夜，積潦接郊郛。", "小艇家家有，危椽處處扶。", "稍晴人共喜，却暖鳥爭呼。", "海若一何暴，幾翻天地樞。"]'),
('4d4ae097-3263-4a67-807c-d784a2f82efe','自和二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','已喜收微雨，還愁合暮雲。',48,'全唐诗/poet.song.43000.json','["已喜收微雨，還愁合暮雲。", "潮痕殊未減，屋拆厭頻聞。", "天地溟濛內，山川早晚分。", "吾民方乏食，何以慰耕耘。"]'),
('85614013-6f94-4b46-aa80-3e4587710ed0','自和二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','猛風來半夜，駭浪却平郛。',48,'全唐诗/poet.song.43000.json','["猛風來半夜，駭浪却平郛。", "避地憂橋斷，登山借杖扶。", "馬牛真不辨，老稚亂相呼。", "安得瞻晴景，蒼苔繡戶樞。"]'),
('148e8eb8-503d-484d-a481-2692b0fbda26','凈惠橋亭爲水所漂因勸寛老葺之二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','怊悵風兼雨，西橋半夜摧。',48,'全唐诗/poet.song.43000.json','["怊悵風兼雨，西橋半夜摧。", "青龍真變化，白鳥漫驚猜。", "蕩潏無遺跡，登臨不再來。", "道師如好事，重爲購良材。"]'),
('171a7f90-a15c-446e-b75c-e6dd8fd09c22','凈惠橋亭爲水所漂因勸寛老葺之二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','水漲西橋折，重來路已差。',48,'全唐诗/poet.song.43000.json','["水漲西橋折，重來路已差。", "簷牙翻駭浪，石脚没平沙。", "夢想追塵跡，湮沈歎物華。", "何人能起廢，壯觀老禪家。"]'),
('cd2c4d30-1729-4dce-895e-b64da3269bcb','送陳輯都曹致仕還鄉','郭祥正','宋','宋诗','song-poetry','','[]','賦筆驚場屋，高才歎陸沈。',48,'全唐诗/poet.song.43000.json','["賦筆驚場屋，高才歎陸沈。", "宦遊今日盡，野興暮年深。", "黄菊看看秀，青雲處處陰。", "君懷能亢爽，吾意亦侵尋。"]'),
('719b483c-750e-4a49-beff-7c1fb1463a0b','舟經彭澤謁靖節祠','郭祥正','宋','宋诗','song-poetry','','[]','彭澤江邊邑，蕭疏靖節祠。',48,'全唐诗/poet.song.43000.json','["彭澤江邊邑，蕭疏靖節祠。", "烟昏鹿皮畫，草暗菊花籬。", "詠德今千載，言歸彼一時。", "男兒要出處，此道幾人知。"]'),
('f0e4caf3-3cba-4d18-89cd-561b5a47d5b0','竹子灘逢廣漕張公詡二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','泗水初傾蓋，西江再逆舟。',48,'全唐诗/poet.song.43000.json','["泗水初傾蓋，西江再逆舟。", "策能誅賊滅，心不爲身謀。", "夜永談無寐，樽空幸少留。", "遲明還惜别，飛槳下灘頭。"]'),
('f18d316b-a0ac-4edf-b01e-954bffbb89e3','竹子灘逢廣漕張公詡二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','會合嗟無酒，留連漫索茶。',48,'全唐诗/poet.song.43000.json','["會合嗟無酒，留連漫索茶。", "晚雲隨落日，歸雁集寒沙。", "自達聊安命，多言任指瑕。", "吾宗有令弟，恩復出君家。"]'),
('1eb9b378-22f1-45a7-9b60-12e3baedcd22','螺川送别王公濟朝奉還臺','郭祥正','宋','宋诗','song-poetry','','[]','亭上客送客，江頭山映山。',48,'全唐诗/poet.song.43000.json','["亭上客送客，江頭山映山。", "白醪須酌盡，彩鳳欲飛還。", "帆轉疏林外，烟生遠渚間。", "離愁自堆積，輒莫唱陽關。"]'),
('5e9f3742-ed87-49fc-9017-12f4c49957c3','送郭晦叔知海州','郭祥正','宋','宋诗','song-poetry','','[]','凜凜汾陽秀，螺川舊徙居。',48,'全唐诗/poet.song.43000.json','["凜凜汾陽秀，螺川舊徙居。", "文名動場屋，孝節冠鄉閭。", "御史論才久，方州躐等除。", "朝廷終器使，宗廟得璠璵。"]'),
('51a9b442-19c8-4bc3-bba8-742804ce0a56','英州烟雨樓','郭祥正','宋','宋诗','song-poetry','','[]','江路分韶廣，城樓壓郡東。',48,'全唐诗/poet.song.43000.json','["江路分韶廣，城樓壓郡東。", "妓歌星漢上，客醉水雲中。", "潑墨天涵暝，鋪綃月映空。", "登臨逢此景，不復念途窮。"]'),
('cb68efeb-c50e-47c8-8600-ea74cdadd26f','南山禪院','郭祥正','宋','宋诗','song-poetry','','[]','棟宇新成寺，黄金貼翠微。',48,'全唐诗/poet.song.43000.json','["棟宇新成寺，黄金貼翠微。", "山眉一雙碧，江带兩條飛。", "亂石森門戟，晴雲作地衣。", "薫弦誰與奏，松響瀉珠璣。"]'),
('500d1551-e3a6-49cf-9d8e-e5b4010729ad','廖華國史君致酒','郭祥正','宋','宋诗','song-poetry','','[]','飛蓋穿林外，行厨就竹間。',48,'全唐诗/poet.song.43000.json','["飛蓋穿林外，行厨就竹間。", "酒狂思海瀉，歌響遏雲還。", "逸驥方騰躍，疲駑强附攀。", "磨崖記名姓，長伴水潺潺。"]'),
('c1f15458-e79c-45f6-8f6c-5d27157c3e4a','同穎叔修撰游吳圃分得須字','郭祥正','宋','宋诗','song-poetry','','[]','地與浮丘接，花如錦帳鋪。',48,'全唐诗/poet.song.43000.json','["地與浮丘接，花如錦帳鋪。", "杜康傾琥珀，海若獻珊瑚。", "老竹爭抽笋，幽禽自引雛。", "人生行樂爾，富貴亦何須。"]'),
('0f9a041d-8424-45a3-95c4-755602c3dc96','即席和穎叔送别四韻','郭祥正','宋','宋诗','song-poetry','','[]','二月溟濛雨，春寒反似秋。',48,'全唐诗/poet.song.43000.json','["二月溟濛雨，春寒反似秋。", "玉觥浮濁浪，蘭楫擬滄洲。", "自顧駑駘困，寧攀逸驥游。", "楚歌彈未徹，歸思已難留。"]'),
('8db4a105-b9ce-46c4-b48a-17d0956ad401','蔡梧州叙拜禮用四韻謝之兼送别','郭祥正','宋','宋诗','song-poetry','','[]','卓犖金閨客，經過慰老夫。',48,'全唐诗/poet.song.43000.json','["卓犖金閨客，經過慰老夫。", "能當韓子拜，深愧孟生愚。", "開卷詩千首，論交酒一壺。", "春風送和氣，連夜入蒼梧。"]'),
('ce61e4e9-2da5-4be7-8306-e6d4f71a5791','寄東莞李宰宣德','郭祥正','宋','宋诗','song-poetry','','[]','舊交幾人在，寧嫌雙鬢皤。',48,'全唐诗/poet.song.43000.json','["舊交幾人在，寧嫌雙鬢皤。", "一生長作客，九死漫悲歌。", "歲月驚秋速，關山恨别多。", "君須陟臺省，吾欲隱松蘿。"]'),
('c5b9f39c-f14f-42cb-8c63-f7ade9b4dd6c','送象守賈正夫朝奉還臺二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','六載爲南郡，歸時雪滿顛。',48,'全唐诗/poet.song.43000.json','["六載爲南郡，歸時雪滿顛。", "一家纔度嶺，單騎欲朝天。", "介潔終無玷，精神老尚全。", "十分愁别酒，魂斷鵠亭前。"]'),
('0acfb499-ab14-4ebb-a065-3d079da33740','送象守賈正夫朝奉還臺二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','十載音書絕，扁舟忽見過。',48,'全唐诗/poet.song.43000.json','["十載音書絕，扁舟忽見過。", "有樽傾别酒，無妓唱離歌。", "海闊春光少，城空瘴霧多。", "羨君先度嶺，猿叫隔雲蘿。"]'),
('87e31537-af98-44bf-baf4-fb5eeb99200b','追和李白金陵月下懷古','郭祥正','宋','宋诗','song-poetry','','[]','歷覽古都會，金陵冠南州。',72,'全唐诗/poet.song.43000.json','["歷覽古都會，金陵冠南州。", "天開鍾阜倚，江轉玉繩流。", "異代有興廢，前賢歸塚丘。", "草没烏衣巷，塵埋結綺樓。", "城空龍虎踞，臺罷鳳凰游。", "默想秦淮月，曾悲玉樹秋。"]'),
('0a3a8147-db61-409a-b032-e1b74e383659','和穎叔千歲棗','郭祥正','宋','宋诗','song-poetry','','[]','彼美祗園棗，珍同玉井船。',216,'全唐诗/poet.song.43000.json','["彼美祗園棗，珍同玉井船。", "後期千載熟，今日萬珠圓。", "地潤仍依佛，欄深自羃烟。", "結花雖最晚，藏核莫如堅。", "鴨脚看何小，雞頭美未全。", "種來誰共老，服久必成仙。", "大食移根遠，番禺記蒂連。", "舊名稽藥録，新賞著詩編。", "甜出諸餳上，香居百果前。", "黑腰虚羨爾，紅皺豈爲然。", "柔脆憐金鳳，飄零難木綿。", "諷包丹荔賦，精奪寶刀篇。", "靜夜風回海，清秋月蘸天。", "綵山要客集，翠顆繞枝駢。", "邂逅爲公壽，婆娑與世延。", "暮鐘催酒散，嘶馬引旗旋。", "今作中州瑞，原從異國傳。", "何當廣栽植，欲以慰饑年。"]'),
('1bc0f7cd-307e-4895-9899-cf0052ad3685','同穎叔修撰登蕃塔','郭祥正','宋','宋诗','song-poetry','','[]','寶塔疑神運，擎天此柱雄。',120,'全唐诗/poet.song.43000.json','["寶塔疑神運，擎天此柱雄。", "勢分吳越半，影插斗牛中。", "拔地無層限，登霄有路通。", "三城依作鎮，一海自横空。", "禮佛諸蕃異，焚香與漢同。", "祝堯齊北極，望舶請南風。", "瑞氣凝仙露，靈光散玉虹。", "鐸音爭響亮，春色正冲融。", "視筆添清逸，凭欄洗困蒙。", "更當高萬丈，吾欲跨冥鴻。"]'),
('dfe26bc5-bb69-429b-a821-e8fce17eb534','將至歷陽先寄王純父賢守','郭祥正','宋','宋诗','song-poetry','','[]','竹馬交游早，星軺會遇難。',144,'全唐诗/poet.song.43000.json','["竹馬交游早，星軺會遇難。", "行年均坎坷，撫己共悲酸。", "鳳去鍾山暝，龍沉洛水寒。", "朝廷新日月，風俗舊衣冠。", "佳郡分符印，修途振羽翰。", "樽醪千蟻汎，樓瓦萬鱗蟠。", "直節堅逾柏，忠心赤奪丹。", "才華僉論著，功業鼎銘刊。", "賤子初投穽，收身即棄官。", "生涯添鬢雪，歲序走江湍。", "造膝思陳榻，論詩愧杜壇。", "鷦鷯信微物，聊假一枝寛。"]'),
('23f8014d-2d5c-4eda-a721-7b40fb4bce78','鄭致國宣義見過小山留飲敘舊','郭祥正','宋','宋诗','song-poetry','','[]','一見翰林子，悵然懷昨游。',144,'全唐诗/poet.song.43000.json','["一見翰林子，悵然懷昨游。", "盡爲泉下鬼，猶有水中漚。", "屏跡今雖久，驚魂恐未收。", "殘年唯伏枕，幾月不登樓。", "促榻開青眼，論詩慰白頭。", "嶺雲遮薄暑，江雨濕新秋。", "蔬飯慚無味，星軺强少留。", "會難真可惜，老去只添愁。", "明歲聞官滿，高才副帝求。", "功名隨會遇，閥閲暢源流。", "養大應知損，安卑且尚柔。", "不孤將有託，吾說肯虚投。"]'),
('b53fdf4e-2f71-4f1a-b5ed-37ef35fae023','得瑞金暉評上人書因以酬之','郭祥正','宋','宋诗','song-poetry','','[]','野寺三秋别，緘書一度收。',48,'全唐诗/poet.song.43000.json','["野寺三秋别，緘書一度收。", "青開今日眼，白盡昔年頭。", "高義嗟難得，勞生苦遠游。", "新亭名六以，真妄復何求。"]'),
('93cd055c-d396-4374-b2af-c6c177aef518','寄題六以亭','郭祥正','宋','宋诗','song-poetry','','[]','以幻聊觀幻，亭將六以名。',48,'全唐诗/poet.song.43000.json','["以幻聊觀幻，亭將六以名。", "隔林風籟息，滿地月華清。", "不動超千劫，隨緣度一生。", "有時拈榔標，劃斷野泉聲。"]'),
('a8cf7c6b-6b5c-46c7-b189-5e88bff7b411','立夏日示陳安國宣義','郭祥正','宋','宋诗','song-poetry','','[]','昨日春歸盡，輕衣畏暑侵。',48,'全唐诗/poet.song.43000.json','["昨日春歸盡，輕衣畏暑侵。", "落花空眷影，新葉自成陰。", "書永惟便睡，蟬清稍伴吟。", "小團宫様茗，分酌莫辭深。"]'),
('021e1a21-b2b7-41b6-9384-9b72e582eb95','攜酒就陳安國隱居小酌','郭祥正','宋','宋诗','song-poetry','','[]','家住逍遙國，門無車馬音。',48,'全唐诗/poet.song.43000.json','["家住逍遙國，門無車馬音。", "十分消睡茗，一寸已灰心。", "春去花應盡，潮生岸恐沉。", "徑須攜飲具，來傍荔支陰。"]'),
('c6702901-aecf-4afd-8e76-d0bf01288d4c','同崔員外訪陳安國隱居','郭祥正','宋','宋诗','song-poetry','','[]','共出塵埃外，來尋董監家。',48,'全唐诗/poet.song.43000.json','["共出塵埃外，來尋董監家。", "未能穿草屩，且欲駕柴車。", "谷斷雙橋險，門荒一徑斜。", "客心聊爲洗，石鼎煮新茶。"]'),
('850fded0-80a0-4b34-934b-15fceb1ca428','書尋真觀王契元先生祠堂','郭祥正','宋','宋诗','song-poetry','','[]','久悟尋真訣，應爲蜕骨仙。',48,'全唐诗/poet.song.43000.json','["久悟尋真訣，應爲蜕骨仙。", "壽齡過九十，功行滿三千。", "舊話皆如約，知心信有緣。", "相思一盃酒，和淚灑雲泉。"]'),
('29758bd8-1d4e-4299-996e-57f34f7b7b7b','寄九江陶子駿通直','郭祥正','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','家住廬山脚，堂開佚老名。',48,'全唐诗/poet.song.43000.json','["家住廬山脚，堂開佚老名。", "清朝知止足，白髮慰平生。", "日月歸千載，乾坤付一觥。", "曾逢金馬客，喚作小淵明。"]'),
('2d750d9a-5a70-4924-aae0-1d353cfa9a1f','寄題程信叔朝散先墳思成堂歸真亭二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','水聚山仍合，營祠構一堂。',48,'全唐诗/poet.song.43000.json','["水聚山仍合，營祠構一堂。", "丹青瞻邃表，簪笏遍諸郎。", "烟雨和春暝，松篁浥野香。", "命書連歲下，潛德發幽光。"]'),
('f05b0100-05a4-4517-a794-7ea5f660a32f','寄題程信叔朝散先墳思成堂歸真亭二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','世澤從今遠，音容杳莫期。',48,'全唐诗/poet.song.43000.json','["世澤從今遠，音容杳莫期。", "桃源春去後，華表鶴歸時。", "月慘烟雲晦，風生竹樹悲。", "登亭還灑涕，千載景豐碑。"]'),
('71e92f59-2f8a-418e-9972-3ab5703b345a','題趙康州石聲編後','郭祥正','宋','宋诗','song-poetry','','[]','一賊鳴銅鼓，孤城隕使星。',48,'全唐诗/poet.song.43000.json','["一賊鳴銅鼓，孤城隕使星。", "形骸糜矢石，忠義貫丹青。", "皎皎張巡傳，新新李子銘。", "吾詩愧涓滴，何以助南溟。"]'),
('c2e62315-3900-4029-891b-ec07467a17e2','宿廣善院','郭祥正','宋','宋诗','song-poetry','','[]','峻嶺隔人世，深雲藏寶坊。',48,'全唐诗/poet.song.43000.json','["峻嶺隔人世，深雲藏寶坊。", "龍鱗蟠碧瓦，虹影卧雕梁。", "道濟三塗苦，齋餘七日香。", "炎天蚊蚋絕，此地信清凉。"]'),
('12739d0a-3265-462a-9fe5-4c3c1bfe635e','謝賈明叔侍御見過弊廬','郭祥正','宋','宋诗','song-poetry','','[]','不是少陵客，寧煩謝守過。',48,'全唐诗/poet.song.43000.json','["不是少陵客，寧煩謝守過。", "雨昏窮巷柳，風折小池荷。", "至論鏗瓊玉，幽情愛薜蘿。", "朝廷容直道，予亦樂漁蓑。"]'),
('3480c679-b2fa-4ece-97fe-2a6bafccf1ee','和胡與幾承議藏雲山雲際寺留題','郭祥正','宋','宋诗','song-poetry','','[]','山路入雲際，山深雲更深。',48,'全唐诗/poet.song.43000.json','["山路入雲際，山深雲更深。", "老龍方晦角，秀木不依林。", "溪溜冰生面，泉泓月贈心。", "何須長抱石，天下望成霖。"]'),
('c1b18bb6-38bf-430d-9ff9-2ad8c127a2f5','上巳席上有贈','郭祥正','宋','宋诗','song-poetry','','[]','眸子剪秋水，丹青畫不真。',48,'全唐诗/poet.song.43000.json','["眸子剪秋水，丹青畫不真。", "誰知上巳日，忽見澣紗人。", "姑射長留月，桃源别有春。", "地衣新様錦，羅襪不生塵。"]'),
('b5100527-01d4-4da2-acb8-f38328b7c1d8','賈侍御同游石盆寺以白玉船酌酒','郭祥正','宋','宋诗','song-poetry','','[]','共訪青山寺，仍翻白玉船。',48,'全唐诗/poet.song.43000.json','["共訪青山寺，仍翻白玉船。", "不憂身墜馬，先覺口流涎。", "水鏡初涵月，雲峰半倚天。", "新堂雖未就，詩思已飄然。"]'),
('f2d44655-abf7-4573-8d11-2d3ed99f4d25','寄漳州陳昌國解元','郭祥正','宋','宋诗','song-poetry','','[]','爲問陳昌國，醇醪幾度春。',48,'全唐诗/poet.song.43000.json','["爲問陳昌國，醇醪幾度春。", "海中消息斷，枕上夢魂頻。", "舊恨隨流水，新吟待故人。", "何當騎鹿去，重笑九溪濱。"]'),
('f8d46091-b8cb-4357-9b98-408882818776','送褚南翁赴潯幕','郭祥正','宋','宋诗','song-poetry','','[]','學行從來著，官臨益有規。',48,'全唐诗/poet.song.43000.json','["學行從來著，官臨益有規。", "衆人皆信謗，惟我獨無疑。", "萬里還趨幕，三年且待時。", "烟霄歧路在，晚達未爲遲。"]'),
('e2952d41-4910-47fe-9a96-085fb467d8f4','送劉彦思推官','郭祥正','宋','宋诗','song-poetry','','[]','入幕三年久，還家萬里遙。',48,'全唐诗/poet.song.43000.json','["入幕三年久，還家萬里遙。", "道孤誰汲引，政善衆歌謠。", "北夢君方穩，南魂我未招。", "官醪不許買，别恨幾時銷。"]'),
('023b8017-ae09-4cea-a213-3f345fe5ac30','謝倪敦復惠酒','郭祥正','宋','宋诗','song-poetry','','[]','江雨今朝霽，柴門爽氣高。',48,'全唐诗/poet.song.43000.json','["江雨今朝霽，柴門爽氣高。", "病餘逢七夕，書至得雙醪。", "飲德知無盡，論心敢憚勞。", "鳳團分賜茗，持以報詩豪。"]'),
('e7d041b3-558d-461f-abb6-9b2ff14c607d','喜胡展誠改官南歸','郭祥正','宋','宋诗','song-poetry','','[]','聞道扁舟至，南歸得意人。',48,'全唐诗/poet.song.43000.json','["聞道扁舟至，南歸得意人。", "拜官臨百里，增祿慰雙親。", "所養應趨大，能廉不患貧。", "山家一樽酒，聊爲拂京塵。"]'),
('a3dc3866-8046-4136-a3e7-e41bce76748a','何明道宣德話所見龍作四韻志之','郭祥正','宋','宋诗','song-poetry','','[]','跬步雙龍起，驚嗟莫遁藏。',48,'全唐诗/poet.song.43000.json','["跬步雙龍起，驚嗟莫遁藏。", "冰鱗搖白影，火鬣縱紅光。", "穴地遺涎在，排雲曳尾長。", "不逢吳手畫，想詠獨難忘。"]'),
('edb15716-0f9e-47f6-84ff-5b0e91151ecd','送南劍王倅奉議','郭祥正','宋','宋诗','song-poetry','','[]','何幸一身老，親逢三世賢。',48,'全唐诗/poet.song.43000.json','["何幸一身老，親逢三世賢。", "文章吾已盡，閥閲爾能傳。", "歸劍光生夜，層樓影插天。", "課書登善最，漢殿席應前。"]'),
('5077fb98-9770-44aa-8b43-70b5b1335bb1','和劉漢陽見寄郎官湖佳作','郭祥正','宋','宋诗','song-poetry','','[]','出郭湖光滿，轉山湖影凉。',48,'全唐诗/poet.song.43000.json','["出郭湖光滿，轉山湖影凉。", "得名因太白，起廢自劉郎。", "石鏡三更見，荷花一丈長。", "客來籌往事，蘭草死猶香。"]'),
('5764b0d2-d2e0-4ab9-8ea3-acd0936e519a','和劉漢陽浩然亭','郭祥正','宋','宋诗','song-poetry','','[]','磴道通絕頂，登臨懷弊廬。',48,'全唐诗/poet.song.43000.json','["磴道通絕頂，登臨懷弊廬。", "山雲數峰斷，江樹一行疏。", "舊史名空在，新亭畫不如。", "自迷姑孰釣，深愧漢陽書。"]'),
('cd8240a6-4761-4d92-b44d-38df1c4427e7','雨中懷倪敦復因以密雲團寄之二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','曲巷無人至，幽居覺日長。',48,'全唐诗/poet.song.43000.json','["曲巷無人至，幽居覺日長。", "數聲猜舊燕，一縷惜殘香。", "著雨花枝困，欹風柳带忙。", "夢魂招不得，惟是到君傍。"]'),
('bb457c4c-a5f6-4ff2-9a2d-5f2fd4be4120','雨中懷倪敦復因以密雲團寄之二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','三載久相依，看看歎别離。',48,'全唐诗/poet.song.43000.json','["三載久相依，看看歎别離。", "可堪江雨隔，空對野梅悲。", "息跡無人問，因禪與物違。", "密雲新様茗，封送習家池。"]'),
('bd4b4202-463f-43a4-9b92-22d2f6b240f3','和朱行中龍圖游澄惠寺','郭祥正','宋','宋诗','song-poetry','','[]','一水碧漪漪，更逢烟雨微。',48,'全唐诗/poet.song.43000.json','["一水碧漪漪，更逢烟雨微。", "草昏千步障，松掛六銖衣。", "冷翠光爭滴，殘紅濕不飛。", "自憐詩句拙，空伴史君歸。"]'),
('5262c061-372b-47a5-a178-5144f1ed2b5c','夏寒','郭祥正','宋','宋诗','song-poetry','','[]','三伏當炎熱，翻如九月天。',48,'全唐诗/poet.song.43000.json','["三伏當炎熱，翻如九月天。", "晨興重衣裌，夜宿盡防川。", "船撼江聲怒，樓侵雨氣纒。", "白頭悲世態，何以度殘年。"]'),
('d5c4ac1e-b829-4c54-adfe-1d123cbee4b2','元輿待制招飲衣錦亭','郭祥正','宋','宋诗','song-poetry','','[]','宿雨消殘暑，嘶蟬引素秋。',48,'全唐诗/poet.song.43000.json','["宿雨消殘暑，嘶蟬引素秋。", "吟悲宋玉賦，醉倚仲宣樓。", "衣錦平時樂，藏舟戰國愁。", "蜀山斜照盡，歸興尚遲留。"]'),
('29df4266-34fd-4743-8aef-cc1a1587692c','元輿待制藏舟浦宴集','郭祥正','宋','宋诗','song-poetry','','[]','聖世銷兵久，樓船不復藏。',48,'全唐诗/poet.song.43000.json','["聖世銷兵久，樓船不復藏。", "清瀾浮桂檝，紅袖薦瑤觴。", "荇菜風牽碧，荷花雨迸香。", "孔融真愛士，寧厭禰生狂。"]'),
('c80fa86d-26d0-4bf4-bdb0-0544d0bc68d6','合肥逢清璉上人','郭祥正','宋','宋诗','song-poetry','','[]','閩國衣冠後，羌廬法性師。',48,'全唐诗/poet.song.43000.json','["閩國衣冠後，羌廬法性師。", "江河傾辨說，冰雪凈容儀。", "塔影龍蛇護，松聲猿鶴悲。", "門人忽相過，話舊涕空垂。"]'),
('664d8e6e-5380-4b15-8694-22cd68df7529','癸酉除夜呈鄰舍劉秀才','郭祥正','宋','宋诗','song-poetry','','[]','六十明朝是，今年此夜除。',48,'全唐诗/poet.song.43000.json','["六十明朝是，今年此夜除。", "勞生一樽酒，陳事數行書。", "臘逐燈缸盡，春回律管初。", "不愁家信斷，安穩藉鄰居。"]'),
('c0231e55-1e20-46cd-b58d-800173ede26f','夜泛麻湖','郭祥正','宋','宋诗','song-poetry','','[]','片片冰消後，盈盈月落初。',48,'全唐诗/poet.song.43000.json','["片片冰消後，盈盈月落初。", "舟輕風勢急，水闊雁鳴疏。", "生事長飄泊，愁懷自卷舒。", "還憑過江夢，一爲省吾廬。"]'),
('c73eccac-1164-4266-af2e-20e4f0a0f459','保寧寺靜軒','郭祥正','宋','宋诗','song-poetry','','[]','隱几得真樂，此軒深復深。',48,'全唐诗/poet.song.43000.json','["隱几得真樂，此軒深復深。", "衆喧從過耳，一法不關心。", "雨止溪添漲，風行竹亂陰。", "誰云非對動，吾欲寫瑤琴。"]'),
('4fcbe24e-b1e2-4c81-bd98-458f141624a1','風','郭祥正','宋','宋诗','song-poetry','','[]','颯颯來何處，空巖虎一聲。',48,'全唐诗/poet.song.43000.json','["颯颯來何處，空巖虎一聲。", "蕩搖神女態，飄忽楚王情。", "有力疇能禦，無根長自生。", "掃除天際霧，爲放日車明。"]'),
('b60c7d67-7c64-48e3-b38c-653ae1e9dc41','冬夜泊金山','郭祥正','宋','宋诗','song-poetry','','[]','寒野雲陰重，新冬客意忙。',48,'全唐诗/poet.song.43000.json','["寒野雲陰重，新冬客意忙。", "道途無處盡，歲月有時長。", "流落隨江海，崩騰避雪霜。", "還投白蓮社，清凈萬緣忘。"]'),
('342369de-0e1f-47f7-8bcb-bd8c682d9592','寄致政徐丞二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','爲問徐夫子，歸歟樂幾何。',48,'全唐诗/poet.song.43000.json','["爲問徐夫子，歸歟樂幾何。", "宦情今日盡，野興與雲多。", "供佛延親壽，開樽許客過。", "終期卜鄰去，松下接長哦。"]'),
('c61e3282-03f8-480d-9493-f08ee48e7adf','寄致政徐丞二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','爲問徐夫子，身閒心若閒。',48,'全唐诗/poet.song.43000.json','["爲問徐夫子，身閒心若閒。", "一樽陶令酒，十頃謝家山。", "雲外冥鴻去，松顛獨鶴還。", "令人起高興，從此卜追攀。"]'),
('71ad6d54-6b1f-486a-8c76-e78c1ec5d081','送叔父入川','郭祥正','宋','宋诗','song-poetry','','[]','霰雪滿江海，破帆風易吹。',48,'全唐诗/poet.song.43000.json','["霰雪滿江海，破帆風易吹。", "從今孤鳥興，不及共巢時。", "讒謗寧須辨，神明豈易欺。", "峽山雲木老，莫動故園悲。"]'),
('c7459e33-b881-4442-9aa8-7f48e6cfec05','送人赴巫山尉','郭祥正','宋','宋诗','song-poetry','','[]','薄宦杳何所，令人重别離。',48,'全唐诗/poet.song.43000.json','["薄宦杳何所，令人重别離。", "暮天歸鳥盡，濕櫓渡江遲。", "神女十分色，襄王萬古悲。", "到官無盜賊，覽古數題詩。"]'),
('9a30d0f5-9e97-4b1b-b372-bf472413fe47','送許秀才二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','許子來何謂，還家興未忘。',48,'全唐诗/poet.song.43000.json','["許子來何謂，還家興未忘。", "青山聊自愛，白路不知長。", "皓雪飄詩句，寒星動劍鋩。", "嗟予倦塵俗，無術接翺翔。"]'),
('36f4a772-a8d2-4bfb-a69f-34e8500f15a6','送許秀才二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','西風吹落葉，片片旅人心。',48,'全唐诗/poet.song.43000.json','["西風吹落葉，片片旅人心。", "半夜有歸興，明朝雪滿簪。", "濁醪聊惜别，精藝少知音。", "草店青山外，解鞍孤月沉。"]'),
('3090a836-f8b2-4325-9158-28c3c885f607','送衡武陵赴闕','郭祥正','宋','宋诗','song-poetry','','[]','夫君老文學，國士盡知音。',48,'全唐诗/poet.song.43000.json','["夫君老文學，國士盡知音。", "往奏相如賦，休憐阮籍吟。", "一樽江上酒，千里日邊心。", "人問武陵事，桃花春水深。"]'),
('99f651ea-3f7e-448e-ad07-6b95ebb12ca5','采石觀','郭祥正','宋','宋诗','song-poetry','','[]','江水流環合，山形到此孤。',48,'全唐诗/poet.song.43000.json','["江水流環合，山形到此孤。", "突然樓閣聳，疑有鬼神扶。", "門外橋蹤在，沙邊王氣無。", "我來何所得，石上採菖蒲。"]'),
('2f60c32e-0683-4b0e-9133-7c9ac7be0b6f','康王觀','郭祥正','宋','宋诗','song-poetry','','[]','路絕蒼崖險，橋横大壑飛。',48,'全唐诗/poet.song.43000.json','["路絕蒼崖險，橋横大壑飛。", "花殘啼鳥去，雲重老龍歸。", "劍珮塵埃化，冠纓繪塑非。", "客來空悵望，魂斷夕陽西。"]'),
('2d3d645c-dfe1-4dcc-a2c1-afb01431927c','三妓顧予幽獨戲作四韻','郭祥正','宋','宋诗','song-poetry','','[]','忤俗遭羅網，何緣即掛冠。',48,'全唐诗/poet.song.43000.json','["忤俗遭羅網，何緣即掛冠。", "閉門誰復過，獨酌豈成歡。", "客久添衰疾，春餘尚苦寒。", "幽花雖入眼，不似故園看。"]'),
('f9ab5402-7a55-4aa2-93e3-f6d4ac8698ff','贈臨江守范希遠龍圖','郭祥正','宋','宋诗','song-poetry','','[]','傾蓋相逢晚，開樽上小樓。',168,'全唐诗/poet.song.43000.json','["傾蓋相逢晚，開樽上小樓。", "感時心尚壯，欲語涕難收。", "神主方思治，英才悉應求。", "邦畿分使節，玉陛邇宸旒。", "溫密親聞詔，精忠屢獻謀。", "養兵能足食，行縣必寛囚。", "舜日期無盡，堯雲遽莫留。", "鼎湖龍化影，銀海雁沈秋。", "事畢身先貶，名高衆所尤。", "一麾甘去國，千里謾承流。", "兄弟皆朱紱，雙親未白頭。", "遭讒雖坎坷，安命亦優游。", "雪意饒冬暖，灘聲奈客愁。", "須君作霖雨，終附濟川舟。"]'),
('6822ce5c-e81c-4a47-83a8-7f08116a36e2','淮南韓魏公新祠','郭祥正','宋','宋诗','song-poetry','','[]','新祠重見舊風標，儀鳳無聲立紫霄。',64,'全唐诗/poet.song.43000.json','["新祠重見舊風標，儀鳳無聲立紫霄。", "富貴榮華垂四紀，功名事跡冠三朝。", "月移簾影燈長在，春散庭陰木未喬。", "何獨斯民懷惠愛，帝詞天篆刻琨瑤。"]'),
('eee1b13f-8ca3-4b51-9190-f505e67ada31','韶州唐張文獻公祠堂','郭祥正','宋','宋诗','song-poetry','','[]','文獻頎頎學問該，可憐爲相遇嫌猜。',64,'全唐诗/poet.song.43000.json','["文獻頎頎學問該，可憐爲相遇嫌猜。", "當年致主陳金鏡，後世空祠見鐵胎。", "武水直疑龍卧久，韶山時想鶴歸來。", "我朝繼有襄公出，誰道南方乏美材。"]'),
('a8b9dac8-87ac-425b-b167-7f1b3fd365f2','謝發運穎叔寵寄新什','郭祥正','宋','宋诗','song-poetry','','[]','春風冉冉送流年，一望雲霄一慘然。',64,'全唐诗/poet.song.43000.json','["春風冉冉送流年，一望雲霄一慘然。", "帝閣輟才聞出使，漁蓑終老不成仙。", "已甘荆棘填靈府，想見蛟龍走蜀牋。", "正是水深波浪闊，忽逢高雁寄華篇。"]'),
('180a5a06-e25a-4c8e-b21e-2dddbf3b3dc0','陳秀才惠示長歌答以四韻','郭祥正','宋','宋诗','song-poetry','','[]','世路飄零久愈羞，詩壇誰許結英游。',64,'全唐诗/poet.song.43000.json','["世路飄零久愈羞，詩壇誰許結英游。", "身留海上三年夢，心寄江南一葉秋。", "已分羽毛藏枳棘，儘從讒謗起戈矛。", "真才合比驪珠貴，何事傾懷輒暗投。"]'),
('bfb30d67-c6ff-49df-8101-98c4836dfe71','和君儀感時書事','郭祥正','宋','宋诗','song-poetry','','[]','海角逢春仔細看，一番鶯燕展輕翰。',64,'全唐诗/poet.song.43000.json','["海角逢春仔細看，一番鶯燕展輕翰。", "約風柳带金爭軟，着雨梨花玉鬭寒。", "隴笛不知何處咽，秦箏着意爲誰彈。", "留郎更賦多情曲，直欲豪華將杜壇。"]'),
('bc25e1b0-ec78-4b33-8616-3c777bf1d878','阮希聖新軒即席兼呈同會君儀温老三首  其一','郭祥正','宋','宋诗','song-poetry','','[]','阮軒要客暮春時，淡蕩晴絲日正遲。',64,'全唐诗/poet.song.43000.json','["阮軒要客暮春時，淡蕩晴絲日正遲。", "出屋花光紅瑪瑙，隔湖山色碧琉璃。", "老榕垂幹侵疏箔，新鴨呼雛過短籬。", "我欲高吟還閣筆，坐中留蔡總能詩。"]'),
('4e1d3ce5-0c17-4e7a-8152-93dd2913b2ed','阮希聖新軒即席兼呈同會君儀温老三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','海邊邂逅禁烟時，選勝攜壺不可遲。',64,'全唐诗/poet.song.43000.json','["海邊邂逅禁烟時，選勝攜壺不可遲。", "日射山光如琥珀，水涵天影似琉璃。", "蝶隨柳絮翻羅幕，人並桃花映竹籬。", "却憶綠槐陰下坐，曾尋宫葉爲題詩。"]'),
('7319d135-a487-4c06-a59f-1fac39c0b060','阮希聖新軒即席兼呈同會君儀温老三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','誰憐齟齬老明時，把酒尋春已恨遲。',64,'全唐诗/poet.song.43000.json','["誰憐齟齬老明時，把酒尋春已恨遲。", "舟漾綠波飛舴艋，烟籠青瓦濕琉璃。", "狂嗟李白驅鯨海，醉笑陶潛倚菊籬。", "爭似隔林聞一曲，與君重賦杜秋詩。"]'),
('92df293a-fec9-4311-8d84-197c5eb52215','聞陳伯育結綵舟行樂游湖戲寄三首  其一','郭祥正','宋','宋诗','song-poetry','','[]','湖波渺渺浸殘春，東郭開筵迥不羣。',64,'全唐诗/poet.song.43000.json','["湖波渺渺浸殘春，東郭開筵迥不羣。", "聞結綵舟撐碧落，更攜簫鼓度青春。", "自憐玉海終無敵，却憶瓊漿竟未分。", "珠履難陪空悵望，且憑詩句張吾軍。"]'),
('1ba735f9-e0b0-4119-98ff-6f7125b89022','聞陳伯育結綵舟行樂游湖戲寄三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','東陳風義舊傳聞，鵰鶚鸞凰果逸羣。',64,'全唐诗/poet.song.43000.json','["東陳風義舊傳聞，鵰鶚鸞凰果逸羣。", "青竹題詩才倚馬，畫船槌鼓氣凌雲。", "賞心自向明時得，樂事應容下客分。", "敵飲會須翻玉海，背河決勝看齊軍。"]'),
('a62fad71-bff5-4b22-b1d5-3d858017a449','聞陳伯育結綵舟行樂游湖戲寄三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','臨漳多士冠南閩，况復高才更出羣。',64,'全唐诗/poet.song.43000.json','["臨漳多士冠南閩，况復高才更出羣。", "筆下文章翻錦繡，坐中談笑領風雲。", "美名合預青錢選，邪黨今從白眼分。", "聞欲高亭張雅宴，寂寥應憫舊將軍。"]'),
('8c004940-d98b-4ee6-bf04-0123f15a8296','次韻君儀風物可愛之什','郭祥正','宋','宋诗','song-poetry','','[]','二月風光着意看，莫思旅食久艱難。',64,'全唐诗/poet.song.43000.json','["二月風光着意看，莫思旅食久艱難。", "林間鶯喜綿蠻語，水畔花愁料峭寒。", "遊子牽衣攔道飲，美人攜瑟上樓彈。", "少陵野老誰能繼，君有新詩合築壇。"]'),
('c77e9f40-c60c-4345-b08a-5ab4f2c223fe','凈惠山亭要客致酒','郭祥正','宋','宋诗','song-poetry','','[]','何處要賓入醉鄉，窣雲亭榭冠南漳。',64,'全唐诗/poet.song.43000.json','["何處要賓入醉鄉，窣雲亭榭冠南漳。", "城隨山阜龍蛇轉，花覆園林錦繡香。", "三月風光聊酩酊，百年人世少康强。", "採薇甘餓簞瓢樂，安用須爲畫省郎。"]'),
('751c6590-2ab4-4007-b091-e6a087fe5892','感懷寄泉守陳君舉大夫','郭祥正','宋','宋诗','song-poetry','','[]','柴門永日淚沾巾，事與心違漸失真。',64,'全唐诗/poet.song.43000.json','["柴門永日淚沾巾，事與心違漸失真。", "家住江南幾萬里，身留海上巳三春。", "明時枉作銜冤客，皓首翻爲哭子人。", "多謝泉州賢府主，數將書札問悲辛。"]'),
('5d137f9d-e352-4547-bd68-8fa1b432f82c','再和阮軒即事','郭祥正','宋','宋诗','song-poetry','','[]','遊人隨處踏青時，日永天低樂奏遲。',64,'全唐诗/poet.song.43000.json','["遊人隨處踏青時，日永天低樂奏遲。", "水上往還多翠碧，盤中光潔盡琉璃。", "重山複嶺爭侵戶，淺杏深桃半出籬。", "正是鮮春堪愛惜，勸君莫作送春詩。"]'),
('3d4331d0-0973-4153-8898-316378715b81','和君儀高明軒','郭祥正','宋','宋诗','song-poetry','','[]','一軒華榜揭高明，簷角昭昭掛日星。',64,'全唐诗/poet.song.43000.json','["一軒華榜揭高明，簷角昭昭掛日星。", "鷗鷺翩翻下空渚，雲烟時復起中庭。", "長蘿却覆鮫綃帳，遠岫爭開翡翠屏。", "香篆半銷塵念息，始知天地一浮萍。"]'),
('db860523-6e91-4735-b615-b15d1b8c381c','攜茶訪徐彥醇助敎','郭祥正','宋','宋诗','song-poetry','','[]','蓬蓽蕭然一畝宫，生涯四壁有清風。',64,'全唐诗/poet.song.43000.json','["蓬蓽蕭然一畝宫，生涯四壁有清風。", "鄉閭高行終無玷，場屋遺才誤至公。", "書卷五車心盡記，年華八十耳猶聰。", "滿杯雪液聊分酌，别後音塵豈易通。"]'),
('f9a9c87f-3143-44d4-9270-db5ae9538eb3','送饒守李澤民承議','郭祥正','宋','宋诗','song-poetry','','[]','傾蓋論心古亦難，詞源向我瀉潺潺。',64,'全唐诗/poet.song.43000.json','["傾蓋論心古亦難，詞源向我瀉潺潺。", "番川共惜顔公去，漢室誰憎賈傅還。", "莫遣塵埃侵鬢髮，且張圖畫對雲山。", "何時樽酒重相遇，魏北江東落照間。"]'),
('7bc17486-c5d4-462d-b352-9c4ec0931340','南樓有懷元輿','郭祥正','宋','宋诗','song-poetry','','[]','且欲臨高遣百憂，故攜笻杖立城頭。',64,'全唐诗/poet.song.43000.json','["且欲臨高遣百憂，故攜笻杖立城頭。", "田家隔水犬吠犬，天氣新晴鳩喚鳩。", "靡迤物華春又盡，紛霏塵事老何求。", "史君閒暇須遊樂，莫爲愁人罷樂遊。"]'),
('f5e55e0d-7f3e-406c-9272-1fa5b3f98700','次韻元輿言懷','郭祥正','宋','宋诗','song-poetry','','[]','與君交臂每忘憂，用即三公尚黑頭。',64,'全唐诗/poet.song.43000.json','["與君交臂每忘憂，用即三公尚黑頭。", "美化流行非乳虎，新詩老重似雎鳩。", "篋中璣貝方論價，江上田園未足求。", "信道斵輪真妙手，只慚縲紲玷英游。"]'),
('1c07d134-0127-4f04-a4f3-9fd50e326ee2','臨江春晚','郭祥正','宋','宋诗','song-poetry','','[]','黯淡陰晴閣雨天，清明將近見鞦韆。',64,'全唐诗/poet.song.43000.json','["黯淡陰晴閣雨天，清明將近見鞦韆。", "風高喬木鶯初囀，水暖平沙鷺鬭眠。", "身計只知憂陷穽，年華豈解老神仙。", "迢迢歸路三千里，始信家書直萬錢。"]'),
('f69712d4-a2a1-4d6c-a9da-677d3d692c96','次韻元輿臨汀書事三首  其一','郭祥正','宋','宋诗','song-poetry','','[]','福撫開山罷戍兵，我朝仁澤始流行。',64,'全唐诗/poet.song.43000.json','["福撫開山罷戍兵，我朝仁澤始流行。", "嵐烟蒸濕同梅嶺，地脈逶迤接贛城。", "花木藏春先臘拆，兒童要壽半巖名。", "如今太守真黄霸，里巷歌謠善治聲。"]'),
('f4ce27aa-12a6-402b-856b-36e9684d907b','次韻元輿臨汀書事三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','碧瓦參差幾萬間，重樓複閣更回環。',64,'全唐诗/poet.song.43000.json','["碧瓦參差幾萬間，重樓複閣更回環。", "城池影浸水邊水，鼓角聲傳山外山。", "鑿落鬭傾元弛禁，鞦韆爭蹴未容閒。", "史君得意同民樂，日擁笙歌倒醉顔。"]'),
('e03e2cbc-7190-4e2c-b4e6-72ff08941128','次韻元輿臨汀書事三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','近郭溪山最可遊，雨晴天氣返如秋。',64,'全唐诗/poet.song.43000.json','["近郭溪山最可遊，雨晴天氣返如秋。", "人攜羽扇防濃霧，馬惜韉泥涉淺流。", "竹葉要翻金盞底，梨花偏稱玉釵頭。", "卧龍勝事堪圖畫，迥壓閩南七八州。"]'),
('b3cc26cf-e335-4ede-8525-23895e6b32d5','雨中南樓望西方僧舍要元輿同賦','郭祥正','宋','宋诗','song-poetry','','[]','殘春絲雨洗氛埃，一日重城望數回。',64,'全唐诗/poet.song.43000.json','["殘春絲雨洗氛埃，一日重城望數回。", "熟色淺深添草樹，輕綃高下覆樓臺。", "溪聲遠與鐘聲雜，山影分從電影開。", "不得畫工如立本，史君吟寫最多才。"]'),
('fe1ab237-5a23-4e0b-9dd1-43aa48cba5cc','東郊','郭祥正','宋','宋诗','song-poetry','','[]','東郊悵望惜春歸，頗覺年來萬事非。',64,'全唐诗/poet.song.43000.json','["東郊悵望惜春歸，頗覺年來萬事非。", "不奈離愁須覓酒，得聞歌響却沾衣。", "蜜蜂捕蕊穿花去，巢燕尋泥拍水飛。", "物態風光能幾許，老無憂患世人稀。"]'),
('947f3cd3-7d64-4748-8c61-dd4b15a52042','雨霽','郭祥正','宋','宋诗','song-poetry','','[]','今朝晴日照柴扉，即看輕雲捲翠微。',64,'全唐诗/poet.song.43000.json','["今朝晴日照柴扉，即看輕雲捲翠微。", "燕子有情歸舊棟，柳條牽恨拂征衣。", "故鄉書信何時到，瘴地烟嵐此處稀。", "白酒一盃聊强飲，物情人事恐相違。"]'),
('979432b7-fd84-4660-9892-9d2ec5bf0ae2','白蓮院觀蔡君謨要師遺跡','郭祥正','宋','宋诗','song-poetry','','[]','盤屈龍蛇未奮身，老禪當日亦知人。',64,'全唐诗/poet.song.43000.json','["盤屈龍蛇未奮身，老禪當日亦知人。", "來趨蓮幙文章客，去作金鑾侍從臣。", "物外論交終不泯，壁間題字尚如新。", "年年楊柳春先綠，誰復多情與望春。"]'),
('5314859b-33f8-48ba-9496-eb031f0e535a','開元客館','郭祥正','宋','宋诗','song-poetry','','[]','裂瓦欹椽五六間，地形高下頗依山。',64,'全唐诗/poet.song.43000.json','["裂瓦欹椽五六間，地形高下頗依山。", "黄鸝相應雨初過，綠樹成陰春已還。", "土竈有烟營飯飽，柴門無客任苔斑。", "却思一釣滄浪去，蘋葉蓼花相伴閒。"]'),
('6a70c914-6a49-4535-80e3-d578184675ae','開元禪寺','郭祥正','宋','宋诗','song-poetry','','[]','三寺參差見刹竿，開元形勝據龍蟠。',64,'全唐诗/poet.song.43000.json','["三寺參差見刹竿，開元形勝據龍蟠。", "樓臺影落青霄險，鐘磬聲傳碧澗寒。", "物物有緣香供盛，塵塵無礙法筵寛。", "欲隨大士披華藏，北斗容身不亦難。"]'),
('5cbb249c-fb72-49b5-b0ca-a12060e42e81','次韻元與雨中見懷二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','屋漏沿窻玉篆斜，索居蒸濕度年華。',64,'全唐诗/poet.song.43000.json','["屋漏沿窻玉篆斜，索居蒸濕度年華。", "銜冤欲訴中都獄，抱義難酬漂母家。", "地隔五湖秋雁絕，草荒三徑曉猿嗟。", "幸君數送瓊瑤句，枯枿蒙春亦吐花。"]'),
('d9a828a9-8960-4efb-b0a2-8b96ec61a547','次韻元與雨中見懷二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','雨鏁柴門一徑斜，詩筒時復覘英華。',64,'全唐诗/poet.song.43000.json','["雨鏁柴門一徑斜，詩筒時復覘英華。", "自憐白髮非商叟，却對青山憶謝家。", "卞玉逢知終薦達，隋珠投暗只驚嗟。", "悲歌半夜彈雄劍，恨血千年變土花。"]'),
('04d73494-f657-4fa3-832a-2e0cac2e4d42','小閣夜眺','郭祥正','宋','宋诗','song-poetry','','[]','白日塵寰憂思深，夜登危閣解煩襟。',64,'全唐诗/poet.song.43000.json','["白日塵寰憂思深，夜登危閣解煩襟。", "空江雲盡月涵璧，絕壑風生松奏琴。", "佳客不來分坐賞，濁醪誰爲此時斟。", "疏鐘輒莫催清曉，吾欲凭欄更一吟。"]'),
('f49bda3e-7c93-4704-87cb-1c75c2cc621f','南山晚步簡自宣長老','郭祥正','宋','宋诗','song-poetry','','[]','雨過南山紫翠深，團團仙露灑衣襟。',64,'全唐诗/poet.song.43000.json','["雨過南山紫翠深，團團仙露灑衣襟。", "碧雲影裏寒猿嘯，玉澗聲中怨鶴吟。", "期赴前林同茗酌，倦投盤石揀蘿陰。", "憑誰寄語謝康樂，安用披榛故遠尋。"]'),
('e947409c-24da-4b90-9d73-cc8c999f4e04','次韻元輿題王祖聖南澗樓清斯亭二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','平昔朱衣駕兩轓，高樓歸隱卧雲泉。',64,'全唐诗/poet.song.43000.json','["平昔朱衣駕兩轓，高樓歸隱卧雲泉。", "文章未許矜盤谷，水墨無勞畫輞川。", "春日半晴花照地，秋風入夜雁連天。", "燒丹辟穀非吾事，能遠塵寰即是仙。"]'),
('c16f38dc-df8b-4edd-a138-1d0e3b80e435','次韻元輿題王祖聖南澗樓清斯亭二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','松徑沿溪溪水深，水光澄碧倒松陰。',64,'全唐诗/poet.song.43000.json','["松徑沿溪溪水深，水光澄碧倒松陰。", "浮盃可酌劉伶酒，坐石仍彈靖節琴。", "無數輕鷗隨出處，幾番佳客伴登臨。", "自嗟羅網何時脱，往濯塵纓爲一吟。"]'),
('d9b86526-4990-4127-9dd2-a420ea9276de','贈武平許令','郭祥正','宋','宋诗','song-poetry','','[]','昔拜先翁匯水濱，存亡回首幾經春。',64,'全唐诗/poet.song.43000.json','["昔拜先翁匯水濱，存亡回首幾經春。", "鳳毛今喜爲花縣，鶴髮誰嗟困客塵。", "篋有贈篇長取讀，心藏遺德尚如新。", "源源世澤來無盡，桂籍傳家已四人。"]'),
('2ff024d8-89d7-49df-853a-e1f4c4a1a8fb','遷居西湖普賢院寄自省上人','郭祥正','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十畝方塘四岸榕，夕陽初盡月生東。',64,'全唐诗/poet.song.43000.json','["十畝方塘四岸榕，夕陽初盡月生東。", "不嫌瘴地無家别，猶喜山房有路通。", "寧使五塵長我縛，得超三界與師同。", "遷居却作安居計，病入殘年兩耳聾。"]'),
('c5f9221a-6955-4c29-bab2-365899382a73','夢遊金山作四韻既覺止記一聯因足成之','郭祥正','宋','宋诗','song-poetry','','[]','珠簾高卷倚危欄，望盡方知出世間。',64,'全唐诗/poet.song.43000.json','["珠簾高卷倚危欄，望盡方知出世間。", "江海交流雲縹緲，樓臺相映月回環。", "薰成香界渾無地，化作天宫别有山。", "京口瓜洲竟安在，夢醒却欲泛舟還。"]'),
('88c18ecf-a3b1-4b06-a850-bfdd895280e7','次韻無逸長老秋居見寄','郭祥正','宋','宋诗','song-poetry','','[]','榕樹蕭蕭一徑深，門庭秋靜紫苔侵。',64,'全唐诗/poet.song.43000.json','["榕樹蕭蕭一徑深，門庭秋靜紫苔侵。", "能依幻質循元覺，默運真悲拔衆沈。", "有想願分香界飯，忘言求出世間心。", "旃檀謾把爐中爇，無盡無邊結寶陰。"]'),
('bbfc5d11-8aed-4cd0-80d9-5bb75d20ce29','追和紫霞翁記夢二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','乘雲親到紫皇家，不是人間舊物華。',64,'全唐诗/poet.song.43000.json','["乘雲親到紫皇家，不是人間舊物華。", "四座散香春結蓋，一墀栽玉曉生花。", "入盤仙李皆含露，出鼎騠金尚带砂。", "偶對吟牋追昔事，猶疑鸞鳳數行斜。"]'),
('154fee36-199c-4d47-8752-778d345d3448','追和紫霞翁記夢二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','笑上蓬萊第一山，葱蒼半落有無間。',64,'全唐诗/poet.song.43000.json','["笑上蓬萊第一山，葱蒼半落有無間。", "金雲璧月夜何永，玉殿珠樓人鬭閒。", "五嶽已能超險路，九天從此造玄關。", "回頭爲問桃源客，底事雞鳴便欲還。"]'),
('5fb43f28-1419-45ad-856e-322b4809ee7e','次韻元輿見寄二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','不得陪公九日行，想提椽筆瞰西城。',64,'全唐诗/poet.song.43000.json','["不得陪公九日行，想提椽筆瞰西城。", "風流自可追王粲，憔悴猶能憶禰生。", "萬里還家唯有夢，一身投獄豈忘情。", "何時共擲滄溟釣，醉倚三山欲鱠鯨。"]'),
('e1954800-75d6-4a5e-b8d6-593fad61bf21','次韻元輿見寄二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','霜雪蕭然滿鬢鬚，平生憂患更無如。',64,'全唐诗/poet.song.43000.json','["霜雪蕭然滿鬢鬚，平生憂患更無如。", "强傾濁酒消塵事，每見荒榛憶舊居。", "倦鳥久摧千里翼，故人頻枉數行書。", "城頭高閣何時到，多在三春細雨餘。"]'),
('480958e8-dbca-4a6b-8286-624726adca30','酬蔡溫老秀才見寄','郭祥正','宋','宋诗','song-poetry','','[]','一庵聊寄碧巖陰，忽得新詩慰我心。',64,'全唐诗/poet.song.43000.json','["一庵聊寄碧巖陰，忽得新詩慰我心。", "俊逸自追天馬健，崩騰還與海濤深。", "門前俗子無行跡，物外松風有好音。", "病起可能攜杖屨，共尋明月到溪潯。"]'),
('1d95283d-c7bc-4a0c-a01a-1616a9c93a3e','酬崇福長老見寄','郭祥正','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寄榻西湖不掩關，殘年猶得伴僧閒。',64,'全唐诗/poet.song.43000.json','["寄榻西湖不掩關，殘年猶得伴僧閒。", "身投羅網歸無路，目送烟雲幸有山。", "新句忽傳文字外，舊游重想笑談間。", "故人風義如師少，慰我憂愁兩鬢斑。"]'),
('b9fc5979-bd6a-4102-8773-0fc09918e58f','再用前韻寄省上人','郭祥正','宋','宋诗','song-poetry','','[]','四壁蕭然我亦空，更無歸夢到江東。',64,'全唐诗/poet.song.43000.json','["四壁蕭然我亦空，更無歸夢到江東。", "樓臺不礙塵塵現，鐘鼓相聞法法通。", "玉麈揮談真契合，蓮華分座夙緣同。", "回頭重濁堪憐憫，妙性如何自瞽聾。"]'),
('f9d06f2d-8f90-488e-99ad-1af353280651','和安止懷予北歸悵然有作三首  其一','郭祥正','宋','宋诗','song-poetry','','[]','濛濛春氣撲晴霄，遊水登山望泬寥。',64,'全唐诗/poet.song.43000.json','["濛濛春氣撲晴霄，遊水登山望泬寥。", "舊學已荒三歲懶，故鄉何處一身遙。", "沈溝斷木思班匠，吹沫纖鱗待晚潮。", "君有高才當自奮，不應先我問耕樵。"]'),
('247b1a25-18e5-451d-9a77-d15ee9020700','和安止懷予北歸悵然有作三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','雨餘風物一番新，得句慚非畫手親。',64,'全唐诗/poet.song.43000.json','["雨餘風物一番新，得句慚非畫手親。", "柳眼含烟如恨客，花心凝露欲啼春。", "黄鸝出谷方求友，紫燕營巢不避人。", "獨我未沾青帝力，僧窻聊寄幻泡身。"]'),
('b042b97a-f2f0-469c-9b8d-bc4905d2a385','和安止懷予北歸悵然有作三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','一讀詩翁寄我篇，却思鄉國醉瑤泉。',64,'全唐诗/poet.song.43000.json','["一讀詩翁寄我篇，却思鄉國醉瑤泉。", "數聲玉樹秦淮月，萬里春江采石船。", "軒冕浮沈真外物，冤親平等委前緣。", "杜陵子美知何意，更欲吹噓送上天。"]'),
('b39b087e-6cae-488c-a0c2-df6f115ae36e','劍','郭祥正','宋','宋诗','song-poetry','','[]','不得公孫一舞看，空嗟塵漬血痕乾。',64,'全唐诗/poet.song.43000.json','["不得公孫一舞看，空嗟塵漬血痕乾。", "鑄成星斗生光焰，化作龍蛇會屈盤。", "金匣藏時天地靜，玉池磨處雪霜寒。", "誰爲將相扶明主，此物能令社稷安。"]'),
('e09c17a2-b43d-4a5b-8d6d-f731431d27a0','贈裴泰辰先生','郭祥正','宋','宋诗','song-poetry','','[]','匣劍光鋩射斗牛，提攜天下洗人仇。',64,'全唐诗/poet.song.43000.json','["匣劍光鋩射斗牛，提攜天下洗人仇。", "英雄心膽老猶在，道路風塵行未休。", "名重更須完小節，義高何足論閒愁。", "濛濛細雨陵陽市，折取紅梅上酒樓。"]'),
('01cd0a5e-6394-40be-a7a0-38ff37d2cded','次韻俞資深承事二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','聯車同入得仙山，下瞰重城指掌間。',64,'全唐诗/poet.song.43000.json','["聯車同入得仙山，下瞰重城指掌間。", "不憤青春添我老，且傾白酒伴君閒。", "三年共佐閩中郡，一檄誰招海上蠻。", "聞說天門新奏樂，帝樞佳氣紫回環。"]'),
('4ccf871f-3bfb-4c1b-8fd1-ae0d3be78d0c','次韻俞資深承事二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','春歸漳岸撲晴嵐，紫燕黄鸝若縱談。',64,'全唐诗/poet.song.43000.json','["春歸漳岸撲晴嵐，紫燕黄鸝若縱談。", "自愧不才甘薄祿，喜逢佳客解羸驂。", "仙山有路終難繼，海品論珍昔未諳。", "地勝人醇真可樂，夢魂無復憶江南。"]'),
('157d315a-9f71-4a8e-aace-193cdfed5b21','東湖','郭祥正','宋','宋诗','song-poetry','','[]','東湖北漵水相通，十里荷花半白紅。',64,'全唐诗/poet.song.43000.json','["東湖北漵水相通，十里荷花半白紅。", "冷艷已能消酷暑，暗香時復散清風。", "欲眠别浦無魚艇，且倚疏欄學釣翁。", "雲起仙庭飛晚雨，灑然身世出塵籠。"]'),
('12a16939-9ebc-4af6-bec5-c3df2aaba386','圓山謝雨二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','牲牷報祀入圓山，赫赫神功指顧間。',64,'全唐诗/poet.song.43000.json','["牲牷報祀入圓山，赫赫神功指顧間。", "水滿大田甘雨足，龍歸深澗宿雲閒。", "樂聲自和松聲奏，玉色遙瞻酒色殷。", "安得夢魂陪逸駕，更傳仙句落人寰。"]'),
('cfe8c975-392f-4c46-b5d9-80853c7cb3d2','圓山謝雨二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','自挈壺漿款廟門，黄蕉丹荔薦清芬。',64,'全唐诗/poet.song.43000.json','["自挈壺漿款廟門，黄蕉丹荔薦清芬。", "沈烟未過盤中篆，電影已翻江上雲。", "霈澤不惟滋稼穡，凉飈仍爲掃嵐氛。", "圓山信作漳南鎮，想戀枇杷玉色醺。"]'),
('9525fe7f-c810-4525-a338-614bce8ead56','和留秀才秋日田舍','郭祥正','宋','宋诗','song-poetry','','[]','物幻非真只自知，却尋田舍度衰遲。',64,'全唐诗/poet.song.43000.json','["物幻非真只自知，却尋田舍度衰遲。", "漫爲陶令柴桑樂，不學荆軻易水悲。", "午睡最能消永日，一巢長欲寄深枝。", "聞君亦有逍遙趣，可濯滄浪共賦詩。"]'),
('61b96be7-cd09-45be-92cd-528848bb4fe5','和宣守林子中修撰列岫亭','郭祥正','宋','宋诗','song-poetry','','[]','蘇州方稱白公才，又見宣城謝守來。',64,'全唐诗/poet.song.43000.json','["蘇州方稱白公才，又見宣城謝守來。", "兩處溪山重秀發，一亭風月助徘徊。", "水光颭灧龍鱗活，岫影參差雁序開。", "不用紅裙唱金縷，只題佳句殷春雷。"]'),
('6862395d-4742-4575-aa82-471650210ca7','列岫後題','郭祥正','宋','宋诗','song-poetry','','[]','謝公遺句惜湮沈，更作新亭一百尋。',64,'全唐诗/poet.song.43000.json','["謝公遺句惜湮沈，更作新亭一百尋。", "宿靄擁山眉斂翠，夕陽浮水带横金。", "黄鸝喚友鳴聲軟，白鳥窺魚意思深。", "看盡物情俱是幻，要須攜酒數登臨。"]'),
('88a06a63-7ca7-49b9-b266-3a58c3dc71dd','贈子中修撰','郭祥正','宋','宋诗','song-poetry','','[]','承明厭直下天來，聊繼昭亭小謝才。',64,'全唐诗/poet.song.43000.json','["承明厭直下天來，聊繼昭亭小謝才。", "珠迸玉盤詩得句，月騰金浪酒盈盃。", "江城未許民心借，京國顒瞻召節回。", "試問行年俱乙亥，固應憐我困蒿萊。"]'),
('cfd6b9ae-bb84-4296-a17b-b25aacfeafe9','子中修撰疊嶂樓致酒','郭祥正','宋','宋诗','song-poetry','','[]','重山複水碧相連，勝地欣逢太守賢。',64,'全唐诗/poet.song.43000.json','["重山複水碧相連，勝地欣逢太守賢。", "欲倒樽罍秋色裏，故邀賓客畫圖邊。", "丹青迥壓王摩詰，騷雅仍兼白樂天。", "莫戀宣城風物美，玉堂提取筆如椽。"]'),
('c44d0fc9-c33f-4bc9-ad39-a62f3e7c2788','次韻子中修撰寵贈之什','郭祥正','宋','宋诗','song-poetry','','[]','聲名入洛弟兄傳，出擁旌旗老集仙。',96,'全唐诗/poet.song.43000.json','["聲名入洛弟兄傳，出擁旌旗老集仙。", "挹月珠璣光射海，凌秋鵰鶚氣横天。", "文章落筆元無敵，器宇藏春豈有邊。", "一見音容聊莞爾，却攜樽酒共頽然。", "金門曾奏相如賦，水閣重吟杜牧篇。", "强駕蹇驢追逸驥，已知霄壤不相連。"]'),
('2b09fd8c-be9a-4e44-9cae-64736f8802c5','次韻子中修撰塔院題竹','郭祥正','宋','宋诗','song-poetry','','[]','不是集仙來詠竹，更誰能繼紫微吟。',64,'全唐诗/poet.song.43000.json','["不是集仙來詠竹，更誰能繼紫微吟。", "看隨霜雪終吾老，寄語鋤犂勿見侵。", "欲把一竿垂直釣，更須十畝廣清陰。", "蕭郎妙筆堪圖寫，添入蓬萊第幾岑。"]'),
('0e5063af-9bf4-42c3-91ad-f88129ccf287','子中修撰示書有不得同遊水晶宫之歎作唐格四韻寄别','郭祥正','宋','宋诗','song-poetry','','[]','西庵吟醉憶君同，忽得新詩思愈工。',64,'全唐诗/poet.song.43000.json','["西庵吟醉憶君同，忽得新詩思愈工。", "下筆捷才如陣馬，接人和氣似春風。", "敬亭姑孰猶爲遠，庾嶺端山更幾重。", "自歎鷦鷯無健翼，追飛不到水晶宫。"]'),
('634407cb-a610-432c-9cd3-c8e4eca24633','寄鳳凰山張居士','郭祥正','宋','宋诗','song-poetry','','[]','聞君深隱鳳凰山，池水相通竹石間。',64,'全唐诗/poet.song.43000.json','["聞君深隱鳳凰山，池水相通竹石間。", "一念報親長不斷，六經傳子勝空閒。", "青猿摘果啼兼嘯，白鳥穿雲去復還。", "自愧塵埃行老矣，何時載酒伴酡顔。"]'),
('84c30880-cc6f-407e-b58a-4b4603893bfe','永安戴公純秀才','郭祥正','宋','宋诗','song-poetry','','[]','鬖鬖鬢髮一衰翁，又泊倉頭阻逆風。',64,'全唐诗/poet.song.43000.json','["鬖鬖鬢髮一衰翁，又泊倉頭阻逆風。", "推去未應如謝令，重來終是愧司農。", "熙寧父老知誰在，元祐田園喜再豐。", "置酒高臺要我醉，却尋陳跡喜君同。"]'),
('6abac8b4-a589-469a-aa96-addfcaa73d8e','次韻陳思道見送之什','郭祥正','宋','宋诗','song-poetry','','[]','誰聽袁宏夜半吟，一時傾蓋便知心。',64,'全唐诗/poet.song.43000.json','["誰聽袁宏夜半吟，一時傾蓋便知心。", "疲駑自信難追驥，秀木從來忌出林。", "巧匠旁觀應縮手，明珠所得已盈衿。", "嶺頭孤唱思君和，着月梅花似縷金。"]'),
('8be32b38-b2ac-4220-ab5d-9657bc08a0fe','至萬安寄吉守李獻父大夫','郭祥正','宋','宋诗','song-poetry','','[]','江水成文地最奇，風流太守更能詩。',64,'全唐诗/poet.song.43000.json','["江水成文地最奇，風流太守更能詩。", "送將臘盡梅花怨，喚得春回燕子知。", "一餉功勳真夢寐，千年名字付傷悲。", "盛攜樽酒頻賡唱，幕下高才似牧之。"]'),
('cf8675ec-f6d8-4c4a-a820-8efb53696223','將至五羊先寄穎叔修撰','郭祥正','宋','宋诗','song-poetry','','[]','句水分攜二十年，却臨南海望青天。',64,'全唐诗/poet.song.43000.json','["句水分攜二十年，却臨南海望青天。", "元戎爲解陳公榻，下客慚非孺子賢。", "冷艷一枝梅照眼，清光五斗酒盈船。", "朝廷近日無新事，只恐西戎尚擾邊。"]'),
('87596643-117b-4b73-9c00-c4c8655b2c52','南雄望遠亭本朝章郇公所作公嘗爲郡太守種荔子二株今方茂實而後人所種皆不成東美要予致酒亭上爲賦四韻','郭祥正','宋','宋诗','song-poetry','','[]','城角危亭面面開，塵侵丞相舊詩牌。',64,'全唐诗/poet.song.43000.json','["城角危亭面面開，塵侵丞相舊詩牌。", "凌江欲轉鯨魚活，荔子成陰玉樹埋。", "庾嶺乍過無瘴霧，長安不見奈愁懷。", "且傾濁酒承高論，秋水何由辨渚涯。"]'),
('539c2d96-01be-4799-b52e-2084da77dbfd','凌江立春日呈黎東美太守','郭祥正','宋','宋诗','song-poetry','','[]','斗杓東指斡春回，樂奏昇平助殷雷。',64,'全唐诗/poet.song.43000.json','["斗杓東指斡春回，樂奏昇平助殷雷。", "魚躍原無溪面凍，雪光散作嶺頭梅。", "主人和氣均千里，北客歸懷寄一杯。", "色滿皇州三殿喜，瓊林先放桂花開。"]'),
('05593a41-d871-437a-8505-e3ce4a7e9100','韶州武溪亭','郭祥正','宋','宋诗','song-poetry','','[]','滔滔武溪一何深，鳥飛莫渡獸莫臨。',64,'全唐诗/poet.song.43000.json','["滔滔武溪一何深，鳥飛莫渡獸莫臨。", "山色欲學翠鳳舞，笛聲自作蒼龍吟。", "樽罍謾借春力暖，鬢髮未免霜華侵。", "形容不上凌烟閣，馬革裹尸那可尋。"]'),
('e6c28a4c-1e5b-47ae-9157-7b9aae0b1103','六祖南華寺','郭祥正','宋','宋诗','song-poetry','','[]','水轉山來曲曲梯，參差樓殿占清輝。',64,'全唐诗/poet.song.43000.json','["水轉山來曲曲梯，參差樓殿占清輝。", "龍章鳳襲藏天篆，玉索金鈎賁祖衣。", "春去不知庭柏老，月明誰櫂釣船歸。", "曹溪有路人人到，踏斷玄關古亦稀。"]'),
('e46de12e-6b91-48f5-918c-0325a134731e','六祖大湧泉','郭祥正','宋','宋诗','song-poetry','','[]','金鐶一卓透曹溪，禪祖心傳上上機。',64,'全唐诗/poet.song.43000.json','["金鐶一卓透曹溪，禪祖心傳上上機。", "流出山腰蒼兕吼，湧開池面碧綃飛。", "應同霖雨能蘇旱，莫比滄浪只濯衣。", "不願夕陽催我去，要隨幽鳥带雲歸。"]'),
('59cefd2e-2a21-4f56-902f-f631c972a108','武溪亭勸顧歸聖朝奉酒','郭祥正','宋','宋诗','song-poetry','','[]','邂逅窮荒遇俊才，故將懷抱向君開。',64,'全唐诗/poet.song.43000.json','["邂逅窮荒遇俊才，故將懷抱向君開。", "功名未得金横带，老大空驚雪滿腮。", "嶺北嘉蔬無此筍，江南相識尚逢梅。", "夜闌莫作思鄉夢，且聽清歌更一盃。"]'),
('9b3d3da4-a3e2-4f46-b428-1127fe42beac','雪夜宿月華寺','郭祥正','宋','宋诗','song-poetry','','[]','大庾南來山更佳，每逢古寺留柴車。',64,'全唐诗/poet.song.43000.json','["大庾南來山更佳，每逢古寺留柴車。", "曹溪衣傳葛獠布，月嶺樹種蘋婆花。", "千年不壞物稀有，一日寓賞心無涯。", "北人浪說瘴霧惡，行擁貂裘衝雪華。"]'),
('f536ce9b-1900-4c64-87b6-13a4d02e825b','補到難篇終别作八句寄吳聖與長官','郭祥正','宋','宋诗','song-poetry','','[]','結客元和六載春，探深碧落跡如新。',64,'全唐诗/poet.song.43000.json','["結客元和六載春，探深碧落跡如新。", "寸量秋色三千丈，名寫嵐光十四人。", "文格迥欺韓愈老，字書尤逼小王真。", "近來好事誰能及，我續遺音君可嗔。"]'),
('f44cf6ef-22ea-4b4c-825e-66a6c5f9783c','廣慶寺','郭祥正','宋','宋诗','song-poetry','','[]','寺當南北二禺間，合翠全清總見山。',64,'全唐诗/poet.song.43000.json','["寺當南北二禺間，合翠全清總見山。", "一石尚存垂釣處，五羊時載老仙還。", "金流月影真盤谷，黛漲嵐光小劍關。", "安得鵲橋横絕頂，下臨河漢瀉潺潺。"]'),
('6c790f00-0e4b-47cd-9951-1f0f130618e6','次韻彭敎授送别','郭祥正','宋','宋诗','song-poetry','','[]','平生愛着五雲裘，不愛身爲萬戶侯。',64,'全唐诗/poet.song.43000.json','["平生愛着五雲裘，不愛身爲萬戶侯。", "白石清泉隨步到，斷霞殘月滿懷收。", "故園已恨荒三徑，皓首何堪困一州。", "邂逅逢君滄海上，涸鱗終欲借洪流。"]'),
('caf6d796-4a00-4204-bb13-dc28b85f46bd','次韻湛判官送别','郭祥正','宋','宋诗','song-poetry','','[]','一朝傾蓋若忘年，更把新詩物外傳。',64,'全唐诗/poet.song.43000.json','["一朝傾蓋若忘年，更把新詩物外傳。", "側望風流還入幕，應憐憔悴未成仙。", "離樽謾託春風裏，短櫂行依瘴海邊。", "十斛明珠君不惜，珊珊投擲滿巴牋。"]'),
('bcb48267-f4df-4983-a4fc-9e2085e3c38a','次韻廣幕黄承事見寄二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','不記西亭醉别時，别來佳句愈瑰奇。',64,'全唐诗/poet.song.43000.json','["不記西亭醉别時，别來佳句愈瑰奇。", "心隨雲影沈天角，夢逐灘聲到海湄。", "滿目青山誰共樂，何年黄卷得同披。", "遙憐嚴武能爲帥，幕下爭傳杜老詩。"]'),
('34d45c03-4973-4acc-a467-0989cb098290','次韻廣幕黄承事見寄二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','孤城寂寞瘴嵐州，虎竹分符强少留。',64,'全唐诗/poet.song.43000.json','["孤城寂寞瘴嵐州，虎竹分符强少留。", "老鈍不知今世巧，行藏猶愧古人修。", "暗天理釣船千丈，紗帽籠頭茗一甌。", "無奈北歸忘未得，非君求友更誰求。"]'),
('79c173ac-b836-49af-8d76-34b03a595ec5','石室後游','郭祥正','宋','宋诗','song-poetry','','[]','七星山色碧離離，山下空巖世所稀。',64,'全唐诗/poet.song.43000.json','["七星山色碧離離，山下空巖世所稀。", "不獨霧深知豹隱，有時水長見龍歸。", "方牀瑩潔仙人座，文石縱横織女機。", "旋剔蒼苔辨陳跡，李邕詞翰亦依稀。"]'),
('0cdc9a4f-1210-459d-9160-33b085b5534e','寄惠守蘇元之','郭祥正','宋','宋诗','song-poetry','','[]','揮金愛士氣尤雄，暫擁旌旗碧海東。',64,'全唐诗/poet.song.43000.json','["揮金愛士氣尤雄，暫擁旌旗碧海東。", "十八素娥傾皓月，三千佳客倚春風。", "高才可惜經綸晚，把酒何時笑語同。", "霜落草枯應射虎，短衣匹馬欲隨公。"]'),
('dbd7bca5-8582-484c-ba51-0cc608259d2d','寄題李封州宅生堂','郭祥正','宋','宋诗','song-poetry','','[]','鱗鱗鴛瓦構新堂，意在黔烏惠澤長。',64,'全唐诗/poet.song.43000.json','["鱗鱗鴛瓦構新堂，意在黔烏惠澤長。", "峴首去思聞墮淚，召南遺愛有甘棠。", "水光送月浮珍席，山勢和雲插畫梁。", "安得才如張相國，爲君重賦宅生章。"]'),
('1b3d501c-1555-4582-b5ca-6563327d18d1','寄題賀州甑山亭','郭祥正','宋','宋诗','song-poetry','','[]','賀州城西丹甑山，一亭遙插紫雲間。',64,'全唐诗/poet.song.43000.json','["賀州城西丹甑山，一亭遙插紫雲間。", "龍墀讓策名猶在，鶴馭凌風去不還。", "善政再應來瑞物，勝遊安得伴酡顔。", "元戎詞翰鐫金玉，千古長如碧澗潺。"]'),
('4fcf4336-678e-415a-ae67-b79c5fbcd353','次韻宜掾徐子美見寄','郭祥正','宋','宋诗','song-poetry','','[]','去年與子别當塗，彼此形骸若夢餘。',64,'全唐诗/poet.song.43000.json','["去年與子别當塗，彼此形骸若夢餘。", "悵望欲窮千里目，相思不寄一行書。", "青山歸去容身好，白眼從來處世疏。", "桂水東流須入海，新詩時復委雙魚。"]'),
('53f3b93a-9f59-419f-bb1e-b1235a33c590','故人李端夫赴廉州從事石室致酒留别二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','注地銀潢兩峽開，雲林冰凈不浮灰。',64,'全唐诗/poet.song.43000.json','["注地銀潢兩峽開，雲林冰凈不浮灰。", "新詩欲與何人論，舊友今從上國來。", "薄酒謾爲仙室飲，歸鞍無奈夕陽催。", "君懷自有驪珠富，合浦休將一顆迴。"]'),
('2dc86962-1323-4c78-8150-31f2aa60afc8','故人李端夫赴廉州從事石室致酒留别二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','才如吾子尚區區，羽檄從軍萬里餘。',64,'全唐诗/poet.song.43000.json','["才如吾子尚區區，羽檄從軍萬里餘。", "白髮可憐歸計晚，青衫只似拜恩初。", "一樽邀客非無酒，千卷隨車幸有書。", "已把窮通推定分，故人達宦任情疏。"]'),
('4ea91b2d-b59f-4b96-aacc-e9b515af92a7','留湯主簿小飲','郭祥正','宋','宋诗','song-poetry','','[]','窮荒得見故人稀，話舊還驚歲月飛。',64,'全唐诗/poet.song.43000.json','["窮荒得見故人稀，話舊還驚歲月飛。", "君有兒孫能力學，我無金穀可言歸。", "靈仙觀裏黄柑熟，采石江頭白蟹肥。", "北望何時同此樂，暫留行櫂莫相違。"]'),
('7a2db383-06e8-4c67-a1a2-0b27b36966d2','送劉光道赴桂幕','郭祥正','宋','宋诗','song-poetry','','[]','氣吐虹蜺髮未皤，逢人輒莫歎蹉跎。',64,'全唐诗/poet.song.43000.json','["氣吐虹蜺髮未皤，逢人輒莫歎蹉跎。", "邊隅鋒鏑從今少，幕下篇章所得多。", "雨洗山光浮碧玉，春回江色熨青羅。", "元戎早晚歸金闕，薦禰應先著述科。"]'),
('f3d7f5da-adbc-4eee-b29e-2df0f511c09f','九日登北樓示客','郭祥正','宋','宋诗','song-poetry','','[]','九日登高可强歡，聽歌莫放玉杯乾。',64,'全唐诗/poet.song.43000.json','["九日登高可强歡，聽歌莫放玉杯乾。", "黄花爛漫宜新酒，白髮稀疏落小冠。", "桂水波光趨海急，峽山嵐翠带雲寒。", "故鄉萬里知何處，更凭朱欄向北看。"]'),
('62b53f46-14c1-4313-bc22-8cfcd89e0030','次韻宜掾徐子美見寄','郭祥正','宋','宋诗','song-poetry','','[]','忽逢便翼寄新章，不惜明珠滿斛量。',64,'全唐诗/poet.song.43000.json','["忽逢便翼寄新章，不惜明珠滿斛量。", "姑孰萬家花映竹，丹湖千頃月和霜。", "結廬已許陪吟社，衣錦應須返故鄉。", "底事却言歸未得，夢魂猶欲泛滄浪。"]'),
('eff62975-4cd0-45b9-b351-e33c80fb3c74','次韻陳文思見寄','郭祥正','宋','宋诗','song-poetry','','[]','星灣高會豈能忘，萬丈離愁寸寸量。',64,'全唐诗/poet.song.43000.json','["星灣高會豈能忘，萬丈離愁寸寸量。", "東閣賦梅攄錦繡，南山射虎凛冰霜。", "功名未得封千戶，耕鑿何由共一鄉。", "春蕨秋鱸味偏美，時聽社鼓醉淋浪。"]'),
('ecab4f1b-2d48-42fb-b709-767ef798ffe2','寄題羅池廟','郭祥正','宋','宋诗','song-poetry','','[]','種柳江邊不得歸，殁將靈魄寓羅池。',64,'全唐诗/poet.song.43000.json','["種柳江邊不得歸，殁將靈魄寓羅池。", "名參韓子猶爲幸，黨入王生最可悲。", "簾卷瘴雲燈斷續，門荒秋雨菊離披。", "旱穰請禱年年事，瓦鼓巫歌奠一巵。"]'),
('a7099579-893e-4499-adcb-bc7a5b12e487','送穎叔待制拜六路都運之命','郭祥正','宋','宋诗','song-poetry','','[]','朝聞紫詔下龍樓，夕卷紅旌别海陬。',64,'全唐诗/poet.song.43000.json','["朝聞紫詔下龍樓，夕卷紅旌别海陬。", "六路理財煩侍從，一門傳節繼風流。", "詩如老杜猶爲達，策似劉蕡稍見收。", "廊廟乏材終大用，願均和氣及巖幽。"]'),
('e5a8cf98-9492-43a3-9e87-984e76a5ec68','次韻林辨之長官送别之什','郭祥正','宋','宋诗','song-poetry','','[]','十年相識跡非疏，今日江亭歎别車。',64,'全唐诗/poet.song.43000.json','["十年相識跡非疏，今日江亭歎别車。", "牢落名聲讒謗後，支離形影瘴氛餘。", "重來仕路誰爲援，却返家園欲自如。", "烟浪一舟無長物，罷官只似到官初。"]'),
('af2a45cf-44ea-4203-a30e-61f3234de8dc','謝洪府黄安中尚書惠雙泉二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','北風遮莫阻歸舟，公有雙泉慰客愁。',64,'全唐诗/poet.song.43000.json','["北風遮莫阻歸舟，公有雙泉慰客愁。", "玉斗貯來雲尚凍，金蕉傾處蟻爭浮。", "黄花遙想東籬畔，白浪正翻南浦頭。", "醉魄忽成蝴蝶夢，却尋春色到皇州。"]'),
('e339cb88-6260-4a52-9996-730b073720e7','謝洪府黄安中尚書惠雙泉二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','北風變冷水歸𤃩，南浦扁舟未得行。',64,'全唐诗/poet.song.43000.json','["北風變冷水歸𤃩，南浦扁舟未得行。", "孤雁叫雲詩膽碎，怒濤舂岸客魂驚。", "誰陪高論應懸榻，想有雄詞欲鱠鯨。", "病骨支離難强起，尚蒙樽酒慰餘生。"]'),
('0c050ff0-9579-4511-88ec-31e4eb38fa85','次韻黎東美江上偶作','郭祥正','宋','宋诗','song-poetry','','[]','帝庭江國屢相逢，不覺霜毛歲月空。',64,'全唐诗/poet.song.43000.json','["帝庭江國屢相逢，不覺霜毛歲月空。", "君奏課書雙闕下，我攜綸釣五湖東。", "論歸學海方無跡，吟到詩壇始有功。", "一任北風翻地起，且圖樽酒暫時同。"]'),
('d9c90d6c-7004-42a9-a030-4bafc4911f8d','吉州仙都觀覽前守李獻父留題','郭祥正','宋','宋诗','song-poetry','','[]','乍出鋒鋩贛石來，仙都忽見五雲開。',64,'全唐诗/poet.song.43000.json','["乍出鋒鋩贛石來，仙都忽見五雲開。", "霓幡閃閃排真馭，珠網重重覆絳臺。", "照水碧蓮猶未變，遶壇紅杏亦新栽。", "劉郎去後誰行樂，壁上龍蛇半紫苔。"]'),
('1e4f897e-1552-4849-b911-5edef93ba655','貴池寺照遠軒','郭祥正','宋','宋诗','song-poetry','','[]','碧瓦周遭映佛幢，更窮眼界敞軒窻。',64,'全唐诗/poet.song.43000.json','["碧瓦周遭映佛幢，更窮眼界敞軒窻。", "山光半擁初生日，天影寛圍不盡江。", "詩思未容秋色亂，酒醺能使客愁降。", "陶潛肯憶東籬菊，且倚欄干倒一缸。"]'),
('f5cc0a38-4df0-4c66-aaed-34567262ead6','追和梅侍讀題貴池寺元韻','郭祥正','宋','宋诗','song-poetry','','[]','寺插孤峰壓貴池，幽軒占勝敞雙扉。',64,'全唐诗/poet.song.43000.json','["寺插孤峰壓貴池，幽軒占勝敞雙扉。", "陰生廣野千山失，影落空江一雁歸。", "安得有緣陪社客，更尋何處息塵機。", "南來北去無時盡，誰念滄浪可濯衣。"]'),
('58caf55c-bfad-43f8-8cd7-13edb60e8977','寄題吕得中先墳懷先亭','郭祥正','宋','宋诗','song-poetry','','[]','亭壓全閩近冢丘，四時營祀想神游。',64,'全唐诗/poet.song.43000.json','["亭壓全閩近冢丘，四時營祀想神游。", "毫添玉兔新成史，德合銀潢不盡流。", "翼翼棟梁横蜃澤，林林松檟冒霜秋。", "榮名已往餘陰隲，定有兒孫萬戶侯。"]'),
('dfe16180-154a-45c5-9d66-50b973a84737','送魏汝士宣德','郭祥正','宋','宋诗','song-poetry','','[]','隔江爲宰便庭幃，歸去青霄結主知。',64,'全唐诗/poet.song.43000.json','["隔江爲宰便庭幃，歸去青霄結主知。", "租賦寛平民共樂，文書清簡吏常饑。", "始終不變温如玉，離别相憐醉似泥。", "上國故人應問我，爲言耕釣老明時。"]'),
('eb0fa560-9725-4c5d-b26d-8bf5c3350c5a','寄致政蘇子平大夫','郭祥正','宋','宋诗','song-poetry','','[]','十年想見蘇夫子，聞說腰金便棄官。',64,'全唐诗/poet.song.43000.json','["十年想見蘇夫子，聞說腰金便棄官。", "雲在皖山峰上住，龍歸潛水窟中蟠。", "已無俗坌心休洗，更有春醪盞不乾。", "我亦江南專一壑，憶君相伴把漁竿。"]'),
('a548c0f8-9436-459a-8d5a-2723c6457964','送葉聖參守九江郡','郭祥正','宋','宋诗','song-poetry','','[]','湓浦夜濤聲動地，香爐晴影碧連天。',64,'全唐诗/poet.song.43000.json','["湓浦夜濤聲動地，香爐晴影碧連天。", "樓中不負庾公賞，席上誰爲陶令賢。", "且擁旌旗飛畫鷁，行聞臺閣選青錢。", "班春過我舊遊處，門巷桃花應寂然。"]'),
('d986ba41-eb31-4835-8a75-6a05a8557526','送琳長老再游浙東','郭祥正','宋','宋诗','song-poetry','','[]','姑溪不是留君地，雪竇天台更一游。',64,'全唐诗/poet.song.43000.json','["姑溪不是留君地，雪竇天台更一游。", "玉浪濺雲泉尾活，金盤擎海月華秋。", "將心與客無痕跡，問疾何人敢對酬。", "我把釣竿相憶處，蓼花紅影上絲頭。"]'),
('c3595923-9966-4d45-b809-c4dbe25e7a99','姜希哲四照軒送别','郭祥正','宋','宋诗','song-poetry','','[]','幽軒邀客每凭欄，景物蕭然世味閒。',64,'全唐诗/poet.song.43000.json','["幽軒邀客每凭欄，景物蕭然世味閒。", "翠碧濕烟山匼匝，光明隨夜月回環。", "一盃濁酒超塵外，幾首新詩寄壁間。", "不得從容與君語，片帆却欲趁風還。"]'),
('e169eda6-5a04-49f2-a013-b6c9bf6a756e','胡與幾被召訪别','郭祥正','宋','宋诗','song-poetry','','[]','已喜乘軺歸玉闕，尚能騎馬過柴門。',64,'全唐诗/poet.song.43000.json','["已喜乘軺歸玉闕，尚能騎馬過柴門。", "離魂有底銷千丈，殘日無多寄一樽。", "得路看君終直節，閉關唯我守空言。", "霜風素髮頻欹帽，淚對桓伊不可捫。"]'),
('dbf671a2-7ec5-4d8e-a786-c7dddba05d90','再游浮山呈璞禪老','郭祥正','宋','宋诗','song-poetry','','[]','當年尋勝已忘還，乘興重來倍覺閒。',64,'全唐诗/poet.song.43000.json','["當年尋勝已忘還，乘興重來倍覺閒。", "赤脚敬瞻新寶藏，白髯羞對舊青山。", "禪翁昔授嶺頭衲，狂客今探樹穴環。", "行把生涯付妻子，幻身長寄一巖間。"]'),
('b4984a48-8394-4f73-b8b4-800c80edec2c','寄題潘温叟林堂','郭祥正','宋','宋诗','song-poetry','','[]','有堂歸去容身好，天上人間已徧遊。',64,'全唐诗/poet.song.43000.json','["有堂歸去容身好，天上人間已徧遊。", "遠害果能超華左，忘情却欲繼雷劉。", "松臺風送晴空雨，荷沼雲生畫卷秋。", "浩氣本來緣直養，百年等是寄浮漚。"]'),
('eb2bdbb9-18e0-445e-94b4-5ccb7b63193f','和倪敦復觀梅三首  其一','郭祥正','宋','宋诗','song-poetry','','[]','聞說觀梅借燭光，今宵爲我更開觴。',64,'全唐诗/poet.song.43000.json','["聞說觀梅借燭光，今宵爲我更開觴。", "月來枝上冰生艷，風過梢頭玉有香。", "羌笛幾聲傳舊曲，菱花一夜照繁妝。", "坐中老杜凌何遜，索酒題詩思欲狂。"]'),
('e695cef0-3c9e-476d-98eb-c3fdf0a09327','和倪敦復觀梅三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','江月江梅鬭冷光，就梅臨月舉瑤觴。',64,'全唐诗/poet.song.43000.json','["江月江梅鬭冷光，就梅臨月舉瑤觴。", "素娥未許風搖影，青帝寧容蝶採香。", "迢遞一聲羌笛怨，輕盈千點玉人妝。", "出塵標格情多少，東閣曾令杜甫狂。"]'),
('f8698085-5eec-4a86-a03a-fc4d5960ee3c','和倪敦復觀梅三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','月壓江梅似雪光，史君要我共飛觴。',64,'全唐诗/poet.song.43000.json','["月壓江梅似雪光，史君要我共飛觴。", "不饒桂樹輪中影，獨占霜娥鑑裏香。", "信報春來先衆卉，恨隨人去入殘妝。", "孔融愛客君能似，席上應容處士狂。"]'),
('2a9676a2-5c75-47a3-abb9-8a786c2841eb','又同賞落梅二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','江梅千片惜離披，更向風前把一巵。',64,'全唐诗/poet.song.43000.json','["江梅千片惜離披，更向風前把一巵。", "冷艷不辭今日舞，清香還是隔年期。", "客經易水忘歸處，雲倚巫山欲散時。", "安得不吟仍不飲，滿頭華髮擬何爲。"]'),
('c3f15722-6d6c-4a88-a0ec-98fde2f091a0','又同賞落梅二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','誰惜東園玉樹空，且攜樽酒與君同。',64,'全唐诗/poet.song.43000.json','["誰惜東園玉樹空，且攜樽酒與君同。", "盈盈素艷辭寒萼，浥浥餘香散曉風。", "已許冰霜分我瑩，儘饒桃杏向人紅。", "能詩自有倪夫子，何必滁陽覓醉翁。"]'),
('ab4af578-3d1f-4431-846f-f4d051687424','題方處士卷尾','郭祥正','宋','宋诗','song-poetry','','[]','子陵獨往已千年，處士重來把一竿。',64,'全唐诗/poet.song.43000.json','["子陵獨往已千年，處士重來把一竿。", "治亂不同非我計，文章聊許後人看。", "璞中美玉誰雕琢，潭底神龍會屈盤。", "七世有孫方遇主，風流長在瀉驚湍。"]'),
('f8af00bb-ece9-4610-86c7-e26fb9fbf0f2','題謝氏雙溪閣','郭祥正','宋','宋诗','song-poetry','','[]','謝家山下雙溪閣，水遠山深夏亦凉。',64,'全唐诗/poet.song.43000.json','["謝家山下雙溪閣，水遠山深夏亦凉。", "霜練兩條初合影，菱花一鑑瀉餘光。", "樽罍日日邀賓客，倉廩年年富稻粱。", "更約諸孫勤問學，桂科將見綠衣郎。"]'),
('14f0317d-1f60-49b3-9da6-5348bf1b9ffb','重陽懷歷陽孫公素太守','郭祥正','宋','宋诗','song-poetry','','[]','重陽應與客登臨，隔水無緣預盍簪。',64,'全唐诗/poet.song.43000.json','["重陽應與客登臨，隔水無緣預盍簪。", "濁瓮撥醅初泛蟻，佳人纖手鬭挼金。", "南來縱有雞山賞，北望頻興魏闕心。", "安得快風吹我去，勇提椽筆伴君吟。"]'),
('a777f4e5-713d-462c-8262-a19da3bbe93c','公素送酒見及復次前韻和答','郭祥正','宋','宋诗','song-poetry','','[]','摻别城東秋未深，相思白髮已盈簪。',64,'全唐诗/poet.song.43000.json','["摻别城東秋未深，相思白髮已盈簪。", "遠分酒味須頽玉，正是秋香欲散金。", "潤澤生民公有志，浮沈末路我無心。", "扁舟明發穿南斗，聊學滄浪漁父吟。"]'),
('e0f7dbb9-f978-41db-9e1c-57d6eb02f40e','送賈明叔侍御守宣','郭祥正','宋','宋诗','song-poetry','','[]','直節忠言久不聞，堂堂今見賈生孫。',64,'全唐诗/poet.song.43000.json','["直節忠言久不聞，堂堂今見賈生孫。", "老姦去位朝廷正，聖母憐才德業尊。", "句水曉光塵不染，敬山秋色玉無痕。", "北樓把酒頻邀客，紫詔傳呼下國門。"]'),
('203e14c8-3fed-4290-a739-813fb3f887ae','次韻昭掾徐子美見寄二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','居巷雖窮愧彼顔，門無車馬任苔斑。',64,'全唐诗/poet.song.43000.json','["居巷雖窮愧彼顔，門無車馬任苔斑。", "冰將合沼光容凈，鳥不窺魚意思閑。", "蹤跡疏來唯夢往，音郵漫去得詩還。", "浮生七十今六十，早晚歸飛尋舊山。"]'),
('535ce45a-87e0-4450-82d5-20a5ffeb9306','次韻昭掾徐子美見寄二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','侵侵白髮改朱顔，不比當年鬢始斑。',64,'全唐诗/poet.song.43000.json','["侵侵白髮改朱顔，不比當年鬢始斑。", "五斗可憐須苟祿，一巖猶喜早偷閒。", "黄花籬下千枝秀，紫雁雲中幾度還。", "萬里未歸歸便得，昭州何似謝家山。"]'),
('a67a9cf7-92e8-42ff-8bb8-87a7a5ba2164','題金陵白鷺亭呈府公安中尚書二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','青城突兀與雲連，誰作高亭落日邊。',64,'全唐诗/poet.song.43000.json','["青城突兀與雲連，誰作高亭落日邊。", "六代衣冠歸寂寞，一番羅綺自華鮮。", "低徊斗柄斟秋水，飛舞蘆花欲雪天。", "直上烟霄無尺五，欲要王母對賓筵。"]'),
('e0273a85-b181-4454-9203-fa15937a48a2','題金陵白鷺亭呈府公安中尚書二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','西望長安路幾千，此亭更在賞心邊。',64,'全唐诗/poet.song.43000.json','["西望長安路幾千，此亭更在賞心邊。", "黄蘆正耐風霜老，白鷺相將羽翼鮮。", "城竦鼇身山匝地，舟排笋柱水連天。", "龍吟一曲斜陽下，况是史君開别筵。"]'),
('a7869326-b9a5-4959-9add-efc60f20e21a','次韻安中尚書鍾阜軒','郭祥正','宋','宋诗','song-poetry','','[]','鍾山鱗鬣奮晴雷，觀裏幽軒選勝開。',64,'全唐诗/poet.song.43000.json','["鍾山鱗鬣奮晴雷，觀裏幽軒選勝開。", "江水北流朝海去，斗杓東轉斡春回。", "已將白雪傳龍笛，何用黄金築隗臺。", "寶塔中天掛刀尺，層層鴛瓦不浮灰。"]'),
('57393b63-788a-4893-9eff-166ae65219dc','送錢朝請還臺','郭祥正','宋','宋诗','song-poetry','','[]','銓選相逢弱冠前，竹符分得各皤然。',64,'全唐诗/poet.song.43000.json','["銓選相逢弱冠前，竹符分得各皤然。", "開樽且喜君尤健，問舍應輸我最先。", "北上有心思報國，南來無物載歸船。", "冰清世澤源流大，須享人間五福全。"]'),
('c0b8767d-bb4c-474d-a768-59f79043514d','蕪陰北寺檜軒','郭祥正','宋','宋诗','song-poetry','','[]','青幢碧蓋儼天成，濕翠濛濛滴畫楹。',64,'全唐诗/poet.song.43000.json','["青幢碧蓋儼天成，濕翠濛濛滴畫楹。", "禪客自陪千歲老，遊人時把一樽傾。", "恥隨桃李春風短，奪盡松篁夜氣清。", "安得鬼仙提巨筆，不容左紐獨傳名。"]'),
('19442c1d-60e1-4ccc-9de0-af55551cb675','明叔致酒疊嶂樓','郭祥正','宋','宋诗','song-poetry','','[]','陵陽峰頂敞欄干，三伏登臨冰骨寒。',64,'全唐诗/poet.song.43000.json','["陵陽峰頂敞欄干，三伏登臨冰骨寒。", "山卷宿雲開紫府，水和明月瀉金湍。", "謝公風味君能似，李白篇章我到難。", "幸有玉船騰酒浪，欲乘醉興效鵬摶。"]'),
('9007e82c-b334-4b90-89de-7de970976fb5','次韻鄒幾聖舟次蕪江見寄','郭祥正','宋','宋诗','song-poetry','','[]','東風冉冉送年華，末路浮沈豈足嗟。',64,'全唐诗/poet.song.43000.json','["東風冉冉送年華，末路浮沈豈足嗟。", "身着朱衣行直道，手披黄卷悟空花。", "世塵擾擾原無實，客宦悠悠役有涯。", "尚喜甘棠遺愛在，畫船先許過漁家。"]'),
('29ccf704-0a55-4368-b44d-ce594ae55da9','寄題歷陽王純甫新作連雲觀二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','久持使節别堯天，故起朱樓北斗邊。',64,'全唐诗/poet.song.43000.json','["久持使節别堯天，故起朱樓北斗邊。", "勢壓江淮盤地厚，影分吳楚與雲連。", "一聲奏笛龍蛇曉，八法書牌劍戟懸。", "更借湓城庾家月，芟除桂樹照樽前。"]'),
('2fc8a928-f4f8-4c07-a46e-e5c86ccdc9ff','寄題歷陽王純甫新作連雲觀二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','聞道連雲絕世無，急飛輕櫂看規模。',64,'全唐诗/poet.song.43000.json','["聞道連雲絕世無，急飛輕櫂看規模。", "簾鈎低掛半輪月，江岸平分千里圖。", "颭颭金船流玉液，森森珠履踏冰壺。", "高材自是明堂柱，試作斯樓雄楚都。"]'),
('1eafaddd-6183-4074-86c6-75879004270c','送黄奉議知白州前宰清遠','郭祥正','宋','宋诗','song-poetry','','[]','看君新作海邊樓，氣象雄兼四五州。',64,'全唐诗/poet.song.43000.json','["看君新作海邊樓，氣象雄兼四五州。", "把筆共題紅粉壁，開樽仍泛玉蟾秋。", "喜分符竹行千里，莫羨漁蓑退一丘。", "此别定爲生死隔，雪霜霑盡暮年頭。"]'),
('fb60ae33-cd10-4c4b-b689-2ee90e4c081a','次韻朱世昌察院登鍾山','郭祥正','宋','宋诗','song-poetry','','[]','盤龍首尾壓西東，寶塔稜層位正中。',64,'全唐诗/poet.song.43000.json','["盤龍首尾壓西東，寶塔稜層位正中。", "萬古林泉流王氣，六朝冠蓋入悲風。", "烟生城郭塵昏盡，月滿沙汀雪映空。", "回首臨川埋骨處，後來經緯付諸公。"]'),
('a6b98730-0e62-4476-9e98-715ebed0aca6','次韻答光守楊公濟見寄','郭祥正','宋','宋诗','song-poetry','','[]','一别成都揚子雲，夢魂飛斷每沾巾。',64,'全唐诗/poet.song.43000.json','["一别成都揚子雲，夢魂飛斷每沾巾。", "金門賦奏龍蛇曉，原廟詩成錦繡春。", "顧我漫爲長醉客，非君誰是廣騷人。", "榮分符竹歸無路，盛送佳篇慰病身。"]'),
('21ba893a-125f-4993-ac71-558c5a212e08','病中先寄慎宰閻公達承議','郭祥正','宋','宋诗','song-poetry','','[]','松檟相望孰俊名，高才暫屈浚遒城。',64,'全唐诗/poet.song.43000.json','["松檟相望孰俊名，高才暫屈浚遒城。", "公庭寂寂無留訟，四野熙熙有讓耕。", "未作鹽梅調鼎鼐，且鏗金玉直蓬瀛。", "病骸尚阻趨東閣，懷抱思君爲一傾。"]'),
('78cde0af-31b1-43cf-a5b6-fb8bf0959713','陪朱行中龍圖飲澄惠院二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','寒烟淡日滿滄洲，臺榭相通一徑幽。',64,'全唐诗/poet.song.43000.json','["寒烟淡日滿滄洲，臺榭相通一徑幽。", "志欲吞吳嗟隔水，力能成魏密藏舟。", "紙窻趁曉開黄卷，蒲葉涵春付白鷗。", "千載廢興何可問，一樽濁酒更遲留。"]'),
('24a9ed9e-7226-4628-bb18-cd38d974057c','陪朱行中龍圖飲澄惠院二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','島嶼回環水遶堤，碧蘆青荇密相依。',64,'全唐诗/poet.song.43000.json','["島嶼回環水遶堤，碧蘆青荇密相依。", "凌風戰艦知何處，落日遊人尚未歸。", "細細佛香時入坐，雙雙沙鳥靜忘機。", "史君自是蓬萊客，倚遍欄干戀翠微。"]'),
('361cb9bb-1ef5-4cf9-bc27-ca62537e9eca','再見吳淵卿長官時年八十一','郭祥正','宋','宋诗','song-poetry','','[]','十七年前載酒過，重來攜手喜如何。',64,'全唐诗/poet.song.43000.json','["十七年前載酒過，重來攜手喜如何。", "壽齊八十君方健，思及妻兒我已多。", "對檻殘花猶可賞，隔簾小妓且頻歌。", "人間事了無憂患，頭上光陰任擲梭。"]'),
('2e2c7eb2-3133-4b0c-bf4e-a0cb00f3d22b','淵卿席上和李天貺四韻時與鍾離中散并予共四人','郭祥正','宋','宋诗','song-poetry','','[]','悠悠歲月走驚湍，四十三時便棄官。',64,'全唐诗/poet.song.43000.json','["悠悠歲月走驚湍，四十三時便棄官。", "座上得陪諸老醉，樽前須盡一生歡。", "花含餘恨春將去，棋算成功局未殘。", "欲向金城傳盛事，新詩聊代畫圖看。"]'),
('bc6ad653-a7b4-4171-8c83-9117f2db4728','次韻行中龍圖遊後浦六首  其一','郭祥正','宋','宋诗','song-poetry','','[]','密竹疏松鬭老蒼，驚飛白鳥不成雙。',64,'全唐诗/poet.song.43000.json','["密竹疏松鬭老蒼，驚飛白鳥不成雙。", "樓船飄忽隨朝電，佛炬青熒徹夜窻。", "攜酒且來尋島嶼，投竿那用憶湖江。", "君看雨過鋪晴練，得句須令小謝降。"]'),
('cbc05cef-2dc3-4925-bd3a-6fccdde60fe7','次韻行中龍圖遊後浦六首  其二','郭祥正','宋','宋诗','song-poetry','','[]','每欲收吳勢未任，遶城鑿浦跡堪尋。',64,'全唐诗/poet.song.43000.json','["每欲收吳勢未任，遶城鑿浦跡堪尋。", "不知戰罷樓船散，空見春歸荇菜深。", "一坐清風吹往事，四筵白酒洗煩襟。", "公提椽筆詩無敵，未必張遼善醉吟。"]'),
('452946e4-09e1-408b-910c-e9175008e12b','次韻行中龍圖遊後浦六首  其三','郭祥正','宋','宋诗','song-poetry','','[]','細柳高松綠映蒼，深沉臺榭晚生凉。',64,'全唐诗/poet.song.43000.json','["細柳高松綠映蒼，深沉臺榭晚生凉。", "沙邊宿鷺昏昏白，草際流螢點點光。", "投網舟移牽碧荇，採蓮人去濕紅裳。", "欲追逸調嗟何及，雨入盃盤歸興忙。"]'),
('e22e62ef-22d2-4910-a680-f248ab5527e3','次韻行中龍圖遊後浦六首  其四','郭祥正','宋','宋诗','song-poetry','','[]','巨鎮還須濟世才，要賓覽古笑談開。',64,'全唐诗/poet.song.43000.json','["巨鎮還須濟世才，要賓覽古笑談開。", "蜀山迥出千螺秀，肥水長縈一带迴。", "猶有金城藏後浦，不唯銅雀起高臺。", "異時爭戰歸何處，秋雁年年去復來。"]'),
('758cd0b7-e7aa-4428-bfa7-a24a060f770e','次韻行中龍圖遊後浦六首  其五','郭祥正','宋','宋诗','song-poetry','','[]','錦櫂飛飛畫舫迎，焚香夾道看雙旌。',64,'全唐诗/poet.song.43000.json','["錦櫂飛飛畫舫迎，焚香夾道看雙旌。", "佳賓談笑民同樂，善政循良鳥不驚。", "花島可憐春自舞，柳洲遙覺月微明。", "史君一飲詩千句，擲地渾如金玉聲。"]'),
('a05c6fba-8ea2-4e5d-8eda-09121ae62918','次韻行中龍圖遊後浦六首  其六','郭祥正','宋','宋诗','song-poetry','','[]','冠带淮西第一州，揚鞭得從史君遊。',64,'全唐诗/poet.song.43000.json','["冠带淮西第一州，揚鞭得從史君遊。", "木魚聲斷東臺曉，水荇香傳後浦秋。", "雙脊自磨銅雀瓦，密雲時泛建溪甌。", "才清思健知無敵，且與衰殘作廕庥。"]'),
('f39adcdb-0ee5-4f98-ba38-b30b3f278c4a','次韻行中龍圖思宣城','郭祥正','宋','宋诗','song-poetry','','[]','公愛宣城心不休，當年應夢似崔侯。',64,'全唐诗/poet.song.43000.json','["公愛宣城心不休，當年應夢似崔侯。", "兩條溪水横穿市，十里昭山半在州。", "小杜一時誇俊逸，玄暉千載擅風流。", "青氈舊物雖勤請，金馬新恩定再留。"]'),
('0b7d7515-95fc-486f-9d64-48e2cf8881fd','寄題玉笥觀兼簡道正求逐馬草草名逐馬謂服之久則可以行逐良馬','郭祥正','宋','宋诗','song-poetry','','[]','仙梁飛去有遺壇，融結工夫玉未乾。',64,'全唐诗/poet.song.43000.json','["仙梁飛去有遺壇，融結工夫玉未乾。", "一片碧烟鸞舞破，數枝紅蕊鹿銜殘。", "雨經梅澗芝田熟，路入蕭家月屋寒。", "晚景自憐行六十，欲求逐馬問黄冠。"]'),
('aa9ccde5-9f9b-4353-b7b6-1498eecff276','端門肆赦','郭祥正','宋','宋诗','song-poetry','','[]','藹藹端門紫氣濃，卷簾蘭麝散和風。',64,'全唐诗/poet.song.43000.json','["藹藹端門紫氣濃，卷簾蘭麝散和風。", "星環帝座天澄碧，繖映龍顔日透紅。", "寶扇參差移仗裏，金雞綽約下雲中。", "恩覃草木先春力，萬歲歡聲闔國同。"]'),
('e5a97bdf-b943-4e8d-96a3-76b631a1a9bd','王平甫下第南歸','郭祥正','宋','宋诗','song-poetry','','[]','一番黄紙集羣材，南國儒英起草萊。',64,'全唐诗/poet.song.43000.json','["一番黄紙集羣材，南國儒英起草萊。", "至寶不逢知己鑑，束書重見下天來。", "壯心肯向明時屈，孤憤須臨濁酒開。", "許有新詩令我聽，夜堂還使鬼神哀。"]'),
('d554461b-bf43-4752-8b24-1110741f9a57','贈歷溪張居士','郭祥正','宋','宋诗','song-poetry','','[]','七十人稀九十翁，數椽寒屋歷溪東。',64,'全唐诗/poet.song.43000.json','["七十人稀九十翁，數椽寒屋歷溪東。", "俯窺聲利非吾事，自得逍遙與古同。", "三疊琴心調夜月，一盃茗酌送春風。", "趨庭有子明詩禮，善澤源源未可窮。"]'),
('86c91bab-c111-4074-8056-915f51327e02','題濮陽氏新閣','郭祥正','宋','宋诗','song-poetry','','[]','宅据中洲四望寛，隔江山勢舞青鸞。',64,'全唐诗/poet.song.43000.json','["宅据中洲四望寛，隔江山勢舞青鸞。", "岧嶤更起千尋閣，汗漫平吞萬里湍。", "傳業有兒須折桂，開樽留客共彈冠。", "霜消冰泮春將暖，魏闕遙瞻獨倚欄。"]'),
('4533832d-4dff-4f17-98c4-fd663e6c90cd','代先書奉迎廬帥元輿待制','郭祥正','宋','宋诗','song-poetry','','[]','倦提椽筆厭承明，帝與兵符帥十城。',64,'全唐诗/poet.song.43000.json','["倦提椽筆厭承明，帝與兵符帥十城。", "簫鼓裂雲迎五馬，山川收雨引雙旌。", "藏舟浦暖魚頻躍，敎弩臺空雁不驚。", "入境觀風先可喜，秋田高下熟香秔。"]'),
('3b85b576-892d-4940-9d5a-bae411d2124a','許氏樂隱亭','郭祥正','宋','宋诗','song-poetry','','[]','曲水浮基竹遶簷，月華初度晚凉添。',64,'全唐诗/poet.song.43000.json','["曲水浮基竹遶簷，月華初度晚凉添。", "羽觴灧灧荷敷綠，象箸森森笋迸尖。", "白眼傲時饒阮籍，素琴調曲慕陶潛。", "城居樂隱能如此，中散風流友弟兼。"]'),
('2888fc97-01b0-466d-a50c-c6ea2f9721d8','重題嚴伯成秀才西齋喜其子高預鄉薦','郭祥正','宋','宋诗','song-poetry','','[]','賦似相如不遇知，喜聞鄉版薦麟兒。',64,'全唐诗/poet.song.43000.json','["賦似相如不遇知，喜聞鄉版薦麟兒。", "容身安穩書盈篋，與客翺翔酒滿巵。", "夜月影搖楊柳徑，秋風香散菊花籬。", "竇家千載傳遺美，一樹靈椿桂五枝。"]'),
('de656ec2-6e7b-46f4-8101-e74e8dfa29d1','劉交侍禁書報王君安改官監懷州武德鎮鐸以詩喜之','郭祥正','宋','宋诗','song-poetry','','[]','自得劉郎音信通，遂聞增秩喜無窮。',64,'全唐诗/poet.song.43000.json','["自得劉郎音信通，遂聞增秩喜無窮。", "江東子弟誰憐我，洛下文章只有公。", "形影蕭條千里外，交游零落百年中。", "何當老境重相遇，不話風流話苦空。"]'),
('b4f9c977-936b-4afb-ab08-d47dfc147d3e','雪中招徐子美秘校飲二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','冰澌合硯漫書空，密雪飄餘曉色通。',64,'全唐诗/poet.song.43000.json','["冰澌合硯漫書空，密雪飄餘曉色通。", "萬里雲光同浩蕩，四邊山影隔溟濛。", "明明月窟迷驚兔，陣陣桑林叫朔風。", "不惜金龜將貰酒，欲招南郭苦寒翁。"]'),
('d25a6ffa-f765-420e-b7ae-d25649dfc6d1','雪中招徐子美秘校飲二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','霏霏皓雪翳長空，南郭緣何有徑通。',64,'全唐诗/poet.song.43000.json','["霏霏皓雪翳長空，南郭緣何有徑通。", "訪戴船歸清興逸，姓袁人卧冷光濛。", "欲傾樽俎延高蓋，忽得篇章邁古風。", "四十年前除夜樂，如今相對兩衰翁。"]'),
('cf6111fd-7b6e-4a50-b688-563d1d5fa63b','史君梁奉議送客至高明軒爲予言登覽之勝作四韻戲寄','郭祥正','宋','宋诗','song-poetry','','[]','史君送客陟高臺，天宇澄清四望開。',64,'全唐诗/poet.song.43000.json','["史君送客陟高臺，天宇澄清四望開。", "一字横空霜雁去，兩眉分碧楚江來。", "廟堂孰是調羮手，郡國猶淹濟世才。", "新酒正香鱸蟹美，籃輿何日許重陪。"]'),
('f421ccba-b3f5-49dd-b67f-15ad643ea865','次韻徐子美見懷兼簡湯君材','郭祥正','宋','宋诗','song-poetry','','[]','闊别天涯每愴然，相思只欲學飛仙。',64,'全唐诗/poet.song.43000.json','["闊别天涯每愴然，相思只欲學飛仙。", "君承交辟專民事，我慕高風謝世緣。", "南郭不辭三徑遠，東山長與五雲連。", "會須載酒勤相過，齒髮蕭條各暮年。"]'),
('2c3df4ba-d428-4b58-8030-dd2538ec098e','將至壽州先寄知府龍圖三首  其一','郭祥正','宋','宋诗','song-poetry','','[]','感公招我欲論詩，故歲新年頗後期。',64,'全唐诗/poet.song.43000.json','["感公招我欲論詩，故歲新年頗後期。", "冰塞大江舟渡晚，雪迷官道馬行遲。", "深深畫戟雙開處，淺淺梅花半綻時。", "北闕除書應已到，願陪祖帳捧瓊巵。"]'),
('0e35b0dd-b79e-4a8f-8fa6-9d14d29c5629','將至壽州先寄知府龍圖三首  其二','郭祥正','宋','宋诗','song-poetry','','[]','短帽輕衫信馬蹄，只愁吟社爽襟期。',64,'全唐诗/poet.song.43000.json','["短帽輕衫信馬蹄，只愁吟社爽襟期。", "曉回谷口禽聲軟，寒束梅梢春思遲。", "幸挹清標憐野逸，肯將孤憤累明時。", "聽公高論何由盡，應比醍醐灌漏巵。"]'),
('f987142f-30e6-4562-963c-bf32674a1873','將至壽州先寄知府龍圖三首  其三','郭祥正','宋','宋诗','song-poetry','','[]','采石江邊寂寞歸，壽陽重到信前期。',64,'全唐诗/poet.song.43000.json','["采石江邊寂寞歸，壽陽重到信前期。", "聞韶忘味寧非美，傾蓋論交已恨遲。", "白鳳文章元出衆，青雲歧路合逢時。", "杏花正怯清明雨，强欲留連更一巵。"]'),
('0054eb25-c400-46a5-93af-d284e70b0ce5','置酒壽陽樓呈主公龍圖二首  其一','郭祥正','宋','宋诗','song-poetry','','[]','珠履繽紛宴壽陽，欄杆横出白雲傍。',64,'全唐诗/poet.song.43000.json','["珠履繽紛宴壽陽，欄杆横出白雲傍。", "清淮倒影長橋活，古壘無春峽石荒。", "小艇鬭垂凹鼻釣，佳人猶學曉梅妝。", "史君筆力今誰敵，麗句須盈古錦囊。"]'),
('58728364-aea0-4c2f-979b-1d2b5024fd9d','置酒壽陽樓呈主公龍圖二首  其二','郭祥正','宋','宋诗','song-poetry','','[]','置酒南樓瞰夕陽，逶迤淮影轉城傍。',64,'全唐诗/poet.song.43000.json','["置酒南樓瞰夕陽，逶迤淮影轉城傍。", "畫殘數幅山川舊，棋散一枰洲渚荒。", "細柳倚風相並舞，飛梅着地不成妝。", "坐中佳句誰先就，我欲窺公倒智囊。"]'),
('9aec0165-cf7d-493b-ae9b-f4f2a6290251','置酒西樓呈主公龍圖','郭祥正','宋','宋诗','song-poetry','','[]','新樓與客一凭欄，眼界方驚阿堵寛。',64,'全唐诗/poet.song.43000.json','["新樓與客一凭欄，眼界方驚阿堵寛。", "峽石倚天開玉壘，清淮浮日洗金丸。", "少陵才力吟非易，摩詰工夫畫亦難。", "向晚西風吹坐急，欲憑鴻鵠借修翰。"]'),
('23d3c66a-2e43-45a3-aa2b-4523e00464e2','置酒思禹亭呈主公龍圖','郭祥正','宋','宋诗','song-poetry','','[]','小亭危瞰二峰尖，禹跡千年氣象炎。',64,'全唐诗/poet.song.43000.json','["小亭危瞰二峰尖，禹跡千年氣象炎。", "浪濺日華金沸鼎，雲收山色鏡開匳。", "持杯選勝吟誰敵，與客忘形德愈謙。", "淺量爲公甘醉倒，扶頭准擬病厭厭。"]'),
('4d9e29fd-b5ca-4200-a1f8-db10e95e8fda','别行中龍圖','郭祥正','宋','宋诗','song-poetry','','[]','要登畫戟發江南，千里春泥倦亦甘。',64,'全唐诗/poet.song.43000.json','["要登畫戟發江南，千里春泥倦亦甘。", "力探禹工觀駭浪，却尋佛跡宴圜庵。", "欲陳舊學羞茅塞，喜聽新詩縱酒酣。", "歸去憶公勞夢想，冷猿幽鳥語相參。"]'),
('0fcc5385-b30a-41e1-8d17-d9ea845ee151','送廬倅趙習之朝奉還臺','郭祥正','宋','宋诗','song-poetry','','[]','洛陽名譽弟兄兼，霧拂青天幸一瞻。',64,'全唐诗/poet.song.43000.json','["洛陽名譽弟兄兼，霧拂青天幸一瞻。", "善政及瓜民惜去，美材如玉士稱淹。", "風搖湖浪應須避，馬濺春泥不用嫌。", "聞說朝廷圖舊德，姓名交奏動宸嚴。"]'),
('bbd3dd70-f214-4631-b3cc-764c7a6c9d0b','聞宣州王左丞被召還闕擬送','郭祥正','宋','宋诗','song-poetry','','[]','熙寧治蹟儼如新，聖主今朝用舊臣。',64,'全唐诗/poet.song.43000.json','["熙寧治蹟儼如新，聖主今朝用舊臣。", "松冒秋霜方見節，玉經爐炭始知真。", "具瞻盡喜周公入，論道誰先孟子醇。", "試作雲霖蘇旱暵，西疆猶有未來人。"]'),
('5ea8e14f-39f6-44a8-bb6b-11c97ffc525a','送王左丞移鎮金陵','郭祥正','宋','宋诗','song-poetry','','[]','千艘飛櫓入淮灣，竹馬爭迎舊帥還。',64,'全唐诗/poet.song.43000.json','["千艘飛櫓入淮灣，竹馬爭迎舊帥還。", "牛酒未頒諸邑下，旌旗先謁兩山間。", "武侯暫擁元戎節，裴度須歸上宰班。", "精義入神遺像在，載瞻堂廡淚重潸。"]'),
('d70d02d4-ff8e-4499-bffe-9e06f05c1cde','題史君梁正叔浩然堂','郭祥正','宋','宋诗','song-poetry','','[]','養浩深思孟氏醇，一堂窻戶更清新。',64,'全唐诗/poet.song.43000.json','["養浩深思孟氏醇，一堂窻戶更清新。", "篆香未過日停午，蟻酒初浮鶯弄春。", "枉尺直尋非我欲，仁民愛物任吾真。", "三年課績書優最，此地誰來繼後塵。"]'),
('0643c761-9d9f-415e-bfcb-bc9e91be0ced','次韻和孔周翰侍郎洪州絕句十首  其一','郭祥正','宋','宋诗','song-poetry','','[]','誰知北客與春期，乍見山桃一兩枝。',32,'全唐诗/poet.song.43000.json','["誰知北客與春期，乍見山桃一兩枝。", "却憶洛陽行樂處，賣花天氣晚晴時。"]'),
('d4542a38-709a-4cad-8ac7-38c0e16e4da3','次韻和孔周翰侍郎洪州絕句十首  其二','郭祥正','宋','宋诗','song-poetry','','[]','漁船歸盡晚江空，只有楊花罥細風。',32,'全唐诗/poet.song.43000.json','["漁船歸盡晚江空，只有楊花罥細風。", "多少春愁與春恨，爲君都付酒盃中。"]'),
('b3bd55e3-5ba1-49db-83fb-93ec38989a99','次韻和孔周翰侍郎洪州絕句十首  其三','郭祥正','宋','宋诗','song-poetry','','[]','樓居且欲趁虚凉，九月江風未變霜。',32,'全唐诗/poet.song.43000.json','["樓居且欲趁虚凉，九月江風未變霜。", "强把一樽開醉眼，長安不見又殘陽。"]'),
('cbcc507b-9bff-4341-aaa5-28239b39fa5c','次韻和孔周翰侍郎洪州絕句十首  其四','郭祥正','宋','宋诗','song-poetry','','[]','寸心無事自然灰，不是南柯一夢迴。',32,'全唐诗/poet.song.43000.json','["寸心無事自然灰，不是南柯一夢迴。", "水畔小樓無客到，獨攜笻杖等閒來。"]'),
('c6b7b307-2f9b-4238-b4a0-ec424b848e61','次韻和孔周翰侍郎洪州絕句十首  其五','郭祥正','宋','宋诗','song-poetry','','[]','行行楊柳古牆陰，擺盡春風綠轉深。',32,'全唐诗/poet.song.43000.json','["行行楊柳古牆陰，擺盡春風綠轉深。", "俯仰自能無一事，何須投跡向山林。"]'),
('39d3af33-7a0f-42e6-ab61-2f99c176a997','次韻和孔周翰侍郎洪州絕句十首  其六','郭祥正','宋','宋诗','song-poetry','','[]','江雲凝雨疾風過，陣馬爭回萬疊波。',32,'全唐诗/poet.song.43000.json','["江雲凝雨疾風過，陣馬爭回萬疊波。", "平地看時真一笑，鵬騰鼇倒欲如何。"]'),
('078bc8ed-b19c-4811-8450-b36b1cefc03d','次韻和孔周翰侍郎洪州絕句十首  其七','郭祥正','宋','宋诗','song-poetry','','[]','爲問荷華能白紅，東湖遙想鑑湖同。',32,'全唐诗/poet.song.43000.json','["爲問荷華能白紅，東湖遙想鑑湖同。", "金龜換酒要佳客，歸櫂須乘月下風。"]'),
